INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate description of the “selection sort” algorithm?', NULL, 'An intermediate reference value is determined, and then the elements are divided into two groups of “larger” values and “smaller” values. This operation is recursively repeated.', 'Each set of elements extracted at regular intervals is sorted, and then the interval is further decreased. The operation is repeatedly performed until the interval becomes 1.', 'The element with the largest value is determined and swapped for the last element, and then the largest value of the unsorted elements is determined and swapped for the second-to-the-last element. This operation is repeated in the same way.', 'Two adjacent elements are repeatedly compared and swapped if the first element is larger than the second. This operation is repeated until all elements are arranged in an orderly fashion.', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-O-07', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the approximate performance of a CPU in MIPS, when the instruction mix of the CPU is shown in the table below? Here, the CPU does not use a pipeline architecture.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-08.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0wOC5wbmciLCJpYXQiOjE3NDMxMTMwMDAsImV4cCI6MTc3NDY0OTAwMH0.4vTe83eCXJtfSeN1UHOHmc0G2TRLHLnmWr1k9DOzd4Q', '0.03', '0.41', '2.44', '35', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-O-08', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the CPU needs data, it first accesses the cache memory. When the data is not available in the cache memory, the CPU accesses the main memory. If the miss ratio is 0.2 and the access times for cache memory and main memory are as shown below, what is the approximate average memory access time in ns for the CPU?  Here, there are only cache memory and main memory for the CPU, the access time for main memory includes the time to confirm whether the data is available in cache memory, and the overhead time for the cache management can be ignored.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-09.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0wOS5wbmciLCJpYXQiOjE3NDMxMTMwMDgsImV4cCI6MTc3NDY0OTAwOH0.FtyRfWT4OGjVMNZPL2ruWYnnweSR4W_yg5uHNMEQZ2k', '315', '360', '1,215', '1,260', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-O-09', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate purpose of defragmentation of hard disks?', NULL, 'To access disk files faster and more efficiently', 'To clean up temporary and junk files', 'To delete IBG (interblock gap) and increase capacity', 'To protect disk drives from physical failures', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-O-10', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a fail-safe concept for improving the security and reliability of the information system?', NULL, 'Even when the user performs an incorrect operation, a problem does not occur in the system.', 'Even when there is a partial system fault, the required functions of the overall system are maintained.', 'When a device configuring the system fails, damage can be minimized by enabling the system to stop safely.', 'When a system failure occurs, processing is continued by switching to a standby system.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-11', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the approximate availability of the system comprising five devices, namely, A, B, C, D, and E as shown in the figure below? The numeric value in parentheses represents the availability of each device. The system is operational if either device connected in parallel is available.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-12.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0xMi5wbmciLCJpYXQiOjE3NDMxMDk4OTIsImV4cCI6MTc3NDY0NTg5Mn0.jfcmIuW2b2_k1nyma7WEO7oLfg6pMaqJLTHvhd6xLRA', '0.003', '0.031', '0.282', '0.795', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-12', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There are minor and major page faults in an Operating System (OS). Which of the following is an appropriate action of the OS when a major page fault occurs?', NULL, 'Asking the user to input the instruction corresponding to the page', 'Looking for a page in CPU cache', 'Looking for a page in virtual memory on the hard disk', 'Looking for the missed block corresponding to the page on the physical memory', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-O-13', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A real-time OS that performs preemptive priority scheduling for tasks A and B with A having a higher priority than B. Which of the following is the action that the OS takes?', NULL, 'When A is launched during the execution of B, B is put into a ready state and A is executed.', 'When A is launched during the execution of B, B is put into a waiting state and A is executed.', 'When B is launched during the execution of A, A is put into a ready state and B is executed.', 'When B is launched during the execution of A, A is put into a waiting state and B is executed.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-O-14', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An OS chooses a process for CPU execution based on a scheduling algorithm. Consider four processes, P1, P2, P3, and P4, and their corresponding arrival times along with their burst times shown in the table below. Which of the following is the correct combination of waiting times for the processes to be executed in the First-Come-First-Serve (FCFS) scheduling algorithm? Here, arrival time is when a process enters the ready queue, burst time is the time required for CPU xecution, and waiting time is the time a process spends in the ready queue before CPU execution begins.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-15.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0xNS5wbmciLCJpYXQiOjE3NDMxMDk5MDUsImV4cCI6MTc3NDY0NTkwNX0.lclD9m9jUA54DFZews-tjyET9fW0lvsv-97yl9q5PDA', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-O-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A graphical symbol for the 2-to-1 MUX (multiplexer) and its truth table are shown in the figure below. The MUX has two data inputs (I₀, I₁), one select-line (S) and one output (Z). If the select line is S = 0, then the output Z is switched to input I₀, whereas if a select line is S = 1, then the output Z is switched to input I₁.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-16.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0xNi5wbmciLCJpYXQiOjE3NDMxMDk5MTcsImV4cCI6MTc3NDY0NTkxN30.0DxeFe4u9BCzXTfrH3GrWflBDaLAzIv0pydgdxRs70g', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-16-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0xNi1BLnBuZyIsImlhdCI6MTc0MzEwOTk1NiwiZXhwIjoxNzc0NjQ1OTU2fQ.mWeJRNzMpYsMwz8onK15mzytBvvzaNtxzUCVfnplx_A', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-16-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0xNi1CLnBuZyIsImlhdCI6MTc0MzEwOTk3MCwiZXhwIjoxNzc0NjQ1OTcwfQ.sbe88ea5F9gByP6kVwEvQ0dIGNv1oJ-3oLYYYUTMqvk', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-16-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0xNi1DLnBuZyIsImlhdCI6MTc0MzEwOTk3NiwiZXhwIjoxNzc0NjQ1OTc2fQ.wy-JjBVL5NfShTlb7ZAoIKOt-1TtYhVid8kul_5WSBE', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-16-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0xNi1ELnBuZyIsImlhdCI6MTc0MzEwOTk4MSwiZXhwIjoxNzc0NjQ1OTgxfQ.XdCL0mguTOZtcN3vzQzP-9WqJtxSq2YdH74xBYQuSC4', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-O-16', -1.0, 1.0);
