INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('If a transaction processing program ends abnormally while updating the database, the database is recovered by a rollback process. In these circumstances, which of the following is the information that is used?', NULL, 'Post-update information of log files', 'Pre-update information of log files', 'The latest backup file information', 'The latest snapshot information', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-21', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a property on a database that guarantees a result where a transaction either fully completes update processing or is revoked as if no processing took place at all?', NULL, 'Atomicity', 'Consistency', 'Durability', 'Isolation', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-22', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a device that connects LANs?', NULL, 'A bridge relays frames based on IP addresses.', 'A gateway converts the protocols of only the first through third levels in the OSI basic reference model.', 'A repeater extends the transmission distance by amplifying signals between segments of the same type.', 'A router relays frames based on MAC addresses.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-23', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the broadcast address of the network 192.168.128.0/22?', NULL, '192.168.128.127', '192.168.128.255', '192.168.131.255', '192.168.255.255', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-24', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a protocol to gather information on network components to manage and troubleshoot the network?', NULL, 'NTP', 'SMTP', 'SNMP', 'TELNET', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-25', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the way of using a phone to supply an Internet connection to other devices, such as a tablet or laptop computer over either Wi-Fi or Bluetooth?', NULL, 'Dedicated mobile hotspots', 'PPPoE', 'Tethering', 'UPnP', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-26', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of a phishing email?', NULL, 'An email containing pop-up ads for products unrelated to the email', 'An email intercepted, altered, and successfully sent', 'An email with a link that automatically installs an application collecting and sending data to the remote server', 'An email with a link that redirects to a fake banking site', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-27', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following bitwise logical operation can be applied in stream cipher between a plain text and a keystream to produce a cipher text, and between a ciphertext and the keystream to recover the plaintext?', NULL, 'AND', 'NAND', 'OR', 'XOR', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-28', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following description is an appropriate use of asymmetric encryption to ensure the confidentiality of a message that a sender is going to send to a receiver?', NULL, 'The message is encrypted using a pre-shared secret key.', 'The message is encrypted using a private key of the sender.', 'The message is encrypted using a public key of the receiver.', 'The message is encrypted using a public key of the sender.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-29', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which type of attack involves intercepting communication between sender and receiver?', NULL, 'Brute Force Attack', 'Man-in-the-Middle Attack', 'Phishing Attack', 'Ransomware Attack', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-30', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following refers to a technique that is used in a credential stuffing attack?', NULL, 'Focusing on the case where there are users that set a word from the dictionary as their password, selecting one (1) user ID as the target of the attack, and attempting to log in using words in the dictionary and their combinations as the password', '', 'Focusing on the case where there are users that use the same user ID and password on multiple websites, and attempting to log in using a list of user IDs and passwords fraudulently acquired from other websites', 'Selecting one (1) frequently used password, and attempting to log in by using user IDs of all possible combinations of characters', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-31', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the name of an attack where manipulation is made to display a malicious website near the top of the results on a search website?', NULL, 'Cross-site scripting', 'DNS cache poisoning', 'SEO poisoning', 'Social engineering', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-32', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a function of security information and event management (SIEM)?', NULL, 'The centralized control of a range of communication devices in a network, and the changing of network configuration and security settings', 'The execution of a file in an isolated virtual environment, and the monitoring of communication to a C&C server and other behavior', 'The general analysis of logs that are collected from a range of devices, and the support of analysis and action by an administrator', 'The inspection of header information in packets, the identification of application programs that receive communication, and the control of communication', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-33', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the UML behavioral diagram showing the behavior of a single object in response to triggers?', NULL, 'Activity diagram', 'Sequence diagram', 'State machine diagram', 'Use case diagram', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '24-O-34', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In object-oriented programming, which of the following is abstraction?', NULL, 'Concealing implementation details and exposing only a simplified interface for interacting with objects', 'Creating a subclass instance inheriting attributes and behaviors from its superclass', 'Defining multiple methods with the same name but different parameters', 'Redefining in the child class a method that is already provided by the superclass with the same name and parameters but a different implementation', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-O-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of “delegation” in object orientation?', NULL, 'A mechanism that creates one (1) new object using multiple objects as its parts', 'A mechanism where a lower-level class inherits the attribute or operation of a higher level class', 'A mechanism where an application of an operation to a certain object automatically causes the application of that operation to related objects', 'A mechanism where an operation to a certain object is internally requested to be performed by another object', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-O-36', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In unit testing, which of the following activities is part of white box testing?', NULL, 'Boundary value analysis', 'Condition testing', 'Equivalence partitioning', 'Orthogonal array testing', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '24-O-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate explanation of a stub or a driver used in a test?', NULL, 'A driver is a module that is called from the module to be tested', 'A driver passes arguments and calls the module to be tested', 'A stub is a module used to call the module to be tested', 'A stub is used to display or print the values returned from the module to be tested', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '24-O-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Scrum is an agile development method. In Scrum, which of the following is an event where each member of the development team talks in turn about topics such as “things I did yesterday,” “things I will do today,” and “obstacles,” and all members share the status of a project?', NULL, 'Daily Scrum', 'Retrospective', 'Sprint planning', 'Sprint review', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '24-O-39', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among eXtreme Programming (XP) practices, which of the following is adopted to improve program quality in program development through smooth communication between programmers by exchanging their roles and reviewing each other’s work?', NULL, 'Coding standard', 'Pair programming', 'Planning game', 'Test-driven development', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '24-O-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate purpose for using a Work Breakdown Structure (WBS) in a software development project?', NULL, 'To clarify the sequence relation of activities and understand the critical path that should be intensively managed', 'To hierarchically detail activities and segment them into a manageable scale', 'To optimize the total cost when there is a trade-off between the duration and the cost of development', 'To represent the schedule of an activity with a horizontal bar, and clarify the start time and end time of the activity as well as the progress at the present point in time', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '24-O-41', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation concerning the scope creep in project scope management?', NULL, 'A hierarchical decomposition of the total scope of work to be carried out by the project team to accomplish the project objectives and create the required deliverables', 'Any change to the project scope, which almost consistently requires an adjustment to the project cost or schedule', 'The sum of the products, services, and results to be provided as a project', 'The uncontrolled expansion of product or project scope without adjustments to time, cost, and resources', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '24-O-42', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a requirement for service level management?', NULL, 'A capacity plan is created, implemented, and maintained while human, technical,informational, and financial resources are considered.', 'A service catalog and SLA are created for the service to be provided, and they are agreed upon with the customer.', 'Costs are monitored and reported against the budget; the financial forecasts are reviewed, and costs are managed.', 'Risks to service continuity and availability of services are assessed and documented.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '24-O-43', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A device that operates 24 hours a day, 360 days a year has an MTBF value of 1,440 hours. Which of the following is the average number of failures for this device for 360 days? Here, the result is rounded to the closest whole number, and the MTTR of the device is ignored.', NULL, '3', '6', '9', '12', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-O-44', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description of a system auditor?', NULL, 'The entire audit interview must be conducted by one (1) system auditor, because discrepancies may occur in the record if multiple auditors are involved.', 'The system auditor must instruct the department being audited to implement improvement measures for deficiencies identified during the audit interview.', 'The system auditor must make an effort to obtain documents and records that support the information obtained from the department being audited during the audit interview.', 'The system auditor must select audit interviewees from administrators who have been an auditor within the department being audited.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '24-O-45', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of an application architecture that constitutes enterprise architecture?', NULL, 'It systematically describes the business processes or the information flows necessary for the business strategy.', 'It systematically describes the contents of the data necessary for business operations, the relations or structures between the data, etc.', 'It systematically describes the functions or system configurations that support business processes.', 'It systematically describes the technical components necessary for the developments and operations of the information systems.', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '24-O-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of the SOA?', NULL, 'A concept of constructing a system by considering the software functions as components called services and combining them', 'A concept of improving sales efficiency and quality by using IT for sales activities to increase sales and profits as well as to improve customer satisfaction', 'A concept of re-designing the business processes to innovatively improve the cost, quality, service, and speed', 'Outsourcing the in-house operations that are not part of the core businesses to concentrate the management resources on the core businesses', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '24-O-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the work that is performed when non-functional requirements are defined?', NULL, 'Clarifying the flow of information (i.e., data) between the functions constituting business operations', 'Clarifying the interface for exchanging information with other systems', 'Creating the technical requirements for the development criteria and standards according to the programming language used in system development', 'Defining the scope to be implemented as system functions', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '24-O-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of diversity management?', NULL, 'Both labor and management to reach an agreement on working conditions and work together with the aim of increasing profits', 'For employees to harmonize between work and private life, approach their work with a sense of purpose, and increase the vitality of the organization', 'For employees to take an autonomous approach to work with the aim of achieving the objectives that they set for themselves and be evaluated according to the degree of achievement', 'To increase the vitality of the organization by respecting the diversity among its employees in terms of aspects such as gender, age, and nationality', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '24-O-49', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In innovation theory, consumers are classified into five (5) groups innovators, early adopters, early majority, late majority, and laggards according to the timing of their purchase of a new product. Which of the following is the appropriate explanation of the early adopters?', NULL, 'A group that accepts a new product, service, or other such offering at an early phase, has a large impact on consumers, is sensitive to trends, and makes decisions after collecting information themselves', 'A group that accepts a new product, service, or other such offering at the soonest phase without worrying about risks', 'A group that is skeptical about the adoption of a new product or new technology and only adopts it after seeing it being adopted by most people around them', 'A group that is the most conservative, has limited interest in movements in society and tends to adopt new trends only after they become common or, in some cases, remains firm in refusing their adoption', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-O-50', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a definition of Customer Relationship Management (CRM)?', NULL, 'A framework used to support and integrate processes, people, and information across an organization to provide a unified gateway for information and a knowledge base for employees, partners, and customers', 'A technology for managing all of a company’s relationships and interactions with customers and potential customers in order to improve business relationships', 'A type of software that organizations use to manage day-to-day business activities such as accounting, procurement, project management, risk management and compliance, and supply chain operations', 'The broad range of activities required to plan, control, and execute a product''s flow, from acquiring raw materials and production through distribution to the final customer, in the most streamlined and cost-effective way possible', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-O-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of concurrent engineering?', NULL, 'A product development technique that sequentially executes processes, such as design, manufacturing, and sales activities', 'A technique that analyzes a target system and clarifies its specifications', 'A technique that executes processes, such as design and production planning, in parallel with product development', 'A technique that grasps the optimal combination of functions and costs and improves value through systematic procedures', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '24-O-52', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is one of the main characteristics of a blockchain?', NULL, 'A centralized ledger on a server', 'A client-server network', 'A distributed ledger on a peer-to-peer network', 'A type of cryptocurrency', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-53', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the situation where an improvement can be expected by installing a Material Requirements Planning (MRP) system?', NULL, 'High-mix, low-volume production is adopted, so the cost of installing production equipment is increasing.', 'High-mix, low-volume production is adopted, so the cost of installing production equipment is increasing.', 'Information about materials and quantities necessary for production is complicated, so a miscalculation of order quantity or an interruption of production often occurs.', 'There are too many design changes, so production efficiency does not improve.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-O-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the objects that can benefit from the cell production method?', NULL, 'Products that require a wide variety and flexible production', 'Products that require division of labor by standardization, simplification, and specialization', 'Products that require mass production to increase productivity', 'Products whose specifications do not change for a long period', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-O-55', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique that can be used to discover useful information and relationships from large amounts of customer and market data retained by a company?', NULL, 'Data dictionary', 'Data flow diagram', 'Data mining', 'Data warehouse', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-O-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The relationship between the value “x” of a certain factor in the manufacture of a product and the value “y” of a quality characteristic of the product is plotted in the figure below. Which of the following is an appropriate interpretation of this figure?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-57.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy01Ny5wbmciLCJpYXQiOjE3NDMxMTAwODUsImV4cCI6MTc3NDY0NjA4NX0.BqidwBt61YL-iTkJFIUodsivQx0eDrXM_YseXZ0Xa0o', 'In order to estimate y from x, a quadratic regression coefficient needs to be calculated.', 'The correlation coefficient between x and y is negative.', 'The correlation coefficient between x and y is positive.', 'The regression expression for estimating y from x is the same as that for estimating x from y.', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '24-O-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Two (2) types of raw materials A and B are required to manufacture products X and Y. The quantity of each raw material required per unit and the procurable quantity are listed in the table below. When the profit per unit is $1 for product X and $1.5 for product Y, which of the following is the maximum profit in dollar?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-58.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy01OC5wbmciLCJpYXQiOjE3NDMxMTAwOTMsImV4cCI6MTc3NDY0NjA5M30.yPwWDxD26AJTIeXAiwxGc2zrSxwpZAQqhct_g4tbP0o', '50', '60', '70', '80', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '24-O-58', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the selling price of a product is $50 and the fixed costs for production and sales are $100,000, which of the following is the number of units to be sold to achieve the desired profit of $50,000? Here, the variable cost ratio is 60%.', NULL, '5,000', '7,000', '10,000', '12,500', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '24-O-59', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a volume license agreement?', NULL, 'A contract that establishes standard license conditions and deems that a license agreement is automatically established between the rightsholder and the purchaser when a certain amount of package is unwrapped within the scope of the standard license conditions', 'A contract that predefines the number of installations and permits the use of software for companies or other such purchasers of large amounts of software', 'A contract that restricts the location of use and permits the use of an unlimited number of units or persons within a specific facility', 'A contract where use is permitted by selecting to agree to the terms of the contract on the screen that is displayed when software is downloaded from the Internet', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '24-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the decimal representation of the hexadecimal number 123.4?', NULL, '83.25', '83.5', '291.25', '291.5', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-A-01', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Five people are sitting at a table in a restaurant. Two of them ordered coffee, and the other three ordered tea. The waiter forgets who ordered what and puts the drinks in a random order for the five persons. What is the probability that every person gets the correct drink?', NULL, '1/30', '1/20', '1/10', '3/10', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-A-02', 0.0, 1.0);
