INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of feedback control?', NULL, 'It performs control in a predetermined order.', 'It performs control to keep the output in line with the target value.', 'It performs control to prevent external disturbances from affecting the output.', 'It performs control without using the output.', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-A-04', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following represents the post-order traversal of the tree below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-A-05.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtQS0wNS5wbmciLCJpYXQiOjE3NDMxMTMwNTksImV4cCI6MTc3NDY0OTA1OX0.RsgyV59e5Zwl3_DkJhwq72r5Hd1F0wlWlWkaPCbJPRA', '2, 3, 4, 7, 8, 10, 13, 15, 18', '2, 4, 8, 7, 3, 15, 18, 13, 10', '10, 3, 2, 7, 4, 8, 13, 18, 15', '10, 3, 13, 2, 7, 18, 4, 8, 15', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-A-05', -1.0, 1.0);
