INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('How many swaps are required in bubble sort when N elements in the array are already sorted in reverse order?', NULL, 'N(N-1) ÷ 2', 'N² ÷ 2', 'N(N-1)', 'N²', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-A-07', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There are two microprocessors: a 32-bit CPU capable of executing each of 32-bit, 16-bit, and 8-bit long instructions in 1 cycle, and a 16-bit CPU capable of executing each of 16-bit and 8-bit long instructions in 1 cycle. Additionally, the 16-bit CPU can execute a 32-bit long instruction in 2 cycles. When the appearance ratio of 32-bit long instructions is 40%, of 16-bit long instructions is 40%, and of 8-bit long instructions is 20% respectively, what is the percentage improvement in total execution time with the 32-bit CPU compared to the 16-bit CPU? Here, both the 32-bit and 16-bit CPU operate at the same clock speed and have the same performance except for the executable instruction length in 1 cycle.', NULL, '28.57', '40', '50', '71.43', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-A-08', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When an HDD has the specifications below, what is the average access time for an HDD to transfer 1 MB of data in ms? Here, the average access time can be calculated as the sum of the average seek time, controller overhead, rotational latency, and transfer time. Other overheads can be ignored.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-A-09.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtQS0wOS5wbmciLCJpYXQiOjE3NDMxMTMwNjksImV4cCI6MTc3NDY0OTA2OX0.BIwbTLwrxLXQ_tfRDY8NlIcsaHoYGGX3HzXx8olKX6s', '21.93', '26.67', '27.92', '33.92', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '24-A-09', 0.0, 1.0);
