INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The activities and milestones of a project are shown in the arrow diagram below. Which of the following is an appropriate description of the project if the duration of activity B is increased by 5 days?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-A-41.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtQS00MS5wbmciLCJpYXQiOjE3NDMxMTAyNDEsImV4cCI6MTc3NDY0NjI0MX0.im7CHnzQltyKwALCfdaqZK1FE4EG2Sjc1CM64z94hSQ', 'The earliest start time of activity G is delayed by 5 days.', 'The latest start time of activity F is delayed by 5 days.', 'The project’s minimum completion time does not change.', 'The project’s minimum completion time is increased by 5 days.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '24-A-41', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the Cost Performance Index (CPI) of the project under the conditions listed below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-A-42.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtQS00Mi5wbmciLCJpYXQiOjE3NDMxMTAyNTAsImV4cCI6MTc3NDY0NjI1MH0.Kw2gcIx63Ak6Cm4RHhEsXeCaSaqkN0wTV7cgsI1JZq0', '0.25', '0.8', '1.0', '1.25', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '24-A-42', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In ITIL 2011 edition, which of the following is the appropriate order for the service lifecycle stages?', NULL, 'Service design -> Continual service improvement -> Service strategy -> Service operation -> Service transition', 'Service design -> Service strategy -> Service operation -> Service transition -> Continual service improvement', 'Service strategy -> Service design -> Service operation -> Service transition -> Continual service improvement', 'Service strategy -> Service design -> Service transition  -> Service operation -> Continual service improvement', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '24-A-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IT service management, which of the following is an activity performed for the management of incidents and service requests?', NULL, 'Evaluating if customer satisfaction with the service desk meets the agreed service targets and performing a review to identify improvement opportunities', 'Examining measures wherein the amount of free space on a disk is near its threshold', 'Investigating the impact of changes made to a program', 'Receiving a failure report from a user and checking to see if it corresponds to a known error', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '24-A-44', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description concerning an interview conducted by a system auditor?', NULL, 'The administrator of the audited department, who has experience in auditing tasks, is selected as the interviewee.', 'The entire interview is conducted by one (1) system auditor, as discrepancies may occur in the record if multiple auditors are involved.', 'The system auditor instructs the audited department to take improvement measures for deficiencies found during the interview.', 'The system auditor makes an effort to obtain documents and records that support the information obtained from the audited department during the interview.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '24-A-45', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a case that enables the customer support operations at a call center to improve quality by applying a pattern recognition function or machine learning function to the accumulated data?', NULL, 'Deriving the most appropriate response in real time from related materials and all the previous support history according to the content of the inquiry made by a customer', 'Displaying the digital content of a response manual or basic customer information on a pop-up window of a screen for responding to requests from the operators', 'Repeatedly providing role play training to new operators from an experienced operator who serves as a lecturer by using the response manual as the teaching material', 'Transferring a phone call or the relevant support screen to an experienced operator or a dedicated staff when the operator who is responding to a customer over the phone is unable to provide an answer', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-A-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of knowledge management?', NULL, 'Conduct business by a flat organizational structure that has as few hierarchical levels as possible for quick decision making.', 'Conduct business by utilizing its core strength in know-how and technology that are unique to the company and cannot be imitated by others.', 'Conduct business that enhances overall capabilities to solve problems by sharing  knowledge that is scattered throughout the company.', 'Implement management innovation in the company on the basis of a comparative analysis with companies that have achieved superior performance.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-A-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of an RFI?', NULL, 'It is a document describing the basic policy for the system, including a summary of the system, purpose, necessary functions, system requirements, and contract matters.', 'It is a document that is created after an RFP.', 'It is a document used by companies looking for the implementation of computerization to request specific system proposals from prospective suppliers such as system vendors.', 'It is a document used to request information concerning computerization from prospective suppliers such as system vendors.', 'd', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '24-A-48', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a strategy that concentrates resources in the segment of a specific customer or specific product in order to achieve specialization?', NULL, 'Challenger strategy', 'Follower strategy', 'Leader strategy', 'Niche strategy', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-A-49', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of core competence that is adopted in business administration?', NULL, 'It refers to a qualitative and quantitative understanding of its products, services, and operations through comparisons with the strongest competitor or advanced companies.', 'It refers to dramatical improvements in the costs, quality, service, and speed of a company by fundamentally reviewing and radically redesigning its business processes.', 'It refers to the company’s unique skills, technologies, and other strenghts that are superior to other companies, which serve as a source of competitive advantage.', 'It refers to the management of the allocation of company-wide management resources in an effective and integrated manner so as to achieve an improvement in management efficiency.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-A-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of telemarketing?', NULL, 'It refers to direct marketing that includes calling people at home and asking for donations, opinions, or purchases.', 'It refers to direct marketing that sells products and services and builds customer relationships over the Internet.', 'It refers to direct marketing that sends offers, announcements, reminders, or other items to a person at a particular address.', 'It refers to direct marketing that sends sales alerts, links to website updates, appointments, or delivery reminders to large groups of people.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-A-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the technology S curve?', NULL, 'It represents the diffusion process of a new technology. It shows that the growth rate of the penetration rate gradually decreases as products applying the technology penetrate the market, by using a frequency distribution curve.', 'It represents the maturing process of technology. It shows that during the time until the new technology is actually spread, the degree of awareness changes as time passes.', 'It represents the process of technological progress. It shows that technology advances slowly at the beginning, then advances rapidly, and thereafter, slowly stagnates.', 'It represents the relationship between production volume and unit cost. It shows the course of reduction in unit cost with an increase in cumulative production volume.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-A-52', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate computing concept that describes the idea of physical objects, such as devices, vehicles, and buildings, that are connected to the Internet and are able to identify themselves to other devices?', NULL, 'Computer networks', 'Deep learning', 'Internet of things', 'Network topology', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '24-A-53', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A factory manufactures the three products that are shown in the table below. Which of the following is the maximum possible profit in dollars? Here, there is an upper limit to the monthly demand volume for each product. Also, the factory can only use up to 200 hours per month for the manufacturing process and cannot manufacture more than one products in parallel.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-A-54.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtQS01NC5wbmciLCJpYXQiOjE3NDMxMTAyNjAsImV4cCI6MTc3NDY0NjI2MH0.4t1JGJCYF3aEIZXxzVHoH1MiXz1u0SICx2VPPsH_6LA', '26,250', '30,000', '31,500', '33,000', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '24-A-54', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of Consumer Generated Media (CGM)?', NULL, 'A website of a company through which the company publishes information about its management and financial status, as well as performance trends for individual investors.', 'A website of a company through which the company transmits information about the characteristics and usage methods of its products to the general consumers.', 'A website of a government organization through which the organization publishes information about its policies and administrative services to the general public.', 'A website such as a blog and SNS, etc. through which an individual transmits information to an unspecified number of people about the evaluation of products, etc. that the person has used.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '24-A-55', -2.0, 1.0);
