INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a company wants to earn a profit of $42,000, which of following is the number of units that the company must sell under the conditions shown in the table below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-A-57.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtQS01Ny5wbmciLCJpYXQiOjE3NDMxMTAyNjYsImV4cCI6MTc3NDY0NjI2Nn0.jZe1CQXIN59If6YRE7gKvQkzTjszJ5bBnUB1UnwOL4Q', '14,000', '18,200', '26,000', '26,200', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '24-A-57', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is part of total quality management?', NULL, 'Designing products and services that meet or exceed customers’ expectations', 'Focusing on the appointment of staff with long-term work experience in a similar environment', 'Prioritizing central decisions rather than empowerment to ensure the quality of products and services', 'Promoting the capability of each department to work independently in a competitive manner', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '24-A-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a relation between the list price of a product and the demand for the product is defined as a linear equation, which of the following is the appropriate numerical value to be inserted into blank A below? 
(1) When the list price is set to $30, the demand is 0 units. 
(2) When the list price is set to $10, the demand is 60,000 units. 
(3) When the list price is set to $15, the demand is  A units.', NULL, '30,000', '35,000', '40,000', '45,000', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '24-A-59', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When OSS that is released under GPL is modified and distributed, which of the following is an appropriate action to comply with the GPL?', NULL, 'A recipient who obtains the derivative work must be strictly prohibited from redistributing copies.', 'The source code of a separate application that is statically linked to the derivative work does not need to be disclosed.', 'When the software is modified and distributed, the source code of the distributed copies is made availabe to the recipients.', 'When the source code of the derivative work is disclosed, compensation such as related costs cannot be demanded.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '24-A-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a school class, 13 students play basketball and 19 play football. Among them, 8 students play both. Further, 7 students play neither. How many students are there in the class?', NULL, '17', '31', '33', '47', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-O-01', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('N is a binary integer represented in two’s complement. Which of the following operations get the value 7 × n using only bit shifting and an addition or subtraction operation?', NULL, 'Shift n 2 bits to the left, then add n to the result.', 'Shift n 2 bits to the left, then subtract n from the result.', 'Shift n 3 bits to the left, then add n to the result.', 'Shift n 3 bits to the left, then subtract n from the result.', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-O-02', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A parking lot has 10 parking spaces in a row, and 7 cars are parked at random parking spaces. What is the probability that the three empty places are adjacent to each other?', NULL, '1/90', '1/72', '1/15', '1/12', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-O-03', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the sum of two binary fractions 1.0101 and 1.0111 expressed in decimal form?', NULL, '2.5', '2.75', '2.875', '2.9375', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-O-04', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following expressions in postfix notation is equivalent to the expression 2+5×3+4 in infix notation? Here, the operator “×” has higher precedence than “+”.', NULL, '2 5 3 4 × + +', '2 5 + 3 4 × +', '2 5 3 + × 4 +', '2 5 3 × + 4 +', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-O-05', -1.0, 1.0);
