INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the binary search tree below, when a new node of value 11 is inserted, where will this insertion be made?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-08.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy0wOC5wbmciLCJpYXQiOjE3NDMxMTMyMzYsImV4cCI6MTc3NDY0OTIzNn0.uZbggAbjmHlTfOHjizedZgVL7UpHYXKe0iRZElxGRJI', 'Left child of 16', 'Left child of 23', 'Right child of 3', 'Right child of 10', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-O-08', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the table below, there are five items A through E. Each item cannot be divided into smaller pieces. When a knapsack with a maximum volume of 7 units is used for carrying the items, which of the following is a set of items to be packed in the knapsack so that the total price can be maximized?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-09.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy0wOS5wbmciLCJpYXQiOjE3NDMxMTMyNDAsImV4cCI6MTc3NDY0OTI0MH0.7mz4SHj9MwRPIk6hgf8dkODrkbh8lPOng4mP3efPAas', 'A, B, D', 'A, C, D', 'B, E', 'D, E', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-O-09', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning XML?', NULL, 'It is based on HTML and expands its functions.', 'It requires a dedicated editor for writing XML documents.', 'It integrates the logical structure and display style of documents.', 'It enables users to define the attribute information and logical structure of documents by using the user’s own tags.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-10', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a CPU, which of the following is a special register that contains the address of the next instruction to be fetched?', NULL, 'Accumulator', 'Index register', 'Instruction register', 'Program Counter', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-11', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate CPU operation associated with cache memory?', NULL, 'When a cache hit occurs, the CPU fetches data from ROM.', 'When a cache hit occurs, the CPU fetches data from the main memory.', 'When a cache miss occurs, the CPU fetches data from the cache memory.', 'When a cache miss occurs, the CPU fetches data from the main memory.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-12', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a computer architecture in which a processor executes the same instruction on multiple data?', NULL, 'MIMD', 'MISD', 'SIMD', 'SISD', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-13', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('ECC is used for error detection and correction in memory. When n+2 redundant bits are required for a data bus having a width of 2ⁿ bits, what is the number of redundant bits that are required for a data bus having a width of 128 bits?', NULL, '3', '8', '9', '10', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-14', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate explanation of grid computing?', NULL, 'A computing task is distributed to several computers in the network to attain computational capacity.', 'Physical devices such as computers or network devices are emulated to circumvent compatibility constraints and attain software portability and flexibility.', 'Requirements are stated as constraints on response time and/or on the temporal validity of sensory data.', 'Sensing devices are connected to a network to provide feedback and control through personal mobile devices.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an RAID configuration that deploys two parity records to different disk drives enabling two simultaneous disk drive failures in the same RAID group to be recovered?', NULL, 'RAID0', 'RAID1', 'RAID5', 'RAID6', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-16', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following occurs when a program attempts to access a page that is mapped in the virtual address space but is not located in the main memory? Here, the OS supports paging.', NULL, 'Fatal error', 'Page fault', 'Scheduling error', 'Segmentation fault', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-17', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning the round robin process scheduling method?', NULL, 'CPU resources are allocated to each process in order of priority specified in advance when a particular event occurs.', 'CPU resources are allocated to each process in order of processing time from shortest to longest.', 'CPU resources are allocated to the first executable process in the queue when an interval-timer interrupt is generated.', 'CPU resources are allocated to the process that needs to start immediately when some kind of interrupt is generated.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-18', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the function of an archiver that is one of the data management utilities?', NULL, 'Compiling several files into one file or reconstructing the original files in order to perform data backup and distribution', 'Creating both an area for recording data and an area for managing data on a single hard disk', 'Keeping data secure through file protection for safeguarding data from unauthorized use and destruction, and also through copy protection for preventing unauthorized copying', 'Rearranging a file into contiguous areas, to the extent possible, on a hard disk in which fragmentation has occurred', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-19', -2.0, 1.0);
