INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('From a “Score” table, the average score for all subjects is to be calculated for each student, and the student number and average score for students with an average score of 80 or higher are to be determined. Which of the following is the appropriate term or phrase to be entered in blank A? Here, a solid underline represents a primary key.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-28.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy0yOC5wbmciLCJpYXQiOjE3NDMxMTA0MTMsImV4cCI6MTc3NDY0NjQxM30.kWD5INIpPRljC2L92ONqe8Sou_BHAxek69zjwQbKS2o', 'StudentNumber HAVING AVG(Score) >= 80', 'StudentNumber WHERE Score >= 80', 'Subject HAVING AVG(Score) >= 80', 'Subject WHERE Score >= 80', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-28', -1.0, 1.0);
