INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Mr. A encrypts a message to be sent to Mr. B using an asymmetric key encryption method so that only Mr. B can decrypt the message. Which of the following is(are) the private key(s) used to decrypt the message?', NULL, 'A third party’s', 'Both Mr. A’s and Mr. B’', 'Only Mr. A’s', 'Only Mr. B’s', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-36', -1.0, 1.0);
