INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of a behavior of a key logger?', NULL, 'It interrupts the communication between two parties and then collects and falsifies the information being exchanged.', 'When Internet banking is used, it collects the password entered by the user.', 'When the user browses movies on a web browser, it arbitrarily displays unintended advertisements for the user.', 'When the web browser is started, it arbitrarily displays a tool bar that the user has not installed.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a role of a PKI certification authority as a reliable third party?', NULL, 'Adding a digital signature to an e-mail body as requested by a user', 'Enabling the synchronization of time by returning an accurate time to a user’s request', 'Issuing a digital certificate that certifies the private key of a user or server', 'Issuing a digital certificate that certifies the public key of a user or server', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As shown in the figure below, an application on a client accesses the data in the database on a server via database connection programs. Which of the following is a measure for preventing the leakage of the commands and execution results transmitted between the application and database?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-41.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy00MS5wbmciLCJpYXQiOjE3NDMxMTA0MjUsImV4cCI6MTc3NDY0NjQyNX0.fAdEAZuZzrUdXPWCBU-8fh_qRc8Hq-TDA5gBU79dmjE', 'Changing the port number from its initial value that the database connection programs use for communication in the database management system', 'Encrypting the communication between the database connection programs', 'Restricting the IP addresses of the clients that can access the database connection program on the server to only those that are required', 'Setting a password for starting or stopping the database connection program on the server', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Companies usually provide a means for their mobile workforce to access the corporate network securely over the Internet through insecure channels such as open wireless networks in hotels or coffee shops. Which of the following is the appropriate technology that can be used for this purpose?', NULL, 'DMZ (DeMilitarized Zone)', 'SNMP (Simple Network Management Protocol)', 'VoIP (Voice over Internet Protocol)', 'VPN (Virtual Private Network)', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-42', -2.0, 1.0);
