INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a key that the SSL/TLS certificate of a website contains?', NULL, 'The encrypted private-key of the website', 'The encrypted public-key of the website', 'The unencrypted private-key of the website', 'The unencrypted public-key of the website', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-44', -2.0, 1.0);
