INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a critical path of the project activities shown in the arrow diagram below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-54.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy01NC5wbmciLCJpYXQiOjE3NDMxMTA0NzMsImV4cCI6MTc3NDY0NjQ3M30.JDEchKS9A9wDjFY6lA7dThDATlEkvUACls90AfRoTyQ', 'A -> B -> E -> I -> L', 'A -> C -> D -> E -> H -> K', 'A -> C -> F -> I -> L', 'A -> C -> G -> J -> L', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '23-O-54', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate policy for creating an SLA?', NULL, 'Setting a compensation as a penalty for every item that has a service level', 'Setting a service level for every item that can be taken into consideration', 'Setting a service level that is maintained into the future without any changes', 'Setting a service level under the cost and needs of a service provider and its customers', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-O-55', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate characteristic of the “big bang” or all-at once migration method that is one of the system migration methods?', NULL, 'Additional operational costs are incurred because of parallel operations.', 'An additional application is required for connecting the old and new systems.', 'The old and new systems operate in parallel, and migration to the new system is performed at a particular point of time.', 'The problems that occur during migration to the new system have a big impact.', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '23-O-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IT service management, which of the following is a problem management activity that is performed proactively?', NULL, 'Analyzing the occurrence trend of incidents and proposing measures that prevent an incident from occurring in the future', 'Classifying problems that have been detected and recorded, and setting the response priority', 'Evaluating the effectiveness of a resolution to a critical problem', 'Monitoring whether an incident occurs again or not for a certain period of time after the problem is resolved', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-O-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method that restores the system to its initial state and restarts it when a system failure occurs, that does not accompany preprocessing of a copy before/after an update, and that is also called initial program load?', NULL, 'Cold start', 'Rollback', 'Rollforward', 'Warm start', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-O-58', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of an audit work paper?', NULL, 'A compilation of the information security promissory letter that is presented to the audited department when the auditor implements an audit', 'A compilation of the standards and guidelines used by the auditor for implementing an audit', 'A document that must be disclosed along with the audit report to prove that the auditor has fulfilled his or her obligations with proper attention', 'An execution record of the auditing procedure by an auditor, and it forms the basis of the audit opinion', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-O-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning a system audit team?', NULL, 'For an audit of the development progress in an information systems department, the audit team consists of members of the information systems department who are familiar with the details of the development.', 'In order to enable the person requesting the audit to issue improvement instructions on the basis of the audit report, the system audit team reports the audit results to the person requesting the audit.', 'When an audit of the information system is performed as a part of the business operations audit, the audit team is formed by the members of the user’s department.', 'When the system audit team accepts the help of an expert, the decisions concerning the range of support, methods, and audit results is the responsibility of the expert.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The purchase of two types of IT devices A and B is being examined. The payout period is set in consideration of the useful life of each of the devices. Which of the following is an appropriate description for the minimum amount of annual profit necessary to recover the amount of investment within the set payout period for A and B? Here, the annual profit is made evenly each year, and the interest rate is not considered.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-61.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy02MS5wbmciLCJpYXQiOjE3NDMxMTA1MTQsImV4cCI6MTc3NDY0NjUxNH0.ZCasv5fSn-wI1A2FeZMVopbytHPTRImzk-8-DzVDeQo', 'It is necessary for A and B to make the same amount of annual profit.', 'It is necessary for A to make twice as much as the annual profit than that of B.', 'It is necessary for B to make 1.5 times as much as the annual profit than that of A.', 'It is necessary for B to make twice as much as the annual profit than that of A.', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-O-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a purpose of Business Process Management (BPM) in corporate activities?', NULL, 'Analysis and effective use of information resources', 'Conservation and analysis of customer information', 'Continuous improvement of business processes', 'Effective use of management resources', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '23-O-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a scheme where the user establishes a connection to the system of a service provider via the Internet and makes online use of only the necessary functions of the applications provided by the service provider at the necessary time?', NULL, 'ERP', 'SaaS', 'SCM', 'XBRL', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '23-O-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate example of utilizing Business Intelligence (BI)?', NULL, 'Analyzing a large volume of data stored on a business system to evaluate business performance and develop a business strategy', 'Computerizing daily routine works, such as decision requests, to ensure that such procedures are carried out without fail and to enable their swift completion', 'Enabling employees to use computerized learning materials via a network and managing their learning and performance', 'Obtaining publications, such as annual reports issued by competitors, to understand their business strategies and financial situations', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-O-64', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The RFP is presented to each vendor that has responded to an RFI. Which of the following should be done beforehand to proceed fairly with the future vendor selection processes?', NULL, 'Aside from the items of an RFP, giving a high evaluation to a vendor who is familiar with the current system to select that vendor easily', 'Establishing processes of selection such as setting evaluation standards or weighting rules of conformity to the requested items', 'Issuing unofficial agreements to all vendors to whom the RFP has been presented and requesting them to prepare a contract and a statement of work to accelerate the conclusion of the contract after the vendor selection', 'Preparing a bailout for a vendor who received a high evaluation on the response to the RFI, in case it fails in the selection', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '23-O-65', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A company has products that are at the peak of profitability and sales. As a result, many competitors develop similar products to the market. Therefore, a company must develop new products to meet new demands and market opportunities. Which of the following is a state of such events in the product life cycle?', NULL, 'Decline stage', 'Growth stage', 'Introduction stage', 'Maturity stage', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-O-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of benchmarking that is used for corporate management?', NULL, 'It refers to a qualitative and quantitative understanding of a company’s own products, services, and operation through comparison with those of competitors or advanced companies.', 'It refers to drastically reforming the quality and structure of a company by redesigning its business processes from a customer viewpoint and by taking full advantage of information technology.', 'It refers to the ability to plan and manage the allocation of company-wide management resources in an effective and integrated manner and to achieve an improvement in management efficiency.', 'It refers to the concentration of management resources on the unique skills and technologies of a company that can generate profit and that are superior to those of other companies.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-O-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a business management technique that is used to develop specific targets and measures to implement a planned strategy, in consideration of the appropriate mutual relationships among four perspectives (i.e., financial, customer, business process, and learning and growth)?', NULL, 'Balanced scorecard', 'Growth matrix', 'Product portfolio management', 'SWOT analysis', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-O-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of SCM?', NULL, 'To construct favorable customer relationships through unified management, including customer information, purchasing history, and complaints, and also through meticulous customer response', 'To improve management efficiency through integrated management of all information concerning core business operations such as production, sales, inventory, and accounting', 'To improve the efficiency of sales activity through unified management of customer information, business meeting schedules, and business meeting status including progress status', 'To reduce costs and shorten delivery periods through integrated management of information across multiple companies or organizations from procurement to sales', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-O-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the IoT (Internet of Things)?', NULL, 'It refers to a form of electronic commerce carried out over the Internet, consisting of a typical C to C transaction by which a seller posts a product’s name, photo, minimum selling price, and other information on a website, after which the bidder that offers the highest amount within the time limit becomes the successful bidder.', 'It refers to data centers designed for the connection to the Internet, with server operation failure prevented through the implementation of measures including quality management of communication lines, server maintenance, air conditioning, and power source-related countermeasures against power interruptions and outages.', 'It refers to Internet advertising such as a banner advertisement that displays an image, with a link to an advertiser’s website, or an e-mail advertisement that publicizes an advertiser’s website.', 'It refers to the installation of communication functionality to various objects, in addition to information and communication devices, and enabling automatic recognition or remote measurement by connecting these to the Internet, to achieve high-level decision making services and automated control through the collection and analysis of large volumes of data.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-70', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a smart grid?', NULL, 'It is a system that aims at the utilization of recyclable energy, supply of stable electric power, and optimum demand adjustment through the integrated control of power generation and power consumption on the basis of communication and information processing technology.', 'It is a system that can provide ideal health advice to each individual by performing analysis on the basis of similar case reports such as the result of health examinations and medication use.', 'It is a system that can search for information on restaurants and entertainment, send and receive traffic information, and communicate the current position at the time of an emergency by using information-processing equipment installed in vehicles.', 'It is a system that supports varied work styles by enabling mutual communication between workers with varied working styles, such as home-based employees and senior workers.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-71', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of CAD?', NULL, 'Evaluating product performance and functions using computers, without using the actual product to perform testing or experimentation', 'Using a computer to convert product design drawings to process design information, and support automation of machine processing, etc.', 'Using a computer to create product design drawings from attribute data concerning product shape, composition, etc.', 'Using a computer to derive the required volumes and timing of materials from a production schedule, a BOM (bill of materials), inventory volumes, etc.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-O-72', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of an e-marketplace?', NULL, 'It is a method in which many sellers and buyers meet in a market set up on the Internet and trade directly without an intermediate distributor.', 'It is a method that aims for overall optimization from material procurement to product distribution by sharing information such as ordering, inventory, sales, and logistics between a company and its business partners.', 'It is a method that converts information concerning business transactions into a standardized format and electronically exchanges data such as estimation, ordering, shipment and delivery, and payment between companies.', 'It is a method that runs a sales promotion campaign on the Internet and then draws customers to a real store to encourage them to make purchases.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-O-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of an IC tag (RFID)?', NULL, 'It handles a large amount of information. Thus it uses an external storage device for storing information.', 'It is stain-resistant, and recorded information can be read from the outside of the package.', 'It is used by inserting the tag into a dedicated magnetic reader.', 'It uses GPS to display location information or attribute information about the current location.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-O-74', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an officer whose primary responsibility is the security of a company’s information and data?', NULL, 'CCO', 'CIO', 'CISO', 'COO', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-O-75', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method of education and training in which trainees engage in simulated business activities, interact with other people to develop experiences, and try out different strategies?', NULL, 'Case study', 'Debate', 'In-basket', 'Roll-playing', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-O-76', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the weather tomorrow is sunny with 30% probability, cloudy with 50% probability, and rainy with 20% probability, which of the following strategies offers the highest expected value?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-77.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy03Ny5wbmciLCJpYXQiOjE3NDMxMTA1MjEsImV4cCI6MTc3NDY0NjUyMX0.wHYN-BCse4eTromBRrTchhrpG6v4j0YvK5bsSp2mJXc', 'S1', 'S2', 'S3', 'S4', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-O-77', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The following inventory statement of Build-Up Property Company describes the status of the company’s inventory since the beginning of the year 2014. When the company uses a first-in-first-out (FIFO) method for inventory asset valuation, what is the inventory value at the end of the year 2014?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-78.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy03OC5wbmciLCJpYXQiOjE3NDMxMTA1MzEsImV4cCI6MTc3NDY0NjUzMX0.2AvIubiDtNU_rZopLJ6AOmbPrc3Iw28hp8Xwsd3IaEo', '7080', '7600', '7800', '8000', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-O-78', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the type of financial statement that shows a company’s assets, liabilities, and shareholders’ equity at a particular point of time?', NULL, 'Balance sheet', 'Statement of cash flows', 'Statement of changes in equity', 'Statement of profit or loss', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-O-79', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a single-license software package is purchased by a company, which of the following is an activity that is usually permitted in conformity with the concept of the WTO’s Agreement on Trade-Related Aspects of Intellectual Property Rights (TRIPS)?', NULL, 'Installing the software package on a large number of computers that are used for the company’s business', 'Making a backup copy of software for limited purposes, such as the licensee’s personal use or a temporary copy for maintenance', 'Modifying the software package for the company’s internal use and using it on a large number of computers within the company', 'Placing the software package on the company’s internal website so that staff members can download and install it', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-O-80', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a Venn diagram that represents the set below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-01.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0wMS5wbmciLCJpYXQiOjE3NDMxMTMzNDEsImV4cCI6MTc3NDY0OTM0MX0.YtyChBbO9hG_VtEFajwn9IAVRNGgd7rdAZjrLLoAQ3s', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-01-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0wMS1BLnBuZyIsImlhdCI6MTc0MzExMzM1OSwiZXhwIjoxNzc0NjQ5MzU5fQ._E0SPBlbUI9321DkW9K-OLGArQI6a0gfRvOBE4ijzO0', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-01-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0wMS1CLnBuZyIsImlhdCI6MTc0MzExMzM1NSwiZXhwIjoxNzc0NjQ5MzU1fQ.GrHqafaz5vuU3h9QYF9ozOW5eWEyJUCLvuxuXUmbEGc', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-01-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0wMS1DLnBuZyIsImlhdCI6MTc0MzExMzM1MCwiZXhwIjoxNzc0NjQ5MzUwfQ.25qo-LKUsr2pZBLG1sr8nXi0gMsaG0jtv3HtSByA3oY', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-01-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0wMS1ELnBuZyIsImlhdCI6MTc0MzExMzM0NiwiZXhwIjoxNzc0NjQ5MzQ2fQ.6xVi-K6NRVzeSc1X2ZwkWwlNBjbA13nPOLHYZfG-w04', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-A-01', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the hexadecimal value ABCD in a 32-bit register is logically shifted right by two bits, which of the following is the resulting value in hexadecimal?', NULL, '2AF3', '6AF3', 'AF34', 'EAF3', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-A-02', -1.0, 1.0);
