INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an error detection method where, on the sender side, the data sent accompanies a remainder of the data bit sequence divided by a specific generator polynomial, while on the receiver side, error detection is performed by checking if the received bit sequence is divisible by the same polynomial?', NULL, 'CRC', 'Hamming code', 'Horizontal parity check', 'Vertical parity check', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-06', -1.0, 1.0);
