INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A five-digit number a1a2a3a4a5 needs to be stored in an array by means of hashing. When the hash function is mod (a1+a2+a3+a4+a5, 13) and the number is stored in the array element at the position corresponding to the calculated hash value, which of the following is the position where 54321 is stored in the array? Here, the value of mod (x, 13) is the remainder after dividing x by 13.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-09.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0wOS5wbmciLCJpYXQiOjE3NDMxMTMzNzIsImV4cCI6MTc3NDY0OTM3Mn0.brxbE8KyVi1lAd1vaIzeKukSKAJIC-kFMI61-qaWKPo', '1', '2', '7', '11', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '23-A-09', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a program that achieves dynamic processing in a web environment and operates only on a web server?', NULL, 'JavaScript', 'Java applet', 'Java servlet', 'VBScript', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-10', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a CPU has a special register used in push and pop instructions, which of the following is an appropriate term for this register?', NULL, 'Instruction register', 'Program counter', 'Stack pointer', 'Status register', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-11', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is classified as an internal interrupt?', NULL, 'Interrupt caused by an abnormal power condition, such as a momentary loss of commercial power supply', 'Interrupt caused by performing a divide-by-zero operation', 'Interrupt caused by the completion of input or output', 'Interrupt caused by the occurrence of a memory parity error', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-12', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the technique that minimizes the number of write operations to the main memory by updating the data only in the cache memory and updating into the main memory later?', NULL, 'Overlay', 'Write back', 'Write protected', 'Write through', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-13', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a 3D printer’s function?', NULL, 'It detects the shape of three-dimensional objects and produces output of 3D data.', 'It functions by pushing the pins of a high temperature printing head onto heat-sensitive paper.', 'It makes three-dimensional objects using methods such as fused filament fabrication.', 'It projects computer graphics onto uneven three-dimensional objects such as buildings and furniture.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-14', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the RAID configuration for achieving the highest speed disk access at the cost of reliability?', NULL, 'RAID 0', 'RAID 1', 'RAID 5', 'RAID 6', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-15', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When system availabilities of a cold standby system, a simplex system, and a dual system are compared, which of the following shows the order arranged from highest to lowest? Here a computer or computers that compose each system are all the same', NULL, 'Cold standby system, dual system, simplex system', 'Cold standby system, simplex system, dual system', 'Dual system, cold standby system, simplex system', 'Simplex system, cold standby system, dual system', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-16', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A printer prints 400 characters per second. The printer uses interrupt-driven I/O and each character printed requires an interrupt that takes 50 microseconds. What percentage of the printer''s CPU is available to do other work during printing? Here, other overhead time for the CPU can be ignored.', NULL, '98', '96', '4', '2', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-17', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In preemptive Shortest Remaining Time First (SRTF) scheduling, on arrival or completion of any process, the scheduler schedules processes from the list of available processes and running processes that have the least remaining CPU-burst time. The four processes, namely, P1, P2, P3, and P4, their corresponding CPU-burst time and arrival time are shown in the table below. Which of the following is the average waiting time in milliseconds for the processes to be executed in preemptive SRTF scheduling?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-18.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0xOC5wbmciLCJpYXQiOjE3NDMxMTA1NzUsImV4cCI6MTc3NDY0NjU3NX0.nOe9NXN6d1i1o5vLKB6NYm1V4knDp0ir3Xm1VoJUWx4', '3.0', '4.75', '5.5', '10.25', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-18', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the different types of backup methods, which of the following is incremental backup? Here, in the first backup, all files are backed up and the information that indicates a file update managed by the operating system is reset.', NULL, 'All files are backed up regardless of information indicating a file update, and the information indicating a file update is left unchanged.', 'All files are backed up regardless of information indicating a file update, and the information indicating a file update is reset.', 'Only files with information indicating a file update are backed up, and the information indicating a file update is left unchanged.', 'Only files with information indicating a file update are backed up, and the information indicating a file update is reset.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-A-19', -1.0, 1.0);
