INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('At the rising edge of the clock signal, the content of an 8-bit serial-in parallel-out shift register is shifted upward, while positive logic data is simultaneously read into the least significant bit. The value is fixed at the rising edge of a strobe. When the results of an observation of each signal’s waveform are as shown in the diagram below, which of the following is the value of the shift register after it is fixed? Here, numeric values are represented in hexadecimal.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0yMi5wbmciLCJpYXQiOjE3NDMxMTA2ODEsImV4cCI6MTc3NDY0NjY4MX0.dez1FmbuyprKXHqfi6dNMhN4PGb8aoBXHx11rZLnzwU', '63', '8D', 'B1', 'C6', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '23-A-22', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a case where outline fonts rather than bitmap fonts are suitable for use?', NULL, 'To display characters as quickly as possible', 'To display characters in monospace', 'To display single-byte and double-byte characters at the same time', 'To enlarge characters by a given scale factor', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-23', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the approximate minimum required bandwidth for delivering a 30-frames/second video in 800 x 600 pixel and 24-bit full color? Here, the data is not compressed during communication.', NULL, '350 kbps', '3.5 Mbps', '35 Mbps', '350 kbps', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-24', -1.0, 1.0);
