INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of keys in a relational database?', NULL, 'A primary key can be assigned as a composite key and must contain a column that is defined as a foreign key.', 'The values of the primary and foreign keys cannot be duplicated and cannot be null.', 'The values of the primary key must be unique, and the values of the foreign key must match the values of the related table’s primary key and can be duplicated.', 'The values of the primary key need to match the values of the related table’s primary key, but the values of the foreign key do not need to match the values of the related table’s primary key.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-27', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate interpretation of the conceptual data model shown in the diagram in UML?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-28.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS0yOC5wbmciLCJpYXQiOjE3NDMxMTA2OTEsImV4cCI6MTc3NDY0NjY5MX0.dVLVQAmH0eYsFbjQwwoo7HOywJNJchhe_SbsPLyUx90', 'A department cannot exist without any employees.', 'An employee can belong to multiple departments at the same time.', 'An employee does not have to belong to a department.', 'The total number of employees and the total number of departments match.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-28', -1.0, 1.0);
