INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of setting an index in the columns of the table of a relational database by a user?', NULL, 'To enable economization of disk space when a single large table is distributed and saved on several disks.', 'To enable efficient access to the storage location of data in order to improve the search speed.', 'To ensure that no value is duplicated in a column.', 'To match the value of the foreign key column with the value of the primary key of another table.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-30', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a role of DNS in a TCP/IP network?', NULL, 'A private IP address is translated into a global IP address in order to access the Internet.', 'A program in a server can be invoked only by its name without taking the server’s IP address into consideration.', 'Domain names, host names, and other such information are mapped to IP addresses.', 'In response to an assignment request for an IP address from a PC or a printer, an unused address is chosen from the addresses registered in the server.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the same subnet, which of the following is the devices that will receive the data when the destination address is set to 255.255.255.255?', NULL, 'All devices in the same subnet', 'All devices using the same DNS server', 'Only the default gateway of the subnet', 'Only the device sending the data to itself', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-32', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('How many host addresses are there in the network 192.168.10.0/26?', NULL, '30', '62', '126', '254', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-33', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a TCP/IP network, which of the following is a protocol used to match the clocks of the server and the client?', NULL, 'ARP', 'ICMP', 'NTP', 'RIP', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-34', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As for the use of e-mails over the Internet, which of the following is a standard that extends the header field and can handle not only text but also audio and images?', NULL, 'HTML', 'MHS', 'MIME', 'SMTP', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is malware that is activated by attackers to launch attacks on other computers?', NULL, 'Bot', 'Rootkit', 'Trojan Horse', 'Worm', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-36', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is considered a violation of confidentiality?', NULL, 'Denial of services to a website handling confidential information by generating fake heavy traffic in the network', 'Destruction of server hardware storing personal information caused by high voltage due to failure of voltage stabilizer', 'Disturbing communication by destroying ciphertext of confidential information', 'Tricking a user into providing personal information to a fake website', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of “asymmetric encryption,” used for encrypting and decrypting messages for secure communication?', NULL, 'A ciphertext message is shorter than its original plaintext message.', 'A message receiver’s public key is used to encrypt the message and his/her private key is used to decrypt the message.', 'A message sender’s private key is open to everyone and is used to encrypt the message, and each message receiver’s public key is used to decrypt the message.', 'A secret key needs to be shared among those who need to receive the message.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method of social engineering used in a targeted e-mail attack?', NULL, '“Unsolicited advertising” is shown in the subject.', 'Content that appears to be related to the work of the recipient is shown in the subject or body text.', 'In order to make the recipients access a bogus website, the sender pretends to be a financial institution and sends e-mails indiscriminately.', 'In order to make the recipients transfer a fee that they do not need to pay, the sender pretends to be a collection agency and sends e-mails indiscriminately.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In information security, which of the following is a back door?', NULL, 'A LAN port that is incorporated into a switch in order to obtain network communication packets and inspect details of the communication', 'A tool that searches for an open TCP port on a server on the Internet, and identifies running services', 'A URL that enables access to a website without going through the official procedures such as password authentication that are normally required for access', 'An attack that causes a program to crash by entering a string with a length that exceeds the size of an area of memory acquired by the program, causing an overflow', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-40', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An asset valued at $200,000 has an exposure factor of 20% and an annual rate of occurrence of 0.5 for the risk of malware infection. How much (in dollars) is the annual loss expectancy of the asset due to malware infection?', NULL, '20,000', '40,000', '80,000', '100,000', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is residual risk?', NULL, 'Amount of risk that is reduced by implementing risk treatment', 'Risk that exists prior to performing any risk management activities', 'Risk that is identified prior to implementing risk treatment', 'Risk that remains after implementing risk treatment', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '23-A-42', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a security measure that allows users to run potentially malicious programs on a system with the purpose of observing their behavior, while restricting the programs from accessing outside of the system?', NULL, 'Firewall', 'Honeypot', 'IPS', 'Sandbox', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-43', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A packet filtering firewall is installed at the connection point of an internal network and the Internet. Which of the following is the appropriate combination of filtering rules that enables PCs on the internal network to access a web server on the Internet (port number 80)?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-44-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00NC1BLnBuZyIsImlhdCI6MTc0MzExMDcxMiwiZXhwIjoxNzc0NjQ2NzEyfQ.ylTumPZsEpK1pxXF-QGa6v6Lc7Fcj_PVuSHeXZkSU2s', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-44-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00NC1CLnBuZyIsImlhdCI6MTc0MzExMDcxOCwiZXhwIjoxNzc0NjQ2NzE4fQ.wFo9P8QkAowJVw5A2TUnzFDvYbewL0Th7MbDEU07QjM', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-44-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00NC1DLnBuZyIsImlhdCI6MTc0MzExMDczNCwiZXhwIjoxNzc0NjQ2NzM0fQ.hlNcgbIfAXRAhVO7xk9bqqwtP8pTT57TKARvw9xdClA', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-44-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00NC1ELnBuZyIsImlhdCI6MTc0MzExMDczOSwiZXhwIjoxNzc0NjQ2NzM5fQ.Mm7mm5WSUjwXlran7TVbe78ZLA3mXK_6GmRHmNBrZMs', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-44', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a sender from domain A sends an e-mail to a recipient in domain B, which of the following is used by the mail server in domain A for authenticating the sender?', NULL, 'APOP', 'POP3S', 'S/MIME', 'SMTP-AUTH', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-45', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The diagram below is an example of a DFD that is used in the structured analysis method. Which of the following is represented by a “O” in the diagram below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-46.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00Ni5wbmciLCJpYXQiOjE3NDMxMTA3MDQsImV4cCI6MTc3NDY0NjcwNH0.dD6ex0yy146B69_UlIjPganeZxH7G2nlhg7NIS7qKos', 'Activity', 'Data flow', 'Data store', 'Process', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '23-A-46', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the definitions of software quality characteristics, which of the following characteristics refers to the ease of modifying a program for a certain computer so that it can run on a different architecture?', NULL, 'Changeability', 'Interoperability', 'Portability', 'Usability', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '23-A-47', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the error embedding method, when the number of embedded errors is S, the number of discovered errors from the embedded errors is m, the number of latent errors before the start of testing not including embedded errors is T, and the total number of discovered errors is n, which of the following expresses the relationship of S, T, m, and n?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-48-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OC1BLnBuZyIsImlhdCI6MTc0MzExMDc1MCwiZXhwIjoxNzc0NjQ2NzUwfQ.RaRIm3_z0W63tqpyfHWCXCYArlnYIzapOBKiDINuCP0', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-48-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OC1CLnBuZyIsImlhdCI6MTc0MzExMDc1OSwiZXhwIjoxNzc0NjQ2NzU5fQ.pEDvnciWLjGqUv5nnNCQUe-KRTl3AAeVDZLK32GMT4E', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-48-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OC1DLnBuZyIsImlhdCI6MTc0MzExMDc2NCwiZXhwIjoxNzc0NjQ2NzY0fQ.N5RnEvdJS_FdxXjPJNOe23eyumvbn7aQ4Q4sI4hQGEg', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-48-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OC1ELnBuZyIsImlhdCI6MTc0MzExMDc3MCwiZXhwIjoxNzc0NjQ2NzcwfQ.oocxad73EEbqR1IEufZzwyqYonr-Zb_AFG1ShEA_rhQ', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '23-A-48', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate test case when a test is to be performed with decision condition coverage (branch coverage) on the section of a program shown in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-49.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OS5wbmciLCJpYXQiOjE3NDMxMTA4MDUsImV4cCI6MTc3NDY0NjgwNX0.tb3xoeF_AiRcSCIeYkLq7ORiAzFczdJ-i_TFAM_vceg', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-49-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OS1BLnBuZyIsImlhdCI6MTc0MzExMDc4NiwiZXhwIjoxNzc0NjQ2Nzg2fQ.gYSIA2Cz65KiPpUjh_fTzrsmp_xweWHtZDKhzw0PxSM', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-49-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OS1CLnBuZyIsImlhdCI6MTc0MzExMDc5MCwiZXhwIjoxNzc0NjQ2NzkwfQ.1GEEeGflF3zf2dR-Zr5WNEWWk5AwDgwwEuKiywx5yao', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-49-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OS1DLnBuZyIsImlhdCI6MTc0MzExMDc5NiwiZXhwIjoxNzc0NjQ2Nzk2fQ.Jkg71L2oC_Az7UppMaWo5TzbfJruK3h_tp_3336di38', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-49-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00OS1ELnBuZyIsImlhdCI6MTc0MzExMDgwMCwiZXhwIjoxNzc0NjQ2ODAwfQ.HwxUJbTOGIgXXjc9ARlU_UKT8oFx59HNCoZkqEk-eNI', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '23-A-49', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate term for referring to activities such as creating a class diagram in UML from a program?', NULL, 'Backtracking', 'Forward Engineering', 'Reengineering', 'Reverse engineering', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '23-A-50', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As for software development activities, which of the following is refactoring?', NULL, 'In order to improve the maintainability of a program, its internal structure is modified without any change to the external specifications.', 'In order to improve the quality of a program, two programmers cooperate to perform the coding of a single program.', 'In order to obtain feedback from users, the prototype of a program to be provided is created at an early stage.', 'In order to promptly develop a program to be operated, test cases are set in advance and the program is then coded.', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '23-A-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the stakeholders involved in a project?', NULL, 'Some stakeholders receive the project result advantageously and others disadvantageously.', 'The stakeholders are individually identified people, such as project managers.', 'The stakeholders belong within the organization and do not exist outside of it.', 'The stakeholders participate directly in the project; they are not limited to indirect involvement.', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '23-A-52', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In project management, which of the following is the subject group that includes processes having Purpose 1 and those having Purpose 2? 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A project was planned to be completed in six months. After six months, the project is behind schedule. The actual cost of Activity A is $100,000. The planned value of Activity A is $80,000. Activity A is only 75% complete. What is the schedule performance index and cost performance index of the project?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-54.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS01NC5wbmciLCJpYXQiOjE3NDMxMTA4MTcsImV4cCI6MTc3NDY0NjgxN30.dEPR8V-Q7BGJot-hEfIPD7DMHhb_1xqvTn8whbCWu-0', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '23-A-54', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the Function Point method for creating an estimate for software development?', NULL, 'It is a method for estimating the overall workload, where the development work is broken down into units of work items. The cumulative total of the workload for each item is then calculated based on a predefined standard value for the workload that is applied to each individual work item.', 'It is a method for estimating the person-hours and development duration, on the assumption that the development scale is known. It can be applied to all fields, not just to the business field.', 'It is a method for estimating the scale and person-hours of development based on some past experience of similar software, where similarities and differences of software are analyzed while past data is used for the similarities and past experience for the differences.', 'It is a method for estimating the scale of software, where the functions of the software are quantitatively measured using elements such as the number of I/O data items and the number of files, and an adjustment is performed based on the complexity.', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '23-A-55', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When an IT service is discontinued, it is important to comprehensively identify the assets that were used and appropriately remove or free surplus assets. Which of the following is an event that may occur due to mistaken removal of assets that should remain, but does not occur because of the removal of assets that should be removed?', NULL, 'Occurrence of incidents involving other IT services that share assets with the discontinued IT service', 'Overpaying software or hardware maintenance charges', 'Wasting money on software licenses', 'Wasting space that becomes unused on magnetic disks', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-A-56', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As for activities in capacity management to estimate a service’s capacity, capability, and performance, which of the following is trend analysis?', NULL, 'As the first phase of modeling, creating a model that accurately reflects the current performance', 'Generating simulated transactions and predicting the response time and throughput of a service', 'Understanding the chronological usage of a specific resource and predicting usage changes in the future', 'Using mathematical techniques, such as queueing theory, and predicting the response time and throughput of a service', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-A-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning system operation?', NULL, 'Disconnecting failed components to continue the system’s more important functions is called fall back operation.', 'Re-executing a program using data recorded at a checkpoint is called rebooting', 'Recording transactions for the purpose of restoring a database to its condition prior to changes is called data logging.', 'Regularly saving files to another recording media for the purpose of restoration in the event of failure is called restoring.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-A-58', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the system design phase, when an audit is performed on the control to reduce the risk of user requirements not being met, which of the following is a point to be checked?', NULL, 'Whether programming is performed in accordance with the specified conventions and standards', 'Whether the program specifications are created based on the system design documents', 'Whether the test plan is created based on the system test requirements, and the manager’s approval of the system operations department is obtained', 'Whether the user department participates in the review of the system design documents', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '23-A-59', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When an information system department enters data sheets issued by a business operations department, which of the following is an appropriate task executed by the information system department?', NULL, 'The data sheets are retained in the information system department until the due date for processing, and the number of sheets received is checked and confirmed just before the due date', 'To enable the business operations department to check the processing results of each data sheet, the processing results list is sent to that department.', 'To prevent unauthorized use or leakage of confidential information, data sheets are disposed of immediately after data entry is completed.', 'When the data sheet contains an obvious error, the data sheet is corrected, and an entry is made at the discretion of the person in charge of data entry.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '23-A-60', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of RPA that is used to proceed with business innovation with the aim of resolving management issues, such as a shortage of staff members?', NULL, 'Deploying robots for assembly work instead of employees engaged in the assembly of components on the manufacturing line.', 'Processing standardized routine activities such as data input, and cross-checking of the business system by software instead of the clerical staff members.', 'Replacing manned stores with unmanned stores run by cameras and an electronic payment system for analysis of IC tags and images.', 'Replacing transfer of stored products through manual operations by using a forklift or something similar with an automated warehouse system where computer control has rendered human labor obsolete.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a system where the use of a state transition diagram is appropriate when the system is designed?', NULL, 'Electricity charge calculation system that calculates charges based on the amount of power usage from power meter readings.', 'Greenhouse control system that keeps the environment in a greenhouse optimal based on the data of an installed sensor.', 'Inventory control system that performs the collection and aggregation of inventory assets at the end of every month and at the time of settlement.', 'System that measures the operational status of the system resources and creates a report.', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '23-A-62', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the digital divide?', NULL, 'It refers to an economic or social gap that occurs due to differences in abilities and opportunities to use PCs and communications.', 'It refers to communications and broadcast services that any citizen can access with standard charges, without any differences between regions.', 'It refers to the ability of citizens to participate directly in the policies of government and autonomous bodies by using the Internet.', 'It refers to the provision of all services in a single place for each event of the daily life of citizens or each field of corporate activity.', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '23-A-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Procurement is performed by using the comprehensive evaluation bidding method under the conditions shown below. When the bidding prices and technology points of Companies A to D are as shown in the table below, which of the following is the successful bidder? 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of green procurement (sustainable procurement)?', NULL, 'It refers to a certificate that enables commercial trading of green power that is generated from natural energy such as sunlight, biomass, wind power, and geothermal heat.', 'It refers to a mass promotion of environmental protection activities and fund raising from investors for the environmental protection', 'It refers to a preferential purchase of products and services that exert a lower environmental burden.', 'It refers to international standards that employ labels to certify that a product contributes to environmental protection.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-A-65', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the mechanisms that are utilized on the Internet, which of the following is an explanation of crowdfunding?', NULL, 'It refers to a company placing an order with a person who is judged to be qualified to outsource work to an unspecified number of people on the website through prior notification of business operations.', 'It refers to a web service for individuals that displays information on the account transactions of multiple financial institutions at once by a single authentication through prior registration of multiple account information.', 'It refers to payment from an advertiser to a website operator when a person who is browsing the website purchases a product from the EC site by using the link from the published advertisement.', 'It refers to raising money from an unspecified number of individuals who support a business project that is published on the website, and who expect to obtain products and rights in return.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of the maturity stage in the product life cycle?', NULL, 'Demand decreases and some companies start withdrawing. A company determines whether it can be a strong player in this stage and considers advancing into alternative markets.', 'Demand grows, and the product differentiation and segmentation of the market become evident. Competition intensifies, and it becomes important to add new models and reduce cost.', 'Demand is partial, and cultivation of new demand is the key to success or failure. It is necessary to persuade specific targets with conviction.', 'The market begins to understand the value of a product. Both the product line and the channel must be expanded. Sales increase, but investment is also needed in this stage.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-67', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is mostly tacit knowledge?', NULL, 'A list of countries and their capitals', 'An inventory of assets', 'Contents of a washing machine manual', 'How to ride a bicycle', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-68', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate example of a core technology for the creation of competitive advantage?', NULL, 'It is a development technology that combines general components with the purpose of fast-track development and fast-track market introduction of products.', 'It is a device technology that employs the same CPU core as that of competitors and enhances the portability of software.', 'It is an idle reduction technology of an automobile engine that cannot be imitated by competitors.', 'It is an interface technology whose purpose is to create standard interfaces by forming an alliance and use them commonly.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A product that is produced through four (4) processes of A, B, C, and D must be produced in a quantity of 1,000 units per month. The table below lists the manufacturing time per unit, number of machines owned, and monthly production capacity in hours per machine for each process. Which of the following is a process that is lacking in capability?', NULL, 'A', 'B', 'C', 'D', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-70', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of cryptocurrency mining that is enabled by  block chain?', NULL, 'Making payments or settlements by using cryptocurrency in brick-and-mortar stores', 'Obtaining capital gain by buying and selling cryptocurrency', 'Obtaining cryptocurrency as a reward for participation in checking or record calculation of cryptocurrency transactions', 'Transferring money to an individual or organization in cryptocurrency', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-71', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a sharing economy?', NULL, 'It is a concept by which efficient management and operation of renewable energy and urban infrastructure are performed by using IT, which leads to an improvement in the quality of peoples’ lives and helps achieve continuous economic growth.', 'It is a concept by which the productivity of an entire economy increases as a result of utilizing IT, and the supply and demand gap is eliminated via the progress of SCM, which leads to sustainable growth free from inflation.', 'It is a mechanism by which sales both over-the-counter and through the Internet are combined in a business transaction, and the benefits of both are utilized and linked to expand overall sales.', 'It is a mechanism mainly between individuals by which the community function and other functions of social media are utilized to share, lend, or borrow unused assets owned by individuals.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-72', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of digital signage?', NULL, 'A technology to embed identification information in data to prevent abuse', 'An economic or social gap among regions or individuals, arising from lack of opportunities and abilities to utilize information technology', 'An electronic billboard that displays information such as images and characters', 'An electronic signature that is used to ensure the validity of information', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the constituent elements of IoT?', NULL, 'They cover all items that can connect to the Internet or a closed network.', 'They cover all tangible objects except humans and living things.', 'They cover digital type devices, and do not cover analog type devices.', 'They cover only devices that autonomously collect data and perform data analysis.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '23-A-74', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of OJT?', NULL, 'A dedicated approach to education is possible outside of the workplace.', 'Because the boss or senior accosiates provide education in hands-on knowledge and technical skills by staying close to practical affairs, the required competency can be acquired.', 'Education that focuses on generalized knowledge and technology can be acquired', 'Regardless of the ability of the boss or senior associates, occupational knowledge of a specific standard can be acquired.', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-A-75', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('To secure transparency in business administration, which of the following is a concept that supervises and monitors a company’s activities from the perspective of questions such as for whom the company runs its business, how top management is structured, and whether the organization has self-improvement capabilities?', NULL, 'Core competence', 'Corporate governance', 'Corporate identity', 'Stakeholder analysis', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-A-76', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of the ABC analysis?', NULL, 'It analyzes a region in more detail on the basis of various data (population, purchasing power, etc.) by dividing the region into a grid with multiple sections.', 'It arranges products in order of high sales or high gross profit, divides them into levels on the basis of the cumulative ratio, and then plans to increase the volume of product sales at high levels.', 'It classifies and aggregates multiple parts of the survey data by factor, and analyzes the sales capacity and status of purchasing the same products.', 'It repeatedly surveys the same panelist (respondent) many times. This data is used to understand regional trends or changes in the purchasers.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-77', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There are several quality control tools that are used primarily for manufacturing and inspection departments. Which of the following is a graph where appropriate units or attributes for the data are set on the vertical and horizontal axes correspondingly and measured values are plotted accordingly?', NULL, 'Control chart', 'Histogram', 'Pareto chart', 'Scatter diagram', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-A-78', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A company plans to provide a product with a fixed cost of $128,000, a variable cost per unit of $48, and a selling price per unit of $80. Which of the following is the point of sales (in dollars) to become break-even?', NULL, '240,000', '320,000', '480,000', '560,000', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '23-A-79', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In developing new products that are expected to be employed by government agencies of WTO member countries, which of the following are the appropriate standards to be applied?', NULL, 'ANSI standards', 'FCC standards', 'IEEE standards', 'ISO standards', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '23-A-80', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For an 8-bit binary integer, which of the following sets the least significant bit to 1 while leaving the other bits unchanged?', NULL, 'Perform bitwise AND operation with 00000001.', 'Perform bitwise NAND operation with 11111110.', 'Perform bitwise OR operation with 00000001.', 'Perform bitwise XOR operation with 00000001.', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-O-01', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the loss of significance?', NULL, 'It occurs when the result of an operation exceeds the maximum handle limit and raises an exception.', 'It occurs when two nearly equal floating-point numbers are subtracted to produce a result of unacceptably reduced significant digits.', 'It refers to a rounding error that occurs when the part smaller than the least significant digit of the result is rounded off, up, or down in floating-point operations.', 'It refers to the case when two floating-point numbers are added, but the less significant digits of either one do not affect the result.', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-O-02', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When two dice are rolled, what is the probability that the sum of the dice is 5? Here, the two dice are fair and independent.', NULL, '1/18', '1/12', '1/9', '1/6', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-O-03', -1.0, 1.0);
