INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There are three (3) blue balls and four (4) green balls in a box. When two balls are randomly taken out from the box, what is the probability that both are blue?', NULL, '2/49', '1/15', '1/7', '9/49', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-O-06', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Five (5) characters, A, C, K, S, and T, are input in this order. When using stacks, what is the minimum number of stacks required to rearrange the characters and output S, T, A, C, and K, in this order? Here, when a pop operation is performed for any stack, the popped character always becomes an output. Also, characters cannot be moved between stacks.', NULL, '1', '2', '3', '4', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-O-07', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a two-dimensional array A(5,5) is mapped to computer memory (i.e. a one dimensional array) in row-major (row-directional) order or column-major (column directional) order, how many elements occupy the same memory addresses in both cases? Here, the first element A(1,1) is mapped to the same starting memory address in either case.', NULL, '2', '3', '4', '5', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-O-08', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following characterizes the hash method in table search?', NULL, 'It determines the storage location using a function of a key.', 'It is a method that avoids collisions among storage locations.', 'It is one of the methods that use a binary tree.', 'It takes time almost proportional to the table size for searching.', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-O-09', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technology used to provide dynamic UI contents without reloading the entire web page by using an asynchronous communication feature of JavaScript?', NULL, 'Ajax', 'CSS', 'RSS', 'SNS', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-10', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a 32-bit microprocessor with 32-bit external data bus, driven by 64 MHz input clock, and the processor takes 8 input clock cycles to complete 1 bus cycle. What is the theoretical maximum data transfer rate in megabytes per second (MB/s) for the external data bus of the processor?', NULL, '3', '32', '256', '320', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-O-11', 0.0, 1.0);
