INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate explanation of augmented reality (AR)?', NULL, 'By appealing to the five senses through equipment, such as a head-mounted display, a person can experience locations or worlds that do not exist as if they were real.', 'By constructing a 3D virtual space that is natural to humans and changing the virtual space in accordance with a person’s movement, he or she can feel as if he or she were in that place.', 'By seamlessly interweaving computer-generated information with the physical world, the viewer can perceive it as an immersive aspect of the real environment.', 'By viewing a video recorded in the past, the viewer can feel as if he or she were in that era and at that location.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-24', -1.0, 1.0);
