INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a relational database, which of the following is an appropriate purpose for defining a foreign key?', NULL, 'To prevent fragmentation in the record storage area due to the repeated deletion and insertion of records', 'To provide a constraint to maintain referential consistency between the records of related tables', 'To restore as many records as possible when they are damaged by failure, based on the mutual relationship between tables', 'To speed up the searching and updating of related tables by storing them closer together', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-26', -1.0, 1.0);
