INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a company, the received-orders are monitored monthly based on the customer file, product file, person-in-charge file, and the current month’s received-orders file. When the items of each file are as shown in the table below, which of the following can be retrieved for the received orders of current month and the three (3) previous months using the four (4) files?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-O-29.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItTy0yOS5wbmciLCJpYXQiOjE3NDMxMTEwMjAsImV4cCI6MTc3NDY0NzAyMH0.JRp7Q97KE9gRuThuaOQeWeYDF6mvKYfOVc82oLWBKeI', 'Customer-wise received orders by product', 'Customer-wise received orders by the person in charge', 'Person-in-charge-wise received orders by product', 'Product-wise received orders by customer', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-29', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an IP network consisting of four (4) hosts, two (2) L2 switches, and a router shown below, a packet is transmitted from PC01 to PC03. Which of the following is an appropriate combination of the source and destination addresses of this packet when it leaves Switch1?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-O-30.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItTy0zMC5wbmciLCJpYXQiOjE3NDMxMTEwMjcsImV4cCI6MTc3NDY0NzAyN30.JC4T3vCrAn70AqwhmH5bwRoL5XxweOI2yBBi1hd9kso', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-30', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a TCP/IP protocol that is used to find the corresponding MAC address from an IP address?', NULL, 'ARP', 'ICMP', 'IP', 'RARP', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the subnet mask corresponding to an IP address in slash notation, 192.168.22.31/27?', NULL, '255.255.255.192', '255.255.255.224', '255.255.255.248', '255.255.255.252', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-32', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following protocol supports the congestion control feature?', NULL, 'ARP', 'ICMP', 'TCP', 'UDP', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-33', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a global IPv4 address?', NULL, '10.10.10.10', '129.10.9.7', '172.16.1.5', '192.168.20.3', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-34', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The three properties of information security are confidentiality, integrity, and availability. Which of the following is an attack on integrity?', NULL, 'DDoS', 'Phishing', 'Shoulder Surfing', 'Website defacement', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-35', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a system with a database is being developed, a security requirement states that the data must be encrypted with a key before being saved to the database, and the same key is required for decryption when the data is being read. Which of the following is an appropriate algorithm that can be used to satisfy the security requirement?', NULL, 'AES', 'Diffie-Hellman', 'RSA', 'SHA-256', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a cyber-attack that redirects a victim to a fake website by manipulating DNS to obtain personal information from the victim?', NULL, 'Pharming', 'Phishing', 'Spamming', 'Trojan Horse', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-37', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When security risk management processes incorporate the approach of the PDCA (Plan, Do, Check, Act) cycle, which of the following is a process that belongs to Act?', NULL, 'Establish a security policy and develop a security risk management plan.', 'Implement the security risk management plan.', 'Maintain and improve the security risk management plan by learning from incidents.', 'Monitor the security risks as planned in the risk management plan.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the protocol that is used together with HTTP in HTTPS?', NULL, 'SHA', 'SSH', 'TLS', 'VPN', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-39', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate term associated with the fraudulent action of impersonating an authorized person?', NULL, 'Destruction', 'Falsification', 'Spoofing', 'Tapping', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-40', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An attacker calls a corporate help desk, masquerading as an employee who has forgotten his password. The help desk staff resets the password to the company default “password1. ” The attacker then uses this password to access the company network and information on the server. What is this type of attack called?', NULL, 'Buffer overflow attack', 'Denial-of-Service attack', 'Shoulder Surfing', 'Social Engineering', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a biometric authentication system is introduced, which of the following is the most appropriate point to be taken into account?', NULL, 'Adjusting the device by considering both the probability of incorrectly rejecting an authorized user and that of incorrectly accepting an unauthorized user', 'Preventing the decrease in the probability of incorrectly rejecting an authorized user by using a product that frequently updates the malware definition file', 'Requesting an entrusted third party to issue a digital certificate for the person to be authenticated', 'Setting the appropriate amount of knowledge for authentication to balance the amounts of knowledge that cannot be easily guessed and that can be memorized by a person to be authenticated', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-42', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of using a message authentication code?', NULL, 'To check the encryption method of a message', 'To check the overview of a message', 'To confirm that there is no falsification of a message', 'To secure the confidentiality of a message', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of WAF?', NULL, 'It centrally stores and manages operation logs from various systems to quickly detect and analyze an event that can be a security threat', 'It is a standard of encryption methods for wireless LAN, certified by the Wi-Fi Alliance, and supports AES encryption.', 'It is equipped with firewall functions and has antivirus, intrusion detection, and other functions that work together to manage multiple security functions in an integrated manner.', 'It monitors the accesses to a website, and when it detects a pattern that is likely from an attacker, it blocks those accesses.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a UML use case diagram?', NULL, 'It shows the behavior during the object’s life cycle using finite state transitions.', 'It shows the exchange of messages among objects and objects’ lifelines in a time series.', 'It shows the flow from one activity to another activity in a system or business process.', 'It shows the scenarios for how actors, i.e., external users or machines, interact with a system.', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-45', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In UML 2.0, which of the following is a diagram that represents the interactions between objects in time series?', NULL, 'Activity Diagram', 'Component Diagram', 'Sequence Diagram', 'State transition Diagram', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a structural design pattern that allows classes with incompatible interfaces to work together?', NULL, 'Adapter', 'Factory', 'Iterator', 'Singleton', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description of a stack trace that is used for debugging a program?', NULL, 'A trace of call stack methods/functions/subroutines', 'Stacking/gathering the traces left by other programs', 'The traces left in memory from a stack data structure', 'Tracing stack data structure that is used in the program', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the software development activities, which of the following corresponds to refactoring that is emphasized in agile development?', NULL, 'To improve the maintainability of a program, the internal structure of a program is changed without any change in the external specifications.', 'To improve the quality of a program, two (2) programmers cooperate and perform the coding of one (1) program.', 'To obtain feedback from the users, a prototype of the software is created at an early stage.', 'To promptly develop a program, test cases are set in advance, and then the program is coded.', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In eXtreme Programming (XP), which of the following is advocated as a practice?', NULL, 'Inspection', 'Pair programming', 'Structured design', 'Use case utilization', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A project consisting of several activities has a single critical path. Which of the following is an appropriate description of critical path activities for the project?', NULL, 'Critical path activities can be performed in parallel.', 'Critical path activities have a non-zero total float time.', 'For each critical path activity, the early start date equals the late start date.', 'The activity with the longest duration in the project is one of the critical path activities.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '22-O-51', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the Responsibility Assignment Matrix that is used for project human resource management?', NULL, 'Allocating work packages to those who are responsible for project work', 'Defining the limits of the project sponsor’s responsibilities', 'Defining the terms of reference of the project', 'Monitoring the current engagement level of stakeholders', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '22-O-52', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate purpose for using a WBS (work breakdown structure) in a software development project?', NULL, 'To clarify the time sequence of activities and understand the critical path that should be intensively managed', 'To decompose a development task into smaller sub-tasks with a manageable size and organize them into a hierarchical structure', 'To optimize the total cost when there is a trade-off relationship between the number of days and the costs required for development', 'To show the schedule of activities by using bars and clarify the start dates and end dates of the activities as well as the progress at the current point', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '22-O-53', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description for group decision-making techniques used in the estimation process of an activity duration?', NULL, 'The estimates created using these techniques may include contingency reserves, sometimes referred to as time reserves or buffers, in the project schedule to account for schedule uncertainty.', 'These are team-based approaches, such as brainstorming, the Delphi, or nominal group techniques, which are useful for engaged team members to improve their estimation accuracy and commit to the estimates.', 'These techniques use statistical relationships between historical data and project parameters to calculate an estimate for project cost, budget, or duration.', 'Using these techniques, a group of experts, guided by historical information, can provide duration estimate information or recommended maximum activity durations from prior similar projects.', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '22-O-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate meaning of a mission-critical system?', NULL, 'As with an operating system, it is an indispensable system necessary for operating a business system.', 'It is a system that has a significant impact on corporate activities and society when a failure occurs.', 'It is a system that is first installed on a trial basis, and if successful, a full-scale installation is implemented.', 'It is a system where the operating performance is close to the limit.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '22-O-55', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the relationship between a record of an incident and a record of a problem in IT service management?', NULL, 'A cross-reference to the incident that triggered the record of the problem is included in the record of the problem.', 'If known errors have been identified at the time of ending the record of the problem, the record of the incident that triggered the record of the problem is deleted.', 'One (1) problem record is always associated with one (1) incident record.', 'Problems are classified and recorded by a different criterion from the classification of incidents.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '22-O-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A system is planned to be operational 22 hours per day. However, there are two (2) failures with downtimes of 0.5 hours and 1.5 hours in 100 days. Which of the following is the approximate MTBF of this system during the period in hours?', NULL, '0.00091', '1.0', '2.0', '1100', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-O-57', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a business continuity plan (BCP) is developed given the possibility of a system failure, which of the following is the item that is implemented as part of business impact analysis?', NULL, 'Collectively educating the concerned persons about the alternate procedures and recovery procedures during an information system failure', 'Determining the maximum allowable downtime for the information system', 'Executing a test to verify the effectiveness of BCP', 'Revising the contents of the BCP given changes in the internal and external environment of the information system', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '22-O-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate purpose for which a system auditor exchanges opinions with an audited department concerning the draft version of an audit report?', NULL, 'To confirm that there are no factual errors in the findings and recommendations to be described in the audit report', 'To issue the audit report to the audited department before the audit report is submitted to the person who is requesting the audit', 'To receive the approval of the responsible person of the audited department concerning the recommendations described in the audit report', 'To substitute with additional auditing activities concerning the part of the audit report for which evidence is insufficient by orally confirming with the audited department', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '22-O-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate activity performed by a system auditor who audits access control?', NULL, 'Creating and storing the access control records for the software', 'Establishing an access control policy for the network', 'Implementing the access control procedures for hardware', 'Viewing the access control rules for data', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '22-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of SOA?', NULL, 'It consists of four (4) main concepts; the business scheme, data scheme, application and processing scheme, and technical scheme, and it aims to optimize the business and the system.', 'It makes it easier to address a change in the business by constructing software from components called services.', 'It performs design at the component levels by using a combination of three (3) logical structures; a sequence, selection, and iteration.', 'It uses a data flow diagram and simultaneously creates a model regarding information and a model regarding functions.', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-61', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of BPR (Business Process Reengineering)?', NULL, 'BPR is a management practice used to provide the overall governance of an organization in a business process environment to improve agility and operational performance.', 'BPR is a management strategy used to automate key business processes that helps in saving time, promoting efficiency, and ultimately reducing costs to enhance the value of an organization.', 'BPR is a management system used in marketing and business to automate the sales activities, such as contact management, order taking and fulfillment, information sharing, inventory monitoring, and sales forecast analysis.', 'BPR is a management technique used to redesign and restructure value-creating processes in an organization to gain significant benefits in productivity, profitability, service, and quality through maximizing the potential of individuals and teams.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-62', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a usage scenario for the adoption of UML as a technique for visualizing business processes?', NULL, 'Diagrams are shown by using a data-oriented approach where objects are handled as entities, their attributes, and the relationships among the entities.', 'To represent processes by using data flows, sources and sinks of data, data stores, and data processes are connected with arrows that indicate data flow.', 'To represent processes from multiple viewpoints, some purpose-specific modeling methods are used, and each model is depicted by using standardized notation rules for object modeling.', 'To thoroughly represent the functions of a process, the events that occur in response to a single request are described by using the conditional branch format.', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-63', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In computerization planning, which of the following is an activity that should be performed?', NULL, 'Clarifying what roles are assigned to the business and information-system departments when the organizational structure of system development is planned and clarifying the basis of cost calculation for the development, operation, and maintenance when considering the costs', 'Determining interfaces, such as screens or forms, based on the requirements definition document and describing them in the design document', 'Performing maintenance and management of the system so that it conforms to the business and environment and analyzing details and clarifying the potential impacts of modification requests', 'Performing system startup and shutdown, monitoring, and file maintenance in a planned manner and verifying that business is being carried out smoothly', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '22-O-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When an information system is procured through the steps shown in the figure below, which of the following is a word or phrase that should be inserted in the blank B?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-O-65.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItTy02NS5wbmciLCJpYXQiOjE3NDMxMTEwMzYsImV4cCI6MTc3NDY0NzAzNn0.K1baMtBIxL08ZW9jpi6RP6LUiZ13bMzTiJ9IMmAxYIc', 'Concluding a contract', 'RFI', 'RFP', 'Selecting a provider', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '22-O-65', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a growth matrix proposed by Ansoff, which of the following is a strategy for expanding a business with an existing product in an existing market?', NULL, 'Diversification', 'Market development', 'Market penetration', 'Product development', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('PEST analysis is used to analyze the external environment in determining a business strategy. Which of the following is an appropriate set of external environmental factors that PEST analysis analyzes?', NULL, 'Politics, Economics, Society, Technology', 'Politics, Enterprises, Society, Time', 'Price, Economics, Satisfaction, Technology', 'Price, Enterprises, Safety, Time', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a process that aims to produce ideal technology, technology follows an evolutionary process that progresses from the introduction stage, growth stage, maturity stage, and decline stage. Then, it transitions to the next technological phase. Which of the following is used to represent this technological evolution process?', NULL, 'Bathtub curve', 'Demand curve', 'Learning curve', 'Technology S-curve', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When trial production is performed for components to be loaded into electrical appliances, which of the following is the least expensive development method? Here, the construction time of each process is six (6) months for the creation process, three (3) months for the modification process, and two (2) months for the evaluation process. The cost per one (1) person-month is 6,000 dollars for the creation process and 10,000 dollars for each of the modification and evaluation processes. Costs other than the purchase cost, outsourcing cost, and person-month cost shall not be considered.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-O-69.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItTy02OS5wbmciLCJpYXQiOjE3NDMxMTEwNDEsImV4cCI6MTc3NDY0NzA0MX0.NMXQiAP-3DCv650K9xiK3BztW7zO0gVOG0sti-xtfS8', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-O-69', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of MRP', NULL, 'The development, designing, and production preparation of a product are performed simultaneously in parallel.', 'The number of required components is calculated on the basis of the standard production plan of a product.', 'The production of a product is initiated after an order from a customer is received.', 'Work instructions and transport instructions are provided by using a worksheet.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-70', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the Kanban (just-in-time) system', NULL, 'To improve work efficiency at each operation, parts and semi-finished products having unified specifications are procured.', 'To minimize intermediate stock, parts required for the production line are procured from the previous process on the basis of a production plan.', 'To procure parts efficiently, they are procured from affiliated companies.', 'To procure parts of higher quality, parts are procured via competitive bidding among designated suppliers.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-71', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of Online-to-Offline in net business?', NULL, 'It is a business model that provides a basic service or product for free and charges a fee for advanced or special functions.', 'It is a mechanism that can prevent trouble in electronic commerce, such as the case where the price is paid but the product is not delivered or the case where the product is sent but the price is not paid.', 'It is a mechanism that leads a customer that uses mobile devices to purchase by guiding the customer from a virtual store to a real store or from a real store to a virtual store', 'It is a scheme that starts production of the final product after receiving the order from a customer, in order to realize customization according to customer specifications.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-72', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A smart meter is a highly functional electricity meter with a function for communications and a function for the management of other devices. Which of the following is not appropriate as the purpose of installing a smart meter?', NULL, 'Continuing the power supply for a fixed amount of time by functioning as an auxiliary power source at the time of a power failure', 'Improving the efficiency of meter reading work through automatic meter reading', 'Increasing awareness of power-saving through visualization of the amount of power consumption', 'Restraining peak power through control over power demand by using demand response', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a sharing economy?', NULL, 'It is a concept by which efficient management and operation of renewable energy and urban infrastructure are performed by using IT, which leads to an improvement in the quality of people’s lives and helps achieve continuous economic growth.', 'It is a concept by which the productivity of an entire economy increases as a result of utilizing IT, and the demand-and-supply gap is eliminated via the progress of SCM, which leads to sustainable growth free from inflation.', 'It is a mechanism by which over-the-counter and Internet sales are combined in a business transaction, and the strong points of both are utilized and linked to expanding overall sales.', 'It is a mechanism mainly between individuals to share, lend, or borrow idle assets owned by individuals by utilizing the community functions of social media.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-74', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a management organization that has the characteristic of both project and functional organizations being able to flexibly respond to changes in the business environment?', NULL, 'Divisional organization', 'Hierarchical organization', 'Line and staff organization', 'Matrix organization', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '22-O-75', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a process of discovering useful patterns and relationships by the analysis of large volumes of data?', NULL, 'Brainstorming', 'Data mining', 'Decision tree', 'Document analysis', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-O-76', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a chart that represents values over a period (frequently one year) and shows simultaneously monthly figures (or weekly or daily), cumulative totals, and the moving averages?', NULL, 'Pie intersection chart', 'Radar chart', 'SD chart', 'Z chart (Z graph)', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-O-77', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Company A purchased a machine for the original cost of $126,000. The salvage value after 6 years is $6,000. What is the annual depreciation expense (in dollars) by using the straight-line method?', NULL, '12,000', '20,000', '21,000', '36,000', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '22-O-78', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the estimated probabilities for the number of units that are sold per day for a product are as listed in the table below and the profit per unit is 10 dollars, what is the number of purchased units where the expected value for profit becomes a maximum? Here, a disposal loss of 3 dollars per unit is incurred if the product remains unsold on the day it was purchased.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-O-79.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItTy03OS5wbmciLCJpYXQiOjE3NDMxMTEwNTQsImV4cCI6MTc3NDY0NzA1NH0.GhZDoPQC-NhEGmuBVuL35Ytqa4A8zzpc74HLrTBtZv0', '4', '5', '6', '7', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-O-79', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the scope of software protection under WTO’s Agreement on Trade-Related Aspects of Intellectual Property Rights (TRIPS)?', NULL, 'Algorithms and programming languages are protected.', 'Application programs are protected but system programs such as an OS are not, as the value of the right is included in the hardware cost.', 'Both source programs and object programs are protected.', 'Documents that describe algorithms are protected, but programs created by using the algorithms are not.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '22-O-80', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For logical variables A and B, which of the following is equivalent to the NOR operation on A and B? Here, A + B, A・B, and A̅ are OR, AND, and NOT operations on the corresponding variables, respectively.', NULL, 'A̅ ⋅ (A + B̅)', 'A̅ ⋅ (A̅ + B̅)', 'B ⋅ (A + B̅)', 'B̅ ⋅ (A̅ + B̅)', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-01', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For non-negative integer A, which of the following has the same value as (A mod 32) + 64? Here, mod, +, AND, and OR are remainder-after-division, arithmetic addition, bitwise AND, and bitwise-OR operators, respectively.', NULL, '(A AND 31) OR 64', '(A AND 32) OR 32', '(A OR 31) AND 64', '(A OR 64) AND 32', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-02', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of normal distribution?', NULL, 'A continuous, bathtub-shaped distribution that is used to express the failure rate', 'A continuous, bell-shaped distribution that is symmetric about its mean', 'A discrete distribution that expresses the probability of an event occurring a given number of times in a fixed interval', 'A discrete distribution where all events have the same probability to occur', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-03', -2.0, 1.0);
