INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The table below shows state transition for character string inspection. During the inspection, if the state changes to E, the string under inspection is rejected. Which of the following is rejected in this inspection? Here, state A is the initial state, strings are inspected from left to right, and symbol △ indicates a blank character.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-05.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0wNS5wbmciLCJpYXQiOjE3NDMxMTM1MzQsImV4cCI6MTc3NDY0OTUzNH0.lmMg-a3ClPs6oigP-23pyRY0QoPnZxto7LSuhFnVFWk', '+0010', '-1', '12.2', '9.△', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-05', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of feedback control?', NULL, 'It detects disturbance and takes a corrective action to prevent its influence.', 'It is vulnerable to disturbance and the influence of the disturbance is amplified.', 'It predicts disturbance and takes a corrective action accordingly.', 'It takes a corrective action after detecting the influence of a disturbance.', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-06', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For two-dimensional integer array A, whose (i, j)-th element A[i, j] is 2 × i + j, what is the value of element A[A[1, 1] × 2, A[2, 2] + 1]?', NULL, '12', '13', '18', '19', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-07', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For two non-negative integers x and y, which of the following is the result of the procedure shown in the flowchart below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-08.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0wOC5wbmciLCJpYXQiOjE3NDMxMTM1NDUsImV4cCI6MTc3NDY0OTU0NX0.F7nnXZfu_fbd53qXeAAdPuKJuqKEY0mk6yWfwYz9OWE', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-08', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a binary search?', NULL, 'A binary search is always faster than a linear search.', 'In a binary search, searching starts from the beginning of the data.', 'The data upon which the binary search is to be performed must be sorted.', 'The number of comparisons that need to be performed during the search is proportional to log2N, where N is the number of data items.', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-09', -2.0, 1.0);
