INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the average cycles per instruction (CPI) of a computer that can execute 1 billion instructions per second at a clock rate of 2.4 GHz?', NULL, '0.04', '0.12', '2.4', '25', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-11', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the approximate average access time in milliseconds (ms) of a magnetic disk with the specifications shown in the table below? Approximate average access time is the sum of average seek time, track-to-track seek time, and average rotational delay. Here, the controller overhead can be ignored.', NULL, '11.67', '12.87', '15.83', '25.00', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-12', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the list that contains A through D sorted starting with the shortest effective access time of the main memory?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-13.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0xMy5wbmciLCJpYXQiOjE3NDMxMTY4ODMsImV4cCI6MTc3NDY1Mjg4M30.f1N1CinS23hMZt8tUrQSVbqOVulFTY9afQXRxQODWI8', 'A, B, C, D', 'A, D, B, C', 'C, D, A, B', 'D, C, A, B', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-13', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A 12-point character is to be displayed on a 96-dpi display in bitmap. How many dots is the height of a square font? Here, 1 point is 1/72 inch.', NULL, '8', '9', '12', '16', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-14', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of an HA (High Availability) cluster configuration based on a hot standby method when it is compared to a load distribution cluster configuration that uses a load balancer?', NULL, 'A server that has the same specifications is necessary as the secondary server, but since the secondary server takes over the processes in the event of the failure of the primary server, the throughput can be maintained even in the event of a failure.', 'Given that processes are distributed to other operational servers in the event of a failure, the load on the servers in operation increases, and the throughput decreases.', 'Given that processes can be distributed uniformly, server machines can be utilized effectively, and expandability is ensured, even if the amount of processing increases in the future.', 'Given that processes must be consistent among multiple servers in operation, it is necessary to share a database.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the system configuration that has the highest availability? Here, when systems are connected in parallel, the systems are considered to be operational if at least one (1) of them is operating.', NULL, 'A single system with an availability of 99%', 'Four (4) identical systems, each with an availability of 70%, are connected in parallel.', 'Three (3) identical systems, each with an availability of 80%, are connected in parallel.', 'Two (2) identical systems, each with an availability of 90%, are connected in parallel.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-16', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An OS chooses a process for CPU execution based on the First-Come-First-Serve (FCFS) scheduling algorithm. There are four processes, P1, P2, P3, and P4, and their arrival times and burst times are shown in the table below. Which of the following is the appropriate combination of waiting times for the processes to be executed? Here, the arrival time is the time at which a process enters the ready queue and is ready for execution, the burst time is the time a process requires for CPU execution, and the waiting time is the period of time a process spends in the ready queue waiting for the CPU to start execution.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-17.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0xNy5wbmciLCJpYXQiOjE3NDMxMTY4ODksImV4cCI6MTc3NDY1Mjg4OX0.uO__HG8UuKbYeHsEYkFF8puNTAbTfSSg65CssPadVAs', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-17', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate reason for using a real-time OS in an embedded system?', NULL, 'A graphical user interface is provided from an ease-of-use perspective with a real-time OS.', 'A real-time OS guarantees the highest levels of system security and reliability.', 'No data is lost even if an application program hangs up with a real-time OS.', 'With a real-time OS, there is a mechanism available to respond within a limited time.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-18', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is software that can be used without charge but has restrictions on modification and redistribution?', NULL, 'Freeware', 'Package software', 'Public domain software', 'Shareware', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-19', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the function of an actuator?', NULL, 'It changes an analog electrical signal into a digital electrical signal, which a computer can process.', 'It changes an electrical control signal that a computer supplies into a mechanical motion.', 'It identifies a physical quantity and changes it into an electrical signal.', 'It is used in devices such as keyboards or touch panels to enter data into a computer.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '22-A-20', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the Exclusive-NOR logic function that is implemented with two-input NOR gates?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-21-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0yMS1BLnBuZyIsImlhdCI6MTc0MzExNjg5NywiZXhwIjoxNzc0NjUyODk3fQ.5GgkoXGK_nq75FbICxk0gSyx33PF2Awy36DkNVlxfaM', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-21-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0yMS1CLnBuZyIsImlhdCI6MTc0MzExNjkwMSwiZXhwIjoxNzc0NjUyOTAxfQ.JqHbKiWWJezK8jHQ-HXglsl6o_P8Qgp87-uH5hVAzEA', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-21-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0yMS1DLnBuZyIsImlhdCI6MTc0MzExNjkwNSwiZXhwIjoxNzc0NjUyOTA1fQ.WTQhOMcC2ln2A_LZfb6ZMxPBd37xXwgwJ3CydmIJHh0', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-21-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0yMS1ELnBuZyIsImlhdCI6MTc0MzExNjkwOCwiZXhwIjoxNzc0NjUyOTA4fQ.5veUsSnP-zozZAcFj9_7da50MEigVujI2FqAYh1uHec', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-21', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A paper tape reader used as a computer input device reads a tape with five rows of holes as shown below. A hole punched in the tape indicates logic 1, and no hole indicates logic 0. As each hole pattern passes under the photocells, the pattern is translated into logic signals as a variable: A, B, C, D, or E. A valid pattern on the tape has at least one hole, and an invalid pattern has no hole or all five holes punched. Which of the following is a logical expression that has logic 1 when a valid pattern is being read and logic 0 when an invalid pattern is being read? Here, + represents logical OR, ∙ represents logical AND, and represents the negation of A in the logic expression. In the figure, • represents a punched hole on the tape.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0yMi5wbmciLCJpYXQiOjE3NDMxMTY5MTYsImV4cCI6MTc3NDY1MjkxNn0.A_ojse1Nspx259HVXgHBl5taZsLxuyOAGMM5TrosAjg', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-22', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When ordering data is entered in the format shown below, which of the following is appropriate to check whether the order date is on a business day that is the same as or prior to the entering date?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-23.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0yMy5wbmciLCJpYXQiOjE3NDMxMTY5MjQsImV4cCI6MTc3NDY1MjkyNH0.ZVlyYdsv0fDykWeM_GwxbOG83BYnm9TXEsRISIjVC1Y', 'Duplication check', 'Format check', 'Logical check', 'Sequence check', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-23', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate explanation of attributes in the relational model?', NULL, 'It is possible to define attributes that have no name.', 'The domains of definition for attributes within a relation must not overlap.', 'The same name can be given to two (2) or more attributes in a relation.', 'There is no meaning in the order of attributes within a relation, and the relation is the same even if the order is changed.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-24', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When an ER diagram is translated into a set of tables in a relational database, which of the following is an appropriate method to translate a many-to-many relationship between two entities?', NULL, 'Combine two entities and create a single table.', 'Create a table for each entity and import the primary key from a table of smaller size to a table of larger size.', 'Create a table for each entity and import the primary key from one table to another table, and vice versa.', 'Create a table for each entity and then create a new table and import the primary keys from both entities to the new table.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-25', -1.0, 1.0);
