INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Multiple PCs are connected to the Internet with FTTH. The WAN interface of device A has a single global IP address allocated to it. Which of the following is the function of device A that enables these PCs to connect to the Internet by sharing the global IP address?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-30.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS0zMC5wbmciLCJpYXQiOjE3NDMxMTY5NDUsImV4cCI6MTc3NDY1Mjk0NX0.wSIcdkeqR6qMmKgGb2MDPWMzw5cz0slxUZUv7rY3jUo', 'DHCP', 'NAPT (IP masquerade)', 'Packet filtering', 'PPPoE', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-30', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Audio data of 2.4 Mbytes encoded at 192 kbit/s is to be downloaded and played back without interruptions over a network with a communication speed of 128 kbit/s. What is the minimum number of seconds required as the data buffering time before the start of playback?', NULL, '50', '100', '150', '250', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-31', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There exists a system that connects a head office to a factory via a leased line and sends form data. The size of each form is 2,000 bytes, and header data totaling 400 bytes is attached to every two (2) forms to be sent through this system. On average, 100,000 forms per hour are generated. When the line speed is 1 Mbit/s, what is the line’s utilization rate in percentage?', NULL, '6.1', '44', '49', '53', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-32', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IPv4, what is the maximum number of IP addresses that can be assigned to hosts in the network of 172.16.64.0/23? Here, the decimal number after the slash (/) is the number of bits used for the network prefix.', NULL, '254', '256', '510', '512', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-33', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the broadcast address of the network with the address 192.168.128.0/26? Here, the decimal number after the slash (/) is the number of bits used for the network prefix.', NULL, '192.168.128.3', '192.168.128.127', '192.168.128.252', '192.168.128.255', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-34', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an Internet standard that is used to convert IP addresses to the corresponding MAC addresses?', NULL, 'ARP', 'ICMP', 'RARP', 'RIP', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a direct result of SQL injection to a company’s web server?', NULL, 'Data packets to and from the web server are modified.', 'Data that is on the web server but is not accessible via the web application is retrieved or modified.', 'Every key stroke a user makes in the network is captured.', 'The IP headers of packets in the network are captured and modified.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a program that is designed to block access to a computer or encrypt most of the data on that computer until a sum of money is paid?', NULL, 'Adware', 'Ransomware', 'Rootkit', 'Spyware', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-37', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a PKI system, which of the following is an algorithm that creates a key pair?', NULL, 'Hashing algorithm', 'Key generation algorithm', 'Signature verification algorithm', 'Signing algorithm', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-38', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a command and control (C&C) server?', NULL, 'A computer controlled and used by an attacker to send commands to other compromised computers', 'A computer on a cloud service used to securely control the movement of data between on-premise storage and cloud storage using encrypted communication', '', 'A computer used to control the authentication of all users and computers in an organization', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of an advanced persistent threat (APT)?', NULL, 'It is a malware attack that keeps recreating malicious files even after repeated deletions.', 'It is an attack that uses sophisticated techniques and goes undetected over a long time, e.g., months or years', 'It is an attack using malware in computer BIOS, affecting multiple operating systems on a computer that allows multi-booting.', 'It is an attack using malware that disables all of a company’s computers and is difficult to delete.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of footprinting in computer security?', NULL, 'Digital forensic analysis to find the hacker after a hacking incident', 'Gathering information about an organization and its systems in preparation for an attack', 'Listing all affected files in the system in order to assess the impact of an attack', 'Setting up an intrusion detection system in order to detect when an attacker breaks into the internal network', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-41', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate combination of definitions I through IV for authenticity and reliability in ISO/IEC 27000:2018 (Information security management systems – Overview and vocabulary)?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-42.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS00Mi5wbmciLCJpYXQiOjE3NDMxMTY5NDksImV4cCI6MTc3NDY1Mjk0OX0._KvrQzFHYu-BMg_uExRAHWzvfz2ayGpLbWfoCKmJPwE', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-42', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a mirror port is prepared to allow a LAN analyzer to be used for measurement in order to investigate the cause of a network failure, which of the following is a point to consider?', NULL, 'In preparation for a failure, it is necessary to inform network users of the storage location and usage method about the LAN analyzer.', 'Since LAN cables must be temporarily disconnected during measurement, it is necessary to give network users advance notice of the measurement date and time.', 'Since the LAN analyzer can display the packets that pass through the network, it is necessary to pay attention to misuse or abuse, such as wiretapping.', 'Since the LAN analyzer disposes of packets, it is necessary to restrict the use of the non target computers during measurement.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a network that is divided into three (3) segments, namely an external segment, a DMZ, and an internal segment, by one (1) firewall. In this network, a service for users is published on the Internet using a system comprising a web server and a database server that contains critical data. Which of the following is the most appropriate server installation method for protecting critical data from unauthorized access via the Internet? Here, the web server performs front end processing for the database server, and the firewall allows only a specific protocol for communication between the external segment and the DMZ as well as between the DMZ and the internal segment. Direct communication between the external segment and the internal segment is not allowed.', NULL, 'The web server and the database server are installed in the DMZ.', 'The web server and the database server are installed in the internal segment.', 'The web server is installed in the DMZ and the database server is installed in the internal segment.', 'The web server is installed in the external segment and the database server is installed in the DMZ.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a system or network that is intentionally made vulnerable in order to investigate the behavior of an intruder or malware?', NULL, 'Botnet', 'DMZ', 'Honey pot', 'SIEM', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-45', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among UML 2.x (including 2.0 and later versions) diagrams, which of the following is the most appropriate diagram that gives a graphic overview of the actors involved in a system, the different functions those actors need to perform, and how these different functions interact?', NULL, 'Activity diagram', 'Communication diagram', 'Interaction overview diagram', 'Use case diagram', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-A-46', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of encapsulation in object orientation?', NULL, 'Abstraction and grouping of several objects that have common properties', 'Bundling of data and the procedures operating on the data as a single object and concealment of their implementation inside the object', 'Creation of a base class by extracting the properties that are common among classes', 'Inheritance of the properties of a base class by a subclass', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '22-A-47', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique that embeds logical expressions that hold true for the relations or conditions between variables at specific points in the execution of a program and verifies the validity of the program?', NULL, 'Assertion check', 'Code trace', 'Snapshot dump', 'Test coverage analysis', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-A-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate test type that is conducted to ensure that the interfaces and linkages between different software parts work properly?', NULL, 'Acceptance test', 'Functional test', 'Integration test', 'Performance test', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-A-49', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a software development model that repeats the development processes from requirements analysis to implementation?', NULL, 'Prototyping model', 'Relational model', 'Spiral model', 'Waterfall model', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-A-50', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The software reengineering process can be divided into four sub-processes: program modularization, program structure improvement, reverse engineering, and source code translation. Which of the following is a process that focuses on functional analysis and information extraction?', NULL, 'Program modularization', 'Program structure improvement', 'Reverse engineering', 'Source code translation', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '22-A-51', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate tool that implements a deliverable-oriented decomposition of a project into smaller components?', NULL, 'Critical path method (CPM)', 'Gantt chart (Gantt)', 'Program evaluation and review technique (PERT)', 'Work breakdown structure (WBS)', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '22-A-52', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of scope management?', NULL, 'The process of determining and documenting a list of all project goals, tasks, deliverables, deadlines, and budgets as a part of the planning process', 'The process of identifying, analyzing, and responding to any risk that arises over the life cycle of a project to help the project remain on track and achieve its goal', 'The process of planning, estimating, budgeting, and controlling project costs', 'The process of wisely managing the amount of time allocated to a project in order to meet the scheduled delivery date and conclude all work by or before the project completion date', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '22-A-53', -1.0, 1.0);
