INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the capacity management process of IT service management, which of the following is an appropriate precaution to observe when the utilization of an online system’s capacity is monitored?', NULL, 'Focus only on the maximum value of performance data in each time interval and check deviation from the management limit.', 'Measure the performance during offline hours to avoid a decline in service level during online hours.', 'Monitor multiple measurement items such as response time and CPU utilization on a regular basis.', 'Record incidents concerning capacity and performance.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '22-A-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IT service management, which of the following is the most appropriate functional organization that provides a single point of contact and tries to rapidly restore normal service operations to users?', NULL, 'Service desk', 'Service management', 'Service provider', 'Supplier', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '22-A-58', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a checkpoint during the audit of a control for reducing the risk of system trouble regarding the application of a software patch?', NULL, 'A database administrator is appointed and master data management procedures are specified.', 'Capacity planning procedures are set out.', 'Hardware maintenance records are created and managed by system administrators', 'The system''s operation status is properly checked before commencing full-time operations.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '22-A-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is subject to system audits that evaluate and verify internal controls related to IT?', NULL, 'Methods for ensuring accuracy when the sales department inputs into and updates the database', 'The process by which the business planning department leads the creation of a mid-term business plan', 'The results of employee personnel evaluations led by the personnel department', 'The status of production equipment review conducted by the manufacturing department for the purpose of reducing defects', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '22-A-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of enterprise architecture (EA)', NULL, 'It is a technique to abstract and express business processes with the four (4) basic elements of data flow, process, file, and data sources and absorption.', 'It is a technique to analyze each business operation and information system through the four (4) systems of business, data, application, and technology, and reexamine it from the viewpoint of total optimization.', 'It is a technique to analyze or design a system by using schematic diagrams such as a class diagram, and it is developed by integrating and standardizing various methods that support an object-oriented design.', 'It is a technique to clarify the data structure and the relationship between data items by expressing the conceptual data model with entities and relationships.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '22-A-61', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a workflow system is used for business improvement, which of the following is an appropriate effect that can be expected?', NULL, 'Improved processing speed for office procedures, from document submission to approval', 'The provision of a standard protocol used for data exchange between a company and its customers', 'The provision of services such as a discount according to the amount of the customer’s purchase', 'Warehouse automation of shipping and receipt of stocked products', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '22-A-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In computerization investment planning, which of the following is an explanation of ROI as an evaluation index for investment value?', NULL, 'ROI is a measure that indicates market competitiveness in the event that a project is not implemented.', 'ROI is a measure that is calculated by dividing the profit generated through factors such as sales increase and cost reduction by the investment amount.', 'ROI is a measure that is calculated by subtracting the current value of cash outflow from the current value of cash inflow.', 'ROI is a measure that is obtained by comparing some parameters, such as the sales to investment ratio and the amount of investment per employee, with that of other companies.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '22-A-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description that corresponds to CSR procurement?', NULL, 'Choosing the product with the lowest price to minimize costs', 'Having multiple suppliers to avoid situations in which procurement is impossible, such as after a disaster', 'Indicating procurement standards that consider the environment, human rights, etc., and requesting that suppliers comply with these', 'Using EDI to purchase goods in order to perform prompt and accurate procurement', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '22-A-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the core competence?', NULL, 'Corporate activities that comply with laws, various regulations, and social norms for managing business', 'The business domain decided from the viewpoint of the market, technology, and products (or services)', 'The overall business and system optimization methods for achieving the purpose of organizational activities', 'The predominant abilities in the company’s business area, which competitors cannot imitate', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-A-65', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Companies are classified on the basis of their competitive position in the market. There are typically four types: leader, challenger, follower, and nicher. Which of the following is the most appropriate characteristic of a leader’s strategy?', NULL, 'Applying a differentiation strategy to all aspects of products, services, advertising, price and distribution channels or indirectly attacking the competitor’s weaknesses or the gaps in the competitor’s market coverage', 'Capturing a specific market that high-ranking companies do not target and concentrating management resources in order to secure and maintain predominance in the market', 'Determining the challenger company’s real ability in the market and prioritize securing stable profits over expanding the market share by doing as the leader company does', 'Proposing a new product and its usage method to consumers in order to increase the total demand while maintaining or expanding the market share', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-A-66', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the introduction stage of the product life cycle?', NULL, 'It is the stage at which companies sell products to early adopters. Companies adopt strategies to enhance product recognition.', 'It is the stage at which growth in demand slows. Companies try to maintain their market share and secure profits through various means, such as improving product quality.', 'It is the stage at which sales and profit gradually decline. Companies refrain from making additional investments and consider withdrawing from the market.', 'It is the stage at which sales increase rapidly. The market becomes active and competition intensifies because of new market participants.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-A-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of CRM?', NULL, 'Acquisition of customer loyalty and maximization of customer lifetime value', 'Ascertainment of the sales information for each product at the time of sales', 'Determination of the order quantity and order timing of material requirred for manufacturing', 'Reduction in loss of sales opportunities due to inventory shortage', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-A-68', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate description of process innovation?', NULL, 'Development of an innovative new product on the basis of an original and high technology', 'Development of innovative manufacturing procedures that improve the quality of a product', 'Outsourcing manufacturing to another company that has a semiconductor manufacturing process', 'Outsourcing manufacturing to another company that has a semiconductor manufacturing process', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-A-69', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Basic elements and examples of devices and services when the IoT is used in a factory’s equipment maintenance tasks are compiled as shown below. When a) through d) correspond to any one of A through D, which of the following corresponds to A?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-70.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS03MC5wbmciLCJpYXQiOjE3NDMxMTY5NjMsImV4cCI6MTc3NDY1Mjk2M30.92tmxFIGifgf54RmipHHjFGxW5VMbeMYTmK9SL3fJ6U', 'Abnormal value judgment tool', 'Display for work instructions', 'Temperature sensor for equipment', 'Wireless communication within the factory', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-A-70', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below shows the work procedure for MRP (Material Requirements Planning), a technique pertaining to a production management system. Which of the following is a necessary piece of information for calculating the net requirements to be inserted into A in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-A-71.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItQS03MS5wbmciLCJpYXQiOjE3NDMxMTY5NjcsImV4cCI6MTc3NDY1Mjk2N30.JIaFBWymceO501lqsTopXOy9QIuyM8flPnTMA28jUjY', 'Bill of materials (configuration and requirements of each component in the final product)', 'Inventory status (inventory amount, residual orders, in-process quantity)', 'Ordering policy (lot organization method, ordering method, safety stock)', 'Standard schedule (completion period, number of days of lead time)', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-A-71', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of an RFID system?', NULL, 'Multiple RF Tags that are within range communicate with each other, and create a mesh network.', 'RF readers/writers generate an electromagnetic field that charges the RF tags within range to allow transmission of information.', 'RF tags process unique positioning information by using multiple satellites, allowing for item tracking by longitude and latitude coordinates.', 'RF tag transmission does not provide error correcting codes but still acquires high reliability through a wired connection.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-72', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the IoT application examples, which of the following is an explanation of HEMS?', NULL, 'Connecting energy devices such as solar power generators, consumer electronic devices, and sensors, etc., to a household communication network in order to visualize the energy used and optimally control consumption', 'Fully utilizing information communication technology and environment technology in order to visualize the energy urban infrastructure uses, including public facilities such as street-lamps and the transportation system, and optimally controlling consumption', 'Measuring data such as vehicular condition, road status, etc., with the sensors installed in the vehicle and saving and analyzing the data via a network in order to support efficient driving', 'Regularly measuring vibrations, temperature, sound, etc., with the sensors installed in factory machines, analyzing the degraded condition of the machines on the basis of the collected data, and replacing parts at the appropriate time', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-73', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a case using deep learning in order to improve the performance of an in-car device?', NULL, 'An accelerometer detects the collision of the vehicle against a wall and causes the air bag to inflate, thus protecting the passenger from injury.', 'By acquiring and processing numerous images, the driver assistance system can more reliably distinguish between a pedestrian and a vehicle.', 'By installing equipment that automatically performs idling stops, the fuel efficiency improves as compared with a very experienced driver operating a vehicle.', 'The navigation system updates the software via a mobile phone line and refreshes the map.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '22-A-74', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of accountability at the executive managerial level?', NULL, 'A company has a responsibility to explain the content and performance of business activities to shareholders and other interested parties.', 'A company quantifies the cost of environmental maintenance and its effects and announces them periodically as financial information.', 'Investors and analysts must be provided with accurate information that is necessary for investment decisions in a timely manner and on an ongoing basis.', 'Rules, manuals, and verification systems are established on the basis of corporate ethics, and corporate management is performed in accordance with the relevant laws.', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '22-A-75', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following can secure employment and create employment opportunities across an entire society by shortening work hours per employee?', NULL, 'Cafeteria plan', 'Free agent system', 'Work sharing', 'Work-life balance', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '22-A-76', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Products A, B, C, and D are to be introduced to the market. The table below shows the expected profit for each product with three (3) sales forecasts (High, Medium, and Low) that are estimated to occur in accordance with the probability in the table. Which of the following is the product that is expected to make the highest profit according to the expected value principle?', NULL, 'A', 'B', 'C', 'D', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '22-A-77', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A company sells two products, A and B, and makes a profit of 40 dollars and 30 dollars per unit on them respectively. They are produced through a common production process and are sold in two different markets. The production process has a total capacity of 3,000 person-hours. Pruduct A’s production time is 3 person-hours that is three times longer than that of product B. Having surveyed the market, company officials feel that the maximum number of units of product A that can be sold is 8,000, while for product B the maximum number of units is 1,200. Subject to these limitations, products can be sold in any combination. When the linear programming model is applied, which of the following is the formulation result that obtains the production amount that maximizes the company’s total profit? Here, the number of units of products A and B are x and y, respectively.', NULL, 'Objective function  40x+30y -> to be maximized 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In financial statements, which of the following shows the company’s assets, liabilities, and net assets at a certain point in time and indicates the company’s financial situation?', NULL, 'Balance sheet', 'Statement of cash flows', 'Statement of changes in equity', 'Statement of profit or loss', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '22-A-79', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an action that is taken in order to improve the cash flow?', NULL, 'Pay the notes payable on a shorter timeline.', 'Receive payment on the notes receivable on a longer timeline.', 'Shorten the time period for collecting accounts receivable.', 'Shorten the time period for making payments on accounts payable.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '22-A-80', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the octal equivalent value of the hexadecimal number 7B5?', NULL, '735', '3665', '7551', '7561', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-01', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For a non-negative integer x, which of the following gives the remainder after division of x by 8 as a result?', NULL, 'Performing a bitwise AND operation on x and 7', 'Performing a bitwise AND operation on x and 248', 'Performing a bitwise OR operation on x and 8', 'Performing a bitwise OR operation on x and 15', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-02', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For three sets A, B and C, which of the following equalities holds?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-03.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0wMy5wbmciLCJpYXQiOjE3NDMxMTM2NDksImV4cCI6MTc3NDY0OTY0OX0.45f_0oCFeEIcgSH8Hs03W7jL6yr9Uir1MlnnosYUzX4', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-03', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An adjacency matrix is used to indicate which vertices of a directed or undirected graph are adjacent to each other. Which of the following is an appropriate matrix that represents the directed graph below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-04.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0wNC5wbmciLCJpYXQiOjE3NDMxMTM2NjEsImV4cCI6MTc3NDY0OTY2MX0.fLyrTV8yfd0F52whm8RiTb8t-H34conlet6IvDiwjs0', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-04', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When sorting an array of n elements by using a randomized version of the quicksort algorithm, where the pivot is selected randomly, which of the following shows the average case and the worst-case time complexities? Here, big-O notation, O(x), is used to denote the growth rate.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-05.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0wNS5wbmciLCJpYXQiOjE3NDMxMTM2NzEsImV4cCI6MTc3NDY0OTY3MX0.7RSFjNuY84vAeKJBLMLf6Rel44rLtiw2WVCY7ZbRkHw', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-05', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For an automaton with input and output symbols {0, 1} and a state transition diagram shown below, which of the following is the output string for the input string 0011001110? Here, S1 represents the initial state, and the label x/y on each arc indicates that if x is an input, then y is the corresponding output at the state transition.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-06.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0wNi5wbmciLCJpYXQiOjE3NDMxMTM2NzcsImV4cCI6MTc3NDY0OTY3N30.8IMQNu83CKZL6s9YlOje5tVColNrI-zXa2Fn1nEfhKs', '0001000110', '0001001110', '0010001000', '0011111110', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-06', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('After the procedure shown below has been executed in the listed order, which value will be stored in variable y? Here, the stack and queue structures are initially empty, and the four types of operations are defined as shown below.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-07.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0wNy5wbmciLCJpYXQiOjE3NDMxMTM2ODEsImV4cCI6MTc3NDY0OTY4MX0.Grt_svknYvFc31IEjlsep0mPSgrnLjpilVmSRMkjRiw', '1', '2', '3', '4', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-07', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the name for the tree depicted below? Here, the number in each node represents the key of the node.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-08.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0wOC5wbmciLCJpYXQiOjE3NDMxMTM2ODQsImV4cCI6MTc3NDY0OTY4NH0.2KALMjQ6doCjnEztHiU5xa0lCLNlu-yutxJymQxt3dk', 'Balanced tree', 'Binary search tree', 'Max heap', 'Min heap', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-08', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the function M(n) is defined as shown below, what is the value of M(97)?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-09.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0wOS5wbmciLCJpYXQiOjE3NDMxMTM2ODgsImV4cCI6MTc3NDY0OTY4OH0.PfhBperPG43OsPO2AKt2m65N7W7_1seKdhbqsxB8Ccs', '81', '86', '91', '96', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-09', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of XML?', NULL, 'An exclusive editor is required to produce XML documents.', 'It is an integration of the logical structure and document style.', 'It is based on HTML and offers more extended functions.', 'The attributes and logical structure of a document can be defined with user-defined tags.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-10', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate term for a special register that contains the address of the next instruction to be fetched?', NULL, 'Accumulator', 'Instruction register', 'Program counter', 'Status register', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-11', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In memory systems, when data is detected in the cache, it is known as a hit. When data is not detected in the cache, it is read from the main memory and is known as a miss. Which of the following is the approximate hit ratio for the specifications in the table below? Here, effective access time is calculated as the weighted average of hit time and miss time, and other overhead is ignored.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-12.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0xMi5wbmciLCJpYXQiOjE3NDMxMTM3MDAsImV4cCI6MTc3NDY0OTcwMH0.cTI8zbfkLXpFSPeNArRpixugWtQDIJucPLp9yXJCAWk', '0.25', '0.35', '0.73', '0.81', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-12', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a computer architecture where each instruction is divided into multiple stages (e.g., fetch, decode, and execute) in the processor and multiple functional units execute two or more instructions in parallel by slightly shifting execution stages of the instructions?', NULL, 'Multicore', 'Pipeline', 'RISC', 'VLIW', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-13', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a connection method that is referred to as a daisy chain?', NULL, 'A keyboard, a mouse, and a printer are connected to a USB hub, and the USB hub is connected to a PC.', 'A PC and a measuring device are connected with RS-232C, and the PC and a printer are connected by USB.', 'A PC is connected from its own Thunderbolt connection port with a cable to one of the two (2) 4K displays, each of which is equipped with two (2) Thunderbolt connection ports, and the display is connected to the other display with a cable.', 'Several network cameras and PCs are connected to a network hub.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-14', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate description of RAID 5?', NULL, 'Bit-level striping with a dedicated parity disk', 'Block-level striping with a dedicated parity disk', 'Block-level striping with distributed parity disks', 'Byte-level striping with a dedicated parity disk', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the time-chart of a system shown below, the shaded parts represent the normal working hours of the system, and the white parts represent the time when the system is not available due to failure. The numbers inside each part indicate the start and end hours of each state. Which of the following is the availability of the system?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-16.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0xNi5wbmciLCJpYXQiOjE3NDMxMTM3MDQsImV4cCI6MTc3NDY0OTcwNH0.3M9K6Xx8e3Pfjlp2Mc9AJmFJ5PBAfoLHuEjb8HKuxQQ', '0.1', '0.82', '0.9', '0.98', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-16', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In Round Robin scheduling, the CPU-time is shared among processes on the basis of the predefined time slot. There are four processes, namely P1, P2, P3, and P4, and their corresponding CPU-execution times are shown in the table below. All four (4) processes arrive at time 0, in the given order, and waiting time is the total time for which a process has to wait before it obtains its time slice for execution. Each time slot is 10 milliseconds. Which of the following is the average waiting time in milliseconds for the processes to be executed in Round Robin?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-17.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0xNy5wbmciLCJpYXQiOjE3NDMxMTM3MDksImV4cCI6MTc3NDY0OTcwOX0.QJeOHbFObh19TRT5MWpzsAxN3MpJn2BRv94d-b1CYtM', '10.75', '14.25', '15', '16.75', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-17', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There exist methods to obtain backup files for the purpose of recovering files and managing generations. Which of the following is an appropriate description for those methods or procedures?', NULL, 'A differential backup contains all files that are modified following the last full backup, while an incremental backup saves all files that are modified after the last full, differential, or incremental backup.', 'A differential backup may take longer to restore files than an incremental backup, because the most recent versions of files are spread across a larger number of backup sets.', 'A multiplexed backup is used as a mixed combination of a full backup, differential backup, and incremental backup.', 'An incremental backup tends to take longer to backup files than a differential backup because more files are copied during each backup.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-18', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A processor takes 15 seconds to run an application compiled with an old compiler. A new compiler was released. The same application compiled with the new compiler executes fewer instructions by 40%, but the average clock cycles per instruction (CPI) is increased by 10%. How many seconds does it take for the same processor to run the same application compiled with the new compiler?', NULL, '4.125', '6.6', '9.09', '9.9', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-19', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of an actuator?', NULL, 'It amplifies weak electrical signals sent from microphones, sensors, and so on.', 'It compares a given target value and a controlled value obtained from a sensor and outputs an operation amount so that the controlled value is matched with the target value.', 'It converts the power from an energy source into rotation, translational motion, or other movements based on the control signals.', 'It detects position, angle, velocity, acceleration, force, temperature, and so on, and converts them into electric information.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-20', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a logical expression that is equivalent to the logic circuit shown below?', NULL, 'A AND B', 'A AND ( A OR B)', 'A OR B', 'B AND (A OR B)', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-O-21', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A device, which operates using a 100V household power supply and through which a current of 10 A flows during operation, is operated from 0 minutes to 120 minutes as shown in the figure below. How much electrical energy, in watt-hour, is consumed during this time? Here, the value of the voltage and current is the effective value, no current flows when the device stops, and the power factor is 1.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-21.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0yMS5wbmciLCJpYXQiOjE3NDMxMTM3MTgsImV4cCI6MTc3NDY0OTcxOH0.lnm3iOU2PSAL2oDTh_Zbdl0mP7ewNYlJ218c65gVug0', '1,000', '1,200', '1,500', '2,000', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-O-22', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to ISO 9241-11: 2018, which of the following is defined as the “extent to which a system, product, or service can be used by specified users to achieve specified goals with effectiveness, efficiency, and satisfaction in a specified context of use”?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0yMi5wbmciLCJpYXQiOjE3NDMxMTM3MjEsImV4cCI6MTc3NDY0OTcyMX0.v9HzmIeNkKjvtaiaw3IYX-_7GsAgamxXDKgkmrapERI', 'Accessibility', 'Adaptability', 'Availability', 'Usability', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-23', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of clipping in 3D graphics processing?', NULL, 'It is a process that applies shading to the surface of an object for a more 3D appearance.', 'It is a process that defines a window within the image display area, removes the area outside the window, and cuts out the section visible within the window.', 'It is a process that is performed in the last phase of CG video production and visualizes object data so that it can be rendered on the screen.', 'It is a process to hide the jaggies that occur near the edge of a shape because of the limited number of pixels on the screen.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-24', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the relationships between continent and country, and between country and city are shown in the class diagram below, which of the following is an appropriate combination of multiplicities that are to be inserted into blank A through blank D? Here, there are no cross continental countries. Each continent has at least one country, and each country has at least one city.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0yMi5wbmciLCJpYXQiOjE3NDMxMTM3MjEsImV4cCI6MTc3NDY0OTcyMX0.v9HzmIeNkKjvtaiaw3IYX-_7GsAgamxXDKgkmrapERI', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-O-25', -1.0, 1.0);
