INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of an E-R diagram?', NULL, 'A relationship is expressed by describing the related entity name in the entity type.', 'The relationship between entity types is expressed by an arrow from the referencing side in the direction of the referenced side.', 'There are no attributes in the entity type, but the relationship type has attributes', 'There are several kinds of relationships between entity types such as one-to-many or many-to-many.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-27', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the main purpose of transaction support in a database management system?', NULL, 'To ensure that either all the updates corresponding to a given transaction are made or none of them are made', 'To ensure that only authorized users can access the database', 'To help users update data by providing a graphical user interface', 'To provide an accessible catalog in which descriptions of data items are stored', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-28', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of distributed databases?', NULL, 'Access to a database server is shared among a globally distributed userbase so that everyone can access the database.', 'It is a database that is distributed to all interested researchers and other users worldwide so that everyone can benefit.', 'It is a NoSQL database instead of a Relational Database Management System (RDBMS).', 'It stores different parts of a database in different locations, and its processing is distributed across those parts.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-29', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the OSI basic reference model, which of the following is a network device that operates at the network layer?', NULL, 'Access point', 'Bridge', 'Repeater', 'Router', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-30', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a mechanism that enables multiple terminals to have private addresses different from each other to connect to the Internet by sharing a single global IP address?', NULL, 'DHCP', 'DNS', 'NAPT', 'RADIUS', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-31', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a data link layer function that enables a receiver to control the amount of data a sender transmits?', NULL, 'Congestion control', 'Error control', 'Flow control', 'Media access control', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-32', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In TCP/IP, which of the following is an application layer protocol that enables a server to automatically configure its clients with network information such as IP addresses, the subnet mask, and the default gateway address?', NULL, 'ARP', 'DHCP', 'DNS', 'NSLOOKUP', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-33', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of Software-Defined Networking (SDN) that uses OpenFlow?', NULL, 'It is a network technology that logically separates data forwarding and network control, and it is implemented with a combination of network devices specialized for data forwarding function, and a network control software.', 'It is a software technology for business operation analysis and visualization that uses data flow diagrams and activity diagrams to discover problems in business processes and make improvements.', 'It is an Internet of Things (IoT) technology that uses RFID, and it is a software architecture that optimizes distribution networks.', 'It is an optimum deployment method for servers on a network that was developed to efficiently stream a range of content over the Internet.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-34', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a Trojan horse?', NULL, 'A brute force attack software tool', 'A malicious computer program that presents itself as a legitimate one', 'A malicious user that steals private information from a system', 'A software tool to decrypt an encrypted password', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following properties for information security defined in ISO/IEC 27000:2018 refers to a guarantee that the message data received is the same as the message data sent?', NULL, 'Availability', 'Confidentiality', 'Integrity', 'Non-repudiation', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-36', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of ransomware?', NULL, 'A range of different types of software including adware, spyware, and freeware', 'Malicious software blocking access to a victimized computer and demanding money to unblock it', 'Software that assigns randomized MAC addresses to PCs to ensure user privacy on the Internet', 'Software that generates random numbers needed by computer security application software', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A typical example of security threats is information leakage when a sender sends data containing important information to a receiver. Which of the following is the most appropriate measure to prevent information leakage?', NULL, 'The data is encrypted with a private key before being sent to the receiver via email. In a separate email, the private key is sent to the receiver so that the receiver can decrypt the data.', 'The data is password-locked, and it is attached in an email that includes the password in the text part of the email. Before the email is sent, the receiver address is checked to make sure that the email is sent to the correct address.', 'The receiver creates a pair of public/private keys and sends the public key to the sender. The data is encrypted with the public key and sent to the receiver via email. The receiver then decrypts the data with the private key.', 'The sender compresses the data on a USB memory as much as possible before giving the USB memory to the receiver so that the receiver can utilize the rest of the memory space effectively.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-38', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a type of malware that embeds itself within a program and inserts its copy into other programs?', NULL, 'Backdoor', 'Trojan Horse', 'Virus', 'Worm', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-39', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to ISO/IEC 27000:2018 (Information security management systems - Overview and vocabulary), which of the following is the definition of “level of risk”?', NULL, 'Magnitude of a risk expressed in terms of the combination of consequences and their likelihood', 'Terms of reference for evaluating the significance of a risk', 'The priority order assigned to the risks to be handled', 'Weakness of an asset or control that can be exploited by threats', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is dynamic analysis of malware?', NULL, 'Malware is identified by calculating the hash value of the subject for analysis and cross checking it against a list of known malware hash values that are registered in an online database.', 'On the basis of the file extensions and content of file headers on a hard disk, malicious program files with false extensions are detected.', 'The subject for analysis is extracted from communication data on a network and reverse compiled, and the functions of the subject for analysis are investigated from the code obtained.', 'The subject for analysis is run in a sandbox, and its behavior and external communication are observed.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-41', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following technologies is the most suitable to divide the whole company network into networks by department?', NULL, 'DMZ (DeMilitarized Zone)', 'NAT (Network Address Translation)', 'VLAN (Virtual Local Area Network)', 'VPN (Virtual Private Network)', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-42', -1.0, 1.0);
