INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('To provide a guarantee to its online customers that all credit card information is protected when transferred between their PC and the web service over public networks, which of the following technologies should be used?', NULL, 'S/MIME', 'SSH', 'TLS', 'VPN', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following UML diagrams is used to represent the user interactions with the system and the functions of the system?', NULL, 'Activity diagram', 'Class diagram', 'Sequence diagram', 'Use case diagram', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-O-45', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of an acceptance test?', NULL, 'It is conducted by developers to verify response time and other performance items.', 'It is conducted by testers to ensure that the interfaces and linkages between different software parts work properly.', 'It is conducted by the project manager to verify whether users’ functional requirements are met or not.', 'It is conducted by users to confirm that the software is complete and meets the business needs that prompted the software to be developed.', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-O-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the development process, which of the following is an activity that should be performed in software architectural design?', NULL, 'Analyzing the requirements in incremental steps by arranging them in the form of a chart', 'Analyzing the requirements in incremental steps by arranging them in the form of a chart', 'Obtaining the opinion of the customer and deciding the specifications', 'Transforming the requirements for the software into a design that describes its top-level structure and identifies the software components', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-O-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning test data for black box testing?', NULL, 'Test data is created based on branch coverage.', 'Test data is created based on condition coverage.', 'Test data is created based on external specifications.', 'Test data is created based on program structures.', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-O-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an agile software development project, when can the customer review the first piece of working software?', NULL, 'After the completion of the first epic', 'After the completion of the first few releases', 'After the completion of the first iteration', 'After the completion of the whole project', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-O-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the Capability Maturity Model Integration, which of the following is the final and highest level of maturity?', NULL, 'Auditable', 'Custom', 'Optimizing', 'Quantitatively Managemd', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-O-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is one of the major responsibilities of a project manager?', NULL, 'Coding programs and debugging errors', 'Evaluating the quality of project deliverables', 'Organizing project members to achieve a planned result within a budget and schedule', 'Providing the user requirements at the beginning of the project', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '21-O-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A project is planned to complete in 12 months and the budget for the completion of the project is $100,000. After six months, it is found that $60,000 was spent, but only 40% of the work has been completed. If the Cost Performance Index (CPI) is not changed, what is the estimated amount (in dollars) required to complete the remaining tasks of the project?', NULL, '40,000', '60,000', '90,000', '150,000', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '21-O-52', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In project time management, which of the following is the amount of time that the start of a successor activity requires to be delayed after the finish of a predecessor activity?', NULL, 'Free float', 'Lag', 'Lead', 'Total float', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '21-O-53', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The activities and nodes of a project are shown in the arrow diagram below. Which of the following is the effect of extending the duration of activity C by 3 days?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-54.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy01NC5wbmciLCJpYXQiOjE3NDMxMTM3NjAsImV4cCI6MTc3NDY0OTc2MH0.kGI8Y-ZoSMDEpPm9aJsOPW5NfMtp6maQ-InXQy2rOvM', 'The project duration is not affected', 'Ther project duration is extended by 1 day', 'The project duration is extended by 2 days', 'The project duration is extended by 3 days.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '21-O-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following corresponds to benchmarking in process improvement of service management?', NULL, 'The availability, reliability, and performance are measured at the service level, and a report is sent to the customers.', 'The current status of IT service management is analyzed from the viewpoint of strengths, weaknesses, opportunities, and threats.', 'The performance of IT services is measured from the viewpoint of finance, customers, internal processes, and learning and growth, and strategic activities are supported.', 'The service quality and performance level are evaluated in comparison with the best practices within and outside the industry.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-O-55', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate description for a system migration plan?', NULL, 'A system migration plan must describe the decision criteria for restoring the old system in case the migration fails.', 'Operating the new system and the old system in parallel reduces the cost of migration.', 'Sharing a part of the environment between the new system and the old system makes it easier to verify the migration status.', 'The greater the amount of data to be migrated, the more appropriate it would be to migrate the data in a single batch immediately before the system is switched.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-O-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For servers, the total cost of ownership (TCO) is calculated over a period of 5 years. The purchase price of the servers is $120,500 and the other annual costs are listed as below. What is the TCO of the servers (in dollars)?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-57.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy01Ny5wbmciLCJpYXQiOjE3NDMxMTM3NjQsImV4cCI6MTc3NDY0OTc2NH0.OJJWOBCPPK6SfKdn78OMDiJmnxtF6sO6RgYENr709os', '28,100', '120,500', '140,500', '622,500', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-O-57', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the event of a disk failure, which of the following is a method for recovering a database by restoring a full backup data onto a disk from a tape, and then reflecting, from logs, post update copies after the full backup was taken?', NULL, 'Checkpoint restart', 'Reboot', 'Roll forward', 'Rollback', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate point to be checked in the audit of a system test?', NULL, 'The test cases were created comprehensively.', 'The test plan was approved only by the responsible person on the user’s side.', 'The test was performed in an environment where the actual business operations are performed.', 'The test was performed only by the person in charge on the user’s side.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-O-59', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The director requested a system auditor to audit the operating status of an accounting system that was developed by the information systems department and is operated by the accounting department. Which of the following is the most appropriate description concerning the system auditor for this audit?', NULL, 'The system auditor must be a certified public accountant because the accounting system must conform to the various standards of business accounting.', 'The system auditor must be a person who belongs to neither the information systems department nor the accounting department to guarantee independence.', 'The system auditor must report directly to the accounting department manager because the accounting system handles highly confidential information.', 'The system auditor must report directly to the information systems department manager to perform system audits efficiently.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate feasibility evaluation when checking whether the lifetime benefits of the proposed information system is greater than its lifetime costs?', NULL, 'Economic feasibility', 'Operational feasibility', 'Scheduling feasibility', 'Technical feasibility', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '21-O-61', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an evaluation of an IT investment, a preliminary evaluation, an interim evaluation, and a posteriori evaluation are conducted in accordance with the planning, execution, and completion of individual projects. Which of the following is a description of the preliminary evaluation?', NULL, 'A variance between the plan and results as well as its cause are analyzed in detail, and it is determined whether a change is required in the investment amount or the effect goal.', 'An effect goal is set on the basis of the investment purpose, and the information that is required to make a decision on whether it is possible to execute is provided to higher level management.', 'Milestones when the investment effect should be attained and the data collection method that is required for the evaluation are planned in advance, and an evaluation is made at the times of those milestones.', 'The achievement status of the effect goal that was set in advance is evaluated, and improvement measures for achieving the objective is considered when required.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '21-O-62', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of BPO?', NULL, 'It refers to a company not having its own server and operating a system by renting a part of the processing capability or the storage capacity of a server that is owned by a communication service provider.', 'It refers to a company not having its own software and using functions of software that an external specialized vendor provides via a network.', 'It refers to the outsourcing of a whole business process of a specific department of the company, such as the administration department or the call center, together with the operation of a business system to an external specialized vendor.', 'It refers to utilizing employees from a staffing company with lower personnel expenditures than those of the company to reduce the cost of software development.', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '21-O-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In computerization investment, which of the following is a technique that is used to create categories on the basis of the similarities of risks and investment values and perform optimum resource allocation?', NULL, '3C analysis', 'Benchmarking', 'Enterprise architecture', 'IT portfolio', 'd', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '21-O-64', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an activity that is performed when non-functional requirements are defined?', NULL, 'Clarifying the flows of information (i.e., data) between the functions that constitute business operations', 'Creating technical requirements of development standard according to the programming language used in system development', 'Defining the scope to be implemented as system functions', 'Specifying the interface for exchanging information with other systems', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-O-65', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique that is used to identify and evaluate the internal and external factors that are helpful or harmful to the objectives of business organizations or projects?', NULL, 'Five forces analysis', 'PPM analysis', 'SWOT analysis', 'Value chain analysis', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-O-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The sales prices of products are decided according to different sales price setting methods. Which of the following approaches sets a high sales price by using the consumer psychology that high quality equals to high price?', NULL, 'Cost plus pricing', 'Differential pricing', 'Marketing price following pricing', 'Prestige pricing', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-O-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Company T sells three (3) products: A, B, and C. Currently, products A, B, and C have 10,000, 20,000, and 80,000 purchasers every month, respectively. There is a plan to change the product line and sell four (4) new products, P, Q, R, and S, from next year. Accordingly, a trial calculation was made on the proportion of existing customers that will purchase the new products and the number of new customers. Which of the following is an appropriate conclusion from the trial calculation? Here, numerical values up to one (1) decimal point in each line of the table below represent the proportion of people who will change to the new product from the corresponding old product.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-68.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy02OC5wbmciLCJpYXQiOjE3NDMxMTM3NjgsImV4cCI6MTc3NDY0OTc2OH0.L-nJlPeG_ekxJITMcZBvkq2MoF12gM9kEyO1IlmIDTM', 'Among the purchasers of product A, 1,000 people are estimated to purchase the new product Q.', 'Of the prospective purchasers of the new product P, 50% are estimated to be purchasers of product A.', 'The number of new customers of the new product S are estimated to be fewer than the number of people who will purchase the new product S among the purchasers of product C.', 'The purchasers of product B are estimated to purchase any one (1) of the new products P, Q, R, and S.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-O-68', 0.0, 1.0);
