INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of Initial Coin Offering (ICO)?', NULL, 'A crowd-funding method in which backers contribute money toward an idea or a startup and get rewards like physical products', 'A fundraising method that is mainly used by a financially stable company which wants to expand and develop to the public', 'A popular fundraising method that is used primarily by a startup, normally through utilizing cryptocurrency', 'A process of offering shares of a private corporation to the public in a new stock issuance', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-O-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate example of utilizing machine learning at a production site?', NULL, 'Instead of programming the working method for the production robot in the factory, the robot itself learns, thus improving the efficiency of work.', 'The causes for the occurrence of defects in a factory are decomposed and arranged in a tree shape so that analysts can statistically look for the cause and solution.', 'The production equipment in a factory is connected through high-speed communication so that the host computer can be controlled in real time.', 'The productivity of employees in the factory improves each time the cumulative production volume doubles, and the unit cost reduces at a fixed percentage.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-O-74', -1.0, 1.0);
