INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of USB 3.0?', NULL, 'It is a serial interface that adopts isochronous transmission that is suitable for audio or video, and has a broadcast transmission mode.', 'It is a serial interface that has a data transmission mode of 5 Gbit/s that is called super speed.', 'It is a serialized ATA specification that connects a PC to a peripheral device.', 'It is an interface that uses four (4) pairs of signal lines transmitting two (2) bits of information in one (1) clock and has a maximum throughput of 1 Gbit/s.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-A-14', -2.0, 1.0);
