INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the page replacement methods in virtual memory management, which of the following is the LRU control method?', NULL, 'Each page is managed by appending a reference flag and a change flag, and pages without reference or change are replaced with higher priority.', 'One of the pages in main memory is randomly chosen with the same probability and then replaced.', 'The page that has been stored in the main memory for the longest time is replaced.', 'The page that has not been referenced the longest time is replaced.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-A-18', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate function of a linker?', NULL, 'To load a load module to the main memory ahead of execution', 'To monitor the execution of a program and to record the execution of results for each step', 'To perform a resolution of cross references and to create one (1) load module from multiple object modules', 'To register a created program in a library', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-A-19', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate explanation of sequence control for controlling industrial devices?', NULL, 'It is based on fuzziness, such as “slightly more” or “slightly less.”', 'It is resistant to unexpected disturbances because it continuously detects the amount of control and reflects it on the control.', 'It steps through each phase of control one after another according to a predefined order or set of conditions.', 'It takes corrective action in advance by assuming the occurrence of disturbances when disturbances can be expected.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-20', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The half adder in the diagram below adds two (2) single-digit binary numbers, x and y, and produces z (the first digit of the sum) and c (the carry bit) as outputs. Which of the following is the appropriate combination of gate devices A and B?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-21.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS0yMS5wbmciLCJpYXQiOjE3NDMxMTQyMTIsImV4cCI6MTc3NDY1MDIxMn0.cIvLR7khzuhimkvoLL5Pjh2_YGxRFK-49puyEnrdSyE', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-A-21', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is not an implementation of the function F = A • B + C • D? Here, “•” represents the logic AND operation, and “+” represents the logic OR operation in the expression.', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-22-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS0yMi1BLnBuZyIsImlhdCI6MTc0MzExNDIxOSwiZXhwIjoxNzc0NjUwMjE5fQ.Df7mYjmT98OoQMSuYliq2rCEKG9l7otz0ppqNzWXoWw', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-22-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS0yMi1CLnBuZyIsImlhdCI6MTc0MzExNDIyMywiZXhwIjoxNzc0NjUwMjIzfQ.FktqDtN9QXhch_YUOI95s8lRIVQE1ZXV-4aGCKDbSoQ', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-22-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS0yMi1DLnBuZyIsImlhdCI6MTc0MzExNDIyNiwiZXhwIjoxNzc0NjUwMjI2fQ.JGAQOsRIjcia5Wvhdn95NCVXg_OxlryeNG7rUJhyuc0', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-22-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS0yMi1ELnBuZyIsImlhdCI6MTc0MzExNDIzMCwiZXhwIjoxNzc0NjUwMjMwfQ.8qIi-VEZ4iAqzll5oBDixig4e3Py2j-N90Cepq9LCLY', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-A-22', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate purpose of check digit?', NULL, 'To detect an error that an alphabet or a symbol is contained in a numeric item field', 'To detect an error that the number of digits of an entered code is incorrect', 'To detect an error that the value of an entered code is incorrect', 'To detect an error that the value of an entered data is not within a specified range', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-23', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following explains a drawing software?', NULL, 'It can create a picture on a screen using the mouse as a brush that can be saved to a bitmap image file.', 'It can create a scenario-based content by editing and arranging several materials, such as text, images, video, and sound.', 'It can create a simple movie from a series of still images by gradually changing the differences among images.', 'It can create vector graphics composed of lines and curves defined mathematically with geometric characteristics that can then be transformed or combined.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-24', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of a relational database?', NULL, 'Data is represented as a table, and the tables are linked to one another using the column values of these tables.', 'Each attribute is represented as a pair of the attribute value and the storage location of the record having that value and used as an index.', 'The relationship among records is represented by a data structure using links that can represent both tree and network structures.', 'The relationship among records is represented by a data structure using pointers that are limited to representing a tree structure.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-25', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is performed periodically to prevent a decline in the access efficiency of a database?', NULL, 'Backup', 'Database dump', 'Reorganization', 'Rollback', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-26', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A student’s ID, name, and class ID are recorded in the Student table. Which of the following SQL returns records of all students whose names start with A?', NULL, 'SELECT * FROM Student WHERE name LIKE ’%A’;', 'SELECT * FROM Student WHERE name LIKE ‘%A_’;', 'SELECT * FROM Student WHERE name LIKE ‘A_’;', 'SELECT * FROM Student WHERE name LIKE ‘A%’;', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-27', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the search processes for the “Sales” table, which of the following is appropriate to set a hash index rather than a B+ tree index? Here, the column in which the index is set is  shown inside <>.
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate explanation of the key value store that is used in the processing of big data?', NULL, 'It is represented by a two-dimensional table with rows and columns based on the set theory.', 'It represents the relationship among nodes with the three (3) elements, i.e., “node,” “relationship,” and “property.”', 'It saves the desired data together with a value that enables this data to be uniquely identified as a pair.', 'The data for one (1) case is called a “document,” and the data structure of each document is unrestricted and can be changed whenever data is added.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-29', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the response time when a client and server at different locations communicate under the conditions below? Here, the response time is in seconds and starts from the moment the client sends a message until a response is received from the server. 1 MB is 106 bytes. The propagation delay between the client and server can be ignored.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-30.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS0zMC5wbmciLCJpYXQiOjE3NDMxMTQyMzksImV4cCI6MTc3NDY1MDIzOX0.6tVGFct5B3GFRAOZ3zE2aL4k4UryaKB3Z3Ht9sBhVb4', '1.4', '3.8', '5.0', '5.8', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-30', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate transmission operation of a node connected to a CSMA/CD LAN?', NULL, 'All nodes are connected in a ring topology, where a special frame is circulated around to control transmission rights. Only the node that has the special frame can transmit data.', 'Each node is logically ordered, a transmission right is passed along in order, and only the node that has received the right can transmit data.', 'Each node waits for the medium to be idle before transmitting data. When collision occurs, it waits for a random backoff time before retransmission.', 'Only the node that has a time slot assigned can transmit data.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-31', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a TCP/IP environment, which of the following is a protocol for synchronizing the clocks of multiple computers with that of a time server?', NULL, 'FTP', 'NNTP', 'NTP', 'RTP', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-32', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of DHCP?', NULL, 'It is a protocol for accessing a directory service.', 'It is a protocol for automatically assigning an IP address.', 'It is a protocol for converting a private IP address to a global IP address.', 'It is a protocol for forwarding an e-mail.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-33', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is classified as a web beacon?', NULL, 'A potential error of an application program used for a website', 'A technique to collect user information, such as access trends, by embedding a small image in a web page', 'A virus that is downloaded from a website that deletes image files on a PC', 'An abusive method of using a malicious script that is harmful to both client PC and web server', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-34', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When risk treatment is classified as risk avoidance, risk reduction, risk acceptance, and risk sharing, which of the following risk treatments is risk avoidance?', NULL, 'Applying appropriate controls to lower a risk', 'Discontinuing some operations that have a risk', 'Knowingly and objectively not taking any action on a risk', 'Transferring a risk to other parties', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-35', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is installed into an in-house network or server by an intruder to enter through an access path other than the normal path?', NULL, 'Backdoor', 'Forensic', 'Strict routing', 'Thin client agent', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Biometric authentication includes a verification method that extracts physical characteristics and another verification method that extracts behavioral characteristics. Which of the following is the method that uses behavioral characteristics?', NULL, 'Performing authentication by extracting characteristics from pen speed and pressure when a signature is provided', 'Performing authentication by extracting characteristics from the bifurcation angle of the bifurcation point of a blood vessel or from the distance between adjacent bifurcation points', 'Performing authentication by extracting the characteristic point called minutia from the pattern formed by ridges', 'Performing authentication by extracting the characteristics of chaotic wrinkles in the eye from the pupil to the outside', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-37', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an encryption method that can be used for encrypting data managed in a database using the same key for encryption and decryption?', NULL, 'AES', 'PKI', 'RSA', 'SHA-256', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A given application only has the functions of retrieving and displaying user information from a database that stores such information. Considering information security management, which of the following is the appropriate database access right assigned to an account that the application uses when it accesses the database? The names and scopes of rights are listed below. 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A cybersecurity incident response plan is defined as a set of instructions to aid the cybersecurity team to detect, respond to, and recover from cybersecurity incidents. The cybersecurity incident response plan resolves issues, such as cybercrime, data loss, and service outages that threaten daily work. Which of the following is part of the cybersecurity incident response plan?', NULL, 'Attacking systems with scripts', 'Containment', 'Social engineering activities', 'Stealing user credentials', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Between a client and web server, which of the following is used for inspecting the data that is sent from the client to the web server and blocking attacks, such as SQL injections?', NULL, 'Cluster configuration', 'Load balancing function', 'SSL-VPN function', 'WAF', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of SSH?', NULL, 'It cannot use public key pairs, and it uses a password for authentication.', 'It helps in securely loading web site pages over HTTPS.', 'It provides a secure channel for server maintenance over a public network.', 'Its use is required in the Intranet.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-42', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning Sender Policy Framework (SPF) for email communication?', NULL, 'It is a policy of the public relations department to designate a specific person to send emails.', 'It is an email sent from a spoofed email address without authorization.', 'It matches the sender mail server IP address with the information from the domain server and accepts or rejects email.', 'It sends an email to the address of a specific person instead of sending them to multiple email addresses.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-43', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of OP25B for email communication?', NULL, 'Blocking communication to port 25 to reduce mass-scale delivery of spam or junk emails', 'Blocking emails that are sent to more than 25 recipients at once due to organizational policy', 'Blocking Simple Mail Transfer Protocol (SMTP) communication except those sent to port 25', 'Blocklisting email addresses that send spams by monitoring email communication to port 25', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the UML class diagram that shows a generalization relation?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-45-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS00NS1BLnBuZyIsImlhdCI6MTc0MzExNDI1MiwiZXhwIjoxNzc0NjUwMjUyfQ.9z64ImdetdoKERL1Unfi9Y0F-zzzzfDZu_o9yvvGXOQ', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-45-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS00NS1CLnBuZyIsImlhdCI6MTc0MzExNDI1NiwiZXhwIjoxNzc0NjUwMjU2fQ.YxHPhqc1z4Ft-kw35i6Sl9IfcSeOKWfzOJ-TQ1n_jSo', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-45-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS00NS1DLnBuZyIsImlhdCI6MTc0MzExNDI2MCwiZXhwIjoxNzc0NjUwMjYwfQ.G90fUZKGUlmha1o9vJKjuoDCWfSm1ulqXI0dX89ubnU', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-45-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS00NS1ELnBuZyIsImlhdCI6MTc0MzExNDI2NCwiZXhwIjoxNzc0NjUwMjY0fQ.122cwDieGtumTW35CyS5BHuPrxcRnMSKo377WEg1mWY', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-A-45', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below shows an example of a DFD that uses one of the DFD notations and represents a flow of data in a system. Texts in the figure are not shown. Which of the following is represented by the circle “○” in the DFD notation used in the example?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-A-46.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtQS00Ni5wbmciLCJpYXQiOjE3NDMxMTA3MDQsImV4cCI6MTc3NDY0NjcwNH0.dD6ex0yy146B69_UlIjPganeZxH7G2nlhg7NIS7qKos', 'Activity', 'Data flow', 'Data store', 'Process', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-A-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate relationship between classes and instances in object orientation?', NULL, 'An instance defines the specifications of a class.', 'An instance is created based on the definition of a class.', 'Multiple classes correspond to a single instance.', 'Only one (1) instance exists for a single class.', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-A-47', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the weakest module coupling?', NULL, 'To implement as many functions as possible with a single module', 'To pass arguments that control another module’s logic when the module is called', 'To pass only required data items as arguments between two (2) modules', 'To use a global area to share data items with other modules', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-A-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following tests verifies the interfaces between two (2) modules or subsystems?', NULL, 'Acceptance test', 'Integration test', 'Operational test', 'Unit test', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-A-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of a comprehensive patent cross license?', NULL, 'An agreement to share the necessary costs for patent registration is concluded.', 'The source code is published free of charge on the Internet or other places, and anyone may improve and redistribute the software.', 'The use of patent rights is mutually licensed among companies in the specified fields of technologies or products.', 'To ensure that a company’s patent rights are not violated, the right to stop a counterpart’s manufacturing is exercised.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '21-A-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Based on the definition of project management process groups in ISO 21500, which of the following is an activity that is to be implemented in the planning process group among the project management processes?', NULL, 'To define scope', 'To develop a project header', 'To identify stakeholders', 'To perform quality assurance', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '21-A-51', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In project time management, which of the following descriptions is appropriate for “slack time”?', NULL, 'It is the amount of time between the earliest start time and earliest finish time of an activity or between the latest start time and latest finish time of an activity.', 'It is the amount of time for which a non-critical path activity can be deferred without delaying the project.', 'It is the amount of time that an activity can be deferred without delaying the earliest start time of any succeeding activity or violating a schedule constraint.', 'It is the amount of time that an activity can be delayed past its latest start time or latest finish time.', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '21-A-52', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the duration for painting a house is estimated, which of the following is an appropriate technique that estimates the duration on the basis of the actual duration of a similar painting job in the past of the same house or other historical data from similar work?', NULL, 'Analogous estimate', 'Parametric estimate', 'Reserve analysis', 'Three-point estimate', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '21-A-53', -2.0, 1.0);
