INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An IT service is provided under the conditions that are described below. What is the maximum downtime in hours that can satisfy the SLA during a service time period of one (1) month? Here, the number of business days in one (1) month is 30, and no maintenance or other scheduled downtime of the service is performed during the service time period. 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the main purpose of a migration test for a system?', NULL, 'To confirm that a new system possesses all of the required functions', 'To confirm that sufficient performance can be derived from the new system using a copy of the actual data from the existing system', 'To confirm the compatibility of the interface between a program of another existing system and a newly developed program', 'To confirm the switch procedure from the existing system to the new system and the problems that the switch can cause from the perspective of reliability and efficiency', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-A-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IT service management, which of the following is handled by incident management?', NULL, 'Inquiry regarding the function or usage of the IT service or system', 'Long delay in an application response', 'Request for providing the IT service to a new business site', 'Request for training of recruits on the IT service', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-A-57', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the PDCA methodology is applied to a service management system, which of the following corresponds to Act?', NULL, 'Establishing, documenting, and agreeing the service management system', 'Implementing and operating the service management system for the design, transition, delivery, and improvement of services', 'Monitoring, measuring, and reviewing the service management system and services against the policies, objectives, plans, and service requirements, and reporting the results', 'Taking actions to continually improve the performance of the service management system and services', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-A-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the system design stage, which of the following is the point to be checked during the audit of control for reducing the risk of non-fulfillment of user requirements?', NULL, 'All programming should be performed in accordance with the specified standards and conventions.', 'The program specifications should be created on the basis of the system design documents.', 'The test plan should be created on the basis of the system test requirements and must also be approved by the responsible person of the system operations department.', 'The user department should participate in the review of system design.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-A-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When IT controls are classified into preventive controls and detective controls, which of the following is to be classified as a detective control?', NULL, 'A data entry manual is created, and the persons in charge of data entry are trained.', 'A data entry screen is designed so that operation errors are unlikely to occur.', 'Access rights are assigned only to the person in charge of data entry.', 'An output list resulting from data entry is cross-checked with the input form.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '21-A-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of CRM?', NULL, 'It is a business approach for significantly improving the efficiency of the entire supply chain through the real time exchange of information regarding production, inventory, procurement, sales, distribution, etc.', 'It is a concept to optimize customer loyalty by sharing information throughout all customer channels within a company and improving customer satisfaction by raising the level of service.', 'It is a method for improving business efficiency by planning and managing business resources throughout the company effectively and comprehensively.', 'It is a method for wholesale dealers or manufacturers to increase business transactions with retail stores by supporting their business activities, and increasing their sales and profits.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-A-61', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of BPO?', NULL, 'A company outsources all work processes of a specific department, such as management section or call center and its work system operation, to an external provider.', 'A company reduces software development costs by using employees of a temporary employment agency with lower personnel expenses.', 'A company rents a portion of the processing and storage capacities of servers owned by a telecommunications service provider and operates systems without owning its own servers.', 'A company uses software functions provided by an external provider over a network without owning the software.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-A-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of chatbot?', NULL, 'A software that uses image processing techniques and is employed for applications to describe image details to a human', 'A software that uses natural language processing techniques and is employed for applications to communicate with a human', 'A software that uses signal processing techniques and is employed for applications to convert a human’s voice into texts', 'A software that uses speech processing techniques and is employed for applications to generate subtitles automatically for a human to read while watching videos', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique that performs the optimum resource allocation for computerization investment in each category classified by the similarities of risks and investment value?', NULL, '3C analysis', 'Benchmarking', 'Enterprise architecture', 'IT portfolio', 'd', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '21-A-64', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the verification of stakeholder requirements, which of the following indicates the ability to keep track of the process until the implementation of a change request?', NULL, 'Interoperability', 'Maintainability', 'Traceability', 'Usability', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '21-A-65', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of core competence?', NULL, 'The basic mindset and action guidelines behind management activities', 'The business opportunities and threats in the environment around a company', 'The management resources that form the source of competitive advantage over other companies', 'The objectives to be achieved through the execution of a business strategy', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-A-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a product life cycle, which of the following is a stage where the withdrawal of some companies is observed when the demand peaks, and decision-making is necessary to determine whether it is possible to gain a strong foothold?', NULL, 'Decline stage', 'Growth stage', 'Introduction stage', 'Maturity stage', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-A-67', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When an IT vendor uses a “Balanced Scorecard” to promote a solution business, which of the following is an example of the learning and growth KPI goal? Here, “solution” means “to support a customer through information technology and professional services that are offered by experts so that the customer can achieve its management objectives.”', NULL, 'To increase the number of customer proposals by a factor of 1.5 over that of the previous year by preparing an environment for reusing proposals to augment the number of registered solution cases', 'To increase the sales volume in the consulting business for information strategy planning and system planning for it to account for 15% or more of the total sales of the company', 'To set an average satisfaction score of 3.5 out of five (5) or more in a satisfaction survey of customers for whom a service is offered', 'To train 30 employees as IT professionals in order to focus on the consulting services in the information strategy', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-A-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of concurrent engineering?', NULL, 'A new product development technique that sequentially executes processes, such as product design, manufacturing, and sales activities', 'A technique that analyzes a target system and clarifies its specifications', 'A technique that executes processes, such as product design and production planning, in parallel during the new product development procedure', 'A technique that tries to figure out the optimal combination of functions and cost and to improve value through systematic procedures', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-A-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate description of telemedicine?', NULL, 'Caring for patients by using computer technologies when the physician and patients are physically together in a hospital', 'Caring for patients by using electronic communication technologies when the physician and patients are not in the same location', 'Caring for patients by using electronic communication technologies when the physician and patients are physically together at the patients’ house', 'Caring for patients without using computer technologies when the physician and patients are physically together at the physician’s clinic', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '21-A-70', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below shows the relationships among the components of product A, and the numbers in parentheses indicate the quantity of components necessary to produce one unit of the upper-level product or component. When 10 units of product A are produced, how many units of component C must be ordered? Here, there are presently five units of component C in the inventory.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-71.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS03MS5wbmciLCJpYXQiOjE3NDMxMTQzMDcsImV4cCI6MTc3NDY1MDMwN30.cV-J8xbxICqnF64IT42d8QaKhIUyZFZt5Qh2x37iN2o', '15', '20', '25', '30', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '21-A-71', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below shows the transaction model of an escrow service that is used in an Internet auction site or other similar transactions. Which of the following is the action that corresponds to (5) in this figure? Here, (1) through (6) indicate the sequence of transactions, and each of the numbers from (3) to (6) corresponds to an action in a) through d).', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-72.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS03Mi5wbmciLCJpYXQiOjE3NDMxMTQzMTIsImV4cCI6MTc3NDY1MDMxMn0.ZXjYwTJ-7EHKG2S6gFrKnEHnNCNJGA1hl6WUm-hSMD8', 'Notice of payment deposit', 'Notice of product receipt', 'Shipment of product', 'Transfer of payment', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-72', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of HEMS?', NULL, 'It is a system that connects multiple home appliances through a network to visualize the power and perform optimum control of power consumption.', 'It is a system that converts the electricity produced by a solar power generation system and a residential-use fuel cell for the electricity to be useable in households, etc.', 'It is a system that recycles the useful parts of home appliances discarded by general households and offices to reduce the amount of waste materials and promote the effective use of resources.', 'It is an electric hot water supply system that generates a considerable quantity of heat with a relatively small amount of energy by using a heat pump.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '21-A-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When real-time systems are classified into hard real-time and soft real-time systems, which of the following is in the category of a hard real-time system?', NULL, 'Airbag control system', 'Bank ATM system', 'Seat reservation system', 'Web delivery system', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '21-A-74', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an organizational structure of a corporation that is temporarily structured by specialists from each department to reach a specific goal over a limited period and operates independently from all other standing organizations?', NULL, 'Company system organization', 'Divisional system organization', 'Functional organization', 'Project organization', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '21-A-75', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There are several quality control tools that have been used primarily for manufacturing and inspection departments. Which of the following is a combined graph containing a bar graph that shows the numeric values of individual items in descending order, and a line graph that shows the cumulative total of the composition ratios of these numeric values?', NULL, 'Control chart', 'Histogram', 'Pareto chart', 'Scatter diagram', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '21-A-76', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a sampling inspection, which of the following can be used to ascertain the probability of acceptance of a lot with a certain defective ratio?', NULL, 'Bathtub curve', 'Gompertz curve', 'Logistic curve', 'OC curve', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '21-A-77', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of following is an expression for calculating the cost of goods sold (or cost of sales) of a manufacturing company?', NULL, 'Material cost in current period + Labor cost in current period + Expense in current period', 'Product inventory at beginning of period + Product manufacturing cost in current period − Product inventory at end of period', 'Product inventory at beginning of period + Product manufacturing cost in current period − Work in process inventory at end of period', 'Work in process inventory at beginning of period + Product manufacturing cost in current period − work in process inventory at end of period', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '21-A-78', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The break-even point (BEP) is a level where total cost and total revenue are equal. The table below lists the fixed cost, variable cost per unit, price per unit, and BEP in units. Which of the following is a value of the price per unit?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-A-79.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtQS03OS5wbmciLCJpYXQiOjE3NDMxMTQzMjIsImV4cCI6MTc3NDY1MDMyMn0.NSFLvmBvLtUEAXhVgDGBhncPsGuM5SVYq75iyQVFQAo', '4', '8', '12', '16', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '21-A-79', 0.0, 1.0);
