INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the decimal arithmetic expression, 7 / 32, is evaluated, which of the following represents the result in binary?', NULL, '0.001011', '0.001101', '0.00111', '0.0111', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '20-O-01', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A contradiction is a Boolean expression that always evaluates as FALSE for any assignment of truth values to its variables. Which of the following is a contradiction? Here, " ⋅ ", "+", and " ‾‾ " represent the AND, OR, and NOT operators, respectively.', NULL, '( p · ( p̅ + q ) ) · q̅', '( p · q̅ ) · ( p̅ + q̅ )', 'p + ( p · q )', 'p̅ + ( p · q̅ ) + q', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '20-O-02', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A factory manufactures the same products on two production lines, A and B. Line A manufactures 60% of all products, and B manufactures the remaining 40%. Defect rates of products manufactured in A and in B are 2% and 1%, respectively. When a product was randomly chosen for inspection among the products manufactured in this factory, it was found to be defective. What is the percentage of probability that the product was manufactured in Line A?', NULL, '40', '50', '60', '75', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '20-O-03', -1.0, 1.0);
