INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In machine learning, which of the following is an appropriate explanation of supervised learning?', NULL, 'Clusterizing input data according to the statistical features or specific conditions of the data without any explicit processing beforehand', 'Learning to achieve the highest score from rating good and bad aspects of individual actions', 'Predicting a subsequent user action from the frequency of appearances of behavioral data accumulated from computer users', 'Training by feeding input data and their correct output so that the response to unknown data is improved', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '20-O-05', -1.0, 1.0);
