INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of a device driver?', NULL, 'Software to control peripheral devices that are connected to a PC', 'Software to install an application on a PC', 'Software to invade another PC and cause damage', 'Software to register the operation procedures for a keyboard or other devices and to automate this operation', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-O-12', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('ECC is used for error detection and correction in memory. When n+2 redundant bits are required for a data bus having a width of 2ⁿ bits, what is the number of redundant bits that are required for a data bus having a width of 128 bits?', NULL, '3', '8', '9', '10', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-O-13', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a web system, which of the following is an appropriate benefit of a web server and an application (AP) server being placed on different physical servers?', NULL, 'Because the business logic that accompanies an access to data is placed in a program on the web server, the program on the AP server does not need to be changed in association with a change in the business logic.', 'Because the difference between the character coding scheme of the web browser and that of the AP server is absorbed by the web server, garbled (or unreadable) characters do not appear.', 'Because the execution environment of the client is implemented on the web server, the client and the AP server do not need to exchange screen data for each request, and only a small amount of data communication is required.', 'Processing can be distributed according to the type of request from a client in such a way that a request for static content having a light load is processed by the web server, and a request for dynamic content having a heavy load is processed by the AP server.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-14', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following achieves data redundancy via mirroring?', NULL, 'RAID 0', 'RAID 1', 'RAID 5', 'RAID 6', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-15', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the dispatcher in an operating system?', NULL, 'A function in which multiple tasks appear to be running simultaneously on a single processor', 'The allocation of the right to use a processor for a ready process', 'The context that is the information required for process execution', 'The determination of the order of execution for each process', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-O-16', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the processes that are performed by a compiler for a procedural language, which of the following is the process that is performed first?', NULL, 'Lexical analysis', 'Optimization', 'Semantic analysis', 'Syntactic analysis (parsing)', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-O-17', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The table below shows the priority of three tasks, A through C, and the operation sequence and the processing time of the CPU and the I/O device when each task is executed independently. Which of the following represents the scheduling condition during the time period of 7 ms after 3 ms have elapsed since A through C became simultaneously ready for execution? Here, there is no I/O contention, and the overhead of the OS is not considered. And the numbers in parentheses indicate processing time, and “waiting” in the answer group indicates that the task is ready and is waiting for the allocation of the CPU.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-18.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy0xOC5wbmciLCJpYXQiOjE3NDMxMTU4NDcsImV4cCI6MTc3NDY1MTg0N30.DcnM79kCzA5EWT8H-l6a7CLsFV24s3Ip6OJ1-SYL608', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-18-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy0xOC1BLnBuZyIsImlhdCI6MTc0MzExNTg1MSwiZXhwIjoxNzc0NjUxODUxfQ._VhBdKLxk0YafaMnA2GrMFVpm2z6Vzme93uQNqZQiq4', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-18-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy0xOC1CLnBuZyIsImlhdCI6MTc0MzExNTg1NSwiZXhwIjoxNzc0NjUxODU1fQ.JpzShw4Mugv48BrH6_VHIjT_ITTMa-qX0JltVgGH3EM', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-18-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy0xOC1DLnBuZyIsImlhdCI6MTc0MzExNTg1OCwiZXhwIjoxNzc0NjUxODU4fQ.90JEuH6I57WlTwsC3e4XeoFZykfNylqqLTbkb6TtNnE', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-18-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy0xOC1ELnBuZyIsImlhdCI6MTc0MzExNTg2MiwiZXhwIjoxNzc0NjUxODYyfQ.DeSuWshHmLCVEab6VtGjkBB2NlEQsCFAXeZR6afbXr0', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-O-18', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following represents appropriate handling for open source software according to OSI’s definition?', NULL, 'For open- source software that is created for a specific industry, the scope of publishing of the source code can be limited to that industry.', 'If open- source software is to be modified for uses such as internal use by a company without being redistributed, the modified part of the source code does not have to be published.', 'When open- source software is modified and redistributed, the same license as the original software must be used for distribution so that the distribution conditions are remain the same as the original software.', 'When open- source software is redistributed by a third party as a product, the developer of the open- source software can charge a license fee to the third party.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-O-19', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of DRAM?', NULL, 'It is memory that requires a refresh operation, and it is used as the main memory of a PC.', 'It is non-volatile memory of a NAND type or a NOR type, and it is used as an SSD.', 'It is non-volatile memory that is capable of erasing and writing data in byte units, and it is used when data need to be retained even when the power supply is turned off.', 'Its memory cells consist of flip-flops, and it is used for cache memory.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-O-20', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a secondary (rechargeable) battery?', NULL, 'Alkaline–manganese dry-cell battery', 'Fuel cell', 'Lithium-ion battery', 'Silver-oxide battery', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-21', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the correct gate that converts the 2-input OR gate shown below into a NAND gate if the output of the added gate is respectively connected to input X and input Y?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy0yMi5wbmciLCJpYXQiOjE3NDMxMTU4NjgsImV4cCI6MTc3NDY1MTg2OH0.Eu9PqRpm1BsQjPFbnzVm5hFCccWyys2uAgZmUY62LV4', 'AND', 'OR', 'NOT', 'OR', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '20-O-22', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate usage of radio buttons in GUI applications?', NULL, 'To select multiple items from a group of items', 'To select one item from a group of mutually exclusive items', 'To select one item from a list or to enter new item into a text box', 'To select one item from a list that is displayed when a button is pressed', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-23', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method of improving the appearance of a jagged edge of a slanted line to be smoothed on a screen, such as that of an LCD?', NULL, 'Anti-aliasing', 'Bump mapping', 'Shading', 'Texture mapping', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-24', -2.0, 1.0);
