INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The employee’s ID, name, salary, manager ID, and working department are recorded in the Employees table. When a query is formulated in SQL to retrieve the manager ID and the average salary of the employees under his/her direct report, and the output is obtained as below, which of the following is the appropriate combination to be inserted in blanks E and F in the SQL statement?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-26.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy0yNi5wbmciLCJpYXQiOjE3NDMxMTU4NzEsImV4cCI6MTc3NDY1MTg3MX0.ZFYHrUKE1JDn5SDZHOP4tuFiTSywSBzF99U7JwNIJfA', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-26', -1.0, 1.0);
