INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a failure occurs in a storage unit that stores a database, which of the following is an operation that can recover the database by using backup files and a log?', NULL, 'Archive', 'Checkpoint dump', 'Commit', 'Rollforward', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-28', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the granularity of locks?', NULL, 'When a large number of transactions update the same data, and the granularity is set as large, the number of transactions that can be simultaneously executed increases.', 'When all data in a table are referenced, and the granularity is set as large, data referenced from other transactions can be undisturbed.', 'When data are updated, and the granularity is set as large, the waiting times of other transactions increase, and the total throughput declines.', 'When the granularity is set as large, the number of included data increases, and the number of locks that one transaction makes increases.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-29', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Approximately how many seconds is required to transmit a file of 10^6 bytes via a 64 kbit/s communication line? Here, the transmission efficiency of the line is 80%.', NULL, '19.6', '100', '125', '156', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-30', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a device that connects multiple LANs by relaying data through the protocol information of the data link layer of the OSI basic reference model?', NULL, 'Bridge', 'Gateway', 'Repeater', 'Router', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a role played by a DNS in a TCP/IP network?', NULL, 'It assigns an unused IP address from the pool of addresses in response to a request from a PC or a printer.', 'It associates domain or host names with IP addresses.', 'It converts private IP addresses used within a company into global IP addresses, and it enables access to the Internet.', 'It enables a program in a server to be called by only specifying the program name without being aware of the IP address of the server.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-32', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the broadcast address of a network to which the IP address 192.168.57.123/22 belongs?', NULL, '192.168.55.255', '192.168.57.255', '192.168.59.255', '192.168.63.255', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-33', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an Internet standard that extends the format of email header fields to handle not only text messages but also audio and image files?', NULL, 'HTML', 'MHS', 'MIME', 'SMTP', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-34', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following attacks is classified as DNS cache poisoning?', NULL, 'False domain information is injected into the DNS server that is referenced by a PC, and it leads the user to a fake server.', 'The version information of the DNS server software is obtained to identify a security hole.', 'To interrupt the target service, the attacker uses the DNS server as a steppingstone to send a large number of recursive queries.', 'To obtain internal information, the zone information stored in the DNS server is compiled and transferred.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-35', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a type of public-key cryptography that utilizes the difficulty of factorizing extremely large numbers into primes?', NULL, 'AES', 'DH', 'DSA', 'RSA', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is appropriate conduct for a white-hat hacker?', NULL, 'Breaking into a system and changing one of the files without permission and reporting the weaknesses to the owner', 'Breaking into a system to analyze its vulnerabilities with the owner’s permission and within the prescribed rules of engagement', 'Logging into a system to show fellow hackers real-life examples of deleting a file without the owner’s permission', 'Looking at secret data on a system with the motivation of personal or financial objectives, protest, or espionage', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-37', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of an SQL injection attack?', NULL, 'It is an attack in which a command for performing a malicious query or operation is entered in the website where there is a vulnerability in a web application to acquire or falsify data without authorization.', 'It is an attack in which a commercial DBMS vulnerability is exploited to search the host database server and cause repeated infections in order to cause a sudden rise in Internet traffic.', 'It is an attack in which a malicious script is executed on the visitor’s web browser by sending the malicious code to the website displaying the visitor’s input data.', 'It is an attack in which a website visitor is made to view a web page containing an embedded malicious script, and the visitor is then made to perform an unintentional operation on another website.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-38', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate use of a private key for a digital signature?', NULL, 'The recipient can use the private key to restore an encrypted message to its original status.', 'The sender can use the private key to create a signature and attach it to a message, and the recipient can confirm the sender.', 'The sender can use the private key to encrypt a message with an attached fixed string, and the recipient can identify sections that are falsified.', 'The sender can use the private key to encrypt a message, and the content of the message cannot be understood by unrelated parties.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of a worm, as compared with a Trojan horse?', NULL, 'Arbitrarily encrypting files so that they cannot be read normally', 'Causing an infection to spread by itself by using the network and removable media', 'Performing an unauthorized action as an individual program', 'Waiting without performing any activity until a specific condition is established', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of CSIRT?', NULL, 'It is a generic term for an organization that is established within a company, organization, or government agency, and it receives reports on information security incidents for investigation and response.', 'It is a generic term for people or an organization whose aim is to achieve a religious or political goal by utilizing IT.', 'It is an organization that creates technical documents concerning the Internet, and it investigates standardization issues.', 'It is an organization that defines the IP-address allocation policy. It operates and monitors DNS root servers and coordinates DNS management and other such matters on a global scale.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-41', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a network that is divided into three (3) segments (i.e., external segment, DMZ, and internal segment) by one (1) firewall. In this network, a service for users is to be made available over the Internet by using a system comprising a web server and a database server containing important data. Which of the following is the most appropriate method of server installation that can protect important data from unauthorized access from the Internet? Here, only a specific protocol is allowed for communications between the external segment and the DMZ, and between the DMZ and the internal segment by the firewall. Direct communication between the external segment and the internal segment is not allowed.', NULL, 'Installation of the web server and database server in the internal segment', 'Installation of the web server and the database server in the DMZ', 'Installation of the web server in the DMZ and the database server in the internal segment', 'Installation of the web server in the external segment and the database server in the DMZ', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-42', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a purpose of using a port scanner during an inspection of a web server?', NULL, 'Detecting the vulnerability of contents by logging in with a valid user ID and directly checking the contents of the web server', 'Detecting unauthorized use by analyzing the access history of the web server', 'Ensuring that no unnecessary service is operating by enumerating services on the web server', 'Ensuring that there is no deviation from the information-security policy by checking the management status of the web-server user IDs with the operator', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a packet-filtering firewall is to be installed at the point of connection between a company’s internal network and the Internet, and PCs on the internal network are to be allowed to access port 80 of a web server on the Internet, which of the following is an appropriate combination of rules of filters for allowing traffic?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-44-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy00NC1BLnBuZyIsImlhdCI6MTc0MzExNTg4OSwiZXhwIjoxNzc0NjUxODg5fQ.5WLHSHD0tMKxrOMou-ytWnoYhnEq3lN-NqK3HgY16us', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-44-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy00NC1CLnBuZyIsImlhdCI6MTc0MzExNTg5MywiZXhwIjoxNzc0NjUxODkzfQ.qtbdbANsBHUJX6Lm7XWFXKpiYQls3zJOqGojbEUW5as', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-44-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy00NC1DLnBuZyIsImlhdCI6MTc0MzExNTg5NywiZXhwIjoxNzc0NjUxODk3fQ.FcxiEXvZacO9CR87FAvakxsAkaPqLfMNsK7GC1qC-7M', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-44-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy00NC1ELnBuZyIsImlhdCI6MTc0MzExNTkwOSwiZXhwIjoxNzc0NjUxOTA5fQ.LLe9kr7-YK5tcktT5wPQxNN6LXaZFHQNkshYyLmmMhs', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following UML diagrams shows the exchange of messages among objects, message transmission, and object lifelines in a time series?', NULL, 'Activity diagram', 'Communication diagram', 'Sequence diagram', 'State-machine diagram', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-O-45', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate relation between a class and an instance in object-oriented programming?', NULL, 'An instance defines the specifications of a class.', 'An instance is created based on the definition for a class.', 'Multiple classes correspond to one (1) instance.', 'Only one (1) instance exists for one (1) class.', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '20-O-46', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the type of module coupling that has the weakest degree of coupling in which the exchange of information between modules is performed only using parameters?', NULL, 'Common coupling', 'Control coupling', 'Data coupling', 'Content coupling', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-O-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the development process, which of the following is an activity that should be performed for software architectural design?', NULL, 'Analyzing the requirements in incremental steps by expressing them in the form of a diagram, etc.', 'Describing the specifications so that the program is clarified on a line-by-line basis', 'Obtaining the opinion of the customer and determining the specifications', 'Transforming the requirements for the software item into an architecture that describes its top-level structure and identifies its software components', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-O-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below shows that the cumulative number of bugs reached the target value, when the number of completed test items was X. Which of the following is an appropriate explanation of the situation shown in this figure?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-49.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy00OS5wbmciLCJpYXQiOjE3NDMxMTU5MTYsImV4cCI6MTc3NDY1MTkxNn0.gVe6amxv9qC5CCjbivJUlPC_GrmyCgVEU4D3Zu1X_YM', 'It indicates that a large number of bugs may still remain internally.', 'It indicates that desk-checking and simulation were performed satisfactorily prior to testing.', 'It indicates that the probability of occurrence of bugs after shipping is low, because the target cumulative number of bugs was reached.', 'It indicates that the testing process was completed successfully.', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-O-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of an extreme programming (XP) practice?', NULL, 'After the code is created, and it is confirmed that it can be integrated, test cases are created.', 'Integration of the code and testing are continuously repeated.', 'The code that passed the tests is not refactored until the next iteration.', 'The customer is responsible for the specification of unit tests.', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-O-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the 6th edition of the PMBOK Guide, which of the following is an activity for the planning process group in project resource management?', NULL, 'Acquire resources', 'Control resources', 'Develop project team', 'Estimate activity resources', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '20-O-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The activities and milestones of a project are shown in the arrow diagram below. Which of the following is an impact of reducing the duration of activity, D, by 3 days?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-52.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy01Mi5wbmciLCJpYXQiOjE3NDMxMTU5MjIsImV4cCI6MTc3NDY1MTkyMn0.nC0S-mDa-XYSty-onxHu_xxItEhgkda5bHm5RWOdHPo', 'Project duration is not changed', 'Project duration is reduced by 1 day.', 'Project duration is reduced by 2 days.', 'Project duration is reduced by 3 days.', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '20-O-52', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The functional size of a new system was estimated to be 500 function points (FP). Apart from development, the project requires 10 person-months in total for installation of the system and education of developers. Additionally, for project management, 10% of the total person months of development, installation, and education is required. How many person-months are required in total for this project? Here, the productivity in development is 10 FPs per person month.', NULL, '51', '60', '65', '66', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '20-O-53', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is used in quality management to help determine whether a process is stable by using plotted time-series data and limit lines?', NULL, 'Brainstorming', 'Cause-and-effect diagram', 'Control chart', 'Run chart', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '20-O-54', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate definition of the total cost of ownership (TCO) in the context of system cost?', NULL, 'It is the total amount of expenses at the time of system installation.', 'It is the total amount of expenses related to the development of business systems.', 'It is the total amount of expenses, including those from system installation through operation and maintenance/management.', 'It is the total amount of operation expenses for systems related to communications and networking.', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '20-O-55', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IT service management, which of the following is an activity that is performed for management of incidents and service requests?', NULL, 'Evaluating if customer satisfaction with the service desk meets the agreed service targets and performing a review for identifying improvement opportunities', 'Examining measures wherein the amount of free space on a disk is near its threshold', 'Investigating the impact of changes made to a program', 'Receiving a failure report from a user and checking to see if it corresponds to a known error', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-O-56', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description about the backup of data on a disk that is connected to a server?', NULL, 'All data are backed up on the day the system commences full operations, and only frequently updated data are backed up thereafter to shorten the work time.', 'Data distributed and stored in multiple files are backed up when a series of update processes to the files are completed.', 'Data whose frequency of use are low after a certain period of time are deleted from the current disk, and the data that have been backed up are also deleted.', 'Important data are backed up by overwriting data on the same media, so that the backup media are not mistaken.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-O-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description about a system auditor?', NULL, 'The entire interview must be conducted by one (1) system auditor, because discrepancies may occur in the record if multiple auditors are involved.', 'The system auditor must instruct the department being audited to implement improvement measures for deficiencies identified during the interview.', 'The system auditor must make an effort to obtain documents and records that support the information obtained from the department being audited during the interview.', 'The system auditor must select interviewees from administrators who have been an auditor within the department being audited.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-O-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate measure that a management executive must take to secure the appearance of independence for an internal system auditor?', NULL, 'Assigning the system auditor to the internal audit department', 'Making it compulsory for the system auditor to undergo continuous learning of IT', 'Setting up an auditing-skills training system for the system auditor', 'Specifying and publishing the knowledge and experience necessary for the system auditor', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-O-59', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When software asset management is audited, which of the following activities is the most appropriate?', NULL, 'It is checked to see if compatibility with existing systems is evaluated at the time of installation.', 'It is checked to see if evidence, such as a software-license certificate, is properly retained.', 'It is checked to see if failures are localized via database partitioning or other methods.', 'It is checked to see if the organizational and functional structure of the software provider is considered.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of an application architecture that constitutes enterprise architecture?', NULL, 'It systematically describes the business processes or the information flows necessary for the business strategy.', 'It systematically describes the contents of the data necessary for business operations, the relations or structures between the data, etc.', 'It systematically describes the functions or system configurations that support business processes.', 'It systematically describes the technical components necessary for the developments and operations of the information systems.', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '20-O-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an on-demand service?', NULL, 'A DVD movie purchased from an internet site', 'A pocketbook printed by a publishing company using offset printing after deciding the number of copies', 'A repeat broadcast drama that is delivered on the internet in response to the request of the user', 'Internet news periodically delivered to a smart phone', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '20-O-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate example of utilizing Business Intelligence (BI)?', NULL, 'Analyzing a large volume of data stored on a business system to evaluate business performance and develop a business strategy', 'Computerizing the daily routine works, such as decision requests, to ensure that such procedures are carried out without fail and to enable their swift completion', 'Enabling employees to use computerized learning materials via a network and managing their learning and performance', 'Obtaining publications, such as annual reports issued by competitors, to understand their business strategies and financial situations', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-O-63', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When examples of utilizing big data are classified according to the feedback destination of the analysis and the reflection timing, which of the following utilization examples corresponds to D in the table below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-O-64.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtTy02NC5wbmciLCJpYXQiOjE3NDMxMTU5MjgsImV4cCI6MTc3NDY1MTkyOH0.BNEB-9DzLCdIsV2HhennZC56Dz2njoeWjMk5ZxI0w4Q', 'Based on the location data acquired from the smartphone of a customer registered as a member and the purchase history data of the customer, recommended products from nearby retailers are displayed on the smartphone.', 'From the large volume of purchase data collected and accumulated by using member cards, the preferences of each customer are analyzed, and coupons for the next month are issued according to the purchase volume of the previous month.', 'The current traffic status of each road is published on the website by collecting and analyzing data of the position, speed, and other parameters of moving cars.', 'The ranking of the largest-selling products of each month is extracted from the POS data of the last few years from sister stores, and images of the products corresponding to the current month are displayed on monitors inside the store.', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '20-O-64', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In computerization planning, which of the following is an activity that should be performed?', NULL, 'Clarifying what roles are assigned to the business and information-system departments when the organizational structure of system development construction is planned and clarifying the basis of cost calculation for development, operation, and maintenance when considering the costs', 'Determining interfaces, such as screens or forms, based on the requirements definition document and describing them in the design document', 'Performing maintenance and management of the system so that it conforms to the business and the environment and analyzing details and clarifying the potential impacts of modification requests', 'Performing system startup and shutdown, monitoring, and file maintenance in a planned manner and verifying that business is being carried out smoothly', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '20-O-65', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the “competitive strategy” proposed by Philip Kotler, which of the following describes a company that has no high market share but utilizes quantitatively large management resources?', NULL, 'Market challenger', 'Market follower', 'Market leader', 'Market nicher', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-O-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of telemarketing?', NULL, 'Direct marketing that includes calling people at home and asking for donations, opinions, or purchases.', 'Direct marketing that sells products and services and builds customer relationships over the internet.', 'Direct marketing that sends offers, announcements, reminders, or other items to a person at a particular address.', 'Direct marketing that sends sales alerts, links to website updates, appointments, or delivery reminders to large groups of people.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-O-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is mostly tacit knowledge?', NULL, 'A list of countries and their capitals', 'An inventory of assets', 'Contents of a washing machine manual', 'How to ride a bicycle', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-O-68', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is appropriate as a description of Customer Relationship Management (CRM) software?', NULL, 'It mainly provides online tools for sales, customer service, and marketing.', 'It mainly provides partner relationship management.', 'It only supports direct-marketing campaigns.', 'It provides information and tools to make call center, help desk, and customer support staff more efficient mainly by phone.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-O-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a process that aims to produce ideal technology, technology follows an evolutionary process that progresses from the introduction stage, growth stage, maturity stage, decline stage. Then it transitions to the next technological phase. Which of the following is used to represent this technological evolution process?', NULL, 'Bathtub curve', 'Demand curve', 'Learning curve', 'Technology S-curve', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-O-70', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a sharing economy?', NULL, 'It is a concept by which efficient management and operation of renewable energy and urban infrastructure are performed by using IT, which leads to an improvement in the quality of people’s lives and helps achieve continuous economic growth.', 'It is a concept by which the productivity of an entire economy increases as a result of utilizing IT, and the demand-and-supply gap is eliminated via the progress of SCM, which leads to sustainable growth free from inflation.', 'It is a mechanism by which over-the-counter and Internet sales are combined in a business transaction, and the strong points of both are utilized and linked to expand overall sales.', 'It is a mechanism mainly between individuals by which the community function and other functions of social media are utilized to share, lend, or borrow the unemployed assets owned by individuals.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-O-71', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of an IC tag (RFID)?', NULL, 'It handles a large amount of information. Thus it uses an external storage device for storing information.', 'It is stain-resistant, and recorded information can be read from the outside of a package.', 'It is used by inserting the tag into a dedicated magnetic reader.', 'It uses GPS to display location information or attribute information about the current location.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-O-72', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of Consumer Generated Media (CGM)?', NULL, 'A company website through which the company publishes information for individual investors about its management status, financial status, and performance trends', 'A company website through which the company transmits information to general consumers about the characteristics and usage method of its products', 'A website of a governmental organization through which the agency publishes information for general citizens about its policies and administrative services', 'A website, such as a blog or SNS, on which an individual sends information to unspecified large number of people about the evaluation of products used by the individual', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-O-73', -2.0, 1.0);
