INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In object-oriented programming, which of the following is an explanation of overriding that achieves polymorphism?', NULL, 'A feature that allows a class to provide a specific implementation of a method that is already provided by one of its superclasses', 'Creating a class through abstraction by collecting common properties of multiple classes', 'Defining multiple methods in a class that have the same name but differ either in the number of arguments, argument types, or argument order', 'Hiding the internal contracts and structures of an object from its external specification', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '20-A-08', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of a RISC processor when it is compared with a CISC processor?', NULL, 'The RISC processor uses a micro-code architecture.', 'The RISC processor uses a uniform instruction length to process tasks in a pipeline.', 'The RISC processor uses a variable instruction length to optimize task process capability.', 'The RISC processor uses complex instructions to process various tasks with few instructions.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-A-09', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is classified as an internal interrupt?', NULL, 'An interrupt due to an abnormal power condition, such as a momentary loss of the commercial power supply', 'An interrupt due to having performed division by zero', 'An interrupt due to the completion of input or output', 'An interrupt due to the occurrence of a memory parity error', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-A-10', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate characteristic of SRAM compared with DRAM?', NULL, 'Compared with DRAM, SRAM consumes more power while it is idle.', 'Compared with DRAM, SRAM needs a fewer number of transistors to store one bit of data.', 'SRAM does not need to be refreshed periodically as flips flops retain data, and DRAM needs to be refreshed at fixed intervals to retain data.', 'SRAM stores data in a combination of capacitors and transistors, and DRAM stores data in a set of transistors called flip-flops.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-A-11', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which one of the following serial transmission methods is used in asynchronous data communication?', NULL, 'I²C', 'PCI Express', 'SPI', 'UART', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-12', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As a backup system configuration, which of the following is an appropriate description of a hot site?', NULL, 'A shared site is prepared, and at the time of the occurrence of a failure, the backed-up data and program are loaded to recover the system, and business operations are resumed.', 'A site is operated as a standby site, the data and programs are updated at all times via a network, and the business operation is resumed immediately when a failure occurs.', 'A spare site is secured beforehand, and at the time of the occurrence of a failure, the required hardware and the backed-up data and program are loaded to recover the system, and the business operation is resumed.', 'Hardware is prepared at a spare site, and the periodically backed-up data and program are loaded and stored. At the time of occurrence of a failure, the system is restored by making use of these stored entities, and the business operation is resumed.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-A-13', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A RAID 6 server is configured with six hard disk drives, and each drive’s capacity is one TB. What is the maximum total data storage capacity in TB? Here, spare disks are not used.', NULL, '3', '4', '5', '6', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-A-14', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The life cycle of a computer system can be classified from the viewpoint of failure into the three periods of early failure period, random failure period, and wear-out failure period. Which of the following is the most appropriate description of the measures in the early failure period?', NULL, 'Implementing prior replacement of components', 'Implementing scheduled maintenance and condition-based maintenance', 'Performing age-based maintenance on the basis of the cumulative operating time of the items that make up the system', 'Strengthening the design review and failure analysis in order to reduce errors in the design and manufacturing', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-A-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the number of concurrently running programs is increased in a virtual storage system with a small and insufficient main memory capacity, which of the following is the state in which the overhead of the system increases and the processor utilization of the applications decreases?', NULL, 'Bottleneck', 'Fragmentation', 'Paging', 'Thrashing', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-A-16', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the least recently used (LRU) method is used for swapping a block between cache memory and main memory, which of the following is a block in cache memory to be replaced?', NULL, 'A block for which the longest period of time has elapsed since it was added', 'A block for which the longest period of time has elapsed since it was last referenced', 'A block that has been referenced the least frequently', 'A block that has not been referenced for a certain period of time', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '20-A-17', -1.0, 1.0);
