INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of clickjacking?', NULL, 'An attacker gains remote control of the mouse of a computer and maliciously operates the computer.', 'An attacker misleads the user to interact with a user interface and to perform unintended operations.', 'An attacker remotely locks the mouse pointer to prevent the user from moving the pointer anymore.', 'An attacker removes the mouse device driver of the system so that the user cannot stop doing malicious actions.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following activities targets the DHCP server and exhausts all its available IP address pool so that it cannot provide any IP addresses to its clients?', NULL, 'DHCP MAC filtering', 'DHCP snooping', 'DHCP spoofing', 'DHCP starvation', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-38', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Man-in-The-Middle (MITM) attack means the attacker intercepts and alters the communication between the end-user (victim) and the server, which is shown below. In an MITM attack, when the victim sends packets to the server, the attacker receives the packets and then forwards them to the server while the server sends the packets to the victim via the attacker. In this communication channel, which of the following is the appropriate description concerning the MITM attack?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-A-39.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtQS0zOS5wbmciLCJpYXQiOjE3NDMxMTYwODIsImV4cCI6MTc3NDY1MjA4Mn0.1MeUukIvle5n8aQ0fZSwgM5JjYeNnlGelUTpJPsveV0', 'The attacker always uses the server IP during the communication and never uses the victim’s IP.', 'The attacker always uses the victim’s IP during the communication and never uses the server’s IP.', 'The attacker always uses the victim’s IP during the communication with the server and always uses the server IP during the communication with the victim.', 'The attacker always uses the victim’s IP during the communication with the victim and always uses the server IP during the communication with the server.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-39', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the result when person A sends an e-mail that is encrypted by person B’s public key to person B and person C? Here, these three persons have the public keys of all three persons, and all of them have their own private keys.', NULL, 'Both B and C can decrypt the encrypted e-mail using B’s public key.', 'Both B and C can decrypt the encrypted e-mail using their own private keys.', 'Only B can decrypt the encrypted e-mail using A’s public key.', 'Only B can decrypt the encrypted e-mail using B’s own private key.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-40', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a package of unauthorized programs and tools that have functions such as creating a back door on a server and hiding the evidence of intrusion inside a server?', NULL, 'RFID', 'Rootkit', 'TKIP', 'Web beacon', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-41', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate countermeasure against cross-site scripting (XSS) attacks?', NULL, 'Avoiding running a program received in an e-mail from an unknown sender', 'Closing all unnecessary ports apart from standard web server ports', 'Filtering out the input that can be interpreted as a script', 'Using HTTPS instead of HTTP as the default protocol on the web server', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-42', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method to prevent damage caused by an SQL injection attack?', NULL, 'Preventing input characters from being interpreted as characters that have a special meaning in querying or manipulating data in a database', 'Rejecting any input that contains a character string that specifies a higher-level directory (../)', 'Rejecting any input whose total length exceeds the limit', 'Replacing an HTML tag with another character string that is not interpreted as an HTML tag if any input contains an HTML tag', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the network security tool that is usually deployed by a network or system administrator and presents itself as a target machine trying to lure attackers to observe their behavior and attack methodology without harming other systems?', NULL, 'Honeypot', 'Logic analyzer', 'Protocol analyzer', 'Rootkit', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-44', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('SSL/TLS is the industry-standard security technology creating encrypted connections between a web server and a web browser. This is used to maintain data privacy and to protect the information in online transactions. The steps for establishing an SSL/TLS connection are randomly listed as follows:
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a UML use case diagram?', NULL, 'It shows the behavior that occurs during object life cycle using finite state transitions.', 'It shows the exchange of messages among objects, and massage transmissions and object lifelines in a time series.', 'It shows the flow from one activity to another activity in systems and work.', 'It shows the scenarios for what the system will do, from the point of view of actors (i.e., external users or machines).', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-A-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the design techniques that are used in system development, which of the following is an explanation of a decision table?', NULL, 'It represents a combination of conditions and the corresponding operations.', 'It represents entities by a rectangle and their relationship through connecting lines.', 'It represents the flow of controls, such as a process or selection, by linear lines or arrows.', 'It represents the flow of data between an external interface, processes, and data store.', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-A-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Test data about the part of a program shown in the flowchart below is specified by decision condition coverage (branch coverage). When this test data is changed to being specified by multiple-condition coverage, which of the following is the appropriate test data to be added? Here, the part enclosed by parentheses () represents the set of test data.
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the different types of software tests, which of the following is a test that is performed with the purpose of checking whether or not a location that must not be affected by changes made for software maintenance is affected?', NULL, 'Integration test', 'Operational test', 'Regression test', 'System test', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-A-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of reverse engineering of software?', NULL, 'The entire software is reconstructed after analyzing and understanding the existing software.', 'The existing software is analyzed, and its specification and structure are clarified.', 'The internal structure of software is changed without changing the behavior seen from the outside.', 'The source code is created automatically from the design information using a development support tool.', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '20-A-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to PMBOK, which of the following is the description of scope creep?', NULL, 'Any change to the project scope that requires an adjustment to the project cost or schedule', 'The approved version of a scope statement, work breakdown structure (WBS), and its associated WBS dictionary', 'The process of monitoring the status of the project and product scope and managing changes to the scope baseline', 'The uncontrolled expansion to product or project scope without adjustments to time, cost, and resources', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '20-A-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A project with a development period of 10 months and the person-hours required for development as 200 person-months is planned. Which of the following is the number of staff members required during the peak time based on the distribution sheet shown below? Here, the number of staff members does not change from the start till the end of every process.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-A-52.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtQS01Mi5wbmciLCJpYXQiOjE3NDMxMTYwOTYsImV4cCI6MTc3NDY1MjA5Nn0.fWEu3n2S9TE12JXzoyYTA7oBzgqmyXCx-BN_Tr2aVmI', '18', '20', '21', '22', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '20-A-52', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the critical path of the project activities shown in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-A-53.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtQS01My5wbmciLCJpYXQiOjE3NDMxMTYwOTksImV4cCI6MTc3NDY1MjA5OX0.MHlVAVAlnRecR0_S3olZwUC7mPyf7DGqCzD7F6ulWCE', 'A -> B -> E -> I -> L', 'A -> C -> D -> E -> H -> K', 'A  -> C -> F -> I -> L', 'A -> C -> G -> J -> L', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '20-A-53', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the function point method?', NULL, 'The development scale is estimated by adding up the number of steps required for each program to be developed.', 'The development scale is estimated by searching for past examples and then analyzing and evaluating the results and the differences of these examples from the system to be developed.', 'The development scale is estimated from the counts and characteristics of external inputs and outputs, internal logical files, external inquiries, and external interface files.', 'The number of person-hours required for each activity is estimated by creating a WBS of the activities required for a development project.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '20-A-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In ITIL, the reduction in the index value expressing maintainability is cited as an example of a key performance index (KPI) in availability management. Which of the following corresponds to such an index?', NULL, 'Mean time between failures', 'Mean time between service incidents', 'Mean time to restore service', 'Number of interruptions in a certain period of time', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-A-55', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In service management, which of the following is a requirement of service level management?', NULL, 'A capacity plan is created, implemented, and maintained while human, technical, informational, and financial resources are taken into consideration.', 'A service catalog and SLA are created for the service to be provided, and they are agreed upon with the customer.', 'Costs are monitored and reported against the budget; the financial forecasts are reviewed, and costs are managed.', 'The risks to service continuity and availability of services are assessed and documented.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-A-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an effective means of protecting an information system from the damage from over-voltage that occurs because of a lightning strike?', NULL, 'Connecting the communication cable and the computer through a surge protection device (SPD)', 'Digitalizing the control circuit of electric power facilities', 'Installing a private power generator', 'Splitting the communication wire into two (2) systems that have different paths', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-57', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among situations that are identified as results of performing an ISMS internal audit on the basis of ISO/IEC 27001:2013 (Information security management systems— Requirements), which of the following is a situation that the auditor should record in the audit report as a finding?', NULL, 'After a risk assessment was performed, risk acceptance criteria were determined.', 'An incident of erroneous disposal of personal information was reported to a competent authority with specified procedures.', 'Spyware was detected by a malware scan, and it was disinfected.', 'The use of a USB memory was permitted in accordance with defined procedures.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-A-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An information security audit was performed about the security when backup media that contain confidential information are handed over to a vendor for external storage. Among situations that are identified as a result of this audit, which of the following is a situation that the auditor should record in the audit report as a finding?', NULL, 'The person in charge at the outsourcer describes the date and details in a dedicated record book and gets a stamp of receipt from the vendor each time the media is handed over.', 'The person in charge at the outsourcer puts the backup media in a cardboard box and hands it over to the vendor.', 'The responsible person at the outsourcer concludes a contract that requires confirmation of the storage status of media at the vendor at every set period, and then the media is handed over.', 'The responsible person at the outsourcer concludes an outsourcing contract that includes confidentiality provisions with the vendor, and then the media is handed over.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-A-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the system design stage, which of the following is the point to be checked during the audit of control for reducing the risk of non-fulfillment of user requirements?', NULL, 'Programming must be performed in accordance with the specified conventions.', 'The program specifications must be created on the basis of the system design.', 'The test plan must be created on the basis of the system test requirements, and must also be approved by the responsible person in the system operations department.', 'The user department must participate in the review of the system design.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '20-A-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the “four categories ” of enterprise architecture, which of the following is the remaining one after business architecture, technology architecture, and application architecture?', NULL, 'Bus architecture', 'Data architecture', 'Software architecture', 'System architecture', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '20-A-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a workflow system is used for business improvement, which of the following is an appropriate effect that can be expected?', NULL, 'A standard protocol used for data exchange between a company and its customers can be provided.', 'Processing speed for office procedures from document submission to approval can be improved.', 'Services such as discounts can be provided according to the purchase amount of a customer.', 'Shipping and receiving of stocked products can be automated in a warehouse.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '20-A-62', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The weighted comprehensive evaluation method is used to integrate and quantify the evaluation scores of multiple items for quantitatively evaluating the effect of improvements. Which of the following is the improvement proposal that should be prioritized in the table below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-A-63.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtQS02My5wbmciLCJpYXQiOjE3NDMxMTYxMDMsImV4cCI6MTc3NDY1MjEwM30.2ulTrrUHL0vWi_V9w5e-9elLUrJ0B3QimhU37W_EV4s', 'Proposal 1', 'Proposal 2', 'Proposal 3', 'Proposal 4', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-A-63', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of BYOD (bring your own device)?', NULL, 'Carrying information devices loaned by the company for use in work', 'Configuring a usage environment for the personal use of personally-owned information devices', 'Using employees’ personally-owned information devices for work', 'Using laptop computers or other devices owned by the company for personal use outside of the company', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following descriptions corresponds to CSR procurement?', NULL, 'Choosing the product with the lowest price in order to minimize costs', 'Having multiple suppliers to avoid situations in which procurement is not possible after disasters', 'Indicating procurement standards that take the environment, human rights, etc. into account, and requiring suppliers to comply with these', 'Using EDI for purchasing goods to perform prompt and accurate procurement', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '20-A-65', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An RFP is presented to each vendor that has responded to an RFI. Which of the following should be done beforehand in order to proceed with future vendor selection processes fairly?', NULL, 'Besides the items of the RFP, giving a high evaluation to a vendor who is familiar with the current system in order to select that vendor easily', 'Establishing processes of selection, such as setting evaluation standards or weighting rules of conformity to the request items', 'Issuing unofficial agreements to all vendors to whom the RFP has been presented and requesting them to prepare a contract and a statement of work to accelerate the conclusion of the contract after vendor selection', 'Preparing bailout for a vendor that received a high evaluation on the response to the RFI in case it fails in the selection', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '20-A-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a growth matrix proposed by Ansoff, which of the following is a strategy for an organization that tries to expand a business by introducing new products into new markets?', NULL, 'Diversification', 'Market development', 'Market penetration', 'Product development', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-A-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an external factor related to company’s products, identified by SWOT analysis?', NULL, 'Strengths in product functions', 'Strengths in sales power', 'Threats by new entrants', 'Weaknesses in product quality', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-A-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Heskett classified customers into four categories and explained the importance of improving customer satisfaction. Which of the following types of customers is dissatisfied and, if given a chance, would encourage others to switch as well?', NULL, 'Captive', 'Mercenary', 'Propagandist', 'Terrorist', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-A-69', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a definition of Customer Relationship Management (CRM)?', NULL, 'A framework used to support and integrate processes, people, and information across an organization to give a unified gate-way for information and a knowledge base for employees, partners, and customers', 'A technology for managing all of a company’s relationships and interactions with customers and potential customers in order to improve business relationships', 'A type of software that organizations use to manage day-to-day business activities such as accounting, procurement, project management, risk management and compliance, and supply chain operations', 'The broad range of activities required to plan, control and execute a product''s flow, from acquiring raw materials and production through distribution to the final customer, in the most streamlined and cost-effective way possible', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-A-70', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the technology S curve?', NULL, 'It represents the diffusion process of a new technology. It shows that the growth rate of the penetration rate gradually decreases as products applying the technology penetrate the market, by using a frequency distribution curve.', 'It represents the maturing process of technology. It shows that during the time until the new technology is actually spread, the degree of awareness changes as time passes.', 'It represents the process of technological progress. It shows that technology advances slowly at the beginning and then advances rapidly, and thereafter, slowly stagnates.', 'It represents the relationship between production volume and unit cost. It shows the course of reduction in unit cost in accordance with an increase in cumulative production volume.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-A-71', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is one of the main characteristics of a blockchain?', NULL, 'A centralized ledger on a server', 'A client server network', 'A distributed ledger on a peer to peer network', 'A type of cryptocurrency', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '20-A-72', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a production plan is created, it is important to select an appropriate production system. Which of the following is a suitable production system for varied and flexible high mix low-volume production by single or several operators in charge of all processes?', NULL, 'Build-to-order production system', 'Cell production system', 'Continuous production system', 'Individual production system', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '20-A-73', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a control method for a status of “a somewhat large number” or “slightly” ?', NULL, 'Feedback control', 'Fuzzy control', 'PWM (Pulse Width Modulation) control', 'Sequence control', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '20-A-74', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a matrix organization?', NULL, 'A temporary and flexible organization in which experts are gathered together from other departments to solve specific issues with a set time frame and goal', 'An organization having functionally differentiated departments on the basis of specialized knowledge of the work, such as procurement, production, sales, and finance', 'An organization in which members usually belong both to a functional department and to a department that executes specified business', 'An organization in which self-contained management activities can be developed by possessing the functions and the profit responsibility necessary for the business execution on a per-product, per-customer, or per-region basis', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '20-A-75', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of work sharing?', NULL, 'A concept that aims for diverse and flexible working styles, for the purpose of realizing harmony between work and life', 'A method that allows employees to select welfare services within a certain range', 'A system that allows employees to choose their workplace or duty', 'An initiative for securing employment through shortening of work hours per employee and review of work assignments', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '20-A-76', -2.0, 1.0);
