INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Break-even point (BEP) is a point where total costs and total revenue are equal. The table below shows the fixed costs, price per unit, variable costs per unit, and BEP in units for Company A and Company B.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/20-A-78.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjAtQS03OC5wbmciLCJpYXQiOjE3NDMxMTYxMTIsImV4cCI6MTc3NDY1MjExMn0.g71suvUU-TGcRp7yDWZrL_N39iKrGbtT9-KqDYONsOk', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '20-A-78', 0.0, 1.0);
