INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In object-oriented programming, which of the following is an explanation of overriding that achieves polymorphism?', NULL, 'A feature that allows a class to provide a specific implementation of a method that is already provided by one of its super classes', 'Creating a class through abstraction by collecting common properties of multiple classes', 'Defining multiple methods in a class that have the same name, but differ in terms of the number of arguments, argument types, or argument order', 'Hiding internal contracts and structures of an object from its external specification', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '19-O-09', -1.0, 1.0);
