INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of cache memory?', NULL, 'Cache memory is used to fill a gap in memory capacity between the physical memory and the virtual memory.', 'Due to significant improvements in the access speed of semiconductor memory, the need for cache memory is decreasing.', 'If a cache miss occurs, an interrupt is generated, and data is transferred from the main memory to the cache memory by the program.', 'When the write instruction is executed, the cache memory is rewritten in two ways. In one, both the cache memory and the main memory are rewritten, and in the other, only the cache memory is rewritten, and the main memory is rewritten when the relevant data is removed from the cache memory.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-O-13', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When two computers have been prepared, and the computer in use fails, which of the following is the system that continues processing by promptly switching to the backup computer that has started the same online processing programs as those on the currently used computer in advance, and is on standby?', NULL, 'Cold standby system', 'Hot standby system', 'Multiprocessor system', 'Multiuser system', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-O-14', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is essential to realizing a fault-tolerant system?', NULL, 'Automatically recording the history, such as information about changes to the database, while the system is in operation in order to investigate causes of system failure and restore the system in the event of a system failure', 'Designing for easy operations so that operational errors do not occur easily, or designing operations in such a way that even if an operational error occurs, it does not result in a fatal error', 'Periodically taking a data backup so that the status prior to the failure can be restored to a reserve environment without delay in the event of a failure', 'Providing redundancy in the system configuration to minimize the impact from any failure of parts so that processing can be continued without affecting the overall system', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-O-15', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There exists a device with an MTBF of forty-five (45) hours and an MTTR of five (5) hours. What is the availability of a system that connects two (2) such devices in series?', NULL, '0.81', '0.9', '0.95', '0.99', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-O-16', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of a memory leak?', NULL, 'An increase in the number of applications executed concurrently causes most processing time to be spent for paging because of a lack of main memory, and results in an extreme reduction of throughput.', 'It is a method to insert required modules into main memory when there is a restriction on the size of the program area during execution.', 'Part of main memory reserved during operation is not released because of a bug in the OS or an application, and as a result, the usable area of main memory decreases.', 'The total amount of free space available for use in main memory is sufficient, but no space can be reserved for loading a large program because of fragmentation.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-O-17', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An operating system (OS) chooses a process for CPU execution based on a scheduling algorithm. Consider four processes, P1, P2, P3, and P4, and their corresponding arrival times along with their burst times shown in the table below. Which of the following is the correct combination of waiting times for the processes to be executed in the First-Come-First-Serve (FCFS) scheduling algorithm? Here, the arrival time is the time at which a process arrives in the ready queue, the burst time is the time required by a process for CPU execution, and the waiting time is the period of time spent by a process in the ready queue for CPU to start the execution.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-15.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0xNS5wbmciLCJpYXQiOjE3NDMxMTYxNzksImV4cCI6MTc3NDY1MjE3OX0.uGj3L5HkmgJf1VAdQpK8Q_ljTWgrdIZBTgnFGF8iRSU', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-O-18', -1.0, 1.0);
