INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate explanation of augmented reality (AR)?', NULL, 'By appealing to the five senses through equipment, such as a head-mounted display, a person can experience locations or worlds that do not actually exist as if they were real.', 'By constructing a 3D virtual space that is natural to humans, and changing the virtual space in accordance with a person’s movement, he or she can feel as if he or she is in that place.', 'By seamlessly interweaving a computer-generated information with the physical world, the viewer can perceive it as an immersive aspect of the real environment.', 'By viewing a video recorded in the past, the viewer can feel as if he or she were in that era and at that location.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-26', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Of the functions provided by a DBMS, which of the following is a means for achieving protection for data confidentiality?', NULL, 'Checking referential constraints when the data is updated', 'Managing a transaction that combines a series of processes as a logical unit', 'Managing the data access rights of users', 'Placing an exclusive lock on the data before it is updated', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-27', -1.0, 1.0);
