INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of using a message digest in a message authentication code?', NULL, 'To check the encryption method of a message', 'To check the overview of a message', 'To confirm that there is no falsification of a message', 'To secure the confidentiality of a message', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a role that a PKI certification authority performs as a reliable third party?', NULL, 'Allocating a digital signature to an e-mail body as requested by a user', 'Enabling the synchronization of time by returning an accurate time to a user’s request', 'Issuing a digital certificate that certifies the private key of a user or server', 'Issuing a digital certificate that certifies the public key of a user or server', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of a directory traversal attack?', NULL, 'By specifying a file including the path name, the attacker illegally reads an unauthorized file.', 'The attacker enters database command statements as input data for a web application and executes unexpected SQL statements.', 'The attacker guides a user to a website, where vulnerability in the escape processing of HTML output by a web application can be exploited, and then executes a malicious script on the user’s browser.', 'The attacker illegally obtains the session ID of a user who has logged into a session managed by a session ID, and then accesses the server by spoofing the identity of the user.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In ISO/IEC 27000:2018 (Information Security Management Systems – Overview and Vocabulary), which of the following is defined as the “property that an entity is what it claims to be”?', NULL, 'Accountability', 'Authenticity', 'Nonrepudiation', 'Reliability', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-O-41', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of port scanning when an attacker intrudes into the system?', NULL, 'To investigate if evidence of attack remains in the system log at the post-processing stage', 'To investigate if there is a service that can be attacked at the preliminary investigation stage', 'To investigate if there is an account whose privileges can be deprived at the privilege acquisition stage', 'To investigate if there is user information that is beneficial to the attacker at the performance stage of a fraudulent act', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-42', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description that corresponds to two-factor authentication?', NULL, 'Authentication is performed by two (2) different passwords.', 'Authentication is performed by using a password that contains two (2) different types of special characters.', 'Authentication is performed by using the fingerprints of two (2) fingers.', 'Authentication is performed by using the iris and a password.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-43', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the combination of processes that constitutes risk assessment?', NULL, 'Risk analysis, risk evaluation, and risk response', 'Risk analysis, risk response, and risk acceptance', 'Risk identification, risk analysis, and risk evaluation', 'Risk identification, risk evaluation, and risk acceptance', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-44', -1.0, 1.0);
