INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method for preventing an SQL injection attack?', NULL, 'If an input text contains HTML tags, replacement of these tags with other character strings that are not interpreted as HTML tags', 'Nonacceptance of an input text if the overall length of the text exceeds the limit', 'Nonacceptance of an input text that contains a character string that specifies a higher level directory ( . . / )', 'Preventing input characters from being interpreted as characters that have a special meaning in an inquiry or operation on the database', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In object orientation, which of the following is the name of being able to use the attributes and functions of a class in a subclass of that class?', NULL, 'Encapsulation', 'Inheritance', 'Override', 'Polymorphism', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '19-O-47', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the development process, which of the following is an activity that should be performed in software architecture design?', NULL, 'Converting the requirements for a software item into an architecture that represents the top-level structure and identifies software components', 'Refining a program so that the processing of each coded line is clarified', 'Seeking comments from the customer and determining a specification', 'Summarizing the requirements in the form of diagrams and tables, and refining and analyzing them in stages', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '19-O-48', -1.0, 1.0);
