INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate test to ensure that the interfaces and linkages between different parts of software work properly?', NULL, 'Functional test', 'Integration test', 'Performance test', 'Unit test', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '19-O-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among eXtreme Programming (XP) practices, which of the following is adopted to improve program quality in program development through smooth communication between programmers by exchanging their roles and checking each other’s work?', NULL, 'Coding standard', 'Pair programming', 'Planning game', 'Test-driven development', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '19-O-51', -2.0, 1.0);
