INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the technique for estimating activity durations where past information is statistically analyzed and various coefficients are determined?', NULL, 'Analogous estimate', 'Bottom-up estimate', 'Parametric estimate', 'Three-point estimate', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '19-O-53', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the critical path of the project activities shown in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-O-54.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktTy01NC5wbmciLCJpYXQiOjE3NDMxMTYyNTUsImV4cCI6MTc3NDY1MjI1NX0.DZw4rSXaJ7ydRb8dzVtvAsBI0eV4rJh1mEpHSEhCUuE', 'A -> B -> E -> I -> L', 'A -> C -> D -> E -> H -> K', 'A -> C -> F -> I -> L', 'A -> C -> G -> J -> L', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '19-O-54', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In order to analyze the trend of issues that occur in a project, the number of issues by management item, such as the stakeholders, cost, schedule, quality, etc., are arranged in order starting with the highest number of issues in the form of a bar graph, and a diagram is prepared in which the number of issues accumulated in this order are superimposed in the form of a line graph. Which of the following is this diagram?', NULL, 'Cause and effect diagram', 'Control chart', 'Pareto diagram', 'Scatter diagram', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '19-O-55', -1.0, 1.0);
