INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IT service management, which of the following is a problem management activity that is performed proactively?', NULL, 'Analyzing the occurrence trend of incidents and proposing measures that prevent an incident from occurring in the future', 'Classifying problems that have been detected and recorded, and setting the response priority', 'Evaluating the effectiveness of a resolution to a critical problem', 'Monitoring whether an incident occurs again or not for a certain period of time after the problem is resolved', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-O-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the structures and the characteristics of a service desk organization, which of the following is a description of a local service desk?', NULL, 'By locating a service desk near the users, it is possible to provide support for users who speak different languages or come from different cultures, and to provide support for VIPs by dedicated staff.', 'By using communication technology, services can be provided as if they were provided from a single service desk, even when service staff are dispersed across multiple regions or departments.', 'Service staff can efficiently be deployed, or a large number of calls can be handled by concentrating service desks at a single site or at limited locations.', 'Well-controlled services can be provided by centrally integrating and managing all staff, including those at dispersed locations.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-O-58', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate activity for a system auditor?', NULL, 'The auditor moves forward with the preparation of an audit report because the initially scheduled period finished in the middle of an investigation.', 'The auditor orders improvements for problems that are found in the course of each investigation.', 'The auditor points out items that need to be improved regarding problems found during the investigation.', 'The auditor summarizes audit opinions for matters that have not been fully investigated, on the basis of his or her past experience.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-O-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the implementation structures of a system audit, which of the following is the most important to avoid from the standpoint of the independence of a system auditor?', NULL, 'Mr. A of the general affairs department, who was appointed as a member of the audit team, audits the status of entrance and exit control for the general affairs department together with other team members.', 'Mr. B of the audit department audits the status of personal information management by an external contractor to whom his company outsources business operations that deal with personal information.', 'Mr. C, who was transferred to the audit department five (5) years ago from a development manager position in the information system department, audits the status of Internet use in the marketing department.', 'Mr. D of the legal department cooperates with an auditor in an audit of the validity of an outsourcing contract in response to a request from the audit department.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an information security audit, which of the following is a check item for confirming availability?', NULL, 'Appropriate performance of error checking for data entry', 'Encryption of databases', 'Managing and maintaining the level of SLA that defines downtime', 'Prohibiting the taking of external storage media out of the company without permission', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-O-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of SCM (Supply Chain Management)?', NULL, 'Customer information collected through various channels is consolidated and utilized to establish closer relationships with customers.', 'Employees’ skills and behavioral characteristics are managed for appropriate personnel assignment and evaluation from the perspective of human resources strategy.', 'Intellectual assets of individuals, such as know-how and experience, are shared as inspiration for creative work.', 'The sequence of business operations, from purchasing and production to sales and distribution, is reexamined across companies in view of total optimization, so as to minimize inventory and accelerate delivery.', 'd', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '19-O-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Concerning computerization costs, which of the following is the cost that indicates the running cost?', NULL, 'The consulting cost of information systems strategy planning', 'The cost of system engineering for performance requirements definition', 'The installation cost of software packages', 'The maintenance cost of information-processing equipment, such as a server', 'd', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '19-O-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of BPM?', NULL, 'To achieve a reduction in inventory and a shortening of lead time by exchanging information about a series of business processes, from the supply of components to the sale of products, in real time', 'To achieve overall optimization of management resources through consolidated information management of the main corporate activities, such as production, materials flow, sales, finance, and human affairs', 'To incorporate the management cycle of analysis, design, execution, and improvement into business processes in order to continuously execute improvement and revision of business processes', 'To perform consistent management of business processes that concern the customer, which include not only the sales of products but also maintenance service and the handling of queries and claims, based on a customer database', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '19-O-64', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of SaaS?', NULL, 'It is a service where the user uses the functions of application software via the Internet only when necessary.', 'It is a software package for performing integrated management of mission-critical business operations in order to effectively employ the management resources of a company.', 'It refers to a document of consent concerning the content of service quality between the ordering company and the service provider.', 'It refers to a far-reaching revision of the existing organization and business processes, and the redesigning of duties, business flow, management mechanism, and information systems.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-65', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following should be undertaken in order to eliminate the “digital divide”?', NULL, 'Estimating IT investment, setting result targets based on investment goals, and performing prior evaluation of the feasibility of achieving each result target', 'Increasing learning opportunities for information literacy, and preparing an environment to further facilitate the use of information & telecommunications equipment and information services', 'Reducing energy consumption by promoting the efficiency of business operations with the help of IT, including telecommuting, energy savings for electrical appliances and facilities, and so forth', 'Using IC tags to enable the tracking of distribution information on products and foodstuffs, in all processes from production to final consumption or disposal', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-O-66', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the non-functional requirements definition?', NULL, 'It clearly identifies business functions that are difficult to implement in a system, and that constitute manual operation, from among business requirements.', 'It clearly identifies the conformity of a new package to be installed in order to implement business requirements.', 'It clearly identifies the functions that are lacking in the current system in order to determine business requirements.', 'It clearly identifies the quality requirements, technical requirements, and operational requirements necessary to implement business requirements.', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '19-O-67', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an external factor concerning an in-house product identified using SWOT analysis?', NULL, 'Cost competitiveness', 'Functional strengths', 'Quality-related weaknesses', 'Threats owing to a new entry', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-O-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the “competitive strategy” proposed by Philip Kotler, which of the following describes a company that has no high market share, but has the strategic aim to increase income and acquire a unique position by focusing management resources on particular products and services?', NULL, 'Market challenger', 'Market follower', 'Market leader', 'Market nicher', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-O-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique for separating company activities into core activities and support activities for each business function, and analyzing which activities generate the profit derived from the products and services provided to customers?', NULL, '3C analysis', 'Five forces analysis', 'SWOT analysis', 'Value chain analysis', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-O-70', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of knowledge management?', NULL, 'A flat organization structure with minimal hierarchical layers is maintained to accelerate decision-making.', 'Comparative analysis with other successful companies is performed to drive management innovation.', 'Knowledge scattered across an enterprise is shared to improve overall problem-solving capability.', 'Management is centered on proprietary know-how and technology that are not easy for other companies to imitate.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-O-71', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of CAD?', NULL, 'Evaluating product performance and functions using computers, without using the actual product to perform testing or experimentation', 'Using a computer to convert product design drawings to process design information, and support automation of machine processing, etc.', 'Using a computer to create product design drawings from attribute data concerning product shape, composition, etc.', 'Using a computer to derive the required volumes and timing of materials from a production schedule, a BOM (bill of materials), inventory volumes, etc.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-O-72', -2.0, 1.0);
