INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of EDI?', NULL, 'A communication service that provides added value, such as the storage of data transmitted over networks and conversion of data formats', 'An international standard for e-mail services based on the OSI basic reference model, which provides comprehensive services for the generation, transmission, and processing of messages', 'An ordering system that allows orders to be placed by transmitting order information from a data entry terminal to the head office or a supplier', 'The exchange of business transaction data between computers (including terminals) over the Internet on the basis of standard protocols', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-O-74', -2.0, 1.0);
