INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate method to forecast the amount of revenue during an upcoming promotion at a store, based on historical data?', NULL, 'Cluster analysis', 'Delphi method', 'Pareto analysis', 'Regression analysis', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-O-76', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of a scatter diagram?', NULL, 'It is a chart used to determine if a relationship, pattern, or trend exists between two numeric attributes.', 'It is a chart used to summarize the frequency distribution of a given attribute.', 'It is a type of chart that contains both bars and a line graph, where individual values are represented in descending order by bars, and the cumulative total is represented by a line.', 'It is a type of chart used to determine whether a process is in a stable state or not, and it plots characteristic values based on temporal transition.', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-O-77', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a company sells a product at 17 dollars per unit, and the fixed costs and the variable costs are as shown in the tables below (in dollars), how many units does the company have to sell to earn a profit of 42,000 dollars?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-O-78.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktTy03OC5wbmciLCJpYXQiOjE3NDMxMTYyNjIsImV4cCI6MTc3NDY1MjI2Mn0.muAWlq8CEuPLL7j8S21UIrkibjJpLOZEpRC2FNO0Mm0', '10,200', '14,200', '16,200', '18,200', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-O-78', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following inventory valuation methods calculates the inventory unit price by dividing the total purchase amount by the total quantity of items purchased at the end of the accounting period?', NULL, 'First-in- first-out method', 'Last-in- first-out method', 'Moving average method', 'Periodic average method', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-O-79', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the scope of software protection under Agreement on Trade-Related Aspects of Intellectual Property Rights (TRIPS)?', NULL, 'Algorithms and programming languages are protected.', 'Application programs are protected but basic programs such as an OS are not covered, as the value of the right is included in the hardware cost.', 'Both source programs and object programs are protected.', 'Documents that describe algorithms are protected, but programs created by using the algorithms are not protected.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-O-80', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For an eight-bit integer x represented in two’s complement format, which of the following yields the value of 5x? Here, the overflow or underflow can be ignored in this multiplication.', NULL, 'Shift x to the left by 1 bit, then add the initial value of x to it.', 'Shift x to the left by 2 bits, then add the initial value of x to it.', 'Shift x to the right arithmetically by 1 bit, then subtract the initial value of x from it.', 'Shift x to the right arithmetically by 2 bits, then subtract the initial value of x from it.', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '19-A-01', -1.0, 1.0);
