INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The flowchart below shows the algorithm of concatenating two character strings in X and Y, with the resulting character string in Z. Which of the following is the appropriate pair of operations to insert in the blanks, A and B? Here, X and Y are character arrays of dimensions m and n, respectively, where the i-th character of each string is stored as the i-th element of the character array.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-08.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS0wOC5wbmciLCJpYXQiOjE3NDMxMTYzMDIsImV4cCI6MTc3NDY1MjMwMn0.3eyNvE3CUGcbuaDTZcWICiePS2RqISDlTxiYl-s0Pdw', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '19-A-08', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For a processor running at 50 MIPS, what is the average execution time per instruction?', NULL, '20 ns', '50 ns', '2 µs', '5 µs', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-09', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate characteristic of SRAM compared to DRAM? Here, SRAM and DRAM are compared in products manufactured in the same or similar semiconductor geometric process.', NULL, 'SRAM consumes more power, particularly when idle, compared to DRAM.', 'SRAM is non-volatile, whereas DRAM is volatile.', 'SRAM needs to be refreshed, whereas DRAM does not.', 'SRAM uses more transistors in a memory cell compared to DRAM.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-10', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a memory system that has a cache memory, which of the following causes an increase in the average memory access time?', NULL, 'A decrease in the access time to the cache memory', 'A decrease in the cache hit rate', 'A decrease in the cache miss penalty', 'A decrease in the cache miss rate', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-11', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There exists a storage system in which one (1) block is composed of eight (8) sectors of 500 bytes each, and the storage area is block-wise allocated to the files. When a 2,000-byte file and 9,000-byte file are to be saved, what is the total number of sectors that is allocated to these two (2) files? Here, the sectors that are occupied by the directory information and other such management information can be ignored.', NULL, '22', '26', '28', '32', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-12', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning the recording method of RAID5?', NULL, 'It distributes the data over multiple hard disk drives, writes the data in units of bits, and writes the ECC (Error Correction Codes) on multiple hard disk drives.', 'It distributes the data over multiple hard disk drives, writes the data in units of blocks, and distributes and writes the parity on multiple hard disk drives.', 'It distributes the data over multiple hard disk drives, writes the data in units of bytes, and writes the parity on one (1) hard disk drive.', 'It writes the same data on two (2) hard disk drives to create a mirror disk.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-13', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description of a dual system?', NULL, 'It loads the online processing program of the active system on to a backup system and sets it to a standby status. In the event of a failure in the active system, it immediately switches to the backup system and continues the processing.', 'It prepares a duplicate processor, memory, communication channel, and power supply system and continues the processing even in the event of a failure in any of the devices.', 'It provides a duplicate system for performing the same processing and checks the accuracy of the processing by collating the processing results. In the event of a failure in either system, it continues the processing by the degraded operation.', 'It provides an active system for performing online processing and keeps a backup system on standby while batch processing is being performed. In the event of a failure in the active system, it switches to the backup system and continues the online processing.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-14', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A system has devices with availability R, connected as shown in the figure below. Which of the following is the expression that represents the availability of the entire system? Here, a parallel connection only requires either of the two devices to be functional, whereas a series connection requires both the devices to be functional.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-15.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS0xNS5wbmciLCJpYXQiOjE3NDMxMTYzMjksImV4cCI6MTc3NDY1MjMyOX0.v_EawzAIJXyddn-81TB6Zcv4va-1Hg0uzDVvYbjzVps', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-15-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS0xNS1BLnBuZyIsImlhdCI6MTc0MzExNjMxMSwiZXhwIjoxNzc0NjUyMzExfQ.PdItgWLZqISBxHXy4M5oxi8gAwexpRnOOs7riDyxSg4', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-15-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS0xNS1CLnBuZyIsImlhdCI6MTc0MzExNjMxNywiZXhwIjoxNzc0NjUyMzE3fQ.JcXkkHdEvOeFb1vWdEazZZHNQzeEK-F6z0Rw5QHtqoE', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-15-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS0xNS1DLnBuZyIsImlhdCI6MTc0MzExNjMyMywiZXhwIjoxNzc0NjUyMzIzfQ.LxK4KfcIDyF8sFO3uS9j3eGOXEC6hz8jBDfN-pooRQc', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-15-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS0xNS1ELnBuZyIsImlhdCI6MTc0MzExNjMyNiwiZXhwIjoxNzc0NjUyMzI2fQ.Y2N2rfbn377X0RvlRugxgDElICM3EdHdRxJLgSP1wdI', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-15', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of paging?', NULL, 'A method of memory management in which multiple records are read and written as a block on an auxiliary storage', 'A method of memory management in which the main memory is divided into multiple areas so that reading and writing can be performed simultaneously', 'A method of memory management in which the programs are relocated for execution in a different area of the main memory', 'A method of memory management in which the virtual memory space and real memory space are divided into fixed-length blocks for management', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-16', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method that performs data transfer between the main memory and a low-speed output device via a high-speed auxiliary storage device to increase the throughput of the entire system?', NULL, 'Blocking', 'Paging', 'Spooling', 'Swapping', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-17', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the figure below, data are sent continuously for T seconds from the send task to the receive task. When the volume of the data sent per second is S and volume of the data received per second is R, which of the following is an appropriate relational expression for buffer size L for a buffer that does not overflow? Here, the transmission speed for the send task is faster than the transmission speed for the receive task, and there is sufficient time between the transmissions.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-A-14.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtQS0xNC5wbmciLCJpYXQiOjE3NDMxMTYzNDUsImV4cCI6MTc3NDY1MjM0NX0.Yt5aRyLDWDxwsRyOiXAe9VnFwQ8waKh8UkgdNWHnJNI', 'L < ( R − S ) × T', 'L < ( S − R ) × T', 'L ≧ ( R − S ) × T', 'L ≧ ( S − R ) × T', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-18', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('On a virtual memory computer, the number of pages that can be allocated to the real memory is three (3), and the two (2) algorithms of FIFO and LRU are used for selecting the page to be removed. When a page reference string shown below accesses the three (3) pages, which of the following is an appropriate combination of the number of page replacement operations? Here, the three (3) pages are initially empty and filling of an empty page is not considered as a page replacement operation. 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A real-time OS performs preemptive scheduling on a priority basis and schedules two (2) tasks A and B. When A has a higher priority than B, which of the following is an appropriate task management by the real-time OS?', NULL, 'When A is launched during the execution of B, B is assigned a “ready” status and A is executed.', 'When A is launched during the execution of B, B is assigned a “waiting” status and A is executed.', 'When B is launched during the execution of A, A is assigned a “ready” status and B is executed.', 'When B is launched during the execution of A, A is assigned a “waiting” status and B is executed.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '19-A-20', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the function of an actuator?', NULL, 'It changes an analog electrical signal into a digital electrical signal, which a computer can process.', 'It changes an electrical control signal that is supplied by a computer into a mechanical motion.', 'It identifies a physical quantity and changes it into an electrical signal.', 'It is used in devices such as a keyboard or touch panel to enter data in a computer.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-21', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate example of utilizing an RFID?', NULL, 'Close range transmission of data using infrared rays', 'Identification and management of personnel or items by using a very small wireless chip', 'Input of information by using a reader to read a digital code that is printed on a paper', 'Transmission of audio data between a cellphone and headphones', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-22', -2.0, 1.0);
