INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In 3D computer graphics, which of the following is an explanation of hidden-line removal or hidden-surface removal in rendering?', NULL, 'By analyzing the position of the light source and how much light hits the target object, its color and brightness are determined.', 'For the generated image, only the portion that fits the computer display is rendered.', 'For the target object, only the portion that is viewable from a specified viewpoint is rendered.', 'Using a wireframe model with translucency, not only the surface but also the inside of the target object is rendered.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-25', -1.0, 1.0);
