INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an SQL statement, which of the following is a constraint that is specified with FOREIGN KEY and REFERENCES?', NULL, 'Assertion', 'Check constraint', 'Key constraint', 'Referential constraint', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-27', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a client/server system, which of the following is the mechanism that reduces the network load between the client and server by placing the frequently used commands on the DBMS on the server in advance?', NULL, 'Group commitment', 'Multithreading of server processes', 'Stored procedure', 'Two-phase commitment', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-28', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic to guarantee that the result of an update transaction is either performed completely or canceled as if nothing happened?', NULL, 'Atomiticity', 'Consistency', 'Durability', 'Isolation', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-29', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the process that is executed periodically to prevent reducing the access efficiency of the database?', NULL, 'Backup', 'Database dump', 'Reorganization', 'Roll back', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-30', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IPv4, which of following describes the NAT function of a router that connects some computers to the Internet?', NULL, 'It caches the Internet access to speed up the connections when revisiting the same websites.', 'It converts between private and global IP addresses.', 'It inspects the IP packets in a transmission to detect possible attacks and intrusions from the Internet.', 'It only passes the IP packets intended for specific terminals.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a feature of a switching hub (layer 2 switch) network device?', NULL, 'It breaks a received packet into smaller pieces (fragments) in the network layer.', 'It dynamically allocates an IP address for a terminal connected to its LAN port.', 'It forwards a received packet only to its LAN port connected to a device with the packet’s destination MAC address.', 'It forwards a received packet to all its LAN ports (broadcast).', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-32', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the network routing and addressing mechanism that is used in IPv6 but not in IPv4?', NULL, 'Anycast', 'Broadcast', 'Multicast', 'Unicast', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-33', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an IPv4 network with subnet mask 255.255.255.224, what is the maximum number of host addresses assigned?', NULL, '14', '20', '26', '30', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-34', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a protocol that uses TCP as its transport layer protocol?', NULL, 'DHCP', 'SNMP', 'TELNET', 'TFTP', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The IP address of Server X prepared by an attacker was stored in a DNS cache server of Company B as the IP address corresponding to the FQDN of the web server of Company A. Which of the following users will be unintentionally guided to Server X because of this attack? Here, each employee of Company A and Company B performs name resolution by using the DNS cache server of his/her own company.', NULL, 'An employee of Company A who wishes to access the web server of Company A', 'An employee of Company A who wishes to access the web server of Company B', 'An employee of Company B who wishes to access the web server of Company A', 'An employee of Company B who wishes to access the web server of Company B', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of a directory traversal attack?', NULL, 'An attacker enters data consisting of database command statements as the input data for a web application and forces the execution of SQL statements that are not intended by the administrator.', 'An attacker guides a user to a web site, where a defect in the escape processing of the HTML output by a web application is exploited, and forces the execution of a malicious script on the user’s web browser.', 'An attacker illegally obtains the session ID for a user, who has logged into a session managed by the session ID, and accesses the server by spoofing the identity of the user.', 'An attacker specifies a file by using the path name and illegally views a file that is not intended for viewing by the administrator.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of a brute force attack by which an attempt is made to find the key of private key cryptography?', NULL, 'Finding the key by observing the ciphertext change when the plaintext is changed by a certain amount', 'Finding the key by testing all key combinations sequentially when a set of plaintext and ciphertext is given', 'Finding the key by using as a clue the algebraic expression representing the relationship between the plaintext, ciphertext, and key', 'Finding the key by using as a clue the statistical correlation between a part of the information of the plaintext and part of the information of the ciphertext', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-38', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the time stamp service in information security?', NULL, 'It is a service that authenticates biometric information, such as fingerprint, voice print, vein patterns, retina, and iris, by using the date and time when the information is registered in the authentication system.', 'It is a service that certifies that electronic data certainly exist on a particular date and time and that the data have not been falsified since that date and time.', 'It is a service that securely notifies that the date and time information is not falsified midway for setting the clock of the PCs and servers on the network.', 'It is a web service that securely displays the global date and time information used in the official records by using encrypted communication.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-39', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an encryption algorithm for public key cryptography?', NULL, 'AES', 'KCipher-2', 'RSA', 'SHA-256', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-40', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a security attack that prevents users from accessing their accounts?', NULL, 'Brute force', 'Denial of Service', 'Man in the middle', 'Sniffing', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-41', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a botnet?', NULL, 'A collection of internet-connected devices, including IoT devices, infected and controlled by a common type of malware', 'A scalable and reliable network of self-driving vehicles communicating with each other to avoid accidents/collisions', 'A set of honeypots designed to detect and analyze malicious activities by hackers to secure the production systems in the future', 'A wireless network for industrial robots created for collaborative manufacturing in a factory to ensure quality at all levels', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-42', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An attacker captures unencrypted network traffic with a tool and later analyzes it offline to learn about the information contained in those transmissions. Which of the following is this attack?', NULL, 'Buffer overflow attack', 'Phishing attack', 'Smurf attack', 'Sniffing attack', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the technique of actually attempting an attack and intrusion on a system to detect the security-related vulnerabilities of a computer or network?', NULL, 'Penetration test', 'Regression test', 'Software inspection', 'Walk-through', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As shown in the figure below, an application on a client accesses the data of the database on a server via database connection programs. Which of the following is a measure for preventing the leakage of the commands and execution results transmitted between the application and database?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-45.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS00NS5wbmciLCJpYXQiOjE3NDMxMTY0MjQsImV4cCI6MTc3NDY1MjQyNH0.AD_B4buyKuqtduk02EyqDlSCi42uufnRjGizKD1ypH8', 'Changing the port number from its initial value that the database connection programs use for communication in the database management system', 'Encrypting the communication between the database connection programs', 'Restricting the IP addresses of the clients that can access the database connection program on the server to only those that are required', 'Setting a password for starting or stopping the database connection program on the server', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-45', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the UML class diagram, which of the following represents the relationship between the classes as shown in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-46.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS00Ni5wbmciLCJpYXQiOjE3NDMxMTY0MjgsImV4cCI6MTc3NDY1MjQyOH0.pdvqzrNPEYN1GFU3Ute8iykK4DSIgeluhpygza1oxRE', 'Aggregation', 'Association', 'Composition', 'Generalization', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '19-A-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of encapsulation in object orientation?', NULL, 'Abstraction and sorting of several objects that have the same nature', 'Combination of the data and procedures that operate the data into a single object, and their concealment from outside the object', 'Extraction of the nature shared between classes and creation of a base class', 'Inheritance of the nature of a base class by a subclass', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '19-A-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following can generally be called a subclass of an “automobile” based on the concept of object orientation?', NULL, 'Engine', 'Manufacturing number', 'Tire', 'Truck', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '19-A-48', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the flowchart below, what is the minimum number of test cases that satisfies the decision condition coverage (branch coverage)?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-49.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS00OS5wbmciLCJpYXQiOjE3NDMxMTY0MzUsImV4cCI6MTc3NDY1MjQzNX0.iGWrWveupTm5aUcQB1t-4NeIqIwK2ASNPNG180r8BNY', '1', '2', '3', '4', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '19-A-49', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the software development activities, which of the following corresponds to refactoring, which is also emphasized in agile development?', NULL, 'To improve the maintainability of a software, the internal structure of a program is changed without any change in the external specifications.', 'To improve the quality of a software, two (2) programmers cooperate with each other and perform coding of one (1) program.', 'To obtain feedback from the users, a prototype of the software to be provided is created at an early stage.', 'To promptly develop a software to be operated, test cases are set in advance, and then the program is coded.', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '19-A-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the PERT diagram as shown in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-51.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS01MS5wbmciLCJpYXQiOjE3NDMxMTY0MzgsImV4cCI6MTc3NDY1MjQzOH0.cXJrFIuT77XvMljs_zzhtiicUzfTQZ06aeAQvhR05hU', 'The critical path is A – C – G.', 'This project needs at least 11 days', 'When the activity F becomes unnecessary, the project will end 1 day earlier.', 'When the activity H has a delay of 2 days, it will cause the project to be delayed by 2 days.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '19-A-51', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('By using the triangular distribution formula of the three-point estimation technique, which of the following is the expected duration (in days) required for an activity? The estimations are as shown below.
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A project is planned to complete in 12 months and the budget for the completion of the project is $100,000. After six months, it is found that $60,000 are spent, but only 40% of the work is completed. If the Cost Performance Index (CPI) is not changed, what is the estimated amount (in dollars) required to complete the remaining tasks of the project?', NULL, '40,000', '60,000', '90,000', '150,000', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '19-A-53', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate cost estimation technique that estimates the cost of an activity or project using the historical data from a similar project?', NULL, 'Analogous estimating', 'Bottom-up estimating', 'Function point method', 'Parametric estimating', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '19-A-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description concerning a backup method for data in a new system?', NULL, 'In consideration of a possible increase in the response time in the business processes, the backup schedule is adjusted so that it does not overlap with the business processes.', 'To save the backup data for a long period of time, a random-access medium is used.', 'To shorten the time taken for recovery from the backup data, a differential backup is used.', 'To shorten the time taken for the backup process, the backup data are placed in the same storage medium as the source data.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-A-55', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For servers, the total cost of ownership (TCO) is calculated over a period of 5-years. The purchase price of the servers is $120,500 and the other annual costs are listed as below.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-A-56.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktQS01Ni5wbmciLCJpYXQiOjE3NDMxMTY0NDYsImV4cCI6MTc3NDY1MjQ0Nn0.Cf6e8BTbbpfVk-uen-G4xZSiURuLeogOhz5XPdeLqIM', '28,100', '120,500', '140,500', '622,500', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-A-56', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In ITIL, the reduction in the index value expressing the maintainability is cited as an example of a KPI (Key Performance Index) in availability management. Which of the following corresponds to such an index?', NULL, 'Mean time between failures', 'Mean time between service incidents', 'Mean time to restore service', 'Number of interruptions in a certain period', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-A-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the system audit implementation structure that should be avoided from the standpoint of independence of the system auditors?', NULL, 'A person, who five (5) years ago was transferred to the audit department from a development manager position in the information systems department, audits the status of the Internet usage in the marketing department.', 'A person in the audit department audits the status of the personal information management in the external contractor to whom personal information handling is outsourced.', 'A person in the general affairs department, who is appointed as a member of the audit team, audits the status of the entrance and exit control in the general affairs department, together with the other members.', 'A person in the legal department, in response to a request by the audit department, cooperates with the auditors in auditing of the validity of the outsourcing contracts.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-A-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate activity that is undertaken by a system auditor who audits access control?', NULL, 'Confirmation of the management status of the access control concerning the data', 'Creation and storage of a management table for the access control concerning the software', 'Establishment of a management policy for the access control concerning the network', 'Implementation of the operations management for the access control concerning the hardware', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-A-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is subject to system audits that evaluate and verify the internal control related to IT?', NULL, 'The methods for ensuring accuracy in the processes of input and update of a database performed by the sales department', 'The process for the creation of a mid-term business plan by the business planning department', 'The results of the employee personnel evaluations by the personnel department', 'The status of the production equipment review conducted by the manufacturing department for the purpose of reducing defects', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '19-A-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a case that enables the customer support operations at a call center to improve the quality by applying a pattern recognition function or machine learning function to the accumulated data?', NULL, 'Deriving the most appropriate response in real time from the related materials and all the previous support history according to the content of the inquiry made by a customer', 'Displaying the digital content of a response manual or basic customer information on a pop-up window of a screen for responding to the requests from the operators', 'Repeatedly providing a roll play training to new operators from an experienced operator who serves as a lecturer by using the response manual as the teaching material', 'Transferring a phone call or the relevant support screen to an experienced operator or a dedicated staff when the operator who is responding to a customer over the phone is unable to provide an answer', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When an UML is used for business modeling, which of the following is the diagram that can represent a workflow such as the execution sequence of the business processes and branching based on conditions?', NULL, 'Activity diagram', 'Class diagram', 'Component diagram', 'Object diagram', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '19-A-62', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of the SOA?', NULL, 'A concept of constructing a system by considering the software functions as components called services and combining them', 'A concept of improving the sales efficiency and quality by using IT for the sales activities to increase the sales and profits as well as to improve customer satisfaction', 'Outsourcing the in-house operations other than those of the core businesses to concentrate the management resources on the core businesses', '', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '19-A-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a scheme where the user establishes a connection to the system of a service provider via the Internet and makes online use of only the necessary functions of the applications provided by the service provider at the necessary time?', NULL, 'ERP', 'SaaS', 'SCM', 'XBRL', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A company chooses products and services that are acknowledged as actively addressing environmental concerns. What is this initiative called?', NULL, 'CSR', 'Environmental assessment', 'Green procurement', 'Macro environment analysis', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-A-65', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a developmental process of utilizing big data is classified into the four (4) stages below, which of the following is an example that corresponds to the fourth stage?
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a growth matrix proposed by Ansoff, which of the following is a strategy for expanding a business with an existing product in an existing market?', NULL, 'Diversification', 'Market development', 'Market penetration', 'Product development', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-A-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of the growth stage in a product life cycle?', NULL, 'Demand decreases, and the withdrawal of some companies is seen. A decision needs to be made regarding whether it is possible to gain a strong foothold at this stage. Migration into an alternative market is also considered.', 'Demand is occasional, and the exploitation of new demand is the key to success. Conviction for succeeding in a specific target market is necessary.', 'Demand reaches a peak, and the differentiation of the product and segmentation of the market become clear. The competition between the competitors also intensifies, and it becomes important to add new product types and reduce the cost.', 'The market starts to understand the worth of the product. Both the product line and channel need to be expanded. This stage sees an increase in the sales and also requires investment.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-A-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following marketing approaches is for the push strategy?', NULL, 'A manufacturer distinguishes customers into profitable and non-profitable ones so that the manufacturer can provide priority services to the profitable customers.', 'A manufacturer does his/her best to predict what customers want before producing an item or service.', 'A manufacturer receives requests from customers for their own version of products or services they want, so that the manufacturer can produce them.', 'A manufacturer tries to achieve much closer and one-to-one contact with the customers for producing new products.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-A-69', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following can take advantage of the cell production method?', NULL, 'Products that need to be mass produced to increase productivity', 'Products that require division of labor by standardization, simplification, and specialization', 'Products that require flexible production to produce a variety of types', 'Products whose specifications do not change for a long period', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-A-70', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is not appropriate as an application example of the IoT (Internet of Things)?', NULL, 'A computer that independently performs file management, arithmetic and logic operations, printing processing, and other tasks without accessing a server to avoid the security problems on the Internet', 'A system that allows the manufacturer to understand the operating status, failure locations, and parts that require replacement in real-time via the Internet by having sensors and a communication function built in a large-scale construction equipment', 'A system that collects automobile location information in real time and distributes the traffic jam information by communication between automobiles or between automobiles and road side units', 'An electricity meter that sends information on the amount of power usage by communication with a power company in lieu of a meter reader', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-71', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of CGM (Consumer Generated Media)?', NULL, 'It allows the customers of a company who want to join a mailing list to register on it and periodically receive information via e-mail.', 'It enables the delivery of the digital contents prepared by an individual to a viewer or audience and its sharing between the users.', 'It offers functions for trading goods in an auction format and works as an intermediary for the consumers in personal trading.', 'It provides a common ground for online shops of individual storekeepers and takes over the tasks of issuing common points and settling credit card payments.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-A-72', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of the long tail?', NULL, 'A link to a company is placed on a website or blog, and the company pays a referral fee when the product is purchased via the link.', 'By directly shipping products from manufacturers or wholesalers, one can sell products on his or her own website without taking a risk of inventories.', 'It performs necessary processing, including integrated and systematic management, and delivery of digital content such as text and images that comprise web content.', 'The accumulated sales of the product groups that are not selling well account for a percentage that cannot be ignored against the total sales in Internet shopping.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '19-A-73', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a use case of deep learning to improve the performance of an in-car device?', NULL, 'An accelerometer detects the collision of the vehicle against a wall and causes the air bag to blow up, thus protecting the passenger from injury.', 'By installing equipment that automatically performs idling stop, the fuel efficiency improves as compared with the case when a driver with a vast experience of driving drives a vehicle.', 'By the acquisition and processing of numerous images, the driver assistance system can distinguish between a pedestrian and vehicle more reliably.', 'The navigation system updates the software by a mobile phone line and refreshes the map.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '19-A-74', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a major role of a CIO?', NULL, 'The CIO creates a plan for optimizing the effect of investment on the information resources of the entire company to support the business strategy when a computerization strategy is established.', 'The CIO gives advice to the information system department by auditing whether the information system is functioning appropriately with respect to the corporate activities.', 'The CIO receives queries about the information system, reports on the problems, and gives specific instructions to the department in charge so that the information system of the entire company can be managed optimally.', 'The CIO understands the status of the information system development and operation and specifically instructs improvement points so that the information system of the entire company functions optimally.', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '19-A-75', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of the OJT?', NULL, 'A dedicated approach to education is possible by staying away from the work place.', 'Because the boss or a senior associate imparts hands-on knowledge and technical education by staying close to practical affairs, the required competency can be acquired.', 'Education that focuses on generalized knowledge and technology can be received.', 'Regardless of the qualification of the boss or senior associate, occupational knowledge of a specific standard can be acquired.', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-A-76', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of the ABC analysis?', NULL, 'It analyzes a region in more detail based on various data (population, purchasing power, etc.) by dividing the region into a grid with multiple sections.', 'It arranges products in the order of high sales or high gross profit, divides into levels based on the cumulative ratio, and then plans to increase the volume of the sales of products at the high levels.', 'It classifies and aggregates multiple parts of the survey data by a factor and analyzes the sales capacity and status of purchasing the same products.', 'It repeatedly surveys the same panelist (respondent) many times. This data is used to understand the trends in the region or changes in the purchasers.', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-A-77', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a financial statement that represents the assets, liabilities, and net assets of a company at a certain point of time and indicates the financial situation of the company?', NULL, 'Balance sheet', 'Cash flow statement', 'Income statement', 'Statements of shareholder''s equity', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-A-78', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method for making decisions on the basis of the sum of the future cashflows discounted by a discount rate?', NULL, 'Internal Rate of Return Method (IRR)', 'Net Present Value Method (NPV)', 'PayBack Period Method (PBP)', 'Return on Investment Method (ROI)', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-A-79', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a criminal act related to a computer virus according to the Convention on Cybercrime?', NULL, 'A person creates a new virus to develop and test antivirus software.', 'A person forwards a received e-mail that is infected with a virus without being aware of the infection.', 'A person who finds a virus that is created by a stranger stores the virus for the purpose of subsequently running it on another person’s computer.', 'A person who receives and finds a virus offers it to an antivirus organization with a clear indication of the virus’s presence.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '19-A-80', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a logical expression equivalent to the exclusive-OR operation of logical variables p and q? Here, “∨”, “∧”, and “¬” are OR, AND, and NOT operators, respectively.', NULL, '¬p ∨ q', '(p ∨ q) ∧ ¬(p ∧ q)', '¬(p ∨ q) ∨ (p ∧ q)', '(p ∧ ¬q) ∨ ¬(q ∧ p)', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-01', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the bit strings of length 4, how many of them either start with 1 or end with 00?', NULL, '4', '8', '10', '12', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-02', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A factory manufactures the same products in two production lines A and B, where 60% of the products are manufactured in A, and the remaining in B. Defective rates of the products manufactured in A and B are 2% and 1%, respectively. When a product was randomly chosen for inspection, it was found to be defective. What is the percent probability that the product was manufactured in A?', NULL, '40', '50', '60', '72', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-03', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the computational complexity of the Heapsort algorithm? Here, n is the number of elements to be sorted. All comparisons, swaps, and other needed operations can proceed in constant time.', NULL, 'O (log n)', 'O (n)', 'O (n²)', 'O (n log n)', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-04', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A regular expression [A-Z]+[0-9]* represents a set of character strings. Which of the following character strings belongs to this set? Here, the regular expression follows the rules below. 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Data A, B, C and D are entered as an input sequence. Which of the following is a possible output sequence by only using a single stack?', NULL, 'A, D, B, C', 'B, D, A, C', 'C, B, D, A', 'D, C, A, B', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-06', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For integers x and y (x > y ≥ 0), a function F(x, y) is defined as follows. What is the value F(231, 15)? Here, x mod y represents the remainder after division of x by y.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-07.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0wNy5wbmciLCJpYXQiOjE3NDMxMTY0NzAsImV4cCI6MTc3NDY1MjQ3MH0.wij0rrNpVLKakvSJaVgQjHBhoUAVU4C8SGmESD4FEe0', '2', '3', '5', '7', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-07', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a recursive call?', NULL, 'To allow a function to use itself from within its body', 'To execute processes in an event-driven way rather than in a predetermined order', 'To keep a function in memory after its execution in order to reuse', 'To undo an execution of process when it fails', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-08', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a web environment, which of the following is the name of a program that runs on a web server and achieves dynamic processing?', NULL, 'Java applet', 'Java servlet', 'JavaScript', 'VBScript', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-09', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a special purpose register that stores the result of a comparison or the sign of the result of an arithmetic operation?', NULL, 'Accumulator', 'Flags register', 'Instruction register', 'Program counter', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-10', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the addressing mode that references data in main memory as shown in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-11.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0xMS5wbmciLCJpYXQiOjE3NDMxMTY0NzYsImV4cCI6MTc3NDY1MjQ3Nn0.zHevfE9RUCwuJ00BiMoQZv6uLkOhRHjJZWNr5Ebzi4I', 'Direct addressing', 'Indexed addressing', 'Indirect addressing', 'Relative addressing', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-11', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a 1-megabyte memory is connected to the MPU as shown in the figure below, what is the minimum number of signal lines (represented as n) required by address buses? Here, the memory is accessed in units of bytes. In addition, 1 megabyte = 1,024 kilobytes and 1 kilobyte = 1,024 bytes.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-12.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0xMi5wbmciLCJpYXQiOjE3NDMxMTY0ODEsImV4cCI6MTc3NDY1MjQ4MX0.Foi5zLO4TaoFugavB5kHHW9sjKIrXQRv_TAuVFLevzY', '18', '19', '20', '21', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-12', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of USB 3.0?', NULL, 'It uses a serial interface that has a 5 Gbps data transfer mode called super speed.', 'It uses a serial interface that has both an isochronous transfer mode suitable for voice, video, and other data, and a broadcast transfer mode.', 'It uses an interface that transmits 2 bits of information in one (1) clock cycle with four (4) pairs of signal lines, and has a maximum throughput of 1 Gbps.', 'It uses the serial version of ATA interface that is standardized for the connection of a PC to peripheral devices', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-13', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the effect of cache memory?', NULL, 'By reading data from main memory and storing it in cache memory, and then processing instructions in parallel in cache memory, operations are performed at high speed.', 'By reading data from main memory and storing it in cache memory, data transfer is performed at high speed when the CPU reads the same data later.', 'By reading instructions and data simultaneously from main memory to cache memory, data transfer is performed at high speed.', 'By reading instructions from main memory and storing them in cache memory, and then decoding and executing them in cache memory, operations are performed at high speed.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-14', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of a benchmark test?', NULL, 'It evaluates the performance by analyzing the system processing theoretically and estimating the processing time from the number of occurrences and predicted number of executions of individual instructions, rather than actually executing a program.', 'It evaluates the system performance by using a program in which a model is created and simulated for the purpose of evaluation with the inclusion of future estimates.', 'It executes a standard program selected in accordance with the usage purpose, and measures the system’s processing performance.', 'It measures the operating condition of a system and the status of resources using a program for monitoring and measuring, and obtains data on the system configuration and response performance.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-15', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As shown in the figure below, one (1) server, three (3) clients, and two (2) printers are connected via a LAN. This system prints data located on the server in response to instructions from the clients. When the availability of each device is as shown in the table below, which of the following is the expression that represents the availability of the system? Here, the system is considered available when the server, one (1) of the three (3) clients, and one (1) of the two (2) printers are running.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-16.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0xNi5wbmciLCJpYXQiOjE3NDMxMTY0ODYsImV4cCI6MTc3NDY1MjQ4Nn0.t4R64b2UxNHKh9FRqWth2MW0O1r3NZPs5V7W57PhVI4', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-16', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As shown below, there is a set of processes, with the length of the CPU-burst time given in milliseconds, and the processes arrive in the order of P1, P2, P3, P4, and P5 with the arrival time of all processes at t = 0. Which of the following is the average turnaround time of five (5) processes from P1 through P5 with the first-come first-served (FCFS) scheduling algorithm?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-17.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0xNy5wbmciLCJpYXQiOjE3NDMxMTY0OTEsImV4cCI6MTc3NDY1MjQ5MX0.m0n_A4pd5IjnZUxyzwIkXhLgiTrGqO_W14MksGKf0KY', '10', '15', '20', '25', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-17', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate usage method of the priority-based preemptive scheduling that is used in an embedded real-time operating system?', NULL, 'It is used when evenly assigning the execution time for each task.', 'It is used when tasks are processed according to their importance and urgency.', 'It is used when tasks are processed sequentially from the earlier arriving times.', 'It is used when tasks are processed sequentially from the shorter processing times.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-18', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Multiple directories named A and B are managed in the structure shown in the figure below. Which of the following is the case in which the current directory is moved so that “\B\A\B” is the current directory? Here, the method for directory designation is as below, and → indicates the order of movement.
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the virtual memory of a paging system, which of the following is a cause that increases the number of page fault occurrences?', NULL, 'An access to a page that has not been accessed for a long time in main memory', 'An increase in access to a page that does not exist in main memory', 'An increase in access to a page that exists in main memory', 'An increase in the ratio of pages that are updated among the pages in main memory', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-20', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a criterion for a page to be replaced in a Least Recently Used (LRU) algorithm?', NULL, 'The cumulative total number of references', 'The first referenced time', 'The frequency of references per unit of time', 'The last referenced time', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-21', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a logic circuit shown below. When the input values are A = 1, B = 0, and C = 1, which of the following is the combination of the values of E and Y?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0yMi5wbmciLCJpYXQiOjE3NDMxMTY1MDEsImV4cCI6MTc3NDY1MjUwMX0.76hfuirUdLzmOkbgrMupgrxO_hpBN7wV1GEhsHFRA5g', 'E = 0, Y = 0', 'E = 0, Y = 1', 'E = 1, Y = 0', 'E = 1, Y = 1', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-O-22', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('By using a sensor that detects changes in shape, the condition of infrastructure such as elevated highways can be monitored and maintained. Which of the following is a sensor that is used for this purpose?', NULL, 'Gyro', 'Hall element', 'Strain gage', 'Thermistor', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-23', -2.0, 1.0);
