INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Currently, the number of customers is 8,000 with annual increase rate of 20%. By assigning a fixed length code using 26 uppercase alphabet A-Z to each customer, what is the minimum code length required to accommodate all the customers for next three years?', NULL, '3', '4', '5', '6', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-25', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An audio signal is sampled 11,000 times per second while each sample is recorded as an 8-bit data. When a 512×10⁶-byte capacity flash memory is used, what is the maximum number of minutes to record such data?', NULL, '77', '96', '775', '969', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-26', 0.0, 1.0);
