INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The data model in the diagram below is implemented with three (3) tables. Which of the following is an appropriate combination of A and B in table “Transfer” that contains the record that indicates “500 dollars sales to Company X are posted to the cash account on  April 4, 2015”? Here, the data model is described in UML', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-28.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0yOC5wbmciLCJpYXQiOjE3NDMxMTY1NTYsImV4cCI6MTc3NDY1MjU1Nn0.LI4vSkpUIokImc0jLvof85Gf0om2u_suSam9lijGmEE', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-28', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('After relations X and Y are joined, which of the following is (are) the relational algebra operation(s) to obtain relation Z?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-29.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0yOS5wbmciLCJpYXQiOjE3NDMxMTY1NTgsImV4cCI6MTc3NDY1MjU1OH0.ivQGC-j0yWnZNRuH3hqBG1C_YrdiMNtBr_Tqp-UJM28', 'Projection and selection', 'Projection and union', 'Selection', 'Selection and union', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-29', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a DBMS, when multiple transaction programs update the same database simultaneously, which of the following is a technology that is used to prevent logical contradictions?', NULL, 'Exclusive control', 'Integrity constraint', 'Normalization', 'Reorganization', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-30', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As an example of the use of big data, which of the following is a process that uses statistical or other methods to obtain new knowledge (such as trends and patterns) from a large amount of data?', NULL, 'Data dictionary', 'Data mining', 'Data warehouse', 'Metadata', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate information for a router to determine the destination of an incoming packet?', NULL, 'Destination IP address', 'Destination MAC address', 'Source IP address', 'Source MAC address', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-32', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the OSI basic reference model, which of the following is the layer where bridges operate?', NULL, 'Application layer', 'Network layer', 'Datalink layer', 'Transport layer', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-33', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In TCP/IP, which of the following is an application layer protocol that enables a server to automatically configure its clients with network information such as IP addresses, the subnet mask and the default gateway address?', NULL, 'ARP', 'DHCP', 'DNS', 'NSLOOKUP', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-34', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of SDN (Software-Defined Networking) that uses OpenFlow?', NULL, 'It is a business analysis and visualization software technology that uses visual means such as data flow diagrams and activity diagrams to discover problems in business processes.', 'It is a network technology that logically decouples the functions for data transfer and route control, and is implemented with a combination of network devices specialized for data transfer and software-based route control.', 'It is an Internet of Things (IoT) technology that uses RFID, and is a software architecture for the optimization of logistics networks.', 'It is an optimum relocation of servers on a network in order to efficiently deliver a range of software content such as music, videos, and online games over the Internet.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-35', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As shown below, multiple PCs are connected to the home network and they have access to the Internet through FTTH, and a global IP address is assigned to the WAN interface of device A. Which of the following is the function of device A that enables the PCs to use the Internet with this global IP address?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-36.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0zNi5wbmciLCJpYXQiOjE3NDMxMTY1NjUsImV4cCI6MTc3NDY1MjU2NX0.zF7r4tBut-l1Ie1ucXS4aIhlpfApzkn5XBM1jppa8rw', 'DHCP', 'NAPT (IP Masquerade', 'Packet filtering', 'PPPoE', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a password attack that makes use of the possible combination of pre-computed hashes and passwords?', NULL, 'Brute force attack', 'Malware attack', 'Rainbow table attack', 'Zero-day attack', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a spoofing attack?', NULL, 'An attack by encrypting victim’s data and demanding ransom', 'An attack by looking at someone’s keyboard while the victim entering a password', 'An attack by masquerading as someone such as a superior person from an information systems department, or customer', 'An attack by sending excessive requests from multiple computers in an attempt to overload the victim’s computer', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An administrator captures network packets and discovers that hundreds of ICMP packets have been sent to the host. However, it is not a particularly busy time of the day. Which of the following is the most likely the attack executed against the computer in this situation?', NULL, 'Denial of service', 'Man-in-the-middle', 'Spoofing', 'Worm', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-39', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of spyware?', NULL, 'A program that attempts to identify a user’s password by accessing a server and trying to match with all the words in a dictionary', 'A program that extracts HTML tags, JavaScript, and SQL statements in the input data from input forms on a website, and rewrites them to other character strings in order to eliminate malicious input to a website', 'A program that is installed on a PC against the user’s intention and collects information such as the user’s personal information and access history', 'A program that sequentially accesses TCP ports of a server from an attacker’s PC in order to find a vulnerable port that can be a point of intrusion to the server', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-40', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A security question is used to authenticate a user who forgets his/her password for a web system. After the correct answer is given, which of the following is the most appropriate process in terms of security?', NULL, 'Making the user enter an e-mail address again, and sending a URL that is difficult to guess so that the user can access a password reset page', 'Making the user enter an e-mail address again, and sending the current password to that address', 'Sending a URL that is difficult to guess to the user''s pre-registered e-mail address so that the user can access a password reset page', 'Sending the current password to the user’s pre-registered e-mail address', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a role that a PKI certification authority performs as a reliable third party?', NULL, 'It allocates a digital signature to an e-mail body by a user’s request.', 'It enables to synchronize the time by returning an accurate time to a user’s request.', 'It issues a digital certificate that certifies a private key of a user or a server.', 'It issues a digital certificate that certifies a public key of a user or a server.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-42', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning corporate security management when Software as a Service (SaaS) is used?', NULL, 'No system access management needs to be performed, and no consideration concerning the procedure for password initialization or a password policy that satisfies complexity requirements is required.', 'No system construction needs to be performed, and neither the definition of security requirements for application software development nor the design of storage volume for system logs is required.', 'No system operation needs to be performed, and no consideration concerning work procedures at the time of a failure or backup is required.', 'No system security management needs to be performed, and neither the creation of information security management rules nor the assignment of an administrator is required.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning BYOD and the associated information security risk?', NULL, 'An employee takes home an information terminal provided by his or her company and uses it privately, which causes an increase in information security risks such as information leakage.', 'An employee uses an information terminal provided by his or her company to work while in transit to another location such as a customer office, which causes an increase in information security risks such as shoulder hacking.', 'An employee uses his or her own personal terminal for business purposes, which causes an increase in information security risks such as virus infections due to inadequate security settings.', 'An employee uses his or her own personal terminal privately during non-working time such as breaks, which causes an increase in information security risks such as a reduction in awareness of security.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Between a client and a web server, which of the following is used for inspecting the data that is sent from the client to the web server and blocking attacks such as SQL injection?', NULL, 'Cluster configuration', 'Load balancing function', 'SSL-VPN function', 'WAF', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-45', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of honeypots?', NULL, 'Antivirus software to detect and clean or quarantine virus-infected programs', 'Computer system designed to detect or counteract unauthorized access', 'Firewall to detect and prevent unauthorized access to computer systems', 'Security mechanism to run untrusted programs without risking the computer', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-46', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a module strength for the collection of multiple sequential functions, with internal passing of data?', NULL, 'Communicational strength', 'Functional strength', 'Informational strength', 'Procedural strength', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate combination of Class and Object in Object Oriented Programming?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-48.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy00OC5wbmciLCJpYXQiOjE3NDMxMTY1NjksImV4cCI6MTc3NDY1MjU2OX0.s1j_jiR1aYx8S8zPh7CGZKQO37vPHDqrtf_-XEn9LEg', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-O-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning the black box test?', NULL, 'Even if the program to be tested contains redundant code, such code cannot be detected.', 'If the number of branch instructions and modules increases, the test data volume increases rapidly.', 'In consideration of the internal structure of the program, it is verified whether or not the necessary part is executed.', 'The coverage rate of instructions and branches is used as criteria for the creation of test data.', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-O-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate testing type to ensure that the interfaces and linkages between different parts of programs work properly?', NULL, 'Acceptance test', 'Integration test', 'Qualification test', 'Unit test', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-O-50', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of reverse engineering of software?', NULL, 'The entire software is reconstructed after analyzing and understanding the existing software.', 'The existing software is analyzed, and its specification and structure are clarified.', 'The internal structure of software is changed without changing the behavior seen from the outside.', 'The source code is generated automatically from the design information by using a development support tool.', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-O-51', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description for group decision-making techniques used in an estimate activity durations process?', NULL, 'A group of experts, guided by historical information, can provide duration estimate information or recommended maximum activity durations from prior similar projects.', 'The estimates from such techniques may include contingency reserves, sometimes referred to as time reserves or buffers, in the project schedule to account for schedule uncertainty.', 'These are team-based approaches, such as brainstorming, the Delphi or nominal group techniques, which are useful for engaging team members to improve estimate accuracy and commitment to the emerging estimates.', 'These techniques use a statistical relationship between historical data and other variables to calculate an estimates of activity parameters, such as cost, budget, and duration.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-O-52', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the activities on the critical path of a project?', NULL, 'Any activity on the critical path is called a critical path activity.', 'The critical path is the sequence of activities that represents the shortest path through a project.', 'The critical path must contain the activity that has the longest duration compared to the other all activities.', 'The sum of activities on the critical path determines the longest possible project duration.', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-O-53', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate cost estimation technique that uses parametric models to create an objective estimate based on each element size and the complexity of the system (e.g., number of input files, screens, etc.) to be built?', NULL, 'Analogous estimating', 'Bottom-up estimating', 'Function point method', 'Three-point estimating', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-O-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In order to determine the quality condition in a test process, it is necessary to analyze and evaluate the relationship between the number of completed test items and the cumulative number of bugs. Which of the following is the graph that indicates that the quality is becoming stable?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-52-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy01Mi1BLnBuZyIsImlhdCI6MTc0MzExMDQzNSwiZXhwIjoxNzc0NjQ2NDM1fQ.LfDyg4B8ZmMG_ztIN_SCaumupmtZHeFPYlKdk8u7Y3Q', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-52-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy01Mi1CLnBuZyIsImlhdCI6MTc0MzExMDQ0MiwiZXhwIjoxNzc0NjQ2NDQyfQ.9ULY16k5ZM8aGUQaguvtuvw8MhJ_SweAcvmrbxA5slA', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-52-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy01Mi1DLnBuZyIsImlhdCI6MTc0MzExMDQ0NiwiZXhwIjoxNzc0NjQ2NDQ2fQ.kjQjyRw8h1e0sPQgIazYQsym11rgdF7lYO-7t_W-l9c', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-52-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy01Mi1ELnBuZyIsImlhdCI6MTc0MzExMDQ1MCwiZXhwIjoxNzc0NjQ2NDUwfQ.cSEus0iUFviFzd6kF3TmvgvtyiH8QrhLhrZwh0tRPpY', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-O-55', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the development department and operations department of a system are organized separately, which of the following is an appropriate method of smoothly and effectively proceeding with the design and migration of a new service that needs system development?', NULL, 'After the completion of the operational test, the development department explains the system specifications and operation methods to the operations department.', 'The development department conducts operational test, creates the operation manuals, and passes them over to the operations department.', 'The operational test is conducted only by the operations department without the support of the development department.', 'The operations department also participates actively in the extraction of requirements concerning the system operations.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-O-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IT service management, which of the following is the most appropriate functional organization that provides a single point of contact and tries to provide rapid restoration of normal service operations to users?', NULL, 'Service desk', 'Service management', 'Service provider', 'Supplier', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-O-57', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an effective means of protecting an information system from the damage of over-voltage that occurs because of a lightning strike?', NULL, 'Connecting the communication cable and the computer through a surge protection device (SPD)', 'Digitalizing the control circuit of electric power facilities', 'Installing a private power generator', 'Splitting the communication wire into two (2) systems that have different paths', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the statuses found through auditing the operation management of the system operations, which of the following must be described in the audit report as a finding?', NULL, 'The operator decides a daily operation plan and approves it himself.', 'The operator records the exception handling that occurs during the operation.', 'The person responsible for operations checks the operation records created by the operator.', 'The person responsible for operations stores the operation records by specifying the time period.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-O-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description concerning an interview that is conducted by a system auditor?', NULL, 'The administrator of the audited department, who has experience in auditing tasks, is selected as the interviewee.', 'The entire interview is conducted by one (1) system auditor, because discrepancies may occur in the record if multiple auditors are involved.', 'The system auditor instructs the audited department to take improvement measures for deficiencies found during the interview.', 'The system auditor makes an effort to obtain documents and records that support the information obtained from the audited department during the interview.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of audit work papers?', NULL, 'It is a compilation of the information security promissory letter that is presented to the audited department when the auditor implements an audit.', 'It is a compilation of the standards and guidelines used by the auditor for implementing an audit.', 'It is a document that must be disclosed along with the audit report to prove that the auditor has fulfilled his obligations with proper attention.', 'It is an execution record of the auditing procedure implemented by an auditor, and it forms the basis of the audit opinion.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-O-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The table below shows the result of analyzing the activities of a sales representative on one (1) particular day. By installing Sales Force Automation (SFA), preparation time for customer visits can be reduced by 0.1 hours per customer visit. In order to increase the number of customer visits to six (6) per day without changing the total working hours and the hours per customer visit, how many hours must be reduced from “Other operation”?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-62.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy02Mi5wbmciLCJpYXQiOjE3NDMxMTY1ODAsImV4cCI6MTc3NDY1MjU4MH0.WumktFI3fT6eaUUvklLHaFMWHkR5e5MQaf2D7YRMbBQ', '0.3', '0.5', '0.7', '1.0', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-O-62', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of SOA?', NULL, 'It is a business system for performing integrated management (rather than department-wise management) of mission-critical tasks to improve the efficiency of management by effectively utilizing the management resources.', 'It is a document that is agreed upon by an ordering company and an IT outsourcing service provider concerning the quality of a service.', 'It is a system architecture that provides the components of a business process and its supporting IT infrastructure in the form of a service.', 'It is a technique of drastically revising an existing organization and business rules, and reconstructing the workflow, control mechanism, and information system.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of usage of big data by a company?', NULL, 'A large amount of text on various social media channels is analyzed, and the products are improved.', 'Employees in their 10th year of employment are extracted from the personnel information during the creation of a list of intended staff members for in-house training.', 'The contact address is extracted from already-registered customer information for inquiries to the customer center.', 'The sales profit ratio is calculated from the financial statements disclosed by the most important business partner.', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '18-O-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of Business Intelligence (BI)?', NULL, 'It is a method of ensuring continuous improvement in business operations by visualizing the business operations flow and applying the business operations improvement cycle.', 'It is a method of improving the cost, quality, service, etc. by drastically reconstructing the business processes without being bound by the practices in the company.', 'It is a method of supporting the speedup of decision-making of a company by utilizing accumulated internal and external data through classification, processing, and analysis.', 'It is a method of using the entire system efficiently by mutually connecting different systems in the company and integrating the data and processes.', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '18-O-65', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the activity that translates the information gathered during analysis activities into a document as a set of requirements?', NULL, 'Feasibility study', 'Requirement analysis', 'Requirement definition', 'Requirement specification', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-O-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of green procurement?', NULL, 'It refers not only to the fulfillment of the requirements of quality and price but to the preferential purchase of products and services with the lower environmental burden from companies that work toward a reduction in their environmental impact.', 'It refers to a certificate that enables commercial trading of the green power generated from natural energy such as sunlight, biomass, wind power, and geothermal heat.', 'It refers to international standards concerning environmental labels such as eco marks that are certified by a third party on the basis of certain criteria.', 'It refers to mass promotion of the details of environmental protection activities, and the raising of funds for environmental protection from investors.', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-O-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In SWOT analysis, which of the following is generally positioned as a threat?', NULL, 'Entry of strong companies in the market', 'High growth rate of business domain', 'High production efficiency as compared with other competitors', 'Low market share', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-O-68', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a leader strategy among the competitive strategies of a company?', NULL, 'Concentrating limited management resources in a specialized market into which other companies do not enter despite the presence of potential demand', 'Employing a differentiation strategy from various viewpoints such as products, services, sales promotion, and distribution channels, with the aim of seizing the market share', 'Employing an omnidirectional strategy targeting all market customers with the aim of maintaining or improving profit and reputation, and securing optimum market share', 'Suppressing the cost of development and advertising, and aiming for continued existence in the market by observing the strategies of target companies and simulating them promptly', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-O-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of Supply Chain Management (SCM)?', NULL, 'Customer information collected through various channels is consolidated and utilized to establish closer relationships with customers.', 'Employees’ skills and behavior characteristics are grasped, and management such as personnel assignment and evaluation that are appropriate from the perspective of human resources strategy is performed.', 'Intellectual assets of individuals, such as know-how and experience, are shared across the organization as inspiration for creative work.', 'The sequence of business operations, from purchasing and production to sales and distribution, is reexamined within the company and among companies in view of total optimization, so as to accelerate delivery and minimize inventory.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-O-70', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate example of a core technology?', NULL, 'It is a development technology by combining general components with the purpose of fast-track development and fast-track market introduction of products.', 'It is a device technology that employs the same CPU core as that of competitors and enhances the portability of software.', 'It is an idling stop technology of an automobile engine that cannot be imitated by competitors.', 'It is an interface technology whose purpose is to create standard interfaces by forming an alliance and to use them commonly.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-O-71', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When trial production is performed for components to be loaded into electrical appliances, which of the following is the least expensive development method? Here, the construction time of each process is six (6) months for the creation process, three (3) months for the modification process, and two (2) months for the evaluation process. The cost per one (1) person-month is 6,000 dollars for the creation process and 10,000 dollars for each of the modification and evaluation processes. Costs other than the purchase cost, outsourcing cost, and person-month cost shall not be considered.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/22-O-69.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjItTy02OS5wbmciLCJpYXQiOjE3NDMxMTY2MzQsImV4cCI6MTc3NDY1MjYzNH0.Xxxg4rOI-pmOQqjz8J8wiqCO_7pJy661TgBNYSy2y7k', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-O-72', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The basic elements and examples of devices and services when IoT is used in the equipment maintenance tasks of a factory are compiled as shown below. When a) through d) correspond to any one of A through D, which of the following corresponds to A?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-73.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy03My5wbmciLCJpYXQiOjE3NDMxMTY2ODMsImV4cCI6MTc3NDY1MjY4M30.V7YoIA8NYEVXsNqJusTpne_c7aRhgfnfcBrVqmAxAPs', 'Abnormal value judgment tool', 'Display for work instructions', 'Temperature sensor for equipment', 'Wireless communication within factory', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-O-73', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of MRP?', NULL, 'The development, designing, and production preparation of a product are performed simultaneously in parallel.', 'The number of required components is calculated based on the standard production plan of a product.', 'The production of a product is started after an order from a customer is received.', 'Work instructions and transport instructions are provided by using a worksheet.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-O-74', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following corresponds to (5) in an example of a model of an affiliate program shown below in Internet advertising? Here, (1) through (5) indicate the order of operations in the model, and each of (1), (2), (4), and (5) corresponds to one of a) through d).', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-75.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy03NS5wbmciLCJpYXQiOjE3NDMxMTY2NzEsImV4cCI6MTc3NDY1MjY3MX0.N53SVS95E94AXhjjaRmgMN0gRGDjVU8hgIn0dc2B5mo', 'Agree to and participate in the affiliate program', 'Click the advertisement on the website', 'Pay a contingency fee in accordance with the sales of the product', 'Purchase the desired product', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-O-75', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a part of total quality management?', NULL, 'Designing products and services that meet or exceed customers’ expectations', 'Focusing on the appointment of staff with long-term work experience in a similar environment', 'Prioritizing central decisions rather than empowerment for ensuring quality of products and services', 'Promoting the capability of each department to work independently in a competitive manner', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-O-76', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the weather tomorrow is sunny with 30% probability, cloudy with 50% probability, and rainy with 20% probability, which of the following strategies offers the highest expected value?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-77.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy03Ny5wbmciLCJpYXQiOjE3NDMxMTY2NDcsImV4cCI6MTc3NDY1MjY0N30.xmmiofBx5A_ZF34GNWCYzY9gADgXop4dNsvwSipfbRA', 'S1', 'S2', 'S3', 'S4', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-O-77', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There are several quality control tools that have been used primarily for manufacturing and inspection departments. Which of the following sets two corresponding types of data on the vertical and horizontal axes, after which the measured values are plotted?', NULL, 'Control chart', 'Histogram', 'Pareto chart', 'Scatter diagram', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-O-78', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Company Z is planning to start a new project of which the initial investment is 100 million dollars. It is expected to generate cash as shown in the following table. What is the payback period of the new project?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-79.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy03OS5wbmciLCJpYXQiOjE3NDMxMTY2NjEsImV4cCI6MTc3NDY1MjY2MX0.IOQ4Z3PxajOzXTF8Y9kNa2uB4YM1OJUyu1UffNOSvFA', '3.0', '3.2', '3.5', '4.0', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-O-79', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate order of the workflow from transaction records to closing accounts?', NULL, 'General Ledger -> Journal Book -> Trial Balance Sheet -> Work Sheet -> Financial Statements', 'General Ledger -> Journal Book -> Work Sheet -> Trial Balance Sheet -> Financial Statements', 'Journal Book -> General Ledger -> Trial Balance Sheet -> Work Sheet -> Financial Statements', 'Journal Book -> General Ledger -> Work Sheet -> Trial Balance Sheet -> Financial Statements', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-O-80', -1.0, 1.0);
