INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When three sets A, B, and C are given, which of the following equalities holds? Here, ∪ and ∩ are union and intersection symbols, respectively."', NULL, '(A ∪ B) ∩ (A ∩ C) = B ∩ (A ∪ C)', '(A ∪ B) ∩ C = (A ∪ C) ∩ (B ∪ C)', '(A ∩ C) ∪ (B ∩ A) = (A ∩ B) ∪ (B ∩ C)', '(A ∩ C) ∪ (B ∩ C) = (A ∪ B) ∩ C', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-02', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('For two logical variables X and Y, a logical operation X NAND Y is defined as a composite operation NOT (X AND Y). Which of the following is equivalent to the logical operation X OR Y?', NULL, '((X NAND Y) NAND X) NAND Y', '(X NAND X) NAND (Y NAND Y)', '(X NAND Y) NAND (X NAND Y)', 'X NAND (Y NAND (X NAND Y))', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-03', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following bit strings is accepted by the automaton described in the state transition diagram below? Here, each string is processed one bit at a time in sequence from the left.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-04.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0wNC5wbmciLCJpYXQiOjE3NDMxMTY2OTMsImV4cCI6MTc3NDY1MjY5M30.3-r957-X8_U33h8FcZ2RzbnbH2kldBwwjaF7Fvt55AU', '0000', '0111', '1010', '1111', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-04', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a binary search tree whose keys are numbers assigned to nodes in natural order?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-05-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0wNS1BLnBuZyIsImlhdCI6MTc0MzExNjcwMCwiZXhwIjoxNzc0NjUyNzAwfQ.GQfSIU70F_M1k6nodDrVFJSFKuBWl1d_1egEzHYFf5I', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-05-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0wNS1CLnBuZyIsImlhdCI6MTc0MzExNjcwNCwiZXhwIjoxNzc0NjUyNzA0fQ.1dII6KJL7TNqdXpwadoOUcCYN554ykEYynwD9pqNyNY', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-05-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0wNS1DLnBuZyIsImlhdCI6MTc0MzExNjcwNywiZXhwIjoxNzc0NjUyNzA3fQ._rWvkJCsERWDimmOGoJoloqxpnoXR19AP3ONn3cM11w', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-05-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0wNS1ELnBuZyIsImlhdCI6MTc0MzExNjcxMiwiZXhwIjoxNzc0NjUyNzEyfQ.JsGswJax7SdGFVskZg0gcLrD52sCnBH_m5hITH3FUPQ', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-05', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a two-dimensional integer array A whose (i, j)-th element A[i, j] is 2 × i + j. What is the value of the element A[A[1, 1] × 2, A[2, 2] + 1]?', NULL, '12', '13', '18', '19', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-06', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Function F(n) is a recursively defined integer function that calculates the factorial of n for any non-negative integer n. Which of the following is an appropriate expression for the blank A?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-07.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0wNy5wbmciLCJpYXQiOjE3NDMxMTY3MTgsImV4cCI6MTc3NDY1MjcxOH0.cJWT2puu7ZHkPjeFCwAe1KF8OwBzcan9mkgEn83FR7M', 'n + F(n - 1)', 'n - 1 + F(n)', 'n × F(n - 1)', '(n - 1) × F(n)', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-07', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the result of the procedure in the flowchart below, when x and y are positive integers?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-08.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0wOC5wbmciLCJpYXQiOjE3NDMxMTY3MjEsImV4cCI6MTc3NDY1MjcyMX0.2QEQkHWaAo0tF3kTA8SQ1VCfx04wgY-RstcI2DVNBYI', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-08', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following addressing modes determines the effective address by adding the value of the instruction address register (program counter) to the value recorded in the address part of the instruction?', NULL, 'Absolute addressing', 'Base addressing', 'Indexed addressing', 'Relative addressing', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-A-09', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A computer has two levels of memories, cache memory and main memory, with an access time of 0.01 µs and 0.1 µs respectively. If the hit ratio of the cache memory is 90%, which of the following is the appropriate average memory access time for this system? In this scenario, if the data is in the cache memory, the processor accesses the data directly with an access time of 0.01 µs. However, if a cache miss occurs, the data is required to be transferred from the main memory to the cache memory first, and then subsequently accessed from the cache memory. Thus, the access time becomes 0.11 µs.', NULL, '0.011 µs', '0.019 µs', '0.020 µs', '0.091 µs', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-A-10', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an output device for the computer?', NULL, 'Camera', 'Mouse', 'Printer', 'Scanner', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-A-11', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the average rotational latency of a hard disk drive in milliseconds when its rotation speed is 2000 rotations per minute?', NULL, '10', '15', '25', '30', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-A-12', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method that increases the speed of data input/output by dividing logically sequential data and writing the divided data into multiple hard disks?', NULL, 'Disk cache', 'Mirroring', 'Striping', 'Swapping', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-A-13', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of a HA (High Availability) cluster configuration based on a hot standby method when it is compared to a load distribution cluster configuration that uses a load balancer?', NULL, 'A server that has the same specifications is necessary as a secondary server, but since processes are taken over by the secondary server in the event of the primary failure, the throughput can be maintained even in the event of a failure.', 'Given that processes are distributed to other servers in operation in the event of a failure, the load of servers in operation increases and the throughput decreases.', 'Given that processes can be distributed uniformly, server machines can be utilized effectively and expandability is ensured even if the amount of processing increases in the future.', 'Given that processes must be consistent among multiple servers in operation, it is necessary to share a database.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-A-14', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning system availability?', NULL, 'Even if the MTBF is different, the system availability is equal if the MTTR is equal.', 'If the MTTR can be shortened without changing the MTBF, the system availability improves.', 'If the MTTR does not change and the MTBF increases, the system availability deteriorates.', 'If the sum of the MTBF and the MTTR is equal, the system availability is equal.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-A-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a page fault in a virtual memory system?', NULL, 'An access to a page that is mapped in the virtual memory, but not loaded in the physical memory', 'A hardware error in the physical memory', 'A program attempting to insert more data than it can hold in the physical memory', 'A reference to a page that another program is currently using in the virtual memory', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '18-A-16', -2.0, 1.0);
