INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is classified as a function of a static test tool?', NULL, 'Calculating the coverage from the paths executed by the test', 'Detecting an error in a program by analyzing the source code', 'Generating a driver or stub necessary for the module to be tested', 'Generating the data to test a specific path of the program', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-A-18', -1.0, 1.0);
