INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A D/A converter with a resolution of 8 bits generates an output voltage of 0 volts for a digital input value of 0, and an output voltage of 2.5 volts for a digital input value of 128. When the lowest 1 bit of the digital input value is changed, which of the following is the change (in volts) of the output voltage that is generated by the D/A converter?', NULL, '2.5/128', '2.5/255', '2.5/256', '2.5/512', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-21', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The half adder in the diagram below adds two (2) single-digit binary numbers x and y, and produces z (the first digit of the sum) and c (the carry bit) as output. Which of the following is the appropriate combination of gate devices A and B?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0yMi5wbmciLCJpYXQiOjE3NDMxMTY3MzgsImV4cCI6MTc3NDY1MjczOH0.xUS9YkvaSG0M75d1hGQnHJSYWwChYLzYAu11NajvX_g', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-22', -1.0, 1.0);
