INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When ordering data in the format below is entered, which of the following is an appropriate check to examine whether the value of the Order date field is on a business day equal to or prior to the entering date?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-24.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0yNC5wbmciLCJpYXQiOjE3NDMxMTY3ODEsImV4cCI6MTc3NDY1Mjc4MX0.t8wXQeENSQ-94SFdQMbRtDRam-J4E6MheNFcwSIadxk', 'Sequence check', 'Duplication check', 'Format check', 'Logical check', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-24', -2.0, 1.0);
