INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a “Delivery” table that has six (6) records. Which of the following is the functional dependency that is satisfied by this table? Here, “X -> Y” indicates that X functionally determines Y.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-27.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0yNy5wbmciLCJpYXQiOjE3NDMxMTY3OTQsImV4cCI6MTc3NDY1Mjc5NH0.qmLdfwrJWfOm9aALB7520twnbfVrjHC_4yrz186Yl5Q', 'Delivery_date -> Component_ID', 'Delivery_destination -> Component_ID', 'Department_ID -> Component_ID', 'Department_name -> Delivery_destination', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-27', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following methods to join two (2) tables in an RDBMS is a description of the sort-merge join method?', NULL, 'All rows in the tables are re-ordered according to the values in the column to be joined, and they are joined in order from the top.', 'If a column to be joined in one of the tables is included in the index, the column to be joined in the other table and the index value are used to join the tables.', 'The values in a column to be joined in one of the tables are extracted in order, and they are joined with the column to be joined from the other table.', 'The values in a column to be joined in one of the tables are used to create a hash table, and this is joined with the column to be joined from the other table.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-28', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the SQL statement shown below is executed on the “Employee” table and the “Department” table, which of the following is the result?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-29.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0yOS5wbmciLCJpYXQiOjE3NDMxMTY3OTksImV4cCI6MTc3NDY1Mjc5OX0.sPheJW5jFf1Il7wsG8AaDtmtBKarVJesBEcgDB2d0s4', '1', '2', '3', '4', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-29', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a distributed database system, which of the following is a method for the finalization of update processing when an inquiry is made to multiple sites that perform a series of transaction processes as to whether finalization is possible or not and whether finalization is possible at all sites?', NULL, 'Exclusive control', 'Roll back', 'Roll forward', 'Two-phase commitment', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-30', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following TCP/IP protocols is used to assign IP addresses dynamically?', NULL, 'ARP', 'DHCP', 'RIP', 'SMTP', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a TCP/IP network hierarchical model, what is the name for Equipment A that connects two LAN segments at the Internet Layer?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-32.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0zMi5wbmciLCJpYXQiOjE3NDMxMTY4MDMsImV4cCI6MTc3NDY1MjgwM30.FQ0VT0SXpneTZVohy-KozrDYB3Ku6iwUczNTVcOPAO4', 'Bridge', 'Repeater hub', 'Router', 'Switching hub', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-32', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a pair of IP addresses belonging to the same subnet, when the subnet mask is 255.255.255.240?', NULL, '192.168.1.14 and 192.168.1.17', '192.168.1.17 and 192.168.1.29', '192.168.1.29 and 192.168.1.33', '192.168.1.33 and 192.168.1.49', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-33', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following delivery models does an ARP response use?', NULL, 'Anycast', 'Broadcast', 'Multicast', 'Unicast', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-34', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A PC and a web server are communicating via HTTP. When a request packet is sent from the PC to the web server, which of the following combinations of port numbers does the response packet have? Here, the source and the destination port numbers of the request packet are 50001 and 80 respectively.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-35.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS0zNS5wbmciLCJpYXQiOjE3NDMxMTY4MDYsImV4cCI6MTc3NDY1MjgwNn0.op_vSFJzS-VL5krVeJMKmBudDtRHLffHb0X-O13yTLs', 'a', 'b', 'c', 'd', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-35', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technology that prevents automated input by a program by requiring input of characters from a warped image or an image some parts of which are hidden? The technology is based on the differences of recognition of those images between humans and programs.', NULL, 'CAPTCHA', 'QR code', 'Short URL', 'Trackback ping', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-36', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an attack that threatens the “integrity” of information?', NULL, 'A DoS attack which sets the system to an overloaded state', 'Falsification of a web page', 'Tapping of communication content', 'Unauthorized copying of data saved in a system', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the name of an attack where manipulation is made to place a malicious website near the top of the results of a search website?', NULL, 'Cross-site scripting', 'DNS cache poisoning', 'SEO poisoning', 'Social engineering', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of a SQL injection attack?', NULL, 'An attack in which a large volume of packets is sent to a website via another website in order to make the provision of services impossible due to the abnormally high network traffic', 'An attack in which a program is forced to end abnormally, malicious code that is inserted into the data area is executed, or other such actions are performed by reading and writing data beyond the upper or lower limit of an area of memory that is secured for the buffer', 'An attack in which if there is a defect in the way database is called from a web application, an attacker can perform unauthorized retrieval, modification, and deletion of data in a database by entering a malicious character string in the data manipulation language for the call', 'An attack in which when a user views a website on which an attacker has placed a trap and clicks a link to another website that has a vulnerability, a character string that contains a malicious script is sent to the linked website, and when the malicious script that is embedded in the response is executed in the user’s browser, information leakage occurs', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-39', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an e-commerce transaction that uses public key cryptography, which of the following is the role of a certificate agency (CA)?', NULL, 'To encode plain text with the public keys that are shared between the parties involved in the transaction', 'To issue digital certificates for the public keys of the parties involved in the transaction', 'To manage the passwords of the parties involved in the transaction', 'To manage the private key that is shared between the parties involved in the transaction', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-40', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate purpose of using a hash value in digital forensics?', NULL, 'To convert a password with a one-way function so that recovery is not possible, then store it', 'To prove the identicalness between the original and the duplicate copy of the data that can be used as evidence', 'To restore altered data to its original form so that it can be used as evidence', 'To verify whether password tapping occurred or not', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate operation for user authentication that uses an IC card and a PIN?', NULL, 'Given that each user can be identified by an IC card, a common PIN is set for all users in order to reduce the management workload.', 'If an IC card is lost, a new IC card is issued, and after the PIN is reset, the lost IC card is deactivated.', 'The PIN is set by combining the numeric information imprinted on the surface of the IC card.', 'When an IC card is delivered, the PIN is not enclosed, but is notified to the user through another channel.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-42', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When malware that has made a successful intrusion into a PC communicates with a command-and-control server on the Internet, which of the following is a reason for using the TCP port number 80 as the destination port in most cases?', NULL, 'Given that this port is used for browsing websites, there is a high probability that communication is allowed by the firewall.', 'Given that this port is used for browsing websites through HTTPS communication, there is a low probability that this port is detected by an intrusion detection system.', 'Given that this port is used for the name resolution of a domain name, there is a low probability that this port is detected by an intrusion detection system.', 'Given that this port is used in a DNS zone transfer, there is a high probability that communication is allowed by the firewall.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a normally functioning hard disk of a PC on which confidential files are stored is handed over to an industrial waste disposal vendor, which of the following is an appropriate countermeasure against information leakage?', NULL, 'Changing the filename of each confidential file to a random character string multiple times', 'Compressing the confidential files multiple times with different compression techniques', 'Erasing the master boot record of the hard disk multiple times with a specialized erasing tool', 'Overwriting all areas of the hard disk with a random bit string multiple times', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate reason why VLANs are used?', NULL, 'In order to obtain an IP address', 'In order to reduce network traffic', 'To remotely access the intranet from a public network', 'To use a virtual memory system', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-45', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following must be approved by the customer when the external design of a system is completed?', NULL, 'Physical database specification', 'Program flowchart', 'Screen layout', 'System development plan', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-A-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate combination of the basic concept of object orientation?', NULL, 'Abstraction, encapsulation, inheritance, class', 'Embodiment, structuring, continuation, class', 'Normalization, encapsulation, division, class', 'Virtualization, structuring, projection, class', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '18-A-47', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In order to increase module independence, the level of module coupling must be low. Which of the following methods of exchanging information between modules has the lowest level of module coupling?', NULL, 'Control parameters are passed as arguments in order to control the execution order of modules.', 'Only data items that are required for input and output are passed as arguments between modules.', 'Relevant module reference data that is defined in a common area.', 'Required data is declared externally and shared.', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-A-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The integration test for software composed of modules arranged in a hierarchical structure is performed from a high-level module. In such a case, which of the following is a test module that is used as a substitute for a low-level module?', NULL, 'Driver', 'Emulator', 'Simulator', 'Stub', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-A-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the method that uses a modeling tool to create a design document described with E-R diagrams or other representations from the definition information in an active database?', NULL, 'Concurrent engineering', 'Forward engineering', 'Reverse engineering', 'Social engineering', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-A-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the Responsibility Assignment Matrix that is used for project human resource management?', NULL, 'Allocating the current engagement level of the stakeholders.', 'Allocating work packages to those who are responsible for project work.', 'Defining the limits of the project sponsor’s responsibilities.', 'Defining the terms of reference of the project manager.', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-A-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the structure that illustrates the relationship between project activity and the units of project that will perform those activities?', NULL, 'Organizational Breakdown Structure', 'Product Breakdown Structure', 'Responsibility Assignment Matrix', 'Work Breakdown Structure', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-A-52', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the PMBOK Guide – Fifth Edition, which of the following is an appropriate definition of a project stakeholder?', NULL, 'A person or group who provides resources and support for the project, program, or portfolio and is accountable for enabling success.', 'An individual, group, or organization, who may affect, be affected by, or perceive itself to be affected by a decision, activity, or outcome of a project.', 'An organizational structure that standardizes the project-related governance processes and facilitates the sharing of resources, methodologies, tools, and techniques.', 'The person assigned by the performing organization to lead the team that is responsible for achieving the project objectives.', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-A-53', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the Function Point method that is used for system development estimation?', NULL, 'It is a method for estimating the overall workload where the development work is broken down into units of work items and then the workload for each item is accumulated on the basis of a predefined standard value for the unit of workload.', 'It is a method for estimating the person-hours and period of time required to complete development, on the assumption that the development scale is known. It can be applied to all fields, not just to the business field.', 'It is a method for estimating the scale and person-hours of development on the basis of the past experience of a similar system, where past data is used for the same areas and past experience for different areas.', 'It is a method for estimating the scale of a system where the functions of the system are quantitatively measured by using elements such as the number of I/O data items and the number of files, and an adjustment is performed on the basis of the complexity and characteristics of the application.', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-A-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the ITIL 2011 edition, which of the following is an appropriate stage of the service life cycle where a service provider builds and deploys new or modified services?', NULL, 'Service design', 'Service operation', 'Service strategy', 'Service transition', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-55', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('ISO/IEC 20000-1:2011 requires the application of the methodology known as “Plan-Do-Check-Act” (PDCA) to all parts of the Service Management System (SMS) and the services. Which of the following is an activity that is included as a plan in SMS?', NULL, 'Conducting management reviews at planned intervals, and maintaining their records', 'Creating a framework of authorities, responsibilities, and process roles', 'Creating a plan for approved improvements, and implementing and reporting the improvements', 'Implementing and operating SMS through allocation and management activities of funds and budgets', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the ISO/IEC 20000-1:2011, which of the following is a control process that includes the identification, control, recording, tracking, reporting and verification of CI and the management of CI information in the CMDB?', NULL, 'Capacity management', 'Change management', 'Configuration management', 'Release and Deployment management', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate purpose for which a system auditor exchanges opinions with an audited department with respect to the draft version of an audit report?', NULL, 'In order to confirm that there are no factual errors in the findings and recommendations to be described in the audit report.', 'In order to issue the audit report to the audited department before the audit report is submitted to the person who is requesting the audit.', 'In order to receive the approval of the responsible person of the audited department with respect to the recommendations described in the audit report.', 'In order to substitute with an additional investigation concerning the audit report for which the investigation is insufficient, by orally confirming with the audited department.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a checkpoint for auditing the control of the risk of information leakage, falsification, and unauthorized use of documents concerning a system?', NULL, 'Creating the necessary documents even in prototype development', 'Standardizing documents', 'Taking measures in order to ensure the confidentiality of documents', 'Updating documents without delay as changes are made in the system', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning the implementation of a system audit?', NULL, 'For an audit of the development status of an information systems department, the audit team consists of members of the information systems department who are familiar with the details of the development.', 'In order to enable the person requesting the audit to issue improvement instructions on the basis of the audit report, the system auditor reports the audit results to the person requesting the audit.', 'When a system audit is performed as part of an operations audit, the audit team consists of members of the user department.', 'When a system auditor accepts the help of other experts, the experts become responsible for decisions concerning the scope and methods of support, as well as the audit result.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique that is used to perform the optimum resource allocation for a computerization investment in each category classified on the basis of the similarities of risks and the investment value?', NULL, '3C analysis', 'Benchmarking', 'Enterprise architecture', 'IT portfolio', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-A-61', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following represents a part of the total cost of ownership (TCO) for SaaS (Software as a service)?', NULL, 'Cost of upgraded installation', 'Data migration cost', 'New software development cost', 'Server hardware investment to host the software', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a measure for the risk of a decline in the system maintenance and operation quality during the outsourcing of an IT service?', NULL, 'Human resources with assessment capabilities with respect to the service cost of system maintenance and operations are secured in the company.', 'In order to validate the service cost, the detailed fee structure by service is clearly stated in the contract or other documents.', 'The proposal for the human resource development plan of the company after outsourcing is requested during the stage of subcontractor selection, and is also clearly stated in the contract or other documents.', 'The service quality improvement activities are proceeded by agreeing to the desired level of quality with the subcontractor by using indexes that demonstrate the service quality.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-63', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of hosting service?', NULL, 'A usage method, such as a high-performance server of a service provider being exclusively used by a single user, is not supported.', 'In terms of operations management, all activities, including the monitoring of server operations, incident handling, etc. are addressed by users.', 'The utilization right of a server prepared by a service provider is lent out to users.', 'Users freely select and combine servers by providing their own servers to the service provider facility.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '18-A-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of BYOD (Bring Your Own Device)?', NULL, 'Carrying information devices provided by the company at any time for work use', 'Configuring a usage environment for the personal use of personally-owned information devices', 'Using employees’ personally-owned information devices for work', 'Using laptop computers or other information devices provided by the company for personal use outside of the company', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-65', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the work that is performed when non-functional requirements are defined?', NULL, 'Clarifying the flow of information (i.e., data) between the functions constituting business operations', 'Clarifying the interface for exchanging information with other systems', 'Creating the technical requirements for the development criteria and standards according to the programming language used in system development', 'Defining the scope to be implemented as system functions', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '18-A-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the digital divide?', NULL, 'It refers to an economical or social gap that occurs because of differences in abilities and opportunities when using computers and communication networks.', 'It refers to communications and broadcast services that can be used equally by any citizen with reasonable charges, without any difference between regions.', 'It refers to citizens participating directly in government policies and autonomous bodies through the use of the Internet.', 'It refers to the provision of all services from a single place for each event of the daily life of citizens or each field of corporate activity.', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '18-A-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of analyzing business plans and competitive advantages through portfolio management that uses the matrix shown in the figure?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-68.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS02OC5wbmciLCJpYXQiOjE3NDMxMTY4MTUsImV4cCI6MTc3NDY1MjgxNX0.njVWbo2g94HzsvS5tbg1xbC4lHntpyDg_RuxOZJZUwA', 'To evaluate tactics for maintaining a competitive edge in the market by improving product quality', 'To evaluate the change in the market by considering seasonal fluctuation factors and geographical distribution in order to set an objective', 'To evaluate the competitors’ move in the market so that the promotion effect, set as an objective, can be measured', 'To evaluate the position of the company’s business as the basis for setting an objective and prioritizing resource allocation', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-A-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of core competence?', NULL, 'Corporate activities that follow laws, various regulations, and social norms for performance management', 'Overall system and operation optimization techniques to achieve the purposes of organizational activities', 'Predominant abilities that cannot be imitated by competitors in a company’s area of activity', 'The development region of a business that is decided upon based on the viewpoint of the market, technology, and products (or services)', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-A-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the basic strategy of a niche in a competitive position?', NULL, 'A differentiation strategy necessary for a leader attack, such as a share pursuit', 'An imitation strategy that quickly responds to market opportunities', 'An omni-directional strategy that covers the entire market and secures the highest share', 'A specialization strategy that aims at the specialization of the product and market', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-A-70', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below is the work procedure of MRP (Material Requirements Planning), a technique of a production management system. Which of the following information to be inserted into A in the figure below is necessary for calculating the net requirements?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-71.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS03MS5wbmciLCJpYXQiOjE3NDMxMTY4MTgsImV4cCI6MTc3NDY1MjgxOH0.PuwjQsocaqVhDkg95L8M1DmtSvgInbOp1kMftvk-jts', 'Bill of materials (configuration and requirements of each component in the final product)', 'Inventory status (inventory amount, residual orders, in-process quantity)', 'Ordering policy (lot organization method, ordering method, safety stock)', 'Standard schedule (completion period, number of days of lead time)', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-A-71', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following describes an RFID system?', NULL, 'Multiple RF Tags within range communicate with each other, and create a mesh network.', 'RF Readers/Writers generate an electromagnetic field that charges the RF Tags within range to allow transmission of information.', 'RF Tags process unique positioning information by using multiple satellites which allow for the tracking of the item using longitude and latitude coordinates.', 'RF Tag transmission does not provide error correcting codes and still acquires high reliability through a wired connection.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '18-A-72', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a management organization that creates a cross-functional team between project and functional organizations in order to flexibly respond to changes in the business environment?', NULL, 'Divisional organization', 'Line and staff organization', 'Matrix organization', 'Project organization', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-A-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate role of a facilitator in a meeting?', NULL, 'To act as the chairperson and control the discussions so as to work out a conclusion that matches the intentions of the management', 'To encourage the participants of the meeting to put forth their remarks and organize the flow of discussions from a neutral and impartial position', 'To give advice only in discussions related to specific areas in which the facilitator specializes, such as technical or legal fields', 'To offer specialized support for the administration of a meeting, such as adjusting the schedule, preparing materials, or creating minutes.', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-A-74', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of an affinity diagram?', NULL, 'It is a method by which along with the progress in a situation, measures are examined for problems that might have several outcomes, and the process leading to the desired result is decided.', 'It is a method by which a causal relationship is clarified for events intertwined with complex factors.', 'It is a method by which the collected information is categorized on the basis of a mutual relationship, and the problems to be resolved are clarified.', 'It is a method by which the means and measures for achieving the purpose and objectives are developed sequentially, and the most appropriate means or measures are sought.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '18-A-75', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of Green by IT?', NULL, 'Development of efficient in-house software', 'Development of a powerful in-house Data Centre', 'Using a desktop PC instead of a laptop thin client', 'Using web conferencing instead of travelling to meetings', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '18-A-76', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A factory has recorded the number of occurrences of defective products according to the cause of the defect. Based on this record, which of the following is a Pareto chart that shows the top causes of defective product occurrences and the cumulative total of percentages?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-77-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS03Ny1BLnBuZyIsImlhdCI6MTc0MzExNjgzMiwiZXhwIjoxNzc0NjUyODMyfQ.zGl_w6ee4ehJY4zQttBI23MQ71cdNaYhW80dXjc5wtk', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-77-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS03Ny1CLnBuZyIsImlhdCI6MTc0MzExNjgzNSwiZXhwIjoxNzc0NjUyODM1fQ.Mg15gHbT2uVvbt2V0gHTMBflPU7M_ZrOhorbrp9P3ps', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-77-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS03Ny1DLnBuZyIsImlhdCI6MTc0MzExNjgzOCwiZXhwIjoxNzc0NjUyODM4fQ.X8ciyRqKGouTROFwFO_mjaWTW17rdITehv9Elz5BO1o', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-77-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS03Ny1ELnBuZyIsImlhdCI6MTc0MzExNjg0MSwiZXhwIjoxNzc0NjUyODQxfQ.gry9WlRC26vke8Uya-NXkGiBbkINIJY7U0O02jhU_kc', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-A-77', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Company A sets a goal to make a profit of $36,000 under the conditions shown in the table below. What is the minimum sales revenue for the company to achieve its goal?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-A-78.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtQS03OC5wbmciLCJpYXQiOjE3NDMxMTY4MjUsImV4cCI6MTc3NDY1MjgyNX0.I9leLvHj8HdupwGK1xX5ru35IfSByLRYzM0xDNNI1rg', '3,500', '6,500', '140,000', '260,000', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-A-78', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the inventory unit price is determined by dividing the total purchase amount by the total quantity of items purchased, which of the following is an appropriate inventory method to be used?', NULL, 'First-in first-out method', 'Periodic average method', 'Moving average method', 'Final acquisition cost method (Final purchase cost method)', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-A-79', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the scope of software protection under WTO’s Agreement on Trade-Related Aspects of Intellectual Property Rights (TRIPS)?', NULL, 'Algorithms and programming languages are protected.', 'Application programs are protected but basic programs such as an OS are not, as the value of the right is included in the hardware cost.', 'Both source programs and object programs are protected.', 'Documents that describe algorithms are protected, but programs created by using the algorithms are not.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '18-A-80', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the octal representation of a hexadecimal fraction F1B0.C?', NULL, '170660.6', '361540.14', '743300.6', '5213052.3', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '17-O-01', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When two unbiased coins are tossed and an unbiased six-sided die is rolled at the same time, what is the probability that at least one coin shows heads and the die shows an even number?', NULL, '1/4', '3/8', '1/2', '3/4', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '17-O-02', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following expressions in postfix notation is equivalent to an expression 2+5×3+4 in infix notation? Here, the operator ‘×’ has higher precedence than ‘+’.', NULL, '2 5 3 4 × + +', '2 5 + 3 4 × +', '2 5 3 × 4 + +', '2 5 3 × + 4 +', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '17-O-03', -1.0, 1.0);
