INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Values from 1 to 10 are assigned to 10 nodes in the binary tree below so that each node has a different value. In this assignment, the value of each node is greater than the values of the left child and all its descendants, and is less than the values of the right child and all its descendants. Which of the following is a combination of values assigned to node A and node B?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-07.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy0wNy5wbmciLCJpYXQiOjE3NDMxMTU2MDAsImV4cCI6MTc3NDY1MTYwMH0.JoCtFe_ImwRdHDeJZE7qL752gm9Hql2SoDD7OLKi8Ko', 'A = 6, B = 7', 'A = 6, B = 8', 'A = 7, B = 8', 'A = 7, B = 9', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '17-O-07', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There are two boxes; the first box contains two green balls and three red balls; the second box contains three green balls and two red balls. A boy randomly selects a box from the two, and then randomly picks a ball from that box. If the ball is red, what is the probability that he selected the first box?', NULL, '3/20', '3/10', '1/2', '3/5', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '17-O-08', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of symmetric multiprocessing (SMP)?', NULL, 'One CPU core serves as a master, while the other CPU cores act as slaves and perform the tasks assigned to them by the master.', 'One or more programs are loaded in the main memory, and only one program at a time is able to get the CPU for the execution while all the others are waiting their turns.', 'Several CPU cores have schedules for their own tasks, with priorities set by the operating system with equal access to the memory and system resources.', 'While one stage of an instruction is being processed, other instructions may be processed at a different stage so that multiple instructions can be processed at the same time.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-09', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('To determine an effective address from the value recorded in the address part of instruction, various addressing modes are used. Which of the following modes uses the value of the address part as an effective address?', NULL, 'Absolute addressing', 'Base plus index addressing', 'Indexed addressing', 'PC relative addressing', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-10', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a memory device that stores programs or data in factories, and only has the read operation for the stored programs or data?', NULL, 'DRAM', 'Flash memory', 'Mask ROM', 'SRAM', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-11', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate role of a device driver?', NULL, 'It decides the next task to be executed from tasks queued up for execution.', 'It directly controls the hardware according to requests from an application program.', 'It interprets the command strings that are entered by the user, and starts the applicable program.', 'It manages the display status on the screen in multiple windows.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-12', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the RAID level that can recover data from the other disks, with a minimum of two-disk configuration?', NULL, 'RAID 0', 'RAID 1', 'RAID 5', 'RAID 6', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-13', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There exists a system composed of two processing devices. What is the difference in availability between the system that works when either of the devices functions normally and the one when both devices function normally? Here, the availability for both devices is 0.9, and factors other than the processing devices can be ignored.', NULL, '0.09', '0.10', '0.18', '0.19', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-14', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate characteristic of a web system implemented in a three-layer client/server system configuration?', NULL, 'A business process is executed on the server side, and the client software displays the result on a screen according to the HTML coding.', 'A program coded in HTML is run on the server side, and the client software displays the result on a screen.', 'Every time a business process is changed, a business process application for operating the web system must be sent and installed on the client terminal.', 'On the client terminal, it is necessary to have a resident service program waiting to receive an HTTP request from the server side.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following combinations is the average waiting time in millisecond for a First Come, First-Serve (FCFS) scheduling and Shortest-Job-First (SJF) scheduling given that the process arrives in the order P1, P2, P3, and P4, and the latency can be ignored. Note that the burst time is the actual time required to complete a process. Below is the list of processes, P1, P2, P3, and P4, and their burst time for CPU scheduling algorithms.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-16.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy0xNi5wbmciLCJpYXQiOjE3NDMxMTU2MDQsImV4cCI6MTc3NDY1MTYwNH0.IJDn0GhoVHIB3Q0b7VzcLaahu-putotzJJ_3jjBKKYI', 'a', 'b', 'c', 'd', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-16', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In input/output management, which of the following is an appropriate function of a buffer?', NULL, 'Enabling an input/output device to be handled in the same way as a file', 'Enabling the use of an input/output device without the need to consider its unique specifications by creating a data exchange layer between an input/output device and a processing device', 'Notifying a processing device when an input/output device becomes available for use', 'Reducing the difference in processing speed by establishing a special area of memory between an input/output device and a processing device', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-17', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the backup method that requires the longest time to backup but the shortest time to restore?', NULL, 'Differential backup', 'Full backup', 'Incremental backup', 'Synthetic full backup', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-18', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In UNIX, which of the following is a function that links the standard output of a command directly to the standard input of another command?', NULL, 'Background job', 'Brace expansion', 'Pipe', 'Redirect', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-19', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of optimization in a compiler?', NULL, 'Analyzing the source code and generating an object code with an improved run-time processing efficiency', 'Generating an intermediate code for an interpreter rather than generating an object code', 'Generating an object code that displays the called subprogram name or the content of a variable at a particular point in time during the execution of the program', 'Generating an object code that operates in a computer with a different architecture from the computer in which the compiler is implemented', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-O-20', -1.0, 1.0);
