INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The attributes of the relation “OrderRecord” have the functional dependency (1) to (6) below. Normalization is performed with these functional dependencies up to the third normal form, and the decomposition into the relations “Product,” “Customer,” “Order,” and “OrderDetails” are performed. Which of the following is appropriate for the relation “OrderDetails”? Here, {X, Y} represents a combination of the attributes X and Y, and X -> Y represents that X functionally determines Y. The solid underline represents a primary key.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-26.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy0yNi5wbmciLCJpYXQiOjE3NDMxMTU2NDAsImV4cCI6MTc3NDY1MTY0MH0.YneUlPHKgtv3knbwkaHXyFhVTM8F6Kd_3HWADF0FgGI', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-26', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the mapping between the relational model and relational database as its implementation?', NULL, 'A domain is mapped to a character type or a character string type.', 'A relation is mapped to a table.', 'Attributes and columns are ordered from left to right.', 'Neither tuples nor rows have duplicates.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-27', -2.0, 1.0);
