INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following can change the deadlock state of the transaction back to the normal state?', NULL, 'Commit', 'Drop', 'Rollback', 'Roll forward', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-29', -1.0, 1.0);
