INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a PC connected to a LAN is starting up, which of the following protocols is used to automatically assign an IP address to the PC?', NULL, 'DHCP', 'DNS', 'FTP', 'PPP', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following describes an IPv6 feature not existing in IPv4?', NULL, '128-bit addressing is introduced for the IP address space.', 'An IP address is represented as a pair of a network address and a subnet mask.', 'Private addresses are introduced to use IP addresses efficiently.', 'Subnet masks are introduced to use the address space efficiently.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-32', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In TCP/IP network, which of the following is a combination of information that identifies a TCP connection?', NULL, 'IP address, Session ID', 'IP address, Port number', 'MAC address, Session ID', 'Port number, Session ID', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-33', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below shows the basic mechanism to synchronize clocks using the NTP. A response from the NTP server contains a Request Receive Time and a Response Transmit Time. The PC calculates the difference between its internal clock and the NTP server clock using the four times shown in the figure. How is the internal clock of the PC different from that of the NTP server? Here, the request and the response require the same transmission time, and each time in the figure shows the time on the internal clock of the PC or the NTP server. In an expression aa:bb:cc.dddddd, aa, bb, cc, and dddddd represent hour, minute, second, a fraction of a second (in microseconds), respectively.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-34.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy0zNC5wbmciLCJpYXQiOjE3NDMxMTU2NDQsImV4cCI6MTc3NDY1MTY0NH0.0uyK7kHHm4MnG87JIaz_iI0cmS433fP6F_9PsjLxKss', '100 microseconds fast', '200 microseconds fast', '500 microseconds fast', '700 microseconds fast', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-34', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a form of malware that requires a host in order to propagate from one computer to another?', NULL, 'Trojan horses', 'Viruses', 'Worms', 'Zombies (Bots)', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the term used to describe an attack where attackers exploit a vulnerability of computer systems before a patch fixes the vulnerability?', NULL, 'Backdoor attack', 'Man-in-the-middle attack', 'Rootkit attack', 'Zero-day attack', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a buffer overflow attack?', NULL, 'An attack that floods the memory area secured by a program by continuously sending long character strings or data to seize access privileges from the program, and causes malfunctions', 'An attack that fraudulently overwrites cache information', 'An attack that sends a large amount of data continuously to the target server to place an excessive load on the server’s CPU and memory, and obstructs its service', 'An attack that takes advantage of the vulnerabilities in software before the software vendor can provide a fix for the vulnerability', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A typical example of personal security threats is information leakage. Which of the following is the most appropriate measure to prevent information leakage?', NULL, 'Data containing important information is encrypted with a private key before sending it to the receiver via email. In a separate email, the private key is sent to the receiver so that the receiver can decrypt the data.', 'Data containing important information is encrypted with the public key received in advance from the receiver before sending it to the receiver via email. The receiver then decrypts the data with the private key that the receiver has created as the pair of public/private keys.', 'Data containing important information is password-locked, and it is attached in an email that includes the password in the text part of the email. Before sending the email, the receiver address is checked to make sure that the email is sent to the correct address.', 'Stored data containing important information is compressed as much as possible before giving a USB memory to someone so that the new user can utilize the rest of the memory space effectively.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the process shown in the procedure below is performed, in addition to the detection of message falsification, which of the following is what recipient B is able to do?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-39.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy0zOS5wbmciLCJpYXQiOjE3NDMxMTU2NTQsImV4cCI6MTc3NDY1MTY1NH0.bx8YJqEJUg-aBe-Uaf0pt_vdwAmyBz40jaKwA-SBS0c', 'Confirming that the message is from sender A', 'Detecting wiretapping on the message', 'Identifying the areas of falsification', 'Preventing leakage of the message', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the techniques for code breaking given below, which of the following is classified as a brute force attack?', NULL, 'By observing the difference between two different items of plain text and their encrypted text, the key is identified.', 'For a given set of plain text and encrypted text, the key is identified by using all possible combinations.', 'The encrypted text is decoded by analyzing the electromagnetic waves that an encryption device emits during the operation.', 'The statistical bias of an encryption function is approximated with a linear function, and the encrypted text is decoded.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-40', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate terminology concerning the behavior that documents retrieved from distinct origins are isolated from each other?', NULL, 'Clickjacking', 'Cross-Origin Resource Sharing (CORS)', 'Cross-Site Request Forgery (CSRF)', 'Same-Origin Policy', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a mirror port is prepared to allow a LAN analyzer to be used to investigate the cause of a network failure, which of the following is a point to consider?', NULL, 'In preparation for a failure, it is necessary to inform network users of the storage location and usage method of the LAN analyzer.', 'Since LAN cables must be temporarily disconnected during measurement, it is necessary to notify network users in advance of the date and time of measurement.', 'Since the LAN analyzer can display the packets that pass through the network, it is necessary to pay attention to misuse or abuse such as wiretapping.', 'Since the LAN analyzer disposes of packets, it is necessary to restrict the use of the non target computers during measurement.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-42', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate term for an organized and highly skilled team, whose mission is to continuously monitor and improve the organization’s security posture while preventing, detecting, analyzing, and responding to cyber security incidents with the aid of both technology and well-defined processes and procedures?', NULL, 'Cybersecurity', 'Incident Management Center (IMC)', 'Network Operations Center (NOC)', 'Security Operations Center (SOC)', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-43', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a packet filtering firewall controls packets by using a list of rules, which of the following is the rule that is applied to packet A and its action? Here, the firewall applies the rules shown in the list below in the order number 1–4, and if a rule is applied, then the remaining rules are not applied.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-44.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy00NC5wbmciLCJpYXQiOjE3NDMxMTU2NTksImV4cCI6MTc3NDY1MTY1OX0.vYedDuHFIYmhYqvQ13g9gK9qiYHLzG8Zdyntpri_BeA', 'Blocked by number 1', 'Blocked by number 4', 'Permitted by number 2', 'Permitted by number 3', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-O-44', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description of polymorphism in object oriented design?', NULL, 'It allows developers to define classes incrementally by reusing classes defined previously as the basis for new classes.', 'It allows the analyst to focus on the important dimensions while ignoring nonessential dimensions.', 'It combines the processes and data into a single object.', 'It is the provision of a single interface to entities of different types.', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '17-O-45', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the development process, which of the following is an activity that should be performed in software architectural design?', NULL, 'Analyzing the requests in incremental steps by arranging them in the form of a chart', 'Describing the specifications so that the program is clarified on a line-by-line basis', 'Obtaining the opinion of the customer and deciding the specifications', 'Transforming the requirements for the software item into an architecture that describes its top-level structure and identifies the software components', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-O-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description of stack-trace in relation to debugging a program?', NULL, 'A trace of call stack methods/functions/subroutines', 'Stacking/gathering the traces left by other programs', 'The traces left in memory from a stack data structure', 'Tracing stack data structure for appropriate contents', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-O-47', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning a state transition test in a system integration test?', NULL, 'A method for black box tests that does not focus on a system’s internal state.', 'A method that checks whether a system behaves according to the designed combinations of events and internal states.', 'A method that is suitable for tests of calculations and processing systems whose internal state does not change depending on the occurrence of an event.', 'A method that uses a data flow diagram and a decision table to analyze the internal state of a system.', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-O-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a method for analyzing a source and object codes, and extract program specifications and design information?', NULL, 'Reengineering', 'Refactoring', 'Restructuring', 'Reverse engineering', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-O-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the ISO/IEC 12207 (Systems and software engineering – Software life cycle processes (SLCP)), the Software Implementation Process has the following lower-level processes: 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to PMBOK, which of the following processes is included in the Executing Process Group?', NULL, 'Process of auditing the quality requirements and the results from quality control measurements to ensure that appropriate quality, standards and operational definitions are properly implemented', 'Process of checking and recording results of executing the quality activities to assess performance and recommend necessary changes', 'Process of estimating the type and quantities of material, people, equipment, or supplies required to perform each activity', 'Process of prioritizing risks for further analysis or action by assessing and combining their probability of occurrence and impact', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-O-51', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of “Lead” relationship in project time management?', NULL, 'It is the amount of time by which a successor activity can be advanced with respect to a predecessor activity.', 'It is the amount of time by which a successor activity will be delayed with respect to a predecessor activity.', 'It is the amount of time that a schedule activity can be delayed or extended from its early start date without delaying the project completion date or violating a schedule constraint.', 'It is the number of work periods (hours, days) required to complete individual activities with the estimated resources.', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-O-52', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The following arrow diagram shows the activities and the milestones of a project. What is the minimum project completion time in days?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-53.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy01My5wbmciLCJpYXQiOjE3NDMxMTU2NjYsImV4cCI6MTc3NDY1MTY2Nn0.wYOZ59OzHgzBIkPI1IEb2OhX6VbqePu8ckDtUKke3yE', '10', '12', '14', '19', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-O-53', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Company A is going to launch a new software product and the sales team then has to demonstrate it to the customers. There is a risk that the sales team does not understand the product and cannot provide good demonstrations. As a consequence, the sales team will make fewer sales and there will be less revenue for the company. So, the management decided to provide good training for the sales team. Which of the following is the best method to manage the risk?', NULL, 'Risk acceptance', 'Risk exploitation', 'Risk mitigation', 'Risk transfer', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-O-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the function point value of a program that has the functions and characteristics described in the table below? Here, the correction coefficient of complexity is 0.75.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-55.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy01NS5wbmciLCJpYXQiOjE3NDMxMTU2NzAsImV4cCI6MTc3NDY1MTY3MH0.KYgFknhcWn8OWoFNpd-ZVYg6kkEk9Ko90GidHFH7MXU', '18', '24', '30', '32', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-O-55', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate purpose of using a Work Breakdown Structure (WBS) in a software development project?', NULL, 'To clarify the time sequence of activities, and understand the critical path that should be intensively managed', 'To decompose a development task into smaller sub-tasks of a manageable size, and organize them into a hierarchical structure', 'To optimize the total cost when there is a trade-off relationship between the number of days and the cost that is required for development', 'To show the schedule of an activity by using a bar, and clarify the start point and end point of the activity as well as the progress at the current point', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-O-56', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following device is used for protecting power supply circuits, communication devices, or other equipment from the overvoltage and the over current generated from the overvoltage?', NULL, 'AVR', 'CVCF', 'SPD', 'UPS', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-O-57', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate precaution to be observed when monitoring the use of the capacity and performance of an online system in the capacity management process of IT service management?', NULL, 'Incidents concerning capacity and performance are recorded.', 'Multiple measurement items such as the response time and CPU utilization are monitored on a regular basis.', 'Only the maximum value of performance data during a fixed period is focused upon, and deviation from the management limit is checked.', 'Since the measurement of performance during online hours causes a decline in service level, measurement is performed during offline hours.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-O-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to ITIL, which of the following is a description of a virtual service desk among the characteristics of a service desk organization?', NULL, 'By using communication technology, services can be provided from a single service desk as observed by the user, even if the service desk staff members are distributed across multiple regions.', 'Instead of deploying full-time service desk staff members, persons in charge of business operations such as research, development, sales, etc. manage concurrent posts.', 'It exists either at the same or physically close location to the user base.', 'With the purpose of improving cost effectiveness and communication efficiency, service desk staff members are stationed at a single or a few places.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-O-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an information security audit, which of the following is a check item for confirming availability?', NULL, 'Error checks during data input to be performed appropriately.', 'Interruption duration to be managed so that the standard of the SLA specifying the interruption duration can be satisfied', 'The database to be encrypted', 'The unauthorized removal of an external memory medium to be prohibited', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following situation is judged as appropriate when conducting an audit on a Business Continuity Plan (BCP)?', NULL, 'A BCP having the same standard level is applied to all business operations without any prioritization.', 'An emergency contact list of employees is created and updated to the latest version.', 'During normal times, the BCP is not disclosed to employees.', 'The important documents are stored collectively at one place without making copies.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-O-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of Enterprise Architecture (EA)?', NULL, 'It is a technique to abstract and express the business processes with the four (4) basic elements of data flow, process, file, and data sources and absorption.', 'It is a technique to analyze each business operation and information system through the four (4) systems of business, data, application, and technology and reexamine it from the viewpoint of total optimization.', 'It is a technique to analyze or design a system by using schematic diagrams such as a class diagram, and it is developed by integrating and standardizing various methods that support an object-oriented design.', 'It is a technique to clarify the data structure and the relationship between data items by expressing the conceptual data model with entities and relationships.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '17-O-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a project organization?', NULL, 'An organization is structured to extend across multiple companies to actively utilize external management resources such as in strategic alliances or joint development.', 'Each organizational unit, structured on the basis of product, region, etc., is given responsibility for profit.', 'It is formed only for a certain period of time to solve a given problem, and it is dissolved when the problem is solved.', 'Tasks are divided according to functions, and orders and instructions are given to subordinates for each function.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-O-63', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a purpose of Business Process Management (BPM) in corporate activities?', NULL, 'Analysis and effective use of information resources', 'Conservation and analysis of customer information', 'Continuous improvement of business processes', 'Effective use of management resources', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '17-O-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The purchase of two types of IT devices A and B is being examined. The payout period is set in consideration of the useful life of each of the devices. Which of the following is an appropriate description for the minimum amount of annual profit necessary to recover the amount of investment within the set payout period for A and B? Here, the annual profit is made evenly every year, and the interest rate is not considered.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-65.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy02NS5wbmciLCJpYXQiOjE3NDMxMTU2ODIsImV4cCI6MTc3NDY1MTY4Mn0.o94MCMIU4OBiFMvCJxGEOoU5JrNKne-c15USQKLs320', 'It is necessary for A and B to make the same amount of annual profit.', 'It is necessary for A to make twice the annual profit than that of B.', 'It is necessary for B to make 1.5 times the annual profit than that of A.', 'It is necessary for B to make twice the annual profit that of A.', 'd', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '17-O-65', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The weighted comprehensive evaluation method which integrates and quantifies the evaluation scores of multiple items is applied to quantitatively evaluate the effect of improvements. Which of the following is the improvement proposal that should be prioritized in the table below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-66.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy02Ni5wbmciLCJpYXQiOjE3NDMxMTU2ODUsImV4cCI6MTc3NDY1MTY4NX0.yyM_xRpZRfl3QYLClQ6LGxxdMvBj6yuhaAWOOkohbAk', 'Proposal 1', 'Proposal 2', 'Proposal 3', 'Proposal 4', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '17-O-66', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following descriptions corresponds to the CSR procurement?', NULL, 'Choosing the product with the lowest price to minimize costs', 'Having multiple suppliers to avoid situations in which procurement is not possible after disasters', 'Indicating procurement standards that consider the environment, human rights, etc., and requesting suppliers to comply with these', 'Using EDI for purchasing goods to perform prompt and accurate procurement', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '17-O-67', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The RFP is presented to each vendor that has responded to an RFI. Which of the following should be done beforehand to proceed fairly with the future vendor selection processes?', NULL, 'Besides the items of an RFP, giving a high evaluation to a vendor who is familiar with the current system to select that vendor easily', 'Establishing processes of selection such as setting evaluation standards or weighting rules of conformity to the request items.', 'Issuing unofficial agreements to all vendors to whom the RFP has been presented and requesting them to prepare a contract and a statement of work to accelerate the conclusion of the contract after the vendor selection.', 'Preparing a bailout for a vendor who received a high evaluation on the response to the RFI, in case it fails in the selection.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '17-O-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a marketing technique used to provide incentives for distributors by applying conditions such as kickbacks and rebates, and increase the demands of consumers?', NULL, 'Direct marketing', 'Pull strategy', 'Push strategy', 'Relationship marketing', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-O-69', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below illustrates the relationship between the four (4) Ps proposed from the seller’s viewpoint and the four (4) Cs proposed from the buyer’s viewpoint in the marketing mix. Which of the following corresponds to blank A in the figure below? Here, a) through d) correspond to one of blanks A through D, without an exception.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-70.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy03MC5wbmciLCJpYXQiOjE3NDMxMTU2OTYsImV4cCI6MTc3NDY1MTY5Nn0.pl7vhPOLd3N3LfKmOC5XvmSw2D229Azk7HajYCs4Olc', 'Communication (interaction with customers)', 'Convenience (convenience of customers)', 'Cost (customers’ expense)', 'Customer value (value for customers)', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-O-70', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The sales price of products is decided according to the different sales price setting methods. Which of the following approaches sets a high sales price by using the consumer psychology that high quality equals to high price?', NULL, 'Cost plus pricing', 'Differential Pricing', 'Marketing price following pricing', 'Prestige pricing', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-O-71', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the technology S-curve?', NULL, 'It represents the diffusion process of a new technology, where a frequency distribution curve shows the growth of the new technology diffusion gradually decreases as the product using the technology is popularized in the market.', 'It represents the maturing process of technology. It shows that, during the time until the new technology is actually spread, the degree of awareness and expectation changes as time passes.', 'It represents the process of technology progress. It shows that technology advances slowly at the beginning and then advances rapidly; thereafter, its progress gently becomes stagnant.', 'It represents the relationship between production volume and unit cost. It shows the course of reduction in unit cost with an increase in cumulative production volume.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-O-72', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of Consumer Generated Media (CGM)?', NULL, 'A website of a company through which the company publishes information about its management and financial status, as well as performance trends for individual investors', 'A website of a company through which the company transmits information about the characteristics and usage methods of its products to the general consumers', 'A website of a government organization through which the agency publishes information about its policies and administrative services to the general citizens', 'A website such as a blog and SNS, etc. through which an individual transmits information to the general public about the evaluation of products, etc. that he/she has used', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-O-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following indicates a price setting method based on the cost plus approach?', NULL, 'Deciding the price by adding a margin right from the beginning with the prerequisite of offering a discount to the customer', 'Deciding the price by incorporating the desired margin with reference to the manufacturing cost and business expenses', 'Deciding the price on a level that can be expected to compete in the market', 'Deciding the price step-by-step in view of maximum profits and minimum risks through price analysis', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '17-O-74', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The figure below shows the relationships among components for product A, and a number in parentheses is the quantity of components needed to produce one unit of the upper-level product or component. When 10 units of product A are produced, how many units of component C must be ordered? Here, there are presently five units of component C in the inventory, and the components in the inventory must be used for the production before the order.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-O-75.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctTy03NS5wbmciLCJpYXQiOjE3NDMxMTU2OTAsImV4cCI6MTc3NDY1MTY5MH0.N0vl1swhomYWnCVuyjt5n-MLkhhIO5q7-LBEy6Qr_So', '15', '20', '25', '30', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '17-O-75', 0.0, 1.0);
