INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the role of a CIO?', NULL, 'To implement investigation, research, and education of information technology', 'To make a computerization strategy from a corporate level perspective, and confirm and evaluate its consistency with business strategy', 'To manage a project through extensive business experience, knowledge of information technology, and leadership', 'To present the computerization proposal of his/her own department to the information system department as a representative of each department', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '17-O-79', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The horizontal and vertical axes of an Operating Characteristic (OC) curve in quality management generally represent the percent defective of a lot and the success rate of a lot, respectively. Samples of size n are extracted from a lot of size N, and when the number of defective samples is equal to or less than the pass quantity C, the lot is considered to have passed, and when it exceeds C, the lot is considered to have failed. 
