INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the computer architecture where processors execute multiple instruction streams on multiple data streams in parallel?', NULL, 'MIMD', 'MISD', 'SIMD', 'SISD', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-A-11', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of memory interleaving?', NULL, 'It allows CPU to access different banks of the main memory simultaneously.', 'It improves CPU performance by connecting I/O interface directly to the main memory.', 'It makes use of a fast memory between the CPU and the main memory, which serves as a buffer for frequently accessed data.', 'It widens the data bus to read or write several bytes between the CPU and the main memory in a single process.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-A-12', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate role for a device driver?', NULL, 'It decides the next task to be executed from tasks waiting for execution.', 'It directly controls hardware according to requests from an application program.', 'It interprets command strings that are entered by the user, and starts the applicable program.', 'It manages the display status on the screen in multiple windows.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-A-13', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate term to describe the phenomenon when files produced in the process of saving are scattered to different parts of the whole hard disk rather than in continuous clusters?', NULL, 'Contiguity', 'Fragmentation', 'Sector', 'Segmentation', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-A-14', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate explanation of grid computing?', NULL, 'A computing task is distributed to several computers in the network to attain the computational capacity.', 'Physical devices such as computers or network devices are emulated to circumvent compatibility constraints and attain software portability and flexibility.', 'Requirements are stated as constraints on response time and/or on the temporal validity of sensory data.', 'Sensing devices are connected to a network to provide feedback and control through personal mobile devices.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-A-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Consider a RAID 0 (i.e., block-level striping without parity or mirroring) system with two disks; when data is distributed evenly across the two disks and both disks have a failure rate of 0.1%, what is the overall failure rate (as a percentage) of this RAID system? Here, the overall failure rate refers to the probability that the system fails to obtain data from either of the disks.', NULL, '0.0001', '0.01', '0.1999', '1.9990', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-A-16', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning MTBF and MTTR?', NULL, 'MTBF of a system decreases and MTTR of a system increases through remote maintenance.', 'MTBF of a system increases as the number of device types that constitutes the system increases.', 'MTBF of a system increases through preventive maintenance.', 'MTTR increases because of functions such as an error log or an instruction trace.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '17-A-17', -1.0, 1.0);
