INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('ABC company applies a three-generation backup policy. The ABC company’s system automatically performs full back up on the 10th, 17th, and 25th of each month. If the latest back up was performed on 17th September, what is the date that the oldest information was backed up?', NULL, '17th August', '25th August', '10th September', '17th September', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-A-21', -1.0, 1.0);
