INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following SQL statements for the table “ShipmentRecord” obtains the largest value?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-A-31.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctQS0zMS5wbmciLCJpYXQiOjE3NDMxMTU1MzYsImV4cCI6MTc3NDY1MTUzNn0._yu1tu5h1GEEG2vnIYtjaMbEXaq2q50MQKiBzEAqO-A', 'SELECT AVG(Quantity) FROM ShipmentRecord WHERE ProductNumber = ''NP200''', 'SELECT COUNT(*) FROM ShipmentRecord', 'SELECT MAX(Quantity) FROM ShipmentRecord', 'SELECT SUM(Quantity) FROM ShipmentRecord WHERE Date = ''2015-10-11''', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-31', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a routable IP address in the Internet?', NULL, '10.129.205.3', '172.40.77.4', '192.168.10.7', '192.168.203.5', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-32', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the seven layers of the OSI basic reference model, which layer is responsible for forwarding packets, including routing them through intermediate routers?', NULL, 'The data link layer', 'The network layer', 'The session layer', 'The transport layer', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-33', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In an IPv4 network, which of the following is the correct combination of an IP address class, its IP address range, and a subnet mask?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-A-34.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctQS0zNC5wbmciLCJpYXQiOjE3NDMxMTU1NDMsImV4cCI6MTc3NDY1MTU0M30.sdM__IIG_yibvo60CWydD129OcU7q255B7-2v1WUVoM', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-34', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an Internet service that translates a domain name such as www.itpec.org into its corresponding IP address?', NULL, 'ARP', 'DNS', 'RARP', 'TCP', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the netstat utility?', NULL, 'It displays active TCP connections.', 'It displays the contents of the DNS resolver cache.', 'It displays the mapping between IP addresses and corresponding MAC addresses in the cache.', 'It displays the route path to the specified destination and measures the packet delays.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-36', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Alan would like to send an encrypted message to Bob using an asynchronous encryption scheme. Which of the following must occur before Alan sends the encrypted message to Bob? Here, Alan has already proven to Bob with the digital signature that Alan is the person who sends the message to Bob.', NULL, 'Alan provides his private key to Bob.', 'Alan provides his public key to Bob.', 'Bob provides his private key to Alan.', 'Bob provides his public key to Alan.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate term associated with the fraudulent action of impersonating an authorized person?', NULL, 'Destruction', 'Falsification', 'Spoofing', 'Tapping', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-38', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An attacker calls a corporate help desk, masquerading as an employee who has lost their password. The help desk staff resets the password to the company default "password1." The attacker then uses this password to access the company network and information in the server. What is this type of attack called?', NULL, 'Buffer overflow attack', 'Denial-of-Service attack', 'Shoulder surfing', 'Social engineering', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A man-in-the-middle attack happens when an attacker intercepts communication and spoofs the identities of either of the two parties involved. How can such an attack be effectively countered?', NULL, 'Such an attack can be countered by a cyclic redundancy check (CRC).', 'Such an attack can be countered by having an authentication through a digital signature before accepting someone''s public key.', 'Such an attack can be countered by using a parity bit.', 'Such an attack can be countered by using hashing algorithms.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-40', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Bob and Alice encrypt all of their communications with each other. Because of the high level of sensitivity of the information they are sharing, they have implemented a cryptographic mechanism that offers secrecy to their messages. However, the trade-off of this encryption is that it is impossible for Bob or Alice to be 100% sure that they are communicating with each other, nor can they be 100% certain of the integrity of the content of the messages. Which of the following types of encryption methods are Bob and Alice using?', NULL, 'AES (Advanced Encryption Standard)', 'DES (Data Encryption Standard)', 'One-time pad', 'Stream cipher', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A user has just received a file named “image.jpg.” When inspected more closely, it is revealed that the file name is actually “image.jpg .exe,” with spaces between the fake .jpg suffix and the real .exe suffix. Which of the following is the most appropriate term used to describe this type of attack?', NULL, 'Backdoor', 'Trojan horse', 'Virus hoax', 'Worm', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-42', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A data backup system must support restoring all transactions until 5 minutes before a disaster happens. What type of goal is this?', NULL, 'Maximum tolerable downtime', 'Recovery point objective', 'Recovery time objective', 'Service level agreement', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate test to verify the efficacy of security measures by attempting an actual intrusion?', NULL, 'Exception test', 'Functional test', 'Penetration test', 'Stress test', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-44', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate method to prevent a buffer overflow attack?', NULL, 'Performing input filtering and removing browser scripts from all user input on web applications', 'Performing input filtering and removing structural query language commands from all user input', 'Performing the boundary check on all integer variables in the program to confirm that the resulting value from each calculation does not exceed the limit of its destination variable', 'Performing the boundary check on all string variables in the program to confirm that the length of the input string does not exceed the size of the designated variable', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-45', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Companies usually provide a means for their mobile workforce to access the corporate network securely over the Internet through insecure channels such as open wireless networks in hotels or coffee shops. Which of the following is the appropriate technology that can be used for this purpose?', NULL, 'DMZ (DeMilitarized Zone)', 'SNMP (Simple Network Management Protocol)', 'VoIP (Voice over Internet Protocol)', 'VPN (Virtual Private Network)', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-46', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following are components of a UML2.x (including 2.0 and later versions) state diagram?', NULL, 'Message and Activity', 'Message and Transition', 'State and Message', 'State and Transition', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-A-47', -1.0, 1.0);
