INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a software component is tested, which of the following is an appropriate combinations of X and Y?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-A-50.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctQS01MC5wbmciLCJpYXQiOjE3NDMxMTU1NTUsImV4cCI6MTc3NDY1MTU1NX0.Czy51tC7HNY6xrUNzwtMUZ1kB27RPKnT9WmlNmkTB-A', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-A-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the Capability Maturity Model Integration, which is the final stage and has the highest level of maturity?', NULL, 'Auditable', 'Custom', 'Optimized', 'Quantitative', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-A-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to PMBOK, which of the following combinations of processes pertains to project integration management?
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to PMBOK, which of the following is an appropriate explanation concerning the scope creep in project scope management?', NULL, 'A hierarchical decomposition of the total scope of work to be carried out by the project team to accomplish the project objectives and create the required deliverables.', 'Any change to the project scope. It almost always requires an adjustment to the project cost or schedule.', 'The sum of the products, services, and results to be provided as a project.', 'The uncontrolled expansion to product or project scope without adjustments to time, cost, and resources.', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-A-53', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('As shown in the arrow diagram below, there is a project consisting of eight activities A through G. Which of the following is the appropriate combination of the earliest finish time (EFT) and latest start time (LST) of activity G?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-A-54.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctQS01NC5wbmciLCJpYXQiOjE3NDMxMTU1NjIsImV4cCI6MTc3NDY1MTU2Mn0.56nnvD1hq04pqlTREJgDTpqADozvIZ3U_JT_eHVbIp8', 'a', 'b', 'c', 'd', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-A-54', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to EVM (Earned Value Management), the budget of a software development project is $10,000 and the project duration is planned for 10 weeks. After 4 weeks, it is revealed that only 30% of the work has been completed against a cost of $4,200. What is the cost performance index?', NULL, '0.126', '0.300', '0.420', '0.714', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '17-A-55', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the ISO/IEC 20000-1, which of the following is a service delivery process that the service provider shall agree the services to be delivered and shall agree a catalogue of services with the customer?', NULL, 'Capacity management', 'Information security management', 'Service continuity and availability management', 'Service level management', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-A-56', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to ITIL, which of the following is an activity or process in the Service Transition?', NULL, 'Assessing the IT recovery options of the new IT infrastructure considering the business risks and cost to the project', 'Classifying events once it is detected and communicating specific information to corresponding groups as an immediate action', 'Defining the reliability and service life of the IT infrastructure considering projected growth in the service', 'Implementing multiple strategies such as web seminars, newsletters, and visualization in transferring knowledge', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-A-57', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the relationship between a record of an incident and a record of a problem in IT service management?', NULL, 'If known errors have been specified at the time of ending the record of the problem, the record of the incident that acts as the beginning of the record of the problem is deleted.', 'One (1) record of a problem is always associated with one (1) record of an incident.', 'Problems are classified and recorded by a different criterion from the classification of incidents.', 'The cross-referenced information of the incident that acts as the beginning of the record of the problem is included in the record of the problem.', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-A-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate activity that is undertaken by a system auditor who audits access control?', NULL, 'Confirmation of the management status of access control concerning data', 'Creation and storage of a management table for access control concerning software', 'Establishment of a management policy for access control concerning the network', 'Implementation of operations for access control concerning hardware', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-A-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a checkpoint during audit of a control for reducing the risk of system trouble during the application of a software patch?', NULL, 'A database administrator is appointed, and the management procedures of master data are specified.', 'A hardware management ledger is created, which is managed by system administrators.', 'System operation is properly checked before commencing full-time operations.', 'The procedures of capacity planning are specified.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '17-A-60', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When data sheets issued by a business operations department are entered in a system in an information system department, which of the following is an appropriate task executed by the information system department?', NULL, 'The data sheets are retained in the information system department until the due date for processing, and confirmation including a check of the number of sheets received is performed for all sheets collectively just before the due date.', 'To enable the business operations department to check the processing results of each data sheet, the processing results list is sent to the business operations department.', 'To prevent unauthorized use or leakage of confidential information, data sheets are disposed of immediately after completion of data entry.', 'When the data sheet contains an error, and only when the error is obvious, the data sheet is corrected and an entry is made at the judgment of only the person in charge of data entry.', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '17-A-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate feasibility evaluation when checking whether the lifetime benefits of the proposed information system is greater than its lifetime costs?', NULL, 'Economic feasibility', 'Operational feasibility', 'Scheduling feasibility', 'Technical feasibility', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '17-A-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a usage scenario for the adoption of UML as a technique for visualizing business processes?', NULL, 'Diagrams are shown by using a data-oriented approach where objects are handled as entities, their attributes, and the relationships among the entities.', 'To represent processes by using data flows, sources and sinks of data, data stores, and data processes are connected with arrows that indicate data flow.', 'To represent processes from multiple viewpoints, some purpose-specific modeling methods are used, and each model is depicted by using standardized notation rules for object modeling.', 'To thoroughly represent the functions of a process, the events that occur in response to a single request are described by using the conditional branch format.', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '17-A-63', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the “four categories” of the enterprise architecture, which of the following completes the list after business architecture, technology architecture, and application architecture?', NULL, 'Bus architecture', 'Data architecture', 'Software architecture', 'System architecture', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '17-A-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of EMS?', NULL, 'It refers to acting as the customer service desk for responding by telephone to consumer electronics-related inquiries from general consumers.', 'It refers to planning, design, and development of products without owning manufacturing facilities.', 'It refers to the contract production of electronic devices, etc. ordered by other manufacturers.', 'It refers to the dedicated selling of electronic devices, etc. purchased from other manufacturers.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-A-65', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of green procurement?', NULL, 'It refers not only to the fulfillment of the requirements of quality and price, but also to the preferential purchase of products and services that exert a lower environmental burden from companies working towards a reduction in environmental burden.', 'It refers to a certificate that enables commercial trading of the green power generated from natural energy such as sunlight, biomass, wind power, and geothermal heat.', 'It refers to international standards concerning environmental labels such as eco marks that are qualified by a third party based on a certain standard.', 'It refers to mass promotion of the details of environmental protection activities, and the raising of funds from investors.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-A-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of an RFI?', NULL, 'It is a document describing the basic policy for the system, including a summary of the system, the purpose, the necessary functions, the system requirements, and contract matters.', 'It is a document that is created after an RFP.', 'It is a document used by companies looking for implementation of computerization to request specific system proposals from prospective suppliers such as system vendors.', 'It is a document used to request information concerning computerization from prospective suppliers such as system vendors.', 'd', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '17-A-67', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Companies are classified based on their competitive position in the market. There are typically four types: leader, challenger, follower, and nicher. Which of the following is an appropriate characteristic of the strategy of a leader?', NULL, 'A full frontal matching attack against the competitor’s product, advertising, price and distribution, or indirect attack on the competitor’s weaknesses or on gaps in the competitor’s market coverage', 'Capturing a specific market that is not targeted by a high-ranking company and concentrating management resources for securing and maintaining the predominance in the market', 'Determining the real ability of the challenger company in the market, and giving priority for securing stable profits rather than expanding the market share by doing as the leader company does', 'Proposing a new product and its usage method to the consumer to expand the total demand while maintaining or expanding the market share', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-A-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a marketing technique to create demands from consumers by using advertisements that improve the brand image of a company or a product?', NULL, 'Direct marketing', 'Relationship marketing', 'Pull strategy', 'Push strategy', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-A-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('PEST analysis is used for analyzing the external environment in determining a business strategy. What are the external environmental factors the PEST analysis analyzes?', NULL, 'Politics, Economics, Society, Technology', 'Politics, Enterprises, Society, Time', 'Price, Economics, Satisfaction, Technology', 'Price, Enterprises, Safety, Time', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-A-70', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the IoT (Internet of Things)?', NULL, 'It refers to a form of electronic commerce carried out over the Internet, consisting of a typical C to C transaction by which a seller posts a product’s name, photo, minimum selling price, and other information on a website, after which the bidder that offers the highest amount within the time limit becomes the successful bidder.', 'It refers to data centers designed for the connection to the Internet, with server operation failure prevented through the implementation of measures including quality management of communication lines, server maintenance, air conditioning, and power source-related countermeasures against power interruptions and outages.', 'It refers to Internet advertising such as a banner advertisement that displays an image, with a link to an advertiser’s website, or an e-mail advertisement that publicizes an advertiser’s website.', 'It refers to the installation of communication functionality to various objects, in addition to information and communication devices, and enabling automatic recognition or remote measurement by connecting these to the Internet, to achieve high-level decision-making services and automated control through the collection and analysis of large volumes of data.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '17-A-71', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of benchmarking used for corporate management?', NULL, 'It refers to a qualitative and quantitative understanding of a company’s own products, services, and operation through comparison with those of competitors or advanced companies.', 'It refers to drastically reforming the quality and structure of a company by redesigning its business processes from a customer viewpoint and by taking full advantage of information technology.', 'It refers to the ability to plan and manage the allocation of company-wide management resources in an effective and integrated manner and to achieve an improvement in management efficiency.', 'It refers to the concentration of management resources on the unique skills and technologies of a company that can generate profit and that are superior to those of other companies.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-A-72', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the long tail?', NULL, 'Generally known as the 80:20 empirical rule, the name derives from the phenomenon by which 80% of a company’s sales are accounted for by the best-selling 20% of its products, or by which 80% of a company’s losses due to quality defects are accounted for by the top 20% of all causes of defects.', 'If “value of network” is determined as the usefulness of the mutual access by the subscribers of the network,” then the value of the network is approximately proportional to the square of the number of users.', 'It enables a company to share the management resources through conducting multiple business activities simultaneously, and through the effective use of the shared resources, to relatively reduce the cost rather than conducting each business independently.', 'It is effective in reducing the risk of opportunity loss in an online shop that uses the Internet by lining up a broad range of items, including products for which sales opportunities are few.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '17-A-73', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following performs processing according to steps (1) through (3)?
