INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the FIFO method is applied to the purchase and selling record shown below, what is the inventory value at the end of March?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/17-A-78.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTctQS03OC5wbmciLCJpYXQiOjE3NDMxMTU1NzUsImV4cCI6MTc3NDY1MTU3NX0.9Lqw8OsJ_EGDzpxqEcKLGw2NqRTQVNWVgkNnYxidii4', '214', '241', '300', '880', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '17-A-78', 0.0, 1.0);
