INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is not protected by “copyright” that is based on the World Trade Organization’s Agreement on Trade-Related Aspects of Intellectual Property Rights (TRIPS)?', NULL, 'Database', 'Free software publicly available on the Internet', 'Programming language and its conventions', 'Software operation manual', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '17-A-80', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('If a given bit string contains at least one 1-bit, the algorithm below leaves the rightmost 1-bit unchanged but makes all the others 0. For example, if the given bit string is 00101000, the result will be 00001000. Which of the following is the appropriate logical operation to be filled in D?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-11.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0xMS5wbmciLCJpYXQiOjE3NDMxMTU0NTgsImV4cCI6MTc3NDY1MTQ1OH0.WXwVqD2J7aU85FvWJa1OhcMKDM2ZU3TTYhuOqv2ANAA', 'AND (logical product)', 'NAND (negative logical product)', 'OR (logical sum)', 'XOR (exclusive logical sum)', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-O-01', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When 4-bit signed numbers in 2''s complement are used, which of the following operations will cause either an overflow or an underflow?', NULL, 'Add B to A when A is 0110 and B is 1111.', 'Add B to A when A is 1110 and B is 0110.', 'Subtract B from A when A is 0111 and B is 1010.', 'Subtract B from A when A is 1111 and B is 1111.', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-O-02', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When two unbiased dice are rolled one by one, what is the probability that either the first one is 2 or the sum of the two is less than 5?', NULL, '1/6', '2/9', '5/18', '1/3', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-O-03', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A leap year is either a multiple of 4 but not a multiple of 100, or a multiple of 400. How many leap years are there from 1998 to 2110?', NULL, '26', '27', '28', '29', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-O-04', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate description of a queue?', NULL, 'Data that is stored first is retrieved first.', 'Data that is stored last is retrieved first.', 'It references specific data by using an index.', 'It represents the hierarchical relationship of data by using at least two (2) pointers.', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-O-05', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Binary search is used to search for an element from a sorted data of n elements.Which of the following is an expression that represents the order of computational complexity for this process?', NULL, 'log n', 'n', 'n²', 'n log n', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-O-06', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In Java technologies, which of the following is the specification of creating reusable software components that have frequently used functionalities?', NULL, 'Java applet', 'Java application', 'JavaBeans', 'JavaScript', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-O-07', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following best describes the characteristics of XML?', NULL, 'The style languages such as XSL and CSS used in HTML can also be used in XML.', 'XML allows a tag to be defined in order for an easier data exchange between information systems over the network.', 'XML is developed on its own specification, whereas HTML is on the SGML basis.', 'XML is HTML based and has some features added primarily for a performance improvement of displaying a web page.', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-O-08', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the addressing method that references data in the main memory as shown in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-11.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0xMS5wbmciLCJpYXQiOjE3NDMxMTU0NTgsImV4cCI6MTc3NDY1MTQ1OH0.WXwVqD2J7aU85FvWJa1OhcMKDM2ZU3TTYhuOqv2ANAA', 'Direct addressing', 'Indexed addressing', 'Indirect addressing', 'Relative addressing', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-O-09', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is classified as an internal interrupt?', NULL, 'An interrupt because of the occurrence of a memory parity error', 'An interrupt because of the operation of division by zero (0)', 'An interrupt caused by a power failure, such as an instantaneous failure of the commercial power supply', 'An interrupt caused by the completion of I/O', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-O-10', -2.0, 1.0);
