INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of spooling?', NULL, 'It determines the execution order for jobs that are loaded into a system according to characteristics and priority.', 'It sends communication data to a pre-registered agent instead of sending it directly to a counterpart.', 'It temporarily saves input data from a keyboard to the queue in the main memory.', 'It temporarily saves output data for a low-speed device, such as a printer, to a high- speed hard disk, and then sends it to the intended device.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-O-17', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a paged virtual memory system, the LRU method is used in the page replacement algorithm. When the page frame assigned to the main memory is 4, and pages are accessed in the order of 1, 2, 3, 4, 5, 2, 1, 3, 2, 6, which of the following page is replaced at the time of accessing page 6? Here, no page exists in the main memory in the initial state.', NULL, '1', '2', '4', '5', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-O-18', 0.0, 1.0);
