INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following shows the path information from the front page of a web site to the current page, a user is currently viewing?', NULL, 'Breadcrumbs', 'Navigation bar', 'Scroll bar', 'Site map', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-24', -2.0, 1.0);
