INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The data model shown in the figure below is implemented as three (3) tables. At this time, which of the following is an appropriate combination of A and B in the “Transfer” table in which the transaction of “the sales of 500 dollars to Company C are booked in the cash account on April 4, 2015” is recorded? Here, the data model is described in UML.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-28.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0yOC5wbmciLCJpYXQiOjE3NDMxMTUzODEsImV4cCI6MTc3NDY1MTM4MX0.KZMqR-yQhlA6wGcEGxN8tVwXSGwHH7e-801K-Ok2MtU', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-27', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the process of table implementation, which of the following is an appropriate SQL statement that removes a column in an existing table?', NULL, 'ALTER TABLE table_name 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a manager is analyzing the sales of products in a supermarket, he makes a query to list all products with their sales amount, including the products that have no sales amount. Which of the following is an appropriate combination of statements to be filled in the boxes in the query? Here, the columns of Product and Sales are shown below.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-O-29.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtTy0yOS5wbmciLCJpYXQiOjE3NDMxMTUzNzAsImV4cCI6MTc3NDY1MTM3MH0.GDNM-ICgiuRQ3QHnjNUI5ITgopcLPpkORLBXJB9DUwA', 'a', 'b', 'c', 'd', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-29', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of locks?', NULL, 'For a resource on which transaction T1 has acquired an exclusive lock, transaction T2 can acquire an exclusive, but not a shared, lock.', 'For a resource on which transaction T1 has acquired an exclusive lock, transaction T2 can acquire either an exclusive or a shared lock.', 'For a resource on which transaction T1 has acquired a shared lock, transaction T2 can acquire a shared, but not an exclusive, lock.', 'For a resource on which transaction T1 has acquired a shared lock, transaction T2 can acquire either a shared or an exclusive lock.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-30', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a CSMA/CD based LAN, which of the following is an appropriate description of the transmission operation performed by a network node?', NULL, 'All nodes are connected in a ring topology, and a special frame is sent around to control the transmission right. Only the node that receives the special frame can transmit data.', 'Each node checks if the transmission medium is in use, and can transmit data if the medium is not in use. If a conflict is detected, a retransmission occurs after a random interval of time.', 'Each node is assigned a logical priority, and a transmission right is passed along in the order of priority. Only the node with the right can transmit data.', 'Only the node that has been assigned a time slot for transmission can transmit data.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-31', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of network devices?', NULL, 'A bridge relays frames based on IP addresses.', 'A gateway converts protocols of the first through the third layers of the OSI basic reference model.', 'A repeater extends transmission distances by amplifying signals between the segments of the same type.', 'A router relays frames based on MAC addresses.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-32', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a TCP/IP environment, which of the following is a standard for attaching image data to an email?', NULL, 'JPEG', 'MIME', 'MPEG', 'SMTP', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-33', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Concerning email protocols, which of the following descriptions is correct?', NULL, 'IMAP allows the message to remain on the server even after it is downloaded to a local PC.', 'IMAP uses UDP for faster downloading of emails, whereas POP3 uses TCP.', 'POP3 and IMAP uses the same port number for interoperability in email communication.', 'POP3 is used for sending email messages from the sender’s mail server to the receiver’s mail server.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-34', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IPv6 networks, what is the length of an IP address in bits?', NULL, '32', '64', '128', '256', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a secure communication protocol that provides a hybrid cryptosystem where public key cryptography is used to transfer a shared private key securely to the other side, and private key cryptography is used to encrypt subsequent communications for the remaining session?', NULL, 'AES (Advanced Encryption Standard)', 'RSA', 'SSL/TLS (Secure Socket Layer/Transport Layer Security)', 'WAF (Web Application Firewall)', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a meeting session, the security administrator provides a presentation regarding risks on social media and recommends that the attendees not give unnecessary personal information on social media websites. From which of the following attacks do the social media users effectively reduce the security risk most by following this recommendation?', NULL, 'Brute-force attack', 'Cognitive password attack', 'DoS (Denial of Service) attack', 'Phishing attack', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-37', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of a Trojan horse used for security attacks in computing?', NULL, 'It is a brute force attack algorithm.', 'It is an effective way to detect an intruder.', 'It is a rogue program that tricks users.', 'It is a user who steals valuable information.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-38', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate combination of the usage method of a signature key in a digital signature, and the purpose of a digital signature?', NULL, 'By the sender creating a digital signature with the signature key and attaching it to a message, the recipient can confirm the identity of the sender.', 'By the sender encrypting a message to which a fixed string is added with the signature key, the recipient can identify sections that have been falsified.', 'By the sender encrypting a message with the signature key, the content of the message cannot be understood by unrelated parties.', 'The recipient can use the signature key to decrypt an encrypted message to the plain text message.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of improper use of a key logger?', NULL, 'It interrupts the communication between two parties, and then collects and falsifies the information being exchanged.', 'When Internet banking is used, it collects the password entered by the user.', 'When the browser is initiated, it arbitrarily displays a tool bar that the user has not installed.', 'When the user browses movies on a browser, it arbitrarily displays unintended advertisements for the user.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-40', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Biometric authentication includes a method of authentication by extracting physical characteristics, and a method of authentication by extracting behavior characteristics. Which of the following has behavior characteristics?', NULL, 'Performing authentication by extracting characteristics from the branching angle of the branching point of a blood vessel, and the length between the branching points', 'Performing authentication by extracting characteristics from the speed of and pressure on a pen when a signature is written', 'Performing authentication by extracting characteristics of chaotic wrinkles spreading out from the pupil', 'Performing authentication by extracting the characteristic points called minutiae from the patterns formed by ridge lines', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-41', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most effective method of detecting falsification of the contents of a web server?', NULL, 'Communications to the web server are monitored to ensure that there is no communication other than HTTP and HTTPS.', 'The hash value of each file of the contents of the web server is stored and periodically compared with the hash value generated from each file.', 'The memory usage of the web server is checked periodically to ensure that a buffer overflow has not occurred.', 'The updated date of each file of the contents of the web server is stored and compared periodically with the updated date of each file.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-42', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a digital certificate has been installed in an in-house system accessed from a smartphone by an employee, which of the following can be checked using the in-house system?', NULL, 'Ensuring that the applications on the smartphone are the latest versions of the applications', 'Ensuring that the most recent security patch has been applied to the OS of the smartphone', 'Ensuring that the smartphone has been allowed to access the in-house system', 'Ensuring that the smartphone is not infected by a virus', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique where a system is actually attacked and an intrusion attempt is made in order to detect security-related vulnerabilities of a computer or network?', NULL, 'Penetration test', 'Regression test', 'Software inspection', 'Walk-through', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-44', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following can be used to detect worms by using SHA-256 to calculate a hash value from a subject file, and then cross-checking this against a database of hash values from files containing specimens of known worms?', NULL, 'A worm that has the same file size as a worm specimen', 'A worm that is in the same subspecies as a worm specimen', 'A worm with code strings that have the same characteristics as a worm specimen', 'The same worm as a worm specimen', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-45', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate explanation of the deployment diagram defined in UML 2.x (including 2.0 and later versions)?', NULL, 'It addresses the dynamic view of the system. In other words, it is drawn for a single class to show the lifetime behavior of a single object.', 'It describes the types of objects in the system and the various kinds of static relationships that exist among them.', 'It shows a static view of the run-time configuration of processing nodes, such as servers and clients, as well as the components that run on these nodes.', 'It shows the organizations and dependencies among a set of pieces that are independently purchasable and upgradeable, and addresses the static implementation view of the system.', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-O-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In software development for small projects, which of the following is an appropriate explanation of test driven development (TDD)?', NULL, 'All functionalities are identified at the start of the project. Code and test cases are developed together and functionalities are developed simultaneously.', 'Continuous testing is implemented during the coding process using automated testing. The process eliminates the requirement for system testing', 'Development is done in increments of functionality where test cases are executed and the code is developed to pass the test cases before moving to the next increment.', 'Test cases are executed at the end for each stage of the development process where all code must first pass the test case before proceeding to the next stage.', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-O-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a program module that is executed only when the value of integer x is 25 ≤ x < 50. When this module is tested using the boundary value analysis, which of the following is an appropriate combination of values to be tested?', NULL, '24, 25, 49, 50', '24, 25, 50, 51', '25, 26, 49, 50', '25, 26, 50, 51', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-O-48', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate category of system maintenance preformed for the purpose of modifying the system to cope with changes in the software environment (e.g. DBMS, Operating system)?', NULL, 'Adaptive maintenance', 'Corrective maintenance', 'Perfective maintenance', 'Preventive maintenance', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-O-49', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the appropriate order of the six phases in the SDLC (Software Development Life Cycle) model?', NULL, 'Requirements Analysis -> Design -> Programming -> Deployment -> Testing -> Maintenance', 'Requirements Analysis -> Design -> Programming -> Testing -> Deployment -> Maintenance', 'Requirements Analysis -> Design -> Programming -> Testing -> Maintenance -> Deployment', 'Requirements Analysis -> Programming -> Testing -> Design -> Maintenance -> Deployment', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-O-50', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to PMBOK, which of the following is an appropriate explanation of project definition?', NULL, 'It is a group of related projects, subprograms, and program activities managed in a coordinated way to obtain benefits not available from managing them individually.', 'It is a number of people who are gathered to undertake a common job with different tasks with the aim of finishing all the tasks timeously to satisfy their customers or stakeholders.', 'It is a temporary endeavor undertaken to create a unique product, service, or result.', 'It is the application of knowledge, skills, tools, and techniques to a program to meet the program requirements and to obtain benefits and control not available by managing projects individually.', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '16-O-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A project has been defined to contain the activities along with their required times for completion as shown in the table below. Which of the following is the critical path for this project?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-O-52.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtTy01Mi5wbmciLCJpYXQiOjE3NDMxMTUzNTEsImV4cCI6MTc3NDY1MTM1MX0.pfNRbtEwtlbR-6HkTnIP2P7SXK9Ar-owUlcylqK-a2Q', '1-2-3-5-7-9-10', '1-2-3-5-7-8-10', '1-2-4-7-9-10', '1-2-4-6-8-10', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '16-O-52', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the Earned Value Management technique, which of the following is used to calculate the Cost Performance Index (CPI)?', NULL, 'Earned Value (EV) – Planned Value (PV)', 'Earned Value (EV) / Planned Value (PV)', 'Earned Value (EV) – Actual Cost (AC)', 'Earned Value (EV) / Actual Cost (AC)', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '16-O-53', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to PMBOK, which of the following is the project management knowledge area that includes the activities of make-or-buy decisions, development time and material contracts, and selection of sellers from bidders?', NULL, 'Project Communication Management', 'Project Integration Management', 'Project Cost Management', 'Project Procurement Management', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '16-O-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In order to check whether a system works normally, users in the system user department and operators in the system operations department jointly conduct operational testing prior to full operation. Which of the following is an appropriate description of the users should prioritize during testing?', NULL, 'Testing whether all application programs work according to the specifications', 'Testing whether online, batch, and other processing is performed according to the operational procedures', 'Testing whether the performance objective is achieved', 'Testing whether the system operates according to predetermined business procedures', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-O-55', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When data in the business operations department is entered in a data sheet by the information system department, which of the following is an appropriate task executed by the information system department?', NULL, 'In order to prevent unauthorized use or leakage of confidential information, data sheets are disposed of immediately after the completion of data entry.', 'The data sheets are retained in the information system department until the due date for processing, and confirmation including a check of the number of sheets received is performed for all sheets collectively just before the due date.', 'To enable the business operations department to check the processing results of each data sheet, the processing results list is sent to the business operations department.', 'When the data sheet contains an error, and only when the error is obvious, the data sheet is corrected and an entry is made based on the judgment of only the person in charge of data entry.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-O-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the structures and characteristics of a service desk organization, which of the following is a description of a local service desk?', NULL, 'By consolidating the service desks at a single site or limited locations, service staff can be deployed effectively and a large number of calls can be handled.', 'By deploying the service desk near the users, it is possible to provide services for users who have different languages and cultures or for VIPs by dedicated service staff.', 'By performing centralized and integrated management of all service staff including those at the dispersed locations, well-controlled services can be provided.', 'By using communication technology, services such as a single service desk can be provided, even if the service staff is dispersed across several regions and departments.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-O-57', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a version management system for source code is installed, which of the following is an appropriate check point to be added for the confidentiality of the source code during the system audit?', NULL, 'The access control settings of the version management system are appropriate.', 'The installation cost of the version management system is at a proper level.', 'The results of the change registered in the version management system are approved by the person in charge.', 'The version management system is selected by the development department.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-O-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the implementation structure of a system audit?', NULL, 'For an audit of the development progress in an information systems department, the audit team consists of members of the information systems department who are familiar with the details of the development.', 'In order to enable the person requesting the audit to issue improvement instructions on the basis of the audit report, the system auditor reports the audit results to the person requesting the audit.', 'When an audit of the information system is performed as a part of the business operations audit, the audit team is formed by the members of the user’s department.', 'When the system auditor accepts the help of an expert, the decisions concerning the range of support, methods, and audit results is the responsibility of the expert.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-O-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a check point for auditing control in relation to the accuracy of the processing logic of a spreadsheet?', NULL, 'A backup of the spreadsheet is stored.', 'The person who creates and uses the spreadsheet is the same.', 'The program of the spreadsheet is documented and verified.', 'The users of the spreadsheet are defined.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-O-60', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of BPM (Business Process Management) in the context of corporate activity?', NULL, 'Analysis and effective utilization of information resources.', 'Continual improvement of business processes.', 'Effective utilization of management resources.', 'Management and analysis of customer information.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-O-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a workflow system is used for business improvement, which of the following is an appropriate effect that can be expected?', NULL, 'A standard protocol used for data exchange between a company and its customers can be provided.', 'Processing speed for office procedures from document submission to approval can be improved.', 'Services, such as a discount, can be provided according to the amount purchased by the customer.', 'Shipping and receiving of stocked products can be automated in a warehouse.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-O-62', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The table below shows the result of analyzing the daily activities of a sales representative. By implementing SFA (Sales Force Automation), the preparation time for customer visits can be reduced by 0.1 hours per customer visit. In order to increase the number of customer visits to six (6) per day without changing the total working hours and the hours per customer visit, how many hours must be reduced from “Other working time”?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-62.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy02Mi5wbmciLCJpYXQiOjE3NDMxMTUzMzgsImV4cCI6MTc3NDY1MTMzOH0.B3cQKhsqiSVm33Sq5GL3Er6KtoIgE_4XqZOySzM2ajI', '0.3', '0.5', '0.7', '1.0', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-O-63', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of SOA?', NULL, 'It is a concept that considers the functions of software as components called services, and combines these services in order to develop application systems.', 'It is a concept that enhances the efficiency and quality of sales activities by utilizing IT in order to increase sales and profits and to improve customer satisfaction.', 'It is a concept that redesigns the business processes fundamentally in order to improve cost, quality, service, and speed in an innovative manner.', 'It refers to the outsourcing of internal activities other than the core businesses in order to concentrate management resources on the core businesses.', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '16-O-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of application architecture that configures enterprise architecture?', NULL, 'It systematically indicates the business processes and information flow necessary for the business strategy', 'It systematically indicates the content of data required for a business operation, the relationship between data, and the structure of data.', 'It systematically indicates the functions and configuration of a system supporting a business process.', 'It systematically indicates the technical components necessary for the development and the operation of the information system.', 'c', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '16-O-65', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the table shown below, the investment category and KPI have been arranged according to the investment purpose. Which of the following corresponds to investment purpose C ? Here, a) to d) are applied to any one of A to D.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-O-66.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtTy02Ni5wbmciLCJpYXQiOjE3NDMxMTUyOTksImV4cCI6MTc3NDY1MTI5OX0.B2RrxvRcViC5O_1JBS1_uwOmu-wy4CL-jrYGCoykspE', 'Betterment of the work process and improvement of work quality', 'Creation of business and establishment of competitive advantages', 'Reduction of system maintenance and management cost, and improvement of system performance', 'Visualization and sharing of knowledge', 'b', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '16-O-66', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A SWOT analysis is a technique that is used to identify and evaluate the internal and external factors that are advantageous or disadvantageous to achieve the objectives of the business or project. When a company’s situation is analyzed as shown in the table below, which of the following is the most appropriate combination that corresponds to the company’s Strengths that give the company advantages over others, Weaknesses that give the company disadvantages relative to others, Opportunities that are exploited for the company’s advantages, and Threats that cause troubles for the business or project?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-O-67.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtTy02Ny5wbmciLCJpYXQiOjE3NDMxMTUyNzksImV4cCI6MTc3NDY1MTI3OX0.bK4JiEakYeSBdC3nX_yp8FJ0Wiiyh4yBVXERYW6Yiak', 'a', 'b', 'c', 'd', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-O-67', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the “competitive strategy” by Philip Kotler, which of the following is a company that has no high market share, but has the strategic aim of achieving high profits and acquiring a unique position by focusing management resources on particular products and services?', NULL, 'Market challenger', 'Market follower', 'Market leader', 'Market nicher', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-O-68', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of knowledge management?', NULL, 'Management centered on strengths that are a challenge for other companies to imitate, such as the enterprise’s own know-how and technology', 'Management innovation driven by performing comparative analysis with other successful companies', 'Management which improves the overall problem-solving capability by sharing knowledge that is scattered across the enterprise', 'Management which maintains a flat organization structure with minimal hierarchical layers to accelerate decision-making', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-O-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a characteristic of an IC tag (RFID)?', NULL, 'An IC tag handles a significant amount of information, and thus it uses an external storage device for storing information.', 'An IC tag is resistant to dirt, and the recorded information can be read even from outside the container.', 'An IC tag needs to be inserted into a dedicated magnetic reader to read the recorded information.', 'An IC tag uses GPS to display the positional and attribute information of the current location.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-70', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In IT investment opportunities, when the investment effect of five (5) years is evaluated on the basis of ROI (Return On Investment), which of the following four (4) opportunities A through D has the greatest effect? Here, the IRR (Internal Rate of Return) is zero (0).', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-O-71.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtTy03MS5wbmciLCJpYXQiOjE3NDMxMTUyNjksImV4cCI6MTc3NDY1MTI2OX0.xRRDff7tt049Qf0m718SqkDvbi69syE4tXgMvYRsdnA', 'A', 'B', 'C', 'D', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '16-O-71', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an example of the use of social media in business?', NULL, 'A company posts its business strategies regarding accommodating itself to market changes, in professional business magazines, thus aiming to improve their reputation as a trustworthy company.', 'A company sets up a site on the Internet for sharing opinions on matters such as the usage status of its products, which leads to improvement of the product.', 'The researchers of a company buy the latest professional magazines that are not sold within the country through online shopping, which contributes to the research and development activities.', 'The sales department frequently posts product articles in magazines that are circulated in large numbers, thus aiming at improving awareness of the product.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-O-72', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of tethering as a function of cell phones?', NULL, 'A cell phone can be used by inserting a different telecommunications carrier’s SIM card into the cell phone.', 'By using a cell phone as a modem or access point, data communication that uses a network, such as the Internet, is enabled on a PC, game console, or other such devices.', 'Cell phone access to websites that are harmful to young people is disabled on request to the telecommunications carrier.', 'Even outside the service area of the contracted telecommunications carrier, a cell phone can be used with the service of another carrier.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a role that CIO is required to perform?', NULL, 'Design and operation of an organization of legal compliance.', 'Planning and execution of the research and development policy of the company.', 'Planning and implementation of a financial strategy for business administration.', 'Promotion of use of IT services that maximizes business value.', 'd', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '16-O-74', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the measures that a company should adopt in order to fulfill social responsibility, which of the following is implemented in terms of the environment?', NULL, 'To develop an internal organization for the purpose of green purchasing.', 'To enhance the transparency of the management status of the company for shareholders.', 'To establish a system that supports volunteer activities of employees following disasters.', 'To setup an ethics helpline within the company.', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '16-O-75', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following can secure employment and create employment opportunities in an entire society by shortening the work hours per employee?', NULL, 'Cafeteria plan', 'Free agent system', 'Work sharing', 'Work-life balance', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '16-O-76', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of an ABC analysis method?', NULL, 'A survey of the same panelists is repeatedly conducted. This data is used to understand trends in regions and changes in purchasing groups.', 'Products are arranged in order of high sales or high gross margins, and then products are divided into various levels by using the cumulative ratio. Following this, an increase in sales volume is planned for the products at the high levels.', 'Regions are divided into a grid with multiple sections, and detailed regional analysis is performed on the basis of various data, such as population and purchasing power.', 'The sales potential and the purchasing record of a product are analyzed by classifying and aggregating multiple items of survey data by factor.', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '16-O-77', -1.0, 1.0);
