INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique that discovers useful information and relationships from large amounts of customer and market data retained by a company?', NULL, 'Data dictionary', 'Data flow diagram', 'Data mining', 'Data warehouse', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-O-79', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the descriptions of personal data, which of the following is not an appropriate description from the viewpoint of “OECD Guidelines on the Protection of Privacy and Transborder Flows of Personal Data”?', NULL, 'Personal data should be allowed to be acquired without announcing the acquisition of such data.', 'Personal data should be handled within the scope of the purpose of use agreed by the persons whose personal data are collected.', 'Personal data should be kept accurate, complete, and up-to-date within the scope of the purpose of use.', 'Personal data should be outsourced to a third party after the prior consent of the persons whose personal data are collected.', 'a', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '16-O-80', -2.0, 1.0);
