INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a language defined by a context-free grammar with the production rules below:', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-06.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0wNi5wbmciLCJpYXQiOjE3NDMxMTUyMTgsImV4cCI6MTc3NDY1MTIxOH0.SY99lgUPvfqCZbSmi7FSoyrQpSb2rXMB1ewOyqC7aY4', 'E -> 7 + 3 * (F + T)', 'E -> 7 + 3 * E', 'E -> 7 + 3 * (T)', 'E -> 7 + T * (E)', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-A-06', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Let A be an array of integers of size 10, whose ith entry is represented by A[i] for i = 0 to 9, and its initial value is 0. For a positive integer k, the rules below determine the entry in which the value k is stored. When the integers 16, 43, 73, 24, and 85 are processed in this order, in which entry is the last value 85 stored? Here, x mod y represents the remainder after the division of x by y.
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Typical list data type implementations are either array based or pointer based. Which of the following describes a characteristic of array-based implementations?', NULL, 'In addition to space for each element in a list, space for a pointer to the next element is also required.', 'Moving to the middle of a list takes an amount of time proportional to the number of elements, as it requires visiting all the entries from the beginning to the middle.', 'Regardless of the actual number of elements in a list, insertion and removal of an element can be performed in a fixed time.', 'Regardless of the actual number of elements in a list, some space may remain unused as the space for storing the maximum number of elements is pre-allocated.', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-A-08', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('To make the flowcharts below equivalent, which of the following combinations is appropriate for labels A and B? Here, represents the negation of P.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-09.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0wOS5wbmciLCJpYXQiOjE3NDMxMTUyMTAsImV4cCI6MTc3NDY1MTIxMH0.MiIA7ltYsTveBBgW75geT7VLD-9dAzToeuRV9VpRWvE', 'A = No, B = No', 'A = No, B = Yes', 'A = Yes, B = No', 'A = Yes, B = Yes', 'a', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-A-09', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the value of the arithmetic expression resulting from an in-order traversal of the binary tree below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/24-O-05.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjQtTy0wNS5wbmciLCJpYXQiOjE3NDMxMTUxODksImV4cCI6MTc3NDY1MTE4OX0.G5S9rE4aFqzmBHpzIAseE3T9lksB4iMOsp7zm9Jw5Qo', '11', '20', '27', '45', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-A-10', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a CPU with a four (4)-stage pipeline composed of fetch, decode, execute, and write back, each stage takes 10, 6, 8, and 8 ns, respectively. Which of the following is an approximate average instruction execution time in nanoseconds (ns) in the CPU? Here, the number of instructions to be executed is sufficiently large. In addition, the overhead for the pipelining process is negligible, and the latency impact from all hazards is ignored.', NULL, '6', '8', '10', '32', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-11', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the computer architecture where a processor executes the same instruction on multiple data?', NULL, 'MIMD', 'MISD', 'SIMD', 'SISD', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-12', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an addressing mode that provides an offset to the program counter (PC) content to determine the address of the operand?', NULL, 'Immediate addressing mode', 'Indirect addressing mode', 'Register indirect addressing mode', 'Relative addressing mode', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-13', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is used to translate a logical address generated by a CPU into a physical address?', NULL, 'Direct Memory Access Controller (DMAC)', 'Memory Address Register (MAR)', 'Memory Management Unit (MMU)', 'Translation Lookaside Buffer (TLB)', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-14', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning cache memory?', NULL, 'In a multi-tasking environment, a cache memory maintains data from each task to improve performance.', 'Multiprocessors where each has a cache memory need to synchronize values within the cache to maintain coherency.', 'The operating system manages the data transfer between registers and a cache memory.', 'The speed and size of a cache memory are the only consideration when improving performance.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique of segmenting and storing data on multiple hard disks as shown in the figure? Here, b0 through b15 show the sequence in which the data are stored to the data disks on a bit-by-bit basis.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-16.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0xNi5wbmciLCJpYXQiOjE3NDMxMTUxNzcsImV4cCI6MTc3NDY1MTE3N30.sEf0J2WflJwidh_Ba7nh_cTVLh0umAACPkP16NGrszE', 'Blocking', 'Disk cache', 'Mirroring', 'Striping', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-16', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of throughput?', NULL, 'Even if some idle time resulting from operator intervention between the end of a job and the start of the next job occurs in a system, throughput is not affected.', 'Multi-programming contributes to reducing turnaround time, but is not useful in improving throughput.', 'Spooling, which involves temporarily saving the output to a printer in a hard disk, is useful in improving throughput.', 'Throughput is an index of CPU performance and is not affected by the I/O speed, overhead time, and other such factors.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-17', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the mean time between failures (MTBF) value of the entire system where unit A and unit B are connected in series and both units operate as one system? The MTBF value of unit A and unit B is 200 and 300 hours, respectively.', NULL, '200', '250', '300', '500', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-18', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the multiplicity of processing is increased in the virtual memory of a computer system, page-in and page-out operations occur very frequently, and the response speed of the system decreases suddenly. What is this phenomenon called?', NULL, 'Memory compaction', 'Overlay', 'Roll-out', 'Thrashing', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-19', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A company performs a full backup every Sunday night and differential backups every night other than Sunday night. If the failure occurs on Wednesday morning, which of the following backups is least needed to restore the system?', NULL, 'The latest differential backups from Tuesday.', 'The latest full and the latest differential backups from both Monday and Tuesday.', 'The latest full and the latest differential backups from Tuesday.', 'The latest full backups from Sunday.', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-A-20', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation for a non-preemptive scheduling method?', NULL, 'A task cannot move to a running state until another task in the running state either moves to the waiting state by itself or finishes.', 'Each time a new task becomes the ready state, a comparison is made for all tasks in the ready state from the standpoint of the remaining execution time, and the tasks are executed in an order starting from the shortest execution time.', 'When a task becomes the ready state, a comparison is made between the priority of the task and that of the one in the running state at that time, and the task with the higher priority moves to the running state.', 'When a task in the running state does not move to the waiting state within a predetermined time period, the task is interrupted, and the next task in the waiting queue moves to the running state.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-21', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a system composed of two (2) CPUs, and the CPU that is not in use is assigned to a task for which there is an execution request. When two (2) tasks A and B are run on this system, these tasks exclusively use a common resource R. The figure below shows the usage periods of the CPUs and resource R for tasks A and B, and the order in which the tasks are run. When the execution of both the tasks is started simultaneously, how much time, in milliseconds, is required until the completion of processing of both the tasks? Here, both the CPU and resource R are available when tasks A and B are started.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0yMi5wbmciLCJpYXQiOjE3NDMxMTUxNzAsImV4cCI6MTc3NDY1MTE3MH0.OmVZ2j1e7XTmMOYOkt_WuBftMCkwHLEB80ac51-sYmo', '120', '140', '150', '200', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-22', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the Open Source Definition by OSI (Open Source Initiative), which of the following is the appropriate description concerning open source licensing?', NULL, 'The license allows any party to freely use, modify, and distribute a program. A royalty fee is required only if the program is redistributed commercially.', 'The license allows authors to put usage restrictions on a program to prevent such program from being used in business activities.', 'The license requires that all derivative works must be kept secret if the derivative works are based on an original program.', 'The license requires that the source code of a program must be made available either for free or at a reasonable reproduction cost.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-23', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a logical (or Boolean) expression that is equivalent to the logic circuit shown below? Here, “+” is the logical sum, “•” is the logical product, and “X̅” is the negation of X.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-24.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0yNC5wbmciLCJpYXQiOjE3NDMxMTUxNDEsImV4cCI6MTc3NDY1MTE0MX0.3pcdkX3w7mlEjK3Gnpcg_1t1XbhidKQgVwRK1cB-YX0', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-24-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0yNC1BLnBuZyIsImlhdCI6MTc0MzExNTE2NCwiZXhwIjoxNzc0NjUxMTY0fQ.zB_PzABxIlJG3bg3OobVQA7DhO05mwOISJY6Tmgpo0Y', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-24-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0yNC1CLnBuZyIsImlhdCI6MTc0MzExNTE1OSwiZXhwIjoxNzc0NjUxMTU5fQ.aAhi_IL_LOaat8xkrtQoRbWIK3EwFkObbJ0GGtzu1LI', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-24-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0yNC1DLnBuZyIsImlhdCI6MTc0MzExNTE1NCwiZXhwIjoxNzc0NjUxMTU0fQ.gpe5PTf45QVG_eaAhPhCqLf7kftq7pF0OjnIQNpnwt4', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-24-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0yNC1ELnBuZyIsImlhdCI6MTc0MzExNTE1MCwiZXhwIjoxNzc0NjUxMTUwfQ.qaQDwTUFB3YMVXkBZudhjuK8TiomDJgwjm5GqYnoQ5Q', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-A-24', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a sequential circuit that has two (2) stable states?', NULL, 'Adder circuit', 'Flip-flop', 'NAND gate', 'NOR gate', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-25', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate input for a common anode seven-segment display to display a character shown as output? Here, A represents the most significant bit (MSB) and G represents the least significant bit (LSB).', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-26.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0yNi5wbmciLCJpYXQiOjE3NDMxMTUxMzYsImV4cCI6MTc3NDY1MTEzNn0.9lPhE5XTX_GF0BY9ehbc0Oq8Ge35A9iO_dXiJ3UCgbc', '0110000', '0000110', '1001111', '1111001', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '16-A-26', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is more suitable for outline fonts than for bitmap fonts?', NULL, 'To display single-byte and double-byte characters at the same time', 'To display characters as quickly as possible', 'To display characters in monospace', 'To enlarge characters by a given scale factor', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-27', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of texture mapping?', NULL, 'It is a process by which surfaces that should not be visible to the user are prevented from being rendered.', 'It renders a scene by calculating reflection, refraction, and transparency from the light source.', 'It renders shadows based on light sources and shapes of objects when a scene is realized.', 'It represents surface characteristics by pasting an image onto the surface of a three-dimensional object.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-28', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate purpose for adopting a three-layer schema architecture for DBMS?', NULL, 'To avoid making any impact on an application program even if the physical storage structure of data is changed', 'To derive a new table from a source table through a relational operation as if the new table actually existed', 'To restrict programming languages such that the application program and DBMS are linked closely', 'To use an interactively used SQL statement from an application program as well', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-29', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which is the most suitable multiplicity of the “Register” relationship between “Customer” entity and “Car” entity that matches the following diagram? Here, “A..B” and “C..D” respectively indicate the minimum and maximum possible participations to the relationship.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-30.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS0zMC5wbmciLCJpYXQiOjE3NDMxMTUxMzAsImV4cCI6MTc3NDY1MTEzMH0.DOxlKDtYWYYQ6ATE45IG_bNvk9xA5cspvkeALwlpoxk', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-30', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate method used to remove data redundancy in relational database systems?', NULL, 'Entity-relationship', 'Functional dependency', 'Hierarchical', 'Normalization', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a relation schema R = (A, B, C, D, E), the following functional dependencies are held:  
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the main purpose of transaction support in a database management system?', NULL, 'To ensure that either all the updates corresponding to a given transaction are made or none of them is made', 'To ensure that only authorized users can access the database', 'To help users update data by providing a graphical user interface', 'To provide an accessible catalog in which descriptions of data items are stored', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-33', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a data link layer function that enables receivers to control the amount of data to be received from the senders?', NULL, 'Congestion control', 'Error control', 'Flow control', 'Media access control', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-34', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('TCP/IP is a layered set of communication protocols consisting of the Network Interface layer, the Internet layer, the Transport layer, and the Application layer. Which of the following is a combination of the Transport layer protocols?', NULL, 'DHCP, TCP', 'HTTP, UDP', 'IP, TCP', 'TCP, UDP', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is responsible for converting a domain name to a corresponding IP address?', NULL, 'DHCP server', 'DNS server', 'IMAP server', 'SMTP server', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-36', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of Transmission Control Protocol (TCP)?', NULL, 'It ensures reliability by retransmission of data segments if any of them is lost.', 'It is an end-to-end protocol but does not have any mechanism for congestion control.', 'It is connectionless and uses a checksum to ensure the integrity of the data.', 'It is connection oriented but cannot operate if packets are received out of order.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('On the Internet, sometimes when one tries to load a Web page by specifying a URL like http://www.jitec.ipa.go.jp/, the page does not show up and an error page is shown instead. However, one can browse this page correctly by specifying its IP address like this: http://118.151.146.137/. Which of the following TCP/IP layer is responsible for this problem?', NULL, 'Application layer', 'Internet layer', 'Network Interface layer', 'Transport layer', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate method of authenticating users by using a password?', NULL, 'The hash value of the user ID corresponding to the password is registered, and the password entered during authentication is converted by the hash function and compared.', 'The hash value of the user ID corresponding to the password is registered, and the user ID entered during authentication is converted by the hash function and compared.', 'The password is converted to a hash value and registered, and the password entered during authentication is converted by the hash function and compared.', 'The password is converted to a hash value and registered, and the user ID entered during authentication is converted by the hash function and compared.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-39', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When malware that has made a successful intrusion into a PC communicates with a command-and-control server on the Internet, which of the following is a reason for using the TCP port number 80 as the destination port in most cases?', NULL, 'As this port is used for browsing websites, there is a high probability that communication is allowed by the firewall.', 'As this port is used for browsing websites through the HTTPS protocol, there is a low probability that this port is detected by an intrusion detection system.', 'As this port is used for name resolution of a domain name, there is a low probability that this port is detected by an intrusion detection system.', 'As this port is used in a DNS zone transfer, there is a high probability that communication is allowed by the firewall.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique that is classified as social engineering?', NULL, 'Acquiring a password by calling a user and pretending to be a system administrator', 'Analyzing a password by using a round-robin attack tool', 'Entering a system by using software vulnerabilities, such as a buffer overflow', 'Entering a system from a back door created automatically by a virus infection', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-41', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When Mr. A, who has a digital certificate, uses an e-mail to place an order with store B, he uses his own private key and digitally signs the e-mail. Store B then uses Mr. A’s public key to confirm the signature. Which of the following can be achieved using this method? Here, only Mr. A can use his private key.', NULL, 'It can be confirmed that store B is permitted to sell products to Mr. A.', 'It can be confirmed that the order arriving at store B is an order from Mr. A.', 'The order details sent from Mr. A to store B can be prevented from being leaked to third parties.', 'The order sent from Mr. A can be made to arrive at store B.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-42', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of risk assessment?', NULL, 'As the purpose of risk assessment is to prevent a future loss, referencing of data used in the past risk assessment is avoided.', 'Risk assessment is implemented after a risk is identified and the budget for responding to the risk is decided according to the amount of loss.', 'The implementation of risk assessment is avoided before the response to all risks identified beforehand is complete.', 'The priority order of the response to risks is determined by the size of the risk based on the expected amount of loss and occurrence probability.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-43', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of measures against information leakage?', NULL, 'A checksum is added to the data to be sent.', 'A copy of the data backup medium is stored at a remote location', 'The contents of the hard disk of a notebook PC are encrypted.', 'The hard disk in which data are stored is mirrored.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-44', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is a network that is divided into three (3) segments, namely, an external segment, a demilitarized zone (DMZ), and an internal network by one (1) firewall. In the network, when a service for users is published on the Internet by using a system consisting of a Web server and a database (DB) server containing critical data, which of the following is the most appropriate method of server installation for protecting important data from unauthorized access from the Internet? Here, only a specific protocol is allowed for communication between the external segment and the DMZ, and between the DMZ and the internal network by the firewall, and communication between the external segment and the internal network is not allowed', NULL, 'The Web server and the DB server are installed in an internal network.', 'The Web server and the DB server are installed in the DMZ.', 'The Web server is installed in an external segment, and the DB server is installed in the DMZ.', 'The Web server is installed in the DMZ, and the DB server is installed in an internal network.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-45', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a purpose of using a WAF (Web Application Firewall)?', NULL, 'An attack on a vulnerability attributed to a Web server and a Web application is blocked.', 'The entry of a worm into a Web server is detected, and the worm is automatically exterminated.', 'The security hole of a Web server is identified, and an OS security patch is applied.', 'The vulnerabilities and inconsistencies of a Web application are detected during the integration test of content development of the Web server.', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-46', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the pattern-matching method used by antivirus software?', NULL, 'A virus is detected by collating information with the checksum of a file.', 'A virus is detected by comparing a file before and after infection, and examining whether any change has been made to the file.', 'A virus is detected by monitoring an abnormal phenomenon that is caused by a virus in a system.', 'A virus is detected through comparison with the signature of an already-known virus.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-47', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following can be implemented with the functions of HTTPS (HTTP over SSL/TLS)?', NULL, 'Blocking of communication aside from TCP port numbers 80 and 443', 'Encryption of communication between a Web server and a browser', 'Restriction of unauthorized access to a Web server through packet filtering in the Network Interface layer', 'Prevention of an attack on a Web server from an SQL injection', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-48', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to ISO/IEC 25010 (Systems and software engineering — Systems and software Quality Requirements and Evaluation (SQuaRE) — System and software quality models), which of the following is an appropriate quality characteristic that means the degree to which a product or system provides functions that meet stated and implied needs when used under specified conditions?', NULL, 'Functional suitability', 'Performance efficiency', 'Reliability', 'Usability', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-A-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In unit testing, which of the following activities is part of “white box testing”?', NULL, 'Boundary value analysis', 'Condition testing', 'Equivalence partitioning', 'Orthogonal array testing', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-A-50', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a mechanism that allows several subclasses of a common parent class to override the same method with different behaviors?', NULL, 'Aggregation', 'Composition', 'Inheritance', 'Polymorphism', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '16-A-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The integration test for a software that is composed of a set of modules arranged in a hierarchical structure is performed from a low-level module. In such a case, which of the following is a test module used as a substitute for a higher level module?', NULL, 'Driver', 'Emulator', 'Simulator', 'Stub', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-A-52', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a structural design pattern that allows classes with incompatible interfaces to work together and that can be implemented in either form in the two diagrams below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-53.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS01My5wbmciLCJpYXQiOjE3NDMxMTUxMjIsImV4cCI6MTc3NDY1MTEyMn0.wMGQKwejGNib1h2Bm8bVbTHlks2aOS0CYrycuulnYhw', 'Adapter', 'Factory', 'Iterator', 'Singleton', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-A-53', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('hich of the following is a term for the process of generating a Unified Modeling Language (UML) class diagram from a program?', NULL, 'Backtracking', 'Forward engineering', 'Re-engineering', 'Reverse engineering', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-A-54', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an action that is carried out during the work breakdown structure (WBS) creation process in project scope management?', NULL, 'Defining activities for creating deliverables', 'Estimating the man-hours of the work and then estimating costs', 'Ordering the work into a schedule', 'Subdividing the work hierarchically', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '16-A-55', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The arrow diagram below shows the original plan of a project.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-56.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS01Ni5wbmciLCJpYXQiOjE3NDMxMTUxMTQsImV4cCI6MTc3NDY1MTExNH0.dzRIql84oZ2IwFAW-4N5M4kx7E0xIXUJmWL3iePWBLY', 'The project completion date is accelerated by 1 day.', 'The project completion date is delayed by 1 day.', 'The project completion date is delayed by 3 days.', 'The project completion date is neither accelerated nor delayed.', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '16-A-56', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A company is creating a development plan for job A. The first developer can perform this job alone in 10 days. Moreover, the first developer can perform this job in 6 days with the second developer. How many days will be required for the second developer to perform this job alone? Here, owing to communication, the work efficiency for each developer is reduced by 10% and the decimal needs to be rounded up.', NULL, '10', '11', '12', '15', 'c', (SELECT id FROM public.categories WHERE name = 'project-management'), '16-A-57', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate sentence describing the difference between intermediate COCOMO and COCOMO II?', NULL, 'Intermediate COCOMO consists of one overall model based on lines of code, whereas COCOMO II consists of three different models, depending on the available knowledge of product to be built.', 'Intermediate COCOMO estimates cost based on object point, whereas COCOMO II estimates cost based on function points.', 'Intermediate COCOMO has 11 cost drivers, whereas COCOMO II has 17 multiplicative cost drivers.', 'In intermediate COCOMO, exponent b varies between 1.01 and 1.26, depending on the variety of parameters of the model, whereas in COCOMO II, the value of b takes on three different values, depending on whether the mode of the product to be built is organic (b=1.05), semi-detached (b=1.12), or embedded (b=1.20).', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-A-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to ISO/IEC 20000-1 (Information technology — Service management — Part 1: Service management system requirements), which of the following is an appropriate description of problem management?', NULL, 'It is a process used to determine the effect of a change, assess its impact or priority, and then approve or reject it.', 'It is a process used to identify the root cause of an incident, minimize the adverse impact of the incident, and prevent it from occurring again.', 'It is a process used to provide a single point of contact between IT service users and the service provider.', 'It is a process used to restore normal service operations as soon as possible to minimize the adverse impact of an incident.', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-A-59', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following term indicates the amount of data transactions allowed to be lost after a downtime occurs?', NULL, 'Maximum Tolerable Outage (MTO)', 'Recovery Point Objective (RPO)', 'Recovery Time Objective (RTO)', 'Service Delivery Objective (SDO)', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-A-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the Information Technology Infrastructure Library (ITIL), lowering an indicator that represents maintainability is given as an example of a key performance indicator (KPI) for availability management. Which of the following corresponds to this indicator?', NULL, 'Mean time between failures', 'Mean time between service incidents', 'Mean time to restore services', 'The number of interruptions within a fixed period', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-A-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the items to be written into an audit report by a system auditor, which of the following deviates from the scope of work of an auditor?', NULL, 'Judging the urgency of improvements', 'Ordering improvements', 'Pointing out improvements', 'Recommending improvements', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-A-62', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When software asset management is audited, which of the following is the most appropriate point to be checked?', NULL, 'Checking to see whether compatibility with existing systems is evaluated at the time of installation', 'Checking to see whether evidence, such as a software license certificate, is properly retained', 'Checking to see whether failures are localized through database partitioning or other methods', 'Checking to see whether the organizational and functional structure of the software provider is taken into consideration', 'b', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-A-63', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is subject to system audits that evaluate and verify internal control related to IT?', NULL, 'The methods for ensuring accuracy in the processes of input and update of the database being done by the sales department', 'The process of creation of a mid-term business plan being led by the business planning department', 'The results of employee personnel evaluations being led by the personnel department', 'The status of production equipment review being conducted by the manufacturing department for the purpose of reducing defects', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '16-A-64', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate sequence of procedure for creating a business model?
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of cloud computing?', NULL, 'It is a collection of computer resources from multiple locations designed to reach a common goal.', 'It is a field of computer science that studies distributed systems in which components located on networked computers communicate and coordinate their actions by passing messages.', 'It is a model for enabling ubiquitous, convenient, on-demand access to a shared pool of configurable computing resources.', 'It is a service provisioning model in which a service provider makes computing resources and infrastructure management available to the customers as needed and charges them for a specific usage rather than a flat rate.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-66', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate combination of layers managed by vendors when using IaaS?', NULL, 'Middleware, Servers, Storage, Networking', 'Middleware, Virtualization, Servers, Storage', 'Operating system, Virtualization, Storage, Networking', 'Virtualization, Servers, Storage, Networking', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '16-A-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a work that is performed when nonfunctional requirements are defined?', NULL, 'Clarifying flows of information (i.e., data) between functions constituting business operations', 'Creating development criteria and standards based on programming language used in system development', 'Defining the scope to be implemented as system functions', 'Specifying the interface for exchanging information with other systems', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '16-A-68', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the “Question mark” product in the product portfolio management (PPM) matrix?', NULL, 'It needs appropriate investments to maintain, although it has a large rate of market share and a high rate of market growth.', 'It needs minimal investments to harvest owing to a large rate of market share and a low rate of market growth.', 'It needs significant investments to nurture owing to a small rate of market share and a high rate of market growth.', 'It needs to be withdrawn owing to a small rate of market share and a low rate of market growth.', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-A-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An apparel manufacturing and selling company is evaluated by value chain analysis. When activities in the company are classified into inbound logistics, productions, outbound logistics, sales/marketing, and services, which of the following is classified as inbound logistics?', NULL, 'Activity to deliver clothes to a buyer', 'Activity to order material, carry out inspections, and manage inventory', 'Advertising activity', 'Sewing activity', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-A-70', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a price-setting method based on cost-plus pricing?', NULL, 'On the assumption of a discount for a customer, the price is set by adding a profit margin from the beginning.', 'On the basis of manufacturing cost and operating expenses, the price is set by incorporating a desired margin.', 'The maximum profit and minimum risk are considered based on price analysis, and the price is set step by step.', 'The price is set with an estimated competitive price on the market.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-A-71', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of consumer generated media (CGM)?', NULL, 'It allows the customers of a company who want to join a mailing list to be registered to it and periodically delivers information via e-mail.', 'It enables the distribution of digital content that an individual reader creates, and it enables sharing of such content between users.', 'It integrates online shops offered by personal tenants, issues common loyalty points, and settles credit card payments on behalf of those tenants.', 'It offers functions for trading goods in an auction format and works as an intermediary between consumers in personal trading.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-A-72', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of an e-marketplace?', NULL, 'It is a method in which many sellers and buyers meet in a market set up on the Internet and trade directly without an intermediate distributor.', 'It is a method that aims for overall optimization from material procurement to product distribution by sharing information such as ordering, inventory, sales, and logistics between a company and its business partners.', 'It is a method that converts information concerning business transactions into a standardized format and electronically exchanges data such as estimation, ordering, shipment and delivery, and payment between companies.', 'It is a method that runs a sales promotion campaign on the Internet and then draws customers to a real store to encourage them to make purchases.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-A-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of a smart grid?', NULL, 'It is a system that aims at the utilization of recyclable energy, supply of stable electric power, and optimum demand adjustment through the integrated control of power generation and power consumption based on communication and information-processing technology.', 'It is a system that can provide ideal health advice to each individual by performing analysis based on similar case reports, such as the result of health examinations and medication use.', 'It is a system that can search for information on restaurants and entertainment, send and receive traffic information, and communicate the current position at the time of an emergency by using information-processing equipment installed in vehicles.', 'It is a system that supports varied work styles by enabling mutual communication between workers with varied working styles, such as home-based employees and senior workers.', 'a', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-A-74', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Products A, B, C, and D are to be introduced to the market. The table below shows the expected profit for each product with three (3) sales forecasts (High, Medium, and Low) that are estimated to occur in accordance with the probability in the table. Which of the following is the product that is expected to make the highest profit according to the expected value principle?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-75.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS03NS5wbmciLCJpYXQiOjE3NDMxMTUxMDYsImV4cCI6MTc3NDY1MTEwNn0.ULSY-55da9aQJswDMtb56QTp00_iVs--m-i1KxKl7Oo', 'A', 'B', 'C', 'D', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '16-A-75', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate Pareto chart?', NULL, 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-76-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS03Ni1BLnBuZyIsImlhdCI6MTc0MzExNTEwMSwiZXhwIjoxNzc0NjUxMTAxfQ.cWN15HvG-FrDqOfGOH8cDtm33wMYj8uFmL0ipGuF1uA', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-76-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS03Ni1CLnBuZyIsImlhdCI6MTc0MzExNTA5NiwiZXhwIjoxNzc0NjUxMDk2fQ.pw47JbnFEiAOQdIH22mrq1AdA5XmwhsWnmyX8G2GlUo', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-76-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS03Ni1DLnBuZyIsImlhdCI6MTc0MzExNTA5MiwiZXhwIjoxNzc0NjUxMDkyfQ.bOLG0p0upHPSTXTOmC5bjGmB7oFwir703Y1QvhwC_5M', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-76-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS03Ni1ELnBuZyIsImlhdCI6MTc0MzExNTA4OCwiZXhwIjoxNzc0NjUxMDg4fQ.MeXiNByrKuSjYXMhQFdFaTAo5m7t0QdtxJtsG8gk7C0', 'b', (SELECT id FROM public.categories WHERE name = 'project-management'), '16-A-76', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('With the carryover from the previous month and the quantity of inventory transactions for a product shown in the table below, what is the unit price of the product for the succeeding period using the periodic average method?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/16-A-77.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTYtQS03Ny5wbmciLCJpYXQiOjE3NDMxMTUwNzYsImV4cCI6MTc3NDY1MTA3Nn0.kUSi6_olpaShMaHJbrAYwA8hw2e5ltoYDkN82tfgRpU', '64.50', '65.00', '65.40', '70.00', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '16-A-77', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('The following inventory statement of Build-Up Property Company describes the status of the inventory since the beginning of the year 2014. If this company uses a first-in-first-out (FIFO) method for the inventory asset valuation, what is the inventory value at the end of the year 2014?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/23-O-78.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjMtTy03OC5wbmciLCJpYXQiOjE3NDMxMTY5OTMsImV4cCI6MTc3NDY1Mjk5M30.EW6xrK7rtFgXNZ7O20axKKHIwbQNcs1ysc5nU85EuPI', '7,080', '7,600', '7,800', '8,000', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '16-A-78', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A company has planned to provide a product with a fixed cost of $128,000, a variable cost per unit of $48, and a selling price per unit of $80. Which of the following is the point of sales ($) to become break-even?', NULL, '240,000', '320,000', '480,000', '560,000', 'b', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '16-A-79', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a criminal act related to a computer virus according to the Convention on Cybercrime?', NULL, 'A person creates a new virus to develop and test antivirus software.', 'A person forwards a received e-mail that is infected with a virus without being aware of the infection.', 'A person who found a virus that was created by a stranger stores the virus for the purpose that he/she can later run it on another person’s computer.', 'A person who received and found a virus offers it to an antivirus organization with a clear indication of a virus’s presence.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '16-A-80', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the sum of two binary fractions 1.0101 and 1.0111 expressed in decimal?', NULL, '2.5', '2.75', '2.875', '2.9375', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '15-O-01', 0.0, 1.0);
