INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A spam filter checks each incoming message to be classified as either spam or non-spam, and only messages classified as non-spam are to be delivered to each inbox. On average, however, one percent of messages are incorrectly classified. When 95 percent of incoming messages are spam and this filter is applied, what is the percentage of spam in each inbox?', NULL, '0.5', '1', '9.5', '16', 'd', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '15-O-03', 0.0, 1.0);
