INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In order to sort the sequence “98, 12, 4, 56, 34, 23” in ascending order by Bubble Sort algorithm, how many exchange operations are required?', NULL, '5', '7', '9', '11', 'c', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '15-O-08', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Let A be an array of size n, whose elements, A(1), A(2), ... A(n), are in ascending order. For a value k, a procedure for finding the index m which satisfies A(m) = k is described below. If no such index is found, the procedure terminates with m = 0. Which of the following is the appropriate operation to be filled in B? In the options, “/” denotes the quotient whose fractional part is discarded.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-09.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy0wOS5wbmciLCJpYXQiOjE3NDMxMTUwMjcsImV4cCI6MTc3NDY1MTAyN30.maDUKL1CN1B3x2cQVzFAVN_57PDXDl0QIP4qydbapFM', '(x + y) -> m', '(x + y) / 2 -> m', 'x − y) / 2 -> m', '(y − x) / 2 -> m', 'b', (SELECT id FROM public.categories WHERE name = 'basic-theory'), '15-O-09', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the addressing method that references data in main memory as shown in the figure below?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/18-O-11.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTgtTy0xMS5wbmciLCJpYXQiOjE3NDMxMTUwMTksImV4cCI6MTc3NDY1MTAxOX0.FbDYMfCXtkq62D4OfHVR4ZruY8Po8XI7_F6mYSC3Qk4', 'Direct addressing', 'Index addressing', 'Indirect addressing', 'Relative addressing', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-10', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When data is read into a processor and there are no hits in the cache memory, which of the following is the action that the cache memory control unit performs?', NULL, 'The required data is read from disk cache to main memory by using the block transfer mechanism.', 'The required data is read from main memory to cache memory by using the block transfer mechanism.', 'The required data is read from the hard disk to cache memory by using the block transfer mechanism.', 'The required data is written from cache memory to the hard disk by using the block transfer mechanism.', 'b', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-11', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following statement is true for DMA Controller?', NULL, 'DMA controller enables data transfer directly between input/output devices and the memory while the CPU can perform some other operations.', 'DMA controller enables data transfer directly between the cash memory and the main memory while the processor is at the waiting state.', 'DMA controller enables input/output devices to read from and write to the main memory through CPU and system bus.', 'DMA controller enables the CPU to access the main memory directly while input/output devices communicate among themselves at the same time.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-12', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Consider a disk drive that has a capacity of 8 GB. The drive has 5 platters with two surfaces, 10,000 tracks per surface and 200 sectors per track. How many bytes are in each sector? Here, 1GB is 1,000,000,000 bytes.', NULL, '100', '200', '400', '800', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-13', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the concept of a fail-safe design?', NULL, 'When a failure occurs in a leased line, switching to a public line occurs immediately, and the processing continues even though the processing efficiency of the system declines.', 'When a failure occurs in the data transfer process of a data collecting system, only the data input process is performed, and all the data is transmitted at the time of recovery from the failure.', 'When a failure occurs in the data transfer process of a data collecting system, only the data input process is performed, and all the data is transmitted at the time of recovery from the failure.', 'When the system determines that there is a fault in the sensor for detecting if someone has entered the working envelope or work area, the robot arm is stopped forcibly.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-14', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning the reliability of a computer system?', NULL, 'As the system configuration becomes more complicated, MTBF (Mean Time Between Failures) increases.', 'Availability of systems can be improved by increasing MTTR (Mean Time To Repair) and MTBF.', 'Preventive maintenance of systems is performed to increase MTBF.', 'Remote maintenance of systems can increase MTTR and improve availability.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-15', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the expression that indicates the availability of an entire multiplex system composed of five subsystems having an availability of P for each subsystem, as shown in the figure below? Here, as long as at least one of the paths connected in parallel is working, the system can be regarded as working.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-16.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy0xNi5wbmciLCJpYXQiOjE3NDMxMTQ5NzcsImV4cCI6MTc3NDY1MDk3N30.RBOC-ubMSUXRdRQm7vNcr8L_liBNYvyMLsP8rFSYmqE', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-16-A.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy0xNi1BLnBuZyIsImlhdCI6MTc0MzExNDk4NiwiZXhwIjoxNzc0NjUwOTg2fQ.zyA2WSCjzfNZMJVJwlNjGr-wjYZ4zwMmEu5gdVqzkNU', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-16-B.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy0xNi1CLnBuZyIsImlhdCI6MTc0MzExNDk5MCwiZXhwIjoxNzc0NjUwOTkwfQ.H9Xc5lqqOSTvrLssHdhZLzDNYXPx5g0ToUrlhfDQ9EY', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-16-C.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy0xNi1DLnBuZyIsImlhdCI6MTc0MzExNDk5NCwiZXhwIjoxNzc0NjUwOTk0fQ.pU7THyvZ8nmW7FrvGMhlsKS8OQkE8XJME7xolcrhe3s', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-16-D.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy0xNi1ELnBuZyIsImlhdCI6MTc0MzExNDk5OCwiZXhwIjoxNzc0NjUwOTk4fQ.dm-s-_3ARtYXMwBjCQaOWwwcBBqafpH8MDKh284UWgs', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-16', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a paged virtual memory, the LRU method is adopted for the page replacement algorithm. When the page frame allocated to the main memory is 4, which of the following page is to be replaced when page 6 is accessed if the pages are accessed in the order of page 1, 2, 3, 4, 5, 2, 1, 3, 2, 6? Here, no page exists in the main memory in the initial state.', NULL, '1', '2', '4', '5', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-17', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A real-time OS, which performs preemptive scheduling based on priority, schedules the tasks A and B. When A has a higher priority than B, which of the following is an appropriate action that is performed by the real-time OS?', NULL, 'When A is launched during the execution of B, B is put into a “ready” state and A is executed.', 'When A is launched during the execution of B, B is put into a “waiting” state and A is executed.', 'When B is launched during the execution of A, A is put into a “ready” state and B is executed.', 'When B is launched during the execution of A, A is put into a “waiting” state and B is executed.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-18', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the spooling function?', NULL, 'Execution of the programs is temporarily suspended, and control is transferred to the control program.', 'If a CPU becomes idle because of the execution of input/output instructions while executing a certain task, the CPU is assigned to another task.', 'The access time to auxiliary storage devices is reduced by providing a buffer pool consisting of multiple buffers and by increasing the probability of accessing buffers located in the main storage.', 'The overall processing power of a system is enhanced by performing data transfer between the main storage and low-speed input/output devices via auxiliary storage devices.', 'd', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-19', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of an absolute path name of a file system?', NULL, 'It is the path name from the current directory up to the target file.', 'It is the path name from the home directory up to the target file.', 'It is the path name from the root directory up to the target file.', 'It is the shortest path name from among the several path names from a directory up to the target file.', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-20', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of DRAM?', NULL, 'It is memory that needs to be refreshed, and is used for main memory in a PC.', 'It is non-volatile memory that can erase and write data in units of one byte, and it is used when data preservation is required even if the power supply is interrupted.', 'It is non-volatile memory that has NAND types and NOR types, and is used for SSD.', 'Its memory cells are composed of flip-flops, and it is used for cache memory.', 'a', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-21', -2.0, 1.0);
