INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A device, which operates at a 100V household power supply and through which a current of 10 A flows during operation, is operated from 0 minutes to 120 minutes as shown in the figure below. How much electrical energy, in watt-hour, is consumed at this time? Here, the value of the voltage and current is the effective value, and no current flows when the device stops. Moreover, the power factor is 1.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-22.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0yMi5wbmciLCJpYXQiOjE3NDMxMTQ5MTMsImV4cCI6MTc3NDY1MDkxM30.rB9j3JDpUhDwHFf4us9M_yZBDvaGf5If9WzpWhZkdM8', '1,000', '1,200', '1,500', '2,000', 'c', (SELECT id FROM public.categories WHERE name = 'computer-system'), '15-O-23', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the standard used to describe the look and formatting of markup language documents such as HTML and XHTML?', NULL, 'CMS', 'CSS', 'RSS', 'Wiki', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-24', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the process of creating animation, which of the following is used to incorporate the natural movement of objects, humans and animals, by using sensors and video cameras?', NULL, 'Key frame method', 'Morphing', 'Motion Capture', 'Pixel Shader', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-25', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the descriptions concerning database models, which of the following is an appropriate explanation of the network model?', NULL, 'It consists of two or more data files located at different sites on a computer network.', 'It presents information in two-dimensional tables with rows and columns.', 'Its records are organized into a tree structure.', 'Its records can have multiple parent records and multiple child records.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-26', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When the relationships between continent and country and between country and city are shown in the class diagram below, which of the following is an appropriate combination of multiplicities that are to be inserted into blank A through blank D? Here, there is no cross continental country. Each continent has at least one country, and each country has at least one city.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/21-O-25.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMjEtTy0yNS5wbmciLCJpYXQiOjE3NDMxMTQ4ODksImV4cCI6MTc3NDY1MDg4OX0._YBOnl_YqXPmEsw01jcBQwmhGW61BcPTDwCOwrSToQw', 'a', 'b', 'c', 'd', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-27', 0.0, 1.0);
