INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the operation of a relational database, which of the following is an appropriate explanation of projection?', NULL, 'From two or more sets of tables, the sets that match conditions are combined together to create a new table.', 'Only specific columns are extracted from a table.', 'The query result of a table and the query result of another table are combined together and set in one table.', 'The rows that match specific conditions are extracted from a table.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-29', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an SQL statement that gives the same result as the SQL statement that is described below for the “Product” table and the “Inventory” table? Here, the underlined part indicates the primary key.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/19-O-29.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTktTy0yOS5wbmciLCJpYXQiOjE3NDMxMTQ4NjAsImV4cCI6MTc3NDY1MDg2MH0.C4joSdTTe4JEhFvPUleyBZEEXKu1LxzEdPM_lhC_jNk', 'SELECT ProductNumber FROM Product 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the role of DNS in a TCP/IP network?', NULL, 'A private IP address is translated into a global IP address in order to access the Internet.', 'A program in a server can be invoked only by its name without taking the IP address of the server into consideration.', 'In response to an assignment request of an IP address from a PC or a printer, an unused address is chosen from the addresses registered in the server.', 'IP addresses are mapped to domain names, host names, and other such information.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-31', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In OSI basic reference model, what devices are used for segmentation or coupling of Physical layer, Data Link layer and Network layer respectively?', NULL, 'Bridge, Repeater, Router', 'Bridge, Router, Repeater', 'Repeater, Bridge, Router', 'Repeater, Router, Bridge', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-32', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In TCP/IP networks, which command uses the ICMP “Echo”, “Echo Reply” and “Destination Unreachable” messages to test the reachability of the communication partner ?', NULL, 'arp', 'echo', 'ipconfig', 'ping', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-33', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which application protocol must support UDP as its transport layer protocol?', NULL, 'DNS', 'FTP', 'HTTP', 'Telnet', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-34', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of POP3 used in e-mail systems?', NULL, 'It is a protocol used to authenticate a user with his/her user ID and password after the PPP connection is established.', 'It is a protocol used to exchange e-mail messages between mail servers.', 'It is a protocol used to receive e-mail messages from the mailbox of a mail server.', 'It is a protocol used to send e-mail messages from a PC.', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-35', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most appropriate case example of social engineering?', NULL, 'A person scans for open wireless networks available in his/her home area by using his/her portable computer, and then he/she posts the names and locations of the networks found on the website in order to allow his/her friends to have access to free Wi-Fi networks.', 'A phone call was made to a helpdesk of a computer center. By using the personal information scavenged from a trash bin, the caller convinces the helpdesk staff that he/she is a legitimate user, in order to have the password initialized and then break into the system.', 'Advertising messages selling illegal products are sent to an unspecified large number of recipients without prior consent. Even though most recipients ignore or discard the messages, some of them are interested and decide to contact the sender to buy the products.', 'Although a company’s computer network is protected by the firewall, malware is able to spread throughout the company because an employee may unintentionally infect a computer with a virus from his/her personal USB flash memory.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-36', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a purpose of using message digest in a message authentication code?', NULL, 'To check the encryption method of a message', 'To check the overview of a message', 'To confirm that there is no falsification of a message', 'To secure the confidentiality of a message', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-37', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an attack that threatens the “integrity” in information security?', NULL, 'A DoS attack by which the system is set to an overloaded state', 'Falsification of a Web page', 'Tapping of communication content', 'Unauthorized copying of data saved in a system', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-38', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of SQL injection?', NULL, 'It is an attack by sending data containing a malicious script to a website where a visitor views the visitor''s input data on the screen as it is, and making the script executed in the visitor''s browser.', 'It is an attack where a command for performing a malicious query or operation in the database is entered when there is a problem in a Web application, and the data of the database is modified or acquired without authorization.', 'It is an attack where a vulnerability of a commercial DBMS (DataBase Management System) is exploited to search the host database server and cause repeated self-infection in order to cause a rapid increase in Internet traffic.', 'It is an attack where a website visitor is made to view a Web page containing an embedded malicious script, and the visitor is then made to perform an unintentional operation on another website.', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-39', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate operation in user authentication that uses an IC card and PIN?', NULL, 'If an IC card is lost, a new IC card is issued, and after the PIN is reset, the lost IC card is deactivated.', 'Since each user can be identified by an IC card, a common PIN is set for all users in order to reduce the management workload.', 'The PIN is set by combining the numeric information imprinted on the surface of the IC card.', 'When an IC card is delivered, the PIN is not enclosed, but is notified to the user through another channel.', 'd', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-40', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a database that manages user information, there exists an application that searches for user information and displays it. In terms of security management, which of the following is an appropriate level of privilege for access to the database to be assigned to this application? Here, the scope of each privilege is as below.
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('When a biometric authentication system is installed, which of the following is the most appropriate point to be considered?', NULL, 'Adjusting the system in consideration of both the probability of incorrectly rejecting an authorized user and the probability of incorrectly accepting an unauthorized user', 'Combining various measures, such as heuristics, in addition to frequent updates of the pattern file', 'Getting a reliable third party to issue the digital certificate of the concerned person', 'Getting a reliable third party to issue the digital certificate of the concerned person', 'a', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-42', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following technology is the most suitable to divide the whole company network into the networks by department?', NULL, 'DMZ (DeMilitarized Zone)', 'NAT (Network Address Translation)', 'VLAN (Virtual Local Area Network)', 'VPN (Virtual Private Network)', 'c', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-43', -2.0, 1.0);
