INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the most suitable system for a design using a state transition diagram?', NULL, 'A greenhouse control system, which keeps the environment in a greenhouse optimum based on the information of the installed sensors', 'A water bill accounting system, which calculates charges from the data of water meters', 'An inventory-taking system, which counts the inventory assets at the end of each month and at book closing', 'An operations measurement system for system resources, which measures the operational status of the system resources, and generates a report', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-46', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among UML 2.x, (including 2.0 and later versions) diagrams, which of the following is the most appropriate diagram that can gives a graphic overview of the actors involved in a system, different functions needed by those actors and how these different functions are interacted?', NULL, 'Activity diagram', 'Communication diagram', 'Interaction Overview diagram', 'Use Case diagram', 'd', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-47', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation about the following UML class diagram?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-48.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy00OC5wbmciLCJpYXQiOjE3NDMxMTQ3ODQsImV4cCI6MTc3NDY1MDc4NH0.Wlqju_tDTBE3a5y0kUOipZ-KQOqFATvRHWOTy9XfxUo', 'An instance of Class1 associated with has an instance of Class2.', 'An instance of Class2 is a logical part of an instance of Class1.', 'An instance of Class2 is a physical part of an instance of Class1.', 'An instance of Class2 is like an instance of Class1. Class2 inherits from Class1.', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-48', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of how to design test cases for a black box test?', NULL, 'Test cases are designed according to the program’s functional specifications and interface specifications.', 'Test cases are designed on the basis of the procedure and internal structure of the program.', 'Test cases are designed so that each of the decision conditions in the program can evaluate both TRUE and FALSE at least once.', 'Test cases are designed with reference to program specifications or the source list, after the program specifications are finalized or the coding is completed.', 'a', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-49', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the purpose of a stress test?', NULL, 'To compare performance with other computers by measuring the execution time of a standard program', 'To confirm the operation at the limits of processing capability that is required for a system', 'To confirm that there are no unintended effects on the program functions that have no relation to correction or change in the program', 'To evaluate the usability of a system by having actual users use the system', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-50', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the process of changing a software system in such a way that it does not alter the external behavior of the code yet improves its internal structure?', NULL, 'Reengineering', 'Refactoring', 'Restructuring', 'Reverse engineering', 'b', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-51', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the spiral model in system development?', NULL, 'In this model, cycles are divided up into smaller, more easily managed iterations called build. Each iteration passes through the requirements, design, implementation and testing phases.', 'In this model, each phase must be completed in its entirety before the next phase begins. At the end of each phase, a review takes place to determine if the project is on the right path and whether to continue the project or not.', 'This model has four phases: Planning, Risk Analysis, Engineering and Evaluation. A software project repeatedly passes through these phases in iterations.', 'This model is a sequential execution of processes. Each phase must be completed before the next phase begins. Testing is emphasized in this model and the testing procedures are developed early in the life cycle before any coding is done, during each of the phases preceding implementation.', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-52', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate tool that implements a deliverable-oriented decomposition of a project into smaller components?', NULL, 'Critical Path Management (CPM)', 'Gantt Chart (Gantt)', 'Project Evaluation and Review Technique (PERT)', 'Work Breakdown Structure (WBS)', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '15-O-53', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In a project to create the screens for a system that is composed of 100 screens in all, there are 30 small size screens of low complexity, 40 medium size screens of medium complexity, 20 large screens of medium complexity, and 10 large screens of high complexity. When the number of person-days is estimated on the basis of the standard task method with the standard number of person-days as shown in the table below, how many person-days are required to complete the project? Here, a review of all the screens requires five person-days, and project management requires 20% of the total person-days including the person-days for review.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-54.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy01NC5wbmciLCJpYXQiOjE3NDMxMTQ3NzcsImV4cCI6MTc3NDY1MDc3N30.YXBR4UUFLb0yiGVKWtpg019Byiy7sWSde12drhvkA-E', '80', '85', '101', '102', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '15-O-54', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('In the arrow diagram shown in the figure below, in order to reduce the time period of the entire project, some activities from activity A through E are reduced by one day each. Which of the following is a combination of activities by which the entire project can be shortened by two days?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-55.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy01NS5wbmciLCJpYXQiOjE3NDMxMTQ3NzMsImV4cCI6MTc3NDY1MDc3M30.Ueq8QpwdR-yeWDjCVui9AITFEdBxVQSnO-MEijNbmh0', 'A, C, E', 'A, D', 'B, C, E', 'B, D', 'd', (SELECT id FROM public.categories WHERE name = 'project-management'), '15-O-55', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('What is the function point value of a program that has the functions and characteristics shown in the table below? Here, the correction coefficient of complexity is 0.75.', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-56.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy01Ni5wbmciLCJpYXQiOjE3NDMxMTQ3NjgsImV4cCI6MTc3NDY1MDc2OH0.xjGZVKlrEDJfwt0YxEKgJZbAj2DeQgG65QhsXmltj-M', '18', '24', '30', '32', 'a', (SELECT id FROM public.categories WHERE name = 'project-management'), '15-O-56', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('An IT service is provided under the conditions described below. In order to meet the SLA, which of the following is the maximum allowable downtime (in hours) per month during service hours? Here, the number of business days in a month is 30, and there is no planed service outage for a reason of maintenance or something similar during the service hours.
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to ISO/IEC 20000-1, which of the following is an activity in the PDCA of the Service Delivery Processes?', NULL, 'Documenting supplier management, assigning a contact person and reviewing contracts regularly to meet requirements within SLA', 'Establishing processes and procedures in handling customer complaints with escalation channels and feedback', 'Evaluating the projected capacity and performance for service requests, new technologies, and upgrade procedures', 'Recording changes and updates to existing service assets and configuration items while auditing is done to monitor unauthorized changes', 'c', (SELECT id FROM public.categories WHERE name = 'service-management'), '15-O-58', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to ISO/IEC 20000-1, which of the following is the appropriate processes that contain change management, configuration management, and release and deployment management?', NULL, 'Control processes', 'Relationship processes', 'Resolution processes', 'Service delivery processes', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '15-O-59', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a measure that enables an operator to surely recognize the occurrence of a system fault?', NULL, 'To install monitoring cameras covering the entirety of the server room, and to monitor the room continuously', 'To provide a function to perform a full backup of files at a fixed time every day', 'To provide a function to perform a snapshot dump or memory dump in the event of a fault', 'To provide functions to sound an alarm or light indicator lamps, linked to an alarm or other message sent to the system console', 'd', (SELECT id FROM public.categories WHERE name = 'service-management'), '15-O-60', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning an interview conducted during a system audit?', NULL, 'Efforts are made to get documents and records that support the information which has been obtained from the departments under audit through the interview.', 'The departments under audit are immediately instructed to take measures for the improvement of deficiencies identified during the interview.', 'The interview is conducted by one system auditor because some sort of discrepancy may arise in records if multiple auditors are involved.', 'The interviewee is selected from the managers of the departments under audit who are familiar with the business operations to be audited.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '15-O-61', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description concerning the role of a system auditor?', NULL, 'It is to assure the preparation and operations regarding the control of the information system or to give advice on these, from a standpoint of professional standpoint independent from the audit target.', 'It is to evaluate the performance of the information system and to issue an audit working paper to the system users.', 'It is to instruct the testing staff to improve defects found during the comprehensive test for the information system.', 'It is to test if processes are performed according to the plan and then to approve the release.', 'a', (SELECT id FROM public.categories WHERE name = 'service-management'), '15-O-62', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of BPO?', NULL, 'Contracting out all business processes of a company’s specific department, such as an administrative department or call center, to an external service provider, together with the operations of a business system', 'Operating a system by renting part of the processing power and memory capacity of the server owned by a telecom carrier, etc., instead of taking possession of a company’s own server', 'Reducing the cost of software development by using a temporary staff agency’s worker whose labor cost is lower than that of a company’s regular employee', 'Using software functions offered by an external service provider via a network, instead of taking possession of company’s own software', 'a', (SELECT id FROM public.categories WHERE name = 'system-strategy'), '15-O-63', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is the cloud-computing service model that allows users to install operating-system images and their application software on the system?', NULL, 'Desktop as a service (DaaS)', 'Infrastructure as a service (IaaS)', 'Platform as a service (PaaS)', 'Software as a service (SaaS)', 'b', (SELECT id FROM public.categories WHERE name = 'technology-element'), '15-O-64', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('According to the ISO/IEC 12207, the activities of the requirements definition process include stakeholder identification, requirements identification, requirements evaluation, and requirements agreement. Among these activities, which of the following is a task that is implemented in requirements identification?', NULL, 'Analyzing elicited requirements, eliminating conflicting and ambiguous points, and organizing them as a set of consistent requirements', 'Clarifying which parties will take part in which processes throughout the entire system life cycle', 'Clarifying which parties will take part in which processes throughout the entire system life cycle', 'Explaining how to resolve conflicting and impractical requirements to stakeholders, and obtaining agreement', 'c', (SELECT id FROM public.categories WHERE name = 'development-technology'), '15-O-65', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the green procurement (sustainable procurement)?', NULL, 'It refers to a certificate that enables commercial trading of the green power that is generated from natural energy such as sunlight, biomass, wind power, and geothermal heat.', 'It refers to a mass promotion of the environmental protection activities and the fund raising from investors for the environmental protection.', 'It refers to a preferential purchase of products and services that exert a lower environmental burden.', 'It refers to an international standard concerning environmental labels such as eco mark that is certified by a third party as a product that contributes to environment protection.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '15-O-66', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique that is used to identify and evaluate the internal and external factors that are helpful or harmful to the objectives of business organizations or projects?', NULL, 'Five forces analysis', 'PPM analysis', 'SWOT analysis', 'Value chain analysis', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '15-O-67', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a technique for classifying company activities into primary activities and support activities, and analyzing which activities generate the profit of the products or services provided to customers?', NULL, '3C analysis', 'Five forces analysis', 'SWOT analysis', 'Value chain analysis', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '15-O-68', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the core competence?', NULL, 'It refers to the business domain that is decided from the viewpoint of the market, technology, and products (or services).', 'It refers to the corporate activities that comply with laws, various regulations, and social norms for managing business.', 'It refers to the overall system optimization techniques for achieving the purpose of organizational activities.', 'It refers to the predominant abilities in the business area of the company, which cannot be imitated by competitors.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '15-O-69', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is a description of the growth stage of the product life cycle?', NULL, 'It is the stage at which companies sell products to early adopters. Companies adopt strategies to enhance product recognition.', 'It is the stage at which growth in demand slows. Companies try to maintain market share and secure profits through various means such as quality improvements.', 'It is the stage at which sales and profit gradually decline. Companies refrain from additional investment and consider withdrawal from the market.', 'It is the stage at which sales increase rapidly. The market becomes active and the competition intensifies because of new market participants.', 'd', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '15-O-70', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Among the different business systems supported by technology, which of the following analyzes routes of distribution, tracking and load tendency?', NULL, 'LMS', 'OMS', 'TMS', 'WMS', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '15-O-71', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of the strategy map that is used in the balanced score card?', NULL, 'It classifies and shows the products or businesses of a company in the four cells formed by the two axes of the market attractiveness and the company’s superiority.', 'It shows the cause-and-effect relationship between issues, countermeasures, and goals, on the basis of the four perspectives that consist of finance, customer, internal business process, and learning and growth.', 'It shows the position of a company or its products in a market by using two key elements as the X-axis and Y-axis.', 'It shows what types of management resources to be used, what types of products and services to be provided, and what types of customers to be targeted.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '15-O-72', -1.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate explanation of the concurrent engineering?', NULL, 'A new product development technique that sequentially executes processes such as product design, manufacturing, and sales activities', 'A technique that analyzes a target system and clarifies its specifications', 'A technique that executes processes such as product design and production planning in parallel during the new product development procedure', 'A technique that tries to figure out the optimal combinations of functions and cost, and to improve value through systematic procedures', 'c', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '15-O-73', -2.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an explanation of CAD?', NULL, 'By using computers, converting drawings of the product design to the process design information, and supporting automation of machine processing, etc.', 'By using computers, creating drawings of the product design from attribute data concerning product shape, composition, etc.', 'By using computers, evaluating product performance and functions without actual products', 'By using computers, finding required volumes and timing of materials from a production schedule, a BOM (bill of materials), inventory volumes, etc.', 'b', (SELECT id FROM public.categories WHERE name = 'business-strategy'), '15-O-74', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A company sells two products A and B, making a profit of 40 dollars and 30 dollars per unit on them respectively. They are produced in a common production process and are sold in two different markets. The production process has a total capacity of 3000 person-hours. The production time of product A is 3 person-hours which is three times longer than that of product B. The market has been surveyed and company officials feel that the maximum number of units of product A that can be sold is 8000 and that of product B is 1200. Subject to these limitations, products can be sold in any combination. Which of the following is a formulation result of a linear programming model for the question which obtains the production amount that maximizes the total profit of the company? Here, assume the number of units produced of product A and that of product B as x and y, respectively.', NULL, 'Objective function  40x+30y -> to be maximized 
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Peter plans to open his own coffee shop. He uses break-even analysis to evaluate the feasibility. He needs to rent a coffee making machine at 20 dollars per day. The average cost of coffee ingredients is 0.40 dollars per cup and the cost of a plastic cup is 0.10 dollars. He sets a price at 1.50 dollars per cup. What is the sales revenue a day at the break-even point?', NULL, '10', '25', '30', '75', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '15-O-76', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('There is an enterprise whose current liabilities valued 2,400 dollars and the current assets valued 5,000 dollars including inventory assets valued 200 dollars. What is an acid test ratio (in percentage) of the enterprise?', NULL, '108', '148', '200', '220', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '15-O-77', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Break-even point of the new product is 12,000 units a month. Fixed cost is 800,000 dollars a month and variable cost is 20 dollars per unit. Based on the information above, which of the following is a selling price of the new product?', NULL, '46.67', '66.67', '86.67', '89.23', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '15-O-78', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('A cost schedule showing total costs of the production is given below. Which of the following is an appropriate combination of the average cost of producing 2 units, and the marginal cost of producing the 5th unit?', 'https://dmabshuefoqtrtegznzw.supabase.co/storage/v1/object/sign/question-images/15-O-79.png?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1cmwiOiJxdWVzdGlvbi1pbWFnZXMvMTUtTy03OS5wbmciLCJpYXQiOjE3NDMxMTQ3NDYsImV4cCI6MTc3NDY1MDc0Nn0.e5ex2xEVcucG0IExUVofUilQ0bttnS3Msfza4jfDbzI', 'a', 'b', 'c', 'd', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '15-O-79', 0.0, 1.0);
INSERT INTO public.questions (question_text, image_url, option_a, option_b, option_c, option_d, correct_answer, category_id, exam_source, difficulty, discrimination) VALUES ('Which of the following is an appropriate description of the protection scope of software under the WTO’s Agreement on Trade-Related Aspects of Intellectual Property Rights (TRIPS)?', NULL, 'Algorithms and program languages are protected under the agreement.', 'Application programs are protected under the agreement but basic programs such as an OS are not covered, because the value of the right is included in the hardware cost.', 'Both source programs and object programs are protected by the agreement.', 'Documents describing a mathematical formula are not protected under the agreement, but the mathematical formula itself is protected.', 'c', (SELECT id FROM public.categories WHERE name = 'corporate-legal'), '15-O-80', -1.0, 1.0);
